  `category_id` int(10) UNSIGNED NOT NULL COMMENT '文章分类',
  `view_count` int(10) UNSIGNED NOT NULL DEFAULT 0 COMMENT '查看数',
  `cover` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '缩略图',
  `status` tinyint(1) NOT NULL DEFAULT 1 COMMENT '是否显示',
  `order` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '排序',
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  `deleted_at` timestamp(0) NULL DEFAULT NULL,
  `is_recommend` tinyint(1) UNSIGNED NULL DEFAULT 0 COMMENT '是否推荐 1:推荐 0:不推荐',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `articles_user_id_index`(`admin_user_id`) USING BTREE,
  INDEX `articles_category_id_index`(`category_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 177 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '文章' ROW_FORMAT = Compact;

-- ----------------------------
-- Records of articles
-- ----------------------------

