-- ----------------------------
-- Table structure for bank_imports
-- ----------------------------
DROP TABLE IF EXISTS `bank_imports`;
CREATE TABLE `bank_imports`  (
  `id` int(11) UNSIGNED NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NULL DEFAULT NULL,
  `coin_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '',
  `number` decimal(20, 8) NULL DEFAULT NULL,
  `zhe_number` decimal(20, 8) NULL DEFAULT NULL,
  `type` tinyint(2) NULL DEFAULT NULL,
  `bank_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '银行名',
  `bank_branch` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '支行名',
  `bank_branch_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '分行号码',
  `bank_number` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '账户号码',
