  `qr_url` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '二维码地址',
  `status` tinyint(2) NULL DEFAULT NULL COMMENT '状态 0-已提交待审核 1-已审核 2-已付款待审核 3-已完成 4-失败',
