  `created_at` timestamp(0) NULL DEFAULT NULL COMMENT '记录创建时间',
  `updated_at` timestamp(0) NULL DEFAULT NULL COMMENT '记录更新时间',
  `deleted_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 56 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '轮播图' ROW_FORMAT = Compact;

