-- ----------------------------
-- Table structure for bonus_logs
-- ----------------------------
DROP TABLE IF EXISTS `bonus_logs`;
CREATE TABLE `bonus_logs`  (
  `id` int(11) UNSIGNED NOT NULL AUTO_INCREMENT,
  `user_id` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '用户ID',
  `coin_id` int(11) UNSIGNED NULL DEFAULT 0 COMMENT '币种ID',
  `coin_name` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '币种名称',
  `account_type` tinyint(1) UNSIGNED NULL DEFAULT 1 COMMENT '账户类型',
  `rich_type` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '资产类型',
  `amount` decimal(12, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '数量',
  `log_type` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '日志类型',
  `status` tinyint(4) NULL DEFAULT 1 COMMENT '状态 -1已关闭 1待发放 2已发放',
  `hand_time` timestamp(0) NULL DEFAULT NULL COMMENT '发放时间',
  `bonusable_id` int(11) UNSIGNED NULL DEFAULT 0,
  `bonusable_type` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '系统发放分红记录' ROW_FORMAT = Dynamic;

