-- ----------------------------
-- Table structure for center_wallet
-- ----------------------------
DROP TABLE IF EXISTS `center_wallet`;
CREATE TABLE `center_wallet`  (
  `center_wallet_id` smallint(6) UNSIGNED NOT NULL AUTO_INCREMENT,
  `center_wallet_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `center_wallet_account` varchar(80) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL DEFAULT '' COMMENT '中心钱包账户名',
  `center_wallet_address` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL DEFAULT '' COMMENT '中心钱包地址',
  `center_wallet_password` varchar(80) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL DEFAULT '',
  `center_wallet_balance` decimal(25, 12) UNSIGNED NOT NULL DEFAULT 0.000000000000 COMMENT '中央钱包余额',
  `coin_id` int(10) UNSIGNED NOT NULL DEFAULT 0 COMMENT '币种id',
  `private_key` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `min_amount` decimal(12, 4) NULL DEFAULT NULL,
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`center_wallet_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '平台中心钱包账户信息' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for coin_config
-- ----------------------------
DROP TABLE IF EXISTS `coin_config`;
CREATE TABLE `coin_config`  (
  `id` bigint(20) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT 'id',
  `symbol` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '产品代码',
  `datetime` timestamp(0) NULL DEFAULT NULL COMMENT '日期时间',
  `name` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '产品名称',
  `open` float(18, 5) NULL DEFAULT 0.00000 COMMENT '开盘价',
  `high` float(18, 5) NULL DEFAULT 0.00000 COMMENT '最高价',
  `low` float(18, 5) NULL DEFAULT 0.00000 COMMENT '最低价',
  `close` float(18, 5) NULL DEFAULT 0.00000 COMMENT '最新价',
  `min_amount` float(18, 5) UNSIGNED NULL DEFAULT 0.00000 COMMENT '最小成交额',
  `max_amount` float(18, 5) UNSIGNED NULL DEFAULT 0.00000 COMMENT '最大成交额',
  `status` tinyint(1) UNSIGNED NULL DEFAULT 0,
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for coins
-- ----------------------------
DROP TABLE IF EXISTS `coins`;
CREATE TABLE `coins`  (
  `coin_id` int(10) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键',
  `coin_name` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL DEFAULT '' COMMENT '虚拟货币名称',
  `symbol` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `qty_decimals` int(11) NOT NULL,
  `price_decimals` int(11) NOT NULL,
  `full_name` text CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL,
  `withdrawal_fee` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0',
  `withdrawal_min` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0',
  `withdrawal_max` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0',
  `coin_withdraw_message` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '提币时的注意事项',
  `coin_recharge_message` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '充值时的注意事项',
  `coin_transfer_message` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '划转时的注意事项',
  `coin_content` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL,
  `coin_icon` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `status` tinyint(1) UNSIGNED NULL DEFAULT 1,
  `appKey` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `appSecret` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `official_website_link` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '官网链接',
  `white_paper_link` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '白皮书链接',
  `block_query_link` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '区块查询链接',
  `publish_time` timestamp(0) NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP(0) COMMENT '发行时间',
  `total_issuance` bigint(20) NULL DEFAULT NULL COMMENT '发行总量',
  `total_circulation` bigint(20) NULL DEFAULT NULL COMMENT '流通总量',
  `crowdfunding_price` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `order` int(10) UNSIGNED NULL DEFAULT 1,
  `is_withdraw` tinyint(1) UNSIGNED NULL DEFAULT 0 COMMENT '区块提币',
  `is_recharge` tinyint(1) UNSIGNED NULL DEFAULT 0 COMMENT '区块充值',
  `can_recharge` tinyint(1) UNSIGNED NULL DEFAULT 0 COMMENT '可后台充值',
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  `jiedianwangluo` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '节点网络',
  `guding_query_link` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '固定充币地址',
  `is_czlx` tinyint(1) UNSIGNED NULL DEFAULT 0 COMMENT '充值类型',
  PRIMARY KEY (`coin_id`) USING BTREE,
  UNIQUE INDEX `coin_name`(`coin_name`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1084 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '虚拟货币类型' ROW_FORMAT = Compact;

-- ----------------------------
-- Records of coins
-- ----------------------------

