-- ----------------------------
-- Table structure for contract_account
-- ----------------------------
DROP TABLE IF EXISTS `contract_account`;
CREATE TABLE `contract_account`  (
  `id` int(11) UNSIGNED NOT NULL AUTO_INCREMENT,
  `user_id` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '用户ID',
  `coin_id` int(11) UNSIGNED NULL DEFAULT NULL COMMENT '币种ID',
  `coin_name` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '币种名称',
  `margin_name` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'USDT' COMMENT '合约保证金币种',
  `usable_balance` decimal(20, 8) UNSIGNED NOT NULL DEFAULT 0.00000000 COMMENT '可用',
  `used_balance` decimal(20, 8) UNSIGNED NOT NULL DEFAULT 0.00000000 COMMENT '持仓保证金',
  `freeze_balance` decimal(20, 8) UNSIGNED NOT NULL DEFAULT 0.00000000 COMMENT '委托冻结',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `user_id`(`user_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 4 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '永续合约账户' ROW_FORMAT = Compact;

-- ----------------------------
-- Records of contract_account
-- ----------------------------

-- ----------------------------
-- Table structure for contract_deal_robot
-- ----------------------------
DROP TABLE IF EXISTS `contract_deal_robot`;
CREATE TABLE `contract_deal_robot`  (
  `id` bigint(20) UNSIGNED NOT NULL AUTO_INCREMENT,
  `contract_id` int(11) UNSIGNED NULL DEFAULT 0 COMMENT '合约ID',
  `symbol` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '符号',
  `bid_plus_unit` decimal(8, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '买单价格向上波动单位',
  `bid_plus_count` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '买单价格向上波动计数',
  `bid_minus_unit` decimal(8, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '买单价格向下波动单位',
  `bid_minus_count` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '买单价格向下波动计数',
  `ask_plus_unit` decimal(8, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '卖单价格向上波动单位',
  `ask_plus_count` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '卖单价格向上波动计数',
  `ask_minus_unit` decimal(8, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '卖单价格向下波动单位',
  `ask_minus_count` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '卖单价格向下波动计数',
  `status` tinyint(1) UNSIGNED NOT NULL DEFAULT 0 COMMENT '0关闭 1开启',
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `symbol`(`symbol`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '合约交易成交机器人' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for contract_entrust
-- ----------------------------
DROP TABLE IF EXISTS `contract_entrust`;
CREATE TABLE `contract_entrust`  (
  `id` int(10) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键',
  `order_no` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL DEFAULT '0' COMMENT '订单号',
  `order_type` tinyint(1) UNSIGNED NOT NULL DEFAULT 1 COMMENT '交易类型 1开仓 2平仓',
  `user_id` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '用户id',
  `side` tinyint(1) UNSIGNED NOT NULL DEFAULT 1 COMMENT '买卖方向 1买入 2卖出',
  `contract_id` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '合约',
  `contract_coin_id` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '合约币种id',
  `symbol` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '合约symbol',
  `margin_coin_id` int(10) UNSIGNED NOT NULL DEFAULT 1,
  `unit_amount` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `type` tinyint(1) UNSIGNED NOT NULL DEFAULT 1 COMMENT '委托方式 1限价交易 2市价交易',
  `entrust_price` decimal(20, 8) UNSIGNED NULL DEFAULT NULL COMMENT '委托价格',
  `trigger_price` decimal(20, 8) UNSIGNED NULL DEFAULT NULL,
  `amount` int(20) UNSIGNED NOT NULL DEFAULT 0 COMMENT '委托张数',
  `traded_amount` int(20) UNSIGNED NULL DEFAULT 0 COMMENT '已成交张数',
  `avg_price` decimal(20, 8) UNSIGNED NULL DEFAULT NULL COMMENT '成交均价',
  `profit` decimal(20, 8) NULL DEFAULT NULL COMMENT '盈亏',
  `settle_profit` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '实际结算盈亏',
  `is_wear` tinyint(1) UNSIGNED NULL DEFAULT 0 COMMENT '是否穿仓',
  `lever_rate` int(10) UNSIGNED NOT NULL DEFAULT 0 COMMENT '杠杆倍数',
  `margin` decimal(20, 8) NULL DEFAULT NULL COMMENT '委托保证金',
  `fee` decimal(20, 8) NULL DEFAULT NULL COMMENT '委托手续费',
  `status` tinyint(4) UNSIGNED NOT NULL DEFAULT 1 COMMENT '交易进度 0已撤单，1未成交，2部分成交，3全部成交',
  `hang_status` tinyint(1) UNSIGNED NULL DEFAULT 1,
  `cancel_time` int(13) UNSIGNED NULL DEFAULT NULL,
  `ts` int(13) UNSIGNED NOT NULL DEFAULT 0,
  `system` tinyint(1) UNSIGNED NULL DEFAULT 0,
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  `position_id` int(11) NULL DEFAULT 0 COMMENT '仓位ID',
  `tp_price` decimal(20, 8) NULL DEFAULT 0.00000000 COMMENT '止损价',
  `sl_price` decimal(20, 8) NULL DEFAULT 0.00000000 COMMENT '止盈价',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `user_id`(`user_id`) USING BTREE,
  INDEX `contract_id`(`contract_id`) USING BTREE,
  INDEX `side`(`side`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '永续合约委托' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for contract_order
-- ----------------------------
DROP TABLE IF EXISTS `contract_order`;
CREATE TABLE `contract_order`  (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `contract_id` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '合约代码取值范围BTC-USD',
  `symbol` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `unit_amount` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `lever_rate` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '杠杆倍数',
  `order_type` tinyint(1) UNSIGNED NOT NULL DEFAULT 1,
  `buy_id` int(10) UNSIGNED NOT NULL DEFAULT 0 COMMENT '买单ID',
  `sell_id` int(10) UNSIGNED NOT NULL DEFAULT 0 COMMENT '卖单ID',
  `buy_user_id` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '买家用户ID',
  `sell_user_id` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '卖家用户ID',
  `unit_price` decimal(20, 8) UNSIGNED NOT NULL DEFAULT 0.00000000 COMMENT '成交价格',
  `trade_amount` int(20) UNSIGNED NOT NULL DEFAULT 0 COMMENT '交易数量',
  `trade_buy_fee` decimal(20, 8) UNSIGNED NULL DEFAULT 0.00000000 COMMENT '交易手续费',
  `trade_sell_fee` decimal(20, 8) UNSIGNED NULL DEFAULT 0.00000000,
  `status` tinyint(4) UNSIGNED NOT NULL DEFAULT 1 COMMENT '1代表已完成',
  `ts` int(13) UNSIGNED NOT NULL DEFAULT 0,
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '永续合约成交记录' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for contract_pair
-- ----------------------------
DROP TABLE IF EXISTS `contract_pair`;
CREATE TABLE `contract_pair`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `symbol` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '合约symbol',
  `contract_coin_id` int(10) NOT NULL COMMENT '合约币种ID',
  `contract_coin_name` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '合约币种名称',
  `margin_coin_id` int(10) UNSIGNED NOT NULL DEFAULT 1,
  `type` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT 'USDT保证金合约',
  `unit_amount` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '合约单张面值（USDT）',
  `maker_fee_rate` float(10, 5) UNSIGNED NOT NULL DEFAULT 0.00050 COMMENT 'Maker手续费率',
  `taker_fee_rate` float(10, 5) UNSIGNED NOT NULL DEFAULT 0.00050 COMMENT 'Taker手续费率',
  `status` tinyint(1) UNSIGNED NOT NULL DEFAULT 1 COMMENT '状态',
  `trade_status` tinyint(1) UNSIGNED NOT NULL DEFAULT 1 COMMENT '交易状态',
  `lever_rage` json NULL COMMENT '杠杆倍数',
  `default_lever` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '默认杠杠',
  `min_qty` int(10) UNSIGNED NOT NULL DEFAULT 1 COMMENT '单笔最小下单（张）',
  `max_qty` int(10) UNSIGNED NOT NULL DEFAULT 1000 COMMENT '单笔最大下单（张）',
  `total_max_qty` int(10) UNSIGNED NOT NULL DEFAULT 10000 COMMENT '最大持仓量（张）',
  `buy_spread` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `sell_spread` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `settle_spread` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `created_at` timestamp(0) NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP(0),
  `updated_at` timestamp(0) NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP(0),
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `symbol`(`contract_coin_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '永续合约交易对' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of contract_pair
-- ----------------------------

-- ----------------------------
-- Table structure for contract_position
-- ----------------------------
DROP TABLE IF EXISTS `contract_position`;
CREATE TABLE `contract_position`  (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '用户ID',
  `side` tinyint(1) UNSIGNED NOT NULL DEFAULT 1 COMMENT '方向 1多头仓位 2空头仓位',
  `contract_id` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '合约ID',
  `symbol` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `unit_amount` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `contract_coin_id` int(10) NULL DEFAULT NULL,
  `margin_coin_id` int(10) NULL DEFAULT NULL,
  `margin_mode` tinyint(1) UNSIGNED NULL DEFAULT 1 COMMENT '仓位模式：默认1全仓 2逐仓',
  `lever_rate` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '杠杆倍数',
  `liquidation_price` decimal(20, 8) UNSIGNED NULL DEFAULT NULL COMMENT '预估强平价',
  `hold_position` int(20) UNSIGNED NULL DEFAULT 0 COMMENT '持仓数量',
  `avail_position` int(20) UNSIGNED NULL DEFAULT 0 COMMENT '可平数量',
  `freeze_position` int(20) UNSIGNED NULL DEFAULT 0 COMMENT '冻结数量',
  `position_margin` decimal(20, 8) UNSIGNED NULL DEFAULT 0.00000000 COMMENT '保证金',
  `fee` decimal(12, 5) NULL DEFAULT 0.00000 COMMENT '手续费',
  `avg_price` decimal(20, 8) UNSIGNED NULL DEFAULT 0.00000000 COMMENT '开仓平均价',
  `settlement_price` decimal(20, 8) UNSIGNED NULL DEFAULT 0.00000000 COMMENT '结算基准价',
  `maintain_margin_rate` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '维持保证金率',
  `settled_pnl` decimal(20, 8) NULL DEFAULT NULL COMMENT '已结算收益',
  `realized_pnl` decimal(20, 8) NULL DEFAULT NULL COMMENT '已实现盈亏',
  `unrealized_pnl` decimal(20, 8) NULL DEFAULT 0.00000000 COMMENT '未实现盈亏',
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  `open_order_id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '开仓的委托订单ID',
  `close_order_id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '平仓委托订单ID',
  `status` tinyint(1) NULL DEFAULT 1 COMMENT '仓位状态 1-持仓中 2-已平仓',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `user_contract_side`(`user_id`, `side`, `contract_id`) USING BTREE,
  INDEX `symbol`(`symbol`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '永续合约持仓信息' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for contract_share
-- ----------------------------
DROP TABLE IF EXISTS `contract_share`;
CREATE TABLE `contract_share`  (
  `id` int(10) NOT NULL AUTO_INCREMENT,
  `bg_img` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '杠杆倍数',
  `text_img` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `peri_img` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `status` tinyint(1) UNSIGNED NULL DEFAULT 1,
  `created_at` int(13) NULL DEFAULT NULL,
  `updated_at` int(13) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '合约组图' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for contract_strategy
-- ----------------------------
DROP TABLE IF EXISTS `contract_strategy`;
CREATE TABLE `contract_strategy`  (
  `id` int(11) UNSIGNED NOT NULL AUTO_INCREMENT,
  `user_id` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '用户ID',
  `contract_id` int(10) UNSIGNED NOT NULL,
  `symbol` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `position_side` tinyint(1) UNSIGNED NOT NULL COMMENT '仓位方向 1多仓 2空仓',
  `current_price` decimal(10, 2) UNSIGNED NOT NULL COMMENT '当前价',
  `sl_price` decimal(20, 8) UNSIGNED NULL DEFAULT NULL COMMENT '止损委托价',
  `sl_trigger_price` decimal(20, 8) UNSIGNED NULL DEFAULT NULL COMMENT '止损触发价',
  `sl_trigger_type` tinyint(1) UNSIGNED NULL DEFAULT NULL COMMENT '止损委托类型 1限价 2市价',
  `tp_price` decimal(20, 8) UNSIGNED NULL DEFAULT NULL COMMENT '止盈委托价',
  `tp_trigger_price` decimal(20, 8) UNSIGNED NULL DEFAULT NULL COMMENT '止盈触发价',
  `tp_trigger_type` tinyint(1) UNSIGNED NULL DEFAULT NULL COMMENT '止盈委托类型 1限价 2市价',
  `position_id` int(11) NULL DEFAULT 0 COMMENT '仓位ID',
  `status` tinyint(1) UNSIGNED NOT NULL DEFAULT 1,
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `contract_id`(`contract_id`) USING BTREE,
  INDEX `position_side`(`position_side`) USING BTREE,
  INDEX `symbol`(`symbol`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '合约策略(止盈止损)' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for contract_tmp
-- ----------------------------
DROP TABLE IF EXISTS `contract_tmp`;
CREATE TABLE `contract_tmp`  (
  `id` int(11) UNSIGNED NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NULL DEFAULT 0,
  `symbol` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '交易对',
  `side` tinyint(1) NULL DEFAULT 0 COMMENT '方向 1-开多 2-开空',
  `amount` int(11) NULL DEFAULT 1 COMMENT '委托张数',
  `lever_rate` int(11) NULL DEFAULT 0 COMMENT '杠杆倍数',
  `status` tinyint(1) NULL DEFAULT 0 COMMENT '状态 0-委托中 1-已完成 2-开仓失败',
  `delay_time` datetime(0) NULL DEFAULT NULL COMMENT '延时时间',
  `fail_reason` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '失败原因',
  `mark` tinyint(1) NULL DEFAULT 1 COMMENT '标记 1-自动下单 2-修改下单',
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  `change_symbol` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '',
  `is_notic` int(11) NULL DEFAULT 0,
  `scale` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '下单百分比',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = MyISAM AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '合约开仓临时表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for contract_wear_position_record
-- ----------------------------
DROP TABLE IF EXISTS `contract_wear_position_record`;
CREATE TABLE `contract_wear_position_record`  (
  `id` int(11) UNSIGNED NOT NULL AUTO_INCREMENT,
  `user_id` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '用户ID',
  `contract_id` int(10) UNSIGNED NOT NULL COMMENT '合约ID',
  `symbol` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '合约symbol',
  `position_side` tinyint(1) UNSIGNED NOT NULL COMMENT '仓位方向 1多仓 2空仓',
  `open_position_price` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '开仓价',
  `close_position_price` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '平仓价',
  `profit` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '盈亏',
  `settle_profit` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '实际结算盈亏',
  `loss` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `ts` int(13) UNSIGNED NULL DEFAULT NULL,
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '合约穿仓记录' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for country
-- ----------------------------
DROP TABLE IF EXISTS `country`;
CREATE TABLE `country`  (
  `id` int(11) UNSIGNED NOT NULL AUTO_INCREMENT,
  `code` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `country_code` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `order` int(10) UNSIGNED NULL DEFAULT 255,
  `en_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 197 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = Compact;

-- ----------------------------
-- Records of country
-- ----------------------------

-- ----------------------------
-- Table structure for customers
-- ----------------------------
DROP TABLE IF EXISTS `customers`;
CREATE TABLE `customers`  (
  `id` int(11) UNSIGNED NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NULL DEFAULT NULL,
  `question` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '问题',
  `reply` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '回复',
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for data_bt
-- ----------------------------
DROP TABLE IF EXISTS `data_bt`;
CREATE TABLE `data_bt`  (
  `id` int(10) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT 'id',
  `pid` mediumint(18) NULL DEFAULT 0,
  `Symbol` varchar(28) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '产品代码',
  `Date` int(28) NOT NULL DEFAULT 0 COMMENT '时间戳',
  `datetime` datetime(0) NULL DEFAULT NULL,
  `Name` varchar(88) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '产品名称',
  `Open` float(18, 5) NOT NULL DEFAULT 0.00000 COMMENT '开盘价',
  `High` float(18, 5) NOT NULL DEFAULT 0.00000 COMMENT '最高价',
  `Low` float(18, 5) NOT NULL DEFAULT 0.00000 COMMENT '最低价',
  `Close` float(18, 5) NOT NULL DEFAULT 0.00000 COMMENT '最新价',
  `LastClose` float(18, 5) NULL DEFAULT 0.00000 COMMENT '昨收价（日线）',
  `Price2` float(18, 5) NULL DEFAULT 0.00000 COMMENT '期货当日结算价（盘中为0，收盘后交易所才提供）（日线）',
  `Price3` float(18, 5) NULL DEFAULT 0.00000 COMMENT '股票为成交总笔数，期货是前一交易日结算价（日线）',
  `Open_Int` float(18, 5) NULL DEFAULT 0.00000 COMMENT '仅期货有效，持仓（未平仓合约）',
  `Volume` float(18, 5) NULL DEFAULT 0.00000 COMMENT '成交量',
  `Amount` float(18, 5) NULL DEFAULT 0.00000 COMMENT '成交额',
  `is_1min` tinyint(4) NULL DEFAULT 0,
  `is_5min` tinyint(4) NULL DEFAULT 0 COMMENT '是否是5分钟线',
  `is_15min` tinyint(4) NULL DEFAULT 0,
  `is_30min` tinyint(4) NULL DEFAULT 0,
  `is_1h` tinyint(4) NULL DEFAULT 0,
  `is_2h` tinyint(4) NULL DEFAULT 0,
  `is_4h` tinyint(4) NULL DEFAULT 0,
  `is_6h` tinyint(4) NULL DEFAULT 0,
  `is_12h` tinyint(4) NULL DEFAULT 0,
  `is_day` tinyint(4) NULL DEFAULT 0,
  `is_week` tinyint(4) NULL DEFAULT 0,
  `is_month` int(11) NULL DEFAULT 0,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `Date`(`Date`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for data_stai
-- ----------------------------
DROP TABLE IF EXISTS `data_stai`;
CREATE TABLE `data_stai`  (
  `id` int(10) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT 'id',
  `pid` mediumint(18) NULL DEFAULT 0,
  `Symbol` varchar(28) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '产品代码',
  `Date` int(28) NOT NULL DEFAULT 0 COMMENT '时间戳',
  `datetime` datetime(0) NULL DEFAULT NULL,
  `Name` varchar(88) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '产品名称',
  `Open` float(18, 5) NOT NULL DEFAULT 0.00000 COMMENT '开盘价',
  `High` float(18, 5) NOT NULL DEFAULT 0.00000 COMMENT '最高价',
  `Low` float(18, 5) NOT NULL DEFAULT 0.00000 COMMENT '最低价',
  `Close` float(18, 5) NOT NULL DEFAULT 0.00000 COMMENT '最新价',
  `LastClose` float(18, 5) NULL DEFAULT 0.00000 COMMENT '昨收价（日线）',
  `Price2` float(18, 5) NULL DEFAULT 0.00000 COMMENT '期货当日结算价（盘中为0，收盘后交易所才提供）（日线）',
  `Price3` float(18, 5) NULL DEFAULT 0.00000 COMMENT '股票为成交总笔数，期货是前一交易日结算价（日线）',
  `Open_Int` float(18, 5) NULL DEFAULT 0.00000 COMMENT '仅期货有效，持仓（未平仓合约）',
  `Volume` float(18, 5) NULL DEFAULT 0.00000 COMMENT '成交量',
  `Amount` float(18, 5) NULL DEFAULT 0.00000 COMMENT '成交额',
  `is_1min` tinyint(4) NULL DEFAULT 0,
  `is_5min` tinyint(4) NULL DEFAULT 0 COMMENT '是否是5分钟线',
  `is_15min` tinyint(4) NULL DEFAULT 0,
  `is_30min` tinyint(4) NULL DEFAULT 0,
  `is_1h` tinyint(4) NULL DEFAULT 0,
  `is_2h` tinyint(4) NULL DEFAULT 0,
  `is_4h` tinyint(4) NULL DEFAULT 0,
  `is_6h` tinyint(4) NULL DEFAULT 0,
  `is_12h` tinyint(4) NULL DEFAULT 0,
  `is_day` tinyint(4) NULL DEFAULT 0,
  `is_week` tinyint(4) NULL DEFAULT 0,
  `is_month` int(11) NULL DEFAULT 0,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `Date`(`Date`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for data_tkb
-- ----------------------------
DROP TABLE IF EXISTS `data_tkb`;
CREATE TABLE `data_tkb`  (
  `id` int(10) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT 'id',
