  `Open` float(18, 5) NOT NULL DEFAULT 0.00000 COMMENT '开盘价',
  `High` float(18, 5) NOT NULL DEFAULT 0.00000 COMMENT '最高价',
  `Low` float(18, 5) NOT NULL DEFAULT 0.00000 COMMENT '最低价',
  `Close` float(18, 5) NOT NULL DEFAULT 0.00000 COMMENT '最新价',
  `LastClose` float(18, 5) NULL DEFAULT 0.00000 COMMENT '昨收价（日线）',
  `Price2` float(18, 5) NULL DEFAULT 0.00000 COMMENT '期货当日结算价（盘中为0，收盘后交易所才提供）（日线）',
  `Price3` float(18, 5) NULL DEFAULT 0.00000 COMMENT '股票为成交总笔数，期货是前一交易日结算价（日线）',
  `Open_Int` float(18, 5) NULL DEFAULT 0.00000 COMMENT '仅期货有效，持仓（未平仓合约）',
  `Volume` float(18, 5) NULL DEFAULT 0.00000 COMMENT '成交量',
  `Amount` float(18, 5) NULL DEFAULT 0.00000 COMMENT '成交额',
  `is_1min` tinyint(4) NULL DEFAULT 0,
  `is_5min` tinyint(4) NULL DEFAULT 0 COMMENT '是否是5分钟线',
  `is_15min` tinyint(4) NULL DEFAULT 0,
  `is_30min` tinyint(4) NULL DEFAULT 0,
  `is_1h` tinyint(4) NULL DEFAULT 0,
  `is_2h` tinyint(4) NULL DEFAULT 0,
  `is_4h` tinyint(4) NULL DEFAULT 0,
  `is_6h` tinyint(4) NULL DEFAULT 0,
  `is_12h` tinyint(4) NULL DEFAULT 0,
  `is_day` tinyint(4) NULL DEFAULT 0,
  `is_week` tinyint(4) NULL DEFAULT 0,
  `is_month` int(11) NULL DEFAULT 0,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `Date`(`Date`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for failed_jobs
-- ----------------------------
DROP TABLE IF EXISTS `failed_jobs`;
CREATE TABLE `failed_jobs`  (
  `id` bigint(20) UNSIGNED NOT NULL AUTO_INCREMENT,
  `connection` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `queue` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `payload` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `exception` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `failed_at` timestamp(0) NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for follow_plans
-- ----------------------------
DROP TABLE IF EXISTS `follow_plans`;
CREATE TABLE `follow_plans`  (
  `id` int(11) UNSIGNED NOT NULL AUTO_INCREMENT,
  `user_id` int(11) UNSIGNED NULL DEFAULT 0 COMMENT '用户ID',
  `pair_id` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '标的ID',
  `pair_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '交易对',
  `follow_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '带单名称',
  `follow_code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '带单码',
  `side` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '带单方向',
  `amount` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '下单金额',
  `follow_people` int(11) NULL DEFAULT 0 COMMENT '总人数',
  `cycle` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '周期',
  `order_time` timestamp(0) NULL DEFAULT NULL COMMENT '下单时间',
  `is_public` tinyint(1) NULL DEFAULT 0 COMMENT '是否公开 0-私密 1-公开',
  `kongyk` tinyint(1) NULL DEFAULT 0 COMMENT '盈亏结果 1-盈利 2-亏损',
  `profit_ratio` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '盈利比例',
  `status` tinyint(1) NULL DEFAULT 0 COMMENT '计划状态 0-待执行 1-已执行 2-已取消',
  `exc_remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '',
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = MyISAM AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '带单计划' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for follow_records
-- ----------------------------
DROP TABLE IF EXISTS `follow_records`;
CREATE TABLE `follow_records`  (
  `id` int(11) UNSIGNED NOT NULL AUTO_INCREMENT,
  `follow_id` int(11) UNSIGNED NULL DEFAULT 0 COMMENT '跟单计划ID',
  `user_id` int(11) UNSIGNED NULL DEFAULT 0 COMMENT '用户ID',
  `pair_id` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '标的ID',
  `pair_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '交易对',
  `side` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '方向',
  `amount` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '下单金额',
  `cycle` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '周期',
  `order_time` timestamp(0) NULL DEFAULT NULL COMMENT '下单时间',
  `profit_ratio` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '盈利比例',
  `kongyk` tinyint(1) UNSIGNED NULL DEFAULT 0 COMMENT '盈亏 1-盈利 2-亏损',
  `status` tinyint(1) NULL DEFAULT 0 COMMENT '状态 0-待执行 1-跟单中 2-已完成 3-已取消',
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = MyISAM AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for inside_trade_buy
-- ----------------------------
DROP TABLE IF EXISTS `inside_trade_buy`;
CREATE TABLE `inside_trade_buy`  (
  `id` int(10) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键',
  `order_no` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL DEFAULT '0' COMMENT '订单号',
  `user_id` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '用户id',
  `entrust_type` tinyint(1) UNSIGNED NOT NULL DEFAULT 1,
  `symbol` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '币对',
  `type` tinyint(1) UNSIGNED NOT NULL COMMENT '委托方式 1限价交易 2市价交易 3止盈止损',
  `entrust_price` decimal(20, 8) UNSIGNED NULL DEFAULT 0.00000000 COMMENT '委托价格',
  `trigger_price` decimal(20, 8) UNSIGNED NULL DEFAULT NULL COMMENT '触发价',
  `quote_coin_id` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '基础币种',
  `base_coin_id` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '买入的币种',
  `amount` decimal(20, 8) UNSIGNED NULL DEFAULT 0.00000000 COMMENT '委托数量',
  `traded_amount` decimal(20, 8) UNSIGNED NOT NULL DEFAULT 0.00000000 COMMENT '已成交数量',
  `money` decimal(20, 8) UNSIGNED NULL DEFAULT 0.00000000 COMMENT '预期交易额',
  `traded_money` decimal(20, 8) UNSIGNED NULL DEFAULT 0.00000000 COMMENT '已成交额',
  `status` tinyint(4) NOT NULL DEFAULT 1 COMMENT '交易进度 0已撤单，1未成交，2部分成交，3全部成交',
  `cancel_time` int(13) NULL DEFAULT NULL COMMENT '撤单时间',
  `hang_status` tinyint(1) UNSIGNED NULL DEFAULT 1 COMMENT '挂单状态 0未挂单 1已挂单',
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `user_id`(`user_id`) USING BTREE,
  INDEX `trade_order`(`order_no`) USING BTREE,
  INDEX `unit_price`(`entrust_price`) USING BTREE,
  INDEX `base_coin_id`(`quote_coin_id`) USING BTREE,
  INDEX `exchange_coin_id`(`base_coin_id`) USING BTREE,
  INDEX `status`(`status`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '场内交易买单委托' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for inside_trade_deal_robot
-- ----------------------------
DROP TABLE IF EXISTS `inside_trade_deal_robot`;
CREATE TABLE `inside_trade_deal_robot`  (
  `id` bigint(20) UNSIGNED NOT NULL AUTO_INCREMENT,
  `pair_id` int(11) UNSIGNED NULL DEFAULT 0 COMMENT '交易对ID',
  `symbol` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '符号',
  `bid_plus_unit` decimal(8, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '买单价格向上波动单位',
  `bid_plus_count` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '买单价格向上波动计数',
  `bid_minus_unit` decimal(8, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '买单价格向下波动单位',
  `bid_minus_count` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '买单价格向下波动计数',
  `ask_plus_unit` decimal(8, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '卖单价格向上波动单位',
  `ask_plus_count` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '卖单价格向上波动计数',
  `ask_minus_unit` decimal(8, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '卖单价格向下波动单位',
  `ask_minus_count` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '卖单价格向下波动计数',
  `status` tinyint(1) UNSIGNED NOT NULL DEFAULT 0 COMMENT '0关闭 1开启',
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `symbol`(`symbol`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '场内交易自动成交机器人' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for inside_trade_order
-- ----------------------------
DROP TABLE IF EXISTS `inside_trade_order`;
CREATE TABLE `inside_trade_order`  (
  `order_id` int(10) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键',
  `buy_order_no` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '买单订单号',
  `sell_order_no` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '卖单订单号',
  `buy_id` int(10) UNSIGNED NOT NULL DEFAULT 0 COMMENT '买单ID',
  `sell_id` int(10) UNSIGNED NOT NULL DEFAULT 0 COMMENT '卖单ID',
  `buy_user_id` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '买家用户ID',
  `sell_user_id` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '卖家用户ID',
  `unit_price` decimal(20, 8) UNSIGNED NOT NULL DEFAULT 0.00000000 COMMENT '成交价格',
  `symbol` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '币对',
  `quote_coin_id` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '报价币种',
  `base_coin_id` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '交换的币种',
  `trade_amount` decimal(20, 8) UNSIGNED NOT NULL DEFAULT 0.00000000 COMMENT '交易数量',
  `trade_money` decimal(20, 8) UNSIGNED NOT NULL DEFAULT 0.00000000 COMMENT '交易额',
  `trade_buy_fee` decimal(20, 8) UNSIGNED NOT NULL DEFAULT 0.00000000 COMMENT '交易买手续费',
  `trade_sell_fee` decimal(20, 8) UNSIGNED NOT NULL DEFAULT 0.00000000 COMMENT '交易卖手续费',
  `status` tinyint(4) UNSIGNED NOT NULL DEFAULT 1 COMMENT '1代表已完成',
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`order_id`) USING BTREE,
  INDEX `user_id`(`buy_user_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '场内交易成交记录' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for inside_trade_pair
-- ----------------------------
DROP TABLE IF EXISTS `inside_trade_pair`;
CREATE TABLE `inside_trade_pair`  (
  `pair_id` bigint(20) UNSIGNED NOT NULL AUTO_INCREMENT,
  `pair_name` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '交易对名称',
  `symbol` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `quote_coin_id` int(10) NOT NULL,
  `quote_coin_name` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `base_coin_id` int(10) NOT NULL,
  `base_coin_name` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `qty_decimals` int(1) UNSIGNED NOT NULL DEFAULT 2,
  `price_decimals` int(1) UNSIGNED NOT NULL DEFAULT 2,
  `min_qty` decimal(12, 4) NULL DEFAULT NULL,
  `min_total` decimal(12, 4) NULL DEFAULT NULL,
  `trigger_price_buy_rate` decimal(4, 2) UNSIGNED NULL DEFAULT 1.10 COMMENT '3止盈止损委托 买入触发价设定限制比率',
  `trigger_price_sell_rate` decimal(4, 2) UNSIGNED NULL DEFAULT 0.90 COMMENT '3止盈止损委托 卖出触发价设定限制比率',
  `sort` int(10) UNSIGNED NULL DEFAULT 255,
  `status` tinyint(1) UNSIGNED NOT NULL DEFAULT 0 COMMENT '0下线 1上线',
  `trade_status` tinyint(1) UNSIGNED NULL DEFAULT 1,
  `is_market` tinyint(1) UNSIGNED NULL DEFAULT 1,
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`pair_id`) USING BTREE,
  UNIQUE INDEX `symbol`(`symbol`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 16 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '场内交易交易对' ROW_FORMAT = Compact;

-- ----------------------------
-- Records of inside_trade_pair
-- ----------------------------

-- ----------------------------
-- Table structure for inside_trade_risk
-- ----------------------------
DROP TABLE IF EXISTS `inside_trade_risk`;
CREATE TABLE `inside_trade_risk`  (
  `id` bigint(20) UNSIGNED NOT NULL AUTO_INCREMENT,
  `pair_id` int(11) UNSIGNED NULL DEFAULT 0 COMMENT '交易对ID',
  `pair_name` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '交易对名称',
  `symbol` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '符号',
  `up_or_down` tinyint(1) UNSIGNED NULL DEFAULT 1,
  `range` decimal(8, 4) UNSIGNED NULL DEFAULT 0.0000,
  `status` tinyint(1) UNSIGNED NOT NULL DEFAULT 0 COMMENT '0关闭 1开启',
  `start_time` int(13) UNSIGNED NULL DEFAULT 0 COMMENT '开始时间',
  `end_time` int(13) UNSIGNED NULL DEFAULT 0 COMMENT '结束时间 0表示一直运行',
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `symbol`(`symbol`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '场内交易风控任务' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for inside_trade_robot
-- ----------------------------
DROP TABLE IF EXISTS `inside_trade_robot`;
CREATE TABLE `inside_trade_robot`  (
  `id` bigint(20) UNSIGNED NOT NULL AUTO_INCREMENT,
  `pair_id` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '交易对ID',
  `symbol` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '符号',
  `order_amount` decimal(12, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '下单金额',
  `bid_place_threshold` decimal(8, 4) NULL DEFAULT 0.0000 COMMENT '买单价格比率',
  `ask_place_threshold` decimal(8, 4) NULL DEFAULT 0.0000 COMMENT '卖单价格比率',
  `status` tinyint(1) UNSIGNED NOT NULL DEFAULT 0 COMMENT '0关闭 1开启',
  `start_time` int(13) UNSIGNED NULL DEFAULT 0 COMMENT '开始时间',
  `end_time` int(13) UNSIGNED NULL DEFAULT 0 COMMENT '结束时间 0表示一直运行',
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `symbol`(`symbol`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '场内交易交易机器人' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for inside_trade_sell
-- ----------------------------
DROP TABLE IF EXISTS `inside_trade_sell`;
CREATE TABLE `inside_trade_sell`  (
  `id` int(10) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键',
  `order_no` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL DEFAULT '0' COMMENT '订单号',
  `user_id` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '用户id',
  `entrust_type` tinyint(1) UNSIGNED NOT NULL DEFAULT 2,
  `symbol` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '币对',
  `type` tinyint(1) UNSIGNED NOT NULL COMMENT '委托方式 1限价交易 2市价交易 3止盈止损',
  `entrust_price` decimal(20, 8) UNSIGNED NULL DEFAULT 0.00000000 COMMENT '委托价格',
  `trigger_price` decimal(20, 8) UNSIGNED NULL DEFAULT NULL COMMENT '触发价',
  `quote_coin_id` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '基础币种',
  `base_coin_id` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '卖出的币种',
  `amount` decimal(20, 8) UNSIGNED NOT NULL DEFAULT 0.00000000 COMMENT '委托数量',
  `traded_amount` decimal(20, 8) UNSIGNED NOT NULL DEFAULT 0.00000000 COMMENT '已成交数量',
  `money` decimal(20, 8) UNSIGNED NULL DEFAULT 0.00000000,
  `traded_money` decimal(20, 8) UNSIGNED NULL DEFAULT 0.00000000 COMMENT '实际成交交易额',
  `status` tinyint(4) NOT NULL DEFAULT 1 COMMENT '交易进度 0已撤单，1未成交，2部分成交，3全部成交',
  `hang_status` tinyint(1) UNSIGNED NULL DEFAULT 1 COMMENT '挂单状态 0未挂单 1已挂单',
  `cancel_time` int(13) NULL DEFAULT NULL COMMENT '撤单时间',
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `user_id`(`user_id`) USING BTREE,
  INDEX `trade_order`(`order_no`) USING BTREE,
  INDEX `base_coin_id`(`quote_coin_id`) USING BTREE,
  INDEX `exchange_coin_id`(`base_coin_id`) USING BTREE,
  INDEX `unit_price`(`entrust_price`) USING BTREE,
  INDEX `status`(`status`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '场内交易卖单委托' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for jobs
-- ----------------------------
DROP TABLE IF EXISTS `jobs`;
CREATE TABLE `jobs`  (
  `id` bigint(20) UNSIGNED NOT NULL AUTO_INCREMENT,
