-- Records of migrations
-- ----------------------------

-- ----------------------------
-- Table structure for navigation
-- ----------------------------
DROP TABLE IF EXISTS `navigation`;
CREATE TABLE `navigation`  (
  `id` int(10) UNSIGNED NOT NULL AUTO_INCREMENT,
  `type` tinyint(4) UNSIGNED NOT NULL DEFAULT 1 COMMENT '导航位置 1顶部 2服务 3 学院',
  `img` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '导航图片',
  `link_type` varchar(191) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '导航链接类型',
  `link_data` varchar(300) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '导航链接数据',
  `desc` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '导航描述',
  `order` int(10) UNSIGNED NULL DEFAULT 1 COMMENT '排序',
  `status` tinyint(1) UNSIGNED NULL DEFAULT 1 COMMENT '是否显示在首页开关（0不显示1显示）',
  `created_at` datetime(0) NULL DEFAULT NULL,
  `updated_at` datetime(0) NULL DEFAULT NULL,
  `deleted_at` datetime(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 25 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '导航' ROW_FORMAT = Compact;

-- ----------------------------
-- Records of navigation
-- ----------------------------

-- ----------------------------
-- Table structure for navigation_translations
-- ----------------------------
DROP TABLE IF EXISTS `navigation_translations`;
CREATE TABLE `navigation_translations`  (
  `id` smallint(6) NOT NULL AUTO_INCREMENT,
  `locale` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL,
  `name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT 'NULL',
  `n_id` int(11) NOT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 44 CHARACTER SET = utf8 COLLATE = utf8_general_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of navigation_translations
-- ----------------------------

-- ----------------------------
-- Table structure for notifications
-- ----------------------------
DROP TABLE IF EXISTS `notifications`;
CREATE TABLE `notifications`  (
  `id` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `type` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `notifiable_type` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `notifiable_id` bigint(20) UNSIGNED NOT NULL,
  `data` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `read_at` timestamp(0) NULL DEFAULT NULL,
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `notifications_notifiable_type_notifiable_id_index`(`notifiable_type`(191), `notifiable_id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for option_bet_coin
-- ----------------------------
DROP TABLE IF EXISTS `option_bet_coin`;
CREATE TABLE `option_bet_coin`  (
  `id` int(10) UNSIGNED NOT NULL AUTO_INCREMENT,
  `coin_id` int(10) UNSIGNED NOT NULL COMMENT '主键',
  `coin_name` char(11) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL DEFAULT '' COMMENT '虚拟货币名称',
  `min_amount` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '最小购买量',
  `max_amount` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '最大购买量',
  `is_bet` tinyint(1) UNSIGNED NOT NULL DEFAULT 1 COMMENT '是否可期权交易',
  `sort` int(10) UNSIGNED NOT NULL DEFAULT 1 COMMENT '排序',
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '可用期权交易币种列表' ROW_FORMAT = Compact;

-- ----------------------------
-- Records of option_bet_coin
-- ----------------------------

-- ----------------------------
-- Table structure for option_pair
-- ----------------------------
DROP TABLE IF EXISTS `option_pair`;
CREATE TABLE `option_pair`  (
  `pair_id` bigint(20) UNSIGNED NOT NULL AUTO_INCREMENT,
  `pair_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '交易对名称',
  `symbol` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `quote_coin_id` int(10) NOT NULL,
  `quote_coin_name` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `base_coin_id` int(10) NOT NULL,
  `base_coin_name` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `status` tinyint(1) NOT NULL DEFAULT 0,
  `trade_status` tinyint(1) UNSIGNED NULL DEFAULT 1,
  `sort` int(10) UNSIGNED NULL DEFAULT 0,
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`pair_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '期权交易对' ROW_FORMAT = Compact;

-- ----------------------------
-- Records of option_pair
-- ----------------------------

-- ----------------------------
-- Table structure for option_scene
-- ----------------------------
DROP TABLE IF EXISTS `option_scene`;
CREATE TABLE `option_scene`  (
  `scene_id` bigint(20) UNSIGNED NOT NULL AUTO_INCREMENT,
  `scene_sn` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT ' 编号',
  `time_id` int(10) UNSIGNED NOT NULL DEFAULT 0 COMMENT '期权场次id',
  `seconds` int(10) UNSIGNED NULL DEFAULT NULL,
  `pair_id` int(10) UNSIGNED NOT NULL DEFAULT 0 COMMENT '期权交易对id',
  `pair_time_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '期权场景名称',
  `up_odds` json NULL,
  `down_odds` json NULL,
  `draw_odds` json NULL,
  `begin_time` int(13) UNSIGNED NOT NULL COMMENT '开始时间',
  `end_time` int(13) UNSIGNED NOT NULL COMMENT '结束时间',
  `begin_price` decimal(12, 4) UNSIGNED NULL DEFAULT NULL COMMENT '开盘价',
  `end_price` decimal(12, 4) UNSIGNED NULL DEFAULT NULL COMMENT '收盘价',
  `delivery_up_down` tinyint(1) UNSIGNED NULL DEFAULT NULL COMMENT '涨幅结果：1涨 2跌 3平',
  `delivery_range` decimal(12, 3) UNSIGNED NULL DEFAULT NULL COMMENT '幅度绝对值',
  `delivery_time` int(13) UNSIGNED NULL DEFAULT NULL COMMENT '交割时间',
  `status` tinyint(1) NOT NULL DEFAULT 1 COMMENT '1--待购买 2--购买中 3--交割中 4--已交割',
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`scene_id`) USING BTREE,
  INDEX `time_id`(`time_id`) USING BTREE,
  INDEX `pair_id`(`pair_id`) USING BTREE,
  INDEX `begin_time`(`begin_time`) USING BTREE,
  INDEX `end_time`(`end_time`) USING BTREE,
  INDEX `time_pair`(`time_id`, `pair_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '期权场景' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for option_scene_order
-- ----------------------------
DROP TABLE IF EXISTS `option_scene_order`;
CREATE TABLE `option_scene_order`  (
  `order_id` bigint(20) UNSIGNED NOT NULL AUTO_INCREMENT,
  `order_no` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `scene_id` bigint(20) UNSIGNED NOT NULL COMMENT '场景ID',
  `pair_id` int(11) NULL DEFAULT NULL,
  `time_id` int(11) NULL DEFAULT NULL,
  `pair_name` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `time_name` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `user_id` int(11) UNSIGNED NOT NULL COMMENT '用户ID',
  `bet_amount` decimal(12, 4) UNSIGNED NOT NULL DEFAULT 0.0000 COMMENT '购买数量',
  `bet_coin_id` int(10) UNSIGNED NOT NULL DEFAULT 0 COMMENT '币种ID',
  `bet_coin_name` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '币种名称',
  `odds_uuid` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '赔率ID',
  `odds` decimal(8, 2) UNSIGNED NOT NULL COMMENT '赔率（收益率）',
  `range` decimal(12, 3) UNSIGNED NOT NULL COMMENT '幅度绝对值（涨幅 跌幅）',
  `up_down` tinyint(1) UNSIGNED NOT NULL COMMENT '1涨 2跌 3平',
  `status` tinyint(1) NOT NULL DEFAULT 1 COMMENT '状态 1待交割 2已交割',
  `fee` decimal(10, 4) NULL DEFAULT NULL COMMENT '手续费',
  `delivery_time` int(13) NULL DEFAULT NULL COMMENT '交割时间',
  `delivery_amount` decimal(20, 4) NULL DEFAULT NULL,
  `begin_time` int(13) UNSIGNED NULL DEFAULT NULL,
  `end_time` int(13) UNSIGNED NULL DEFAULT NULL,
  `end_price` decimal(12, 4) UNSIGNED NULL DEFAULT NULL COMMENT '作弊收盘价',
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`order_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '期权用户买入记录' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for option_time
-- ----------------------------
DROP TABLE IF EXISTS `option_time`;
CREATE TABLE `option_time`  (
  `time_id` bigint(20) UNSIGNED NOT NULL AUTO_INCREMENT,
  `time_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '场次名称',
  `seconds` int(10) UNSIGNED NOT NULL DEFAULT 0,
  `fee_rate` decimal(10, 4) UNSIGNED NULL DEFAULT 0.0000,
  `odds_up_range` json NULL,
  `odds_down_range` json NULL,
  `odds_draw_range` json NULL,
  `status` tinyint(1) NOT NULL DEFAULT 0,
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`time_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 6 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '期权时间周期' ROW_FORMAT = Compact;

-- ----------------------------
-- Records of option_time
-- ----------------------------

-- ----------------------------
-- Table structure for otc_account
-- ----------------------------
DROP TABLE IF EXISTS `otc_account`;
CREATE TABLE `otc_account`  (
  `id` int(10) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键',
  `user_id` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '用户id',
  `coin_id` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '币种id',
  `coin_name` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '币种名称',
  `usable_balance` decimal(20, 8) UNSIGNED NOT NULL DEFAULT 0.00000000 COMMENT '可用余额',
  `freeze_balance` decimal(20, 8) UNSIGNED NOT NULL DEFAULT 0.00000000 COMMENT '冻结余额',
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `user_coin`(`user_id`, `coin_id`) USING BTREE,
  INDEX `coin_id`(`coin_id`) USING BTREE,
  INDEX `user_id`(`user_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_bin COMMENT = '法币账户' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for otc_appeal
-- ----------------------------
DROP TABLE IF EXISTS `otc_appeal`;
CREATE TABLE `otc_appeal`  (
  `id` bigint(20) UNSIGNED NOT NULL AUTO_INCREMENT,
  `order_id` bigint(20) NOT NULL COMMENT '订单ID',
  `user_id` bigint(20) NOT NULL COMMENT '用户ID',
  `describe` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '描述',
  `image` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '照片',
  `status` tinyint(3) NOT NULL DEFAULT 1 COMMENT '0 已删除 1已经提交 2已解决 3解决失败',
  `created_at` datetime(0) NOT NULL COMMENT '提交时间',
  `updated_at` datetime(0) NULL DEFAULT NULL COMMENT '修改时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '申诉' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for otc_coinlist
-- ----------------------------
DROP TABLE IF EXISTS `otc_coinlist`;
CREATE TABLE `otc_coinlist`  (
  `id` int(10) NOT NULL AUTO_INCREMENT,
  `coin_id` int(10) NOT NULL COMMENT '币种ID',
  `coin_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_unicode_ci NOT NULL COMMENT '币种名称',
  `limit_amount` decimal(8, 4) NOT NULL DEFAULT 0.1000 COMMENT '最低发布数量',
  `max_register_time` varchar(30) CHARACTER SET utf8 COLLATE utf8_unicode_ci NOT NULL DEFAULT '72' COMMENT '最大挂单时间(按小时计算)',
  `max_register_num` varchar(30) CHARACTER SET utf8 COLLATE utf8_unicode_ci NOT NULL DEFAULT '1' COMMENT '最大挂单数',
  `status` tinyint(1) UNSIGNED NOT NULL DEFAULT 0 COMMENT 'status 0禁用 1启用',
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `coin_id`(`coin_id`) USING BTREE,
  INDEX `coin_name`(`coin_name`) USING BTREE,
  INDEX `status`(`status`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 4 CHARACTER SET = utf8 COLLATE = utf8_unicode_ci COMMENT = '交易币种列表' ROW_FORMAT = Compact;

-- ----------------------------
-- Records of otc_coinlist
-- ----------------------------

-- ----------------------------
-- Table structure for otc_entrust
-- ----------------------------
DROP TABLE IF EXISTS `otc_entrust`;
CREATE TABLE `otc_entrust`  (
  `id` int(10) NOT NULL AUTO_INCREMENT,
  `user_id` int(10) NOT NULL COMMENT '用户ID',
  `side` int(2) NOT NULL DEFAULT 0 COMMENT '1买 2卖',
  `order_sn` varchar(50) CHARACTER SET utf8 COLLATE utf8_unicode_ci NOT NULL COMMENT '广告单号',
  `coin_id` int(10) NOT NULL COMMENT '币种ID',
  `coin_name` varchar(30) CHARACTER SET utf8 COLLATE utf8_unicode_ci NOT NULL COMMENT '币种名字',
  `min_num` decimal(20, 6) NULL DEFAULT NULL COMMENT '最小限额',
  `max_num` decimal(20, 6) NULL DEFAULT NULL COMMENT '最大限额',
  `note` text CHARACTER SET utf8 COLLATE utf8_unicode_ci NULL COMMENT '备注',
  `pay_type` varchar(100) CHARACTER SET utf8 COLLATE utf8_unicode_ci NULL DEFAULT NULL COMMENT '付款方式',
  `publish_time` int(13) UNSIGNED NOT NULL COMMENT '发布时间',
  `price` decimal(20, 6) UNSIGNED NOT NULL COMMENT '价格',
  `amount` decimal(20, 6) UNSIGNED NOT NULL DEFAULT 0.000000 COMMENT '数量',
  `cur_amount` decimal(20, 6) UNSIGNED NOT NULL DEFAULT 0.000000,
  `lock_amount` decimal(20, 6) UNSIGNED NOT NULL DEFAULT 0.000000 COMMENT '已成交数量',
  `order_count` int(10) UNSIGNED NOT NULL DEFAULT 0 COMMENT '下单次数',
  `deal_count` int(10) UNSIGNED NOT NULL DEFAULT 0 COMMENT '成交次数',
  `deal_rate` decimal(4, 2) UNSIGNED NULL DEFAULT 0.00 COMMENT '成交率',
  `status` tinyint(1) UNSIGNED NOT NULL DEFAULT 1 COMMENT '状态 1正常 0撤销 2已完成',
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  `overed_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `side`(`side`) USING BTREE,
  INDEX `user_id`(`user_id`) USING BTREE,
  INDEX `coin_name`(`coin_name`) USING BTREE,
  INDEX `coin_id`(`coin_id`) USING BTREE,
  INDEX `status`(`status`) USING BTREE,
  INDEX `deal_count`(`deal_count`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_unicode_ci COMMENT = 'OTC委托' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for otc_order
-- ----------------------------
DROP TABLE IF EXISTS `otc_order`;
CREATE TABLE `otc_order`  (
  `id` int(10) NOT NULL AUTO_INCREMENT,
  `trans_type` tinyint(1) UNSIGNED NOT NULL COMMENT '1买 2卖',
  `order_sn` varchar(50) CHARACTER SET utf8 COLLATE utf8_unicode_ci NOT NULL COMMENT '订单单号',
  `user_id` int(10) UNSIGNED NOT NULL COMMENT 'UID',
  `other_uid` int(10) UNSIGNED NOT NULL COMMENT '对方UID',
  `entrust_id` int(11) UNSIGNED NOT NULL COMMENT '委托ID',
  `coin_id` int(10) NOT NULL COMMENT '币种ID',
  `coin_name` varchar(30) CHARACTER SET utf8 COLLATE utf8_unicode_ci NOT NULL COMMENT '币种名称',
  `amount` float(9, 2) NOT NULL COMMENT '数量',
  `pay_type` varchar(30) CHARACTER SET utf8 COLLATE utf8_unicode_ci NULL DEFAULT NULL,
  `price` float(9, 2) NULL DEFAULT NULL COMMENT '单价',
  `money` varchar(30) CHARACTER SET utf8 COLLATE utf8_unicode_ci NULL DEFAULT NULL,
  `order_time` int(11) UNSIGNED NULL DEFAULT NULL COMMENT '下单时间',
  `pay_time` int(11) UNSIGNED NULL DEFAULT NULL COMMENT '支付时间',
  `deal_time` int(11) UNSIGNED NULL DEFAULT NULL COMMENT '成交时间',
  `status` tinyint(1) NULL DEFAULT 1 COMMENT '0已取消 1待支付 2已支付待确认 3已完成 4申诉中',
  `appeal_status` tinyint(1) NULL DEFAULT NULL COMMENT '申诉状态 1待处理 2处理中 3处理完成',
  `appeal_time` int(11) NULL DEFAULT NULL,
  `paid_img` varchar(100) CHARACTER SET utf8 COLLATE utf8_unicode_ci NULL DEFAULT NULL COMMENT '支付凭证图片',
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  `overed_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `user_id`(`user_id`) USING BTREE,
  INDEX `trans_type`(`trans_type`) USING BTREE,
  INDEX `coin_name`(`coin_name`) USING BTREE,
  INDEX `coin_id`(`coin_id`) USING BTREE,
  INDEX `status`(`status`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_unicode_ci COMMENT = '交易订单' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for payments
-- ----------------------------
DROP TABLE IF EXISTS `payments`;
CREATE TABLE `payments`  (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '支付方式表',
  `currency` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'CNY' COMMENT '货币',
  `exchange_rate` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '兑换USDT汇率',
  `pay_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'bank_card' COMMENT 'bank_card银行卡，alipay支付宝，wechat微信',
  `bank_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '银行名称',
  `real_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '持卡人姓名',
  `card_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'bank_card->卡号 wechat->账户名称  alipay->账户名称',
  `open_bank` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '开户支行',
  `code_img` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '微信/支付宝 二维码',
  `status` tinyint(1) UNSIGNED NOT NULL DEFAULT 1 COMMENT '状态 0禁用 1开启',
  `remark` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `created_at` timestamp(0) NULL DEFAULT NULL COMMENT '添加时间',
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '系统收款账户表' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for performance
-- ----------------------------
DROP TABLE IF EXISTS `performance`;
CREATE TABLE `performance`  (
  `id` int(11) UNSIGNED NOT NULL AUTO_INCREMENT,
  `aid` int(11) UNSIGNED NULL DEFAULT 0 COMMENT '代理ID',
  `start_time` timestamp(0) NULL DEFAULT NULL COMMENT '开始时间',
  `end_time` timestamp(0) NULL DEFAULT NULL COMMENT '结束时间',
  `subscribe_performance` decimal(20, 8) NULL DEFAULT 0.00000000 COMMENT '申购业绩',
  `contract_performance` decimal(20, 8) NULL DEFAULT 0.00000000 COMMENT '合约业绩',
  `option_performance` decimal(20, 8) NULL DEFAULT 0.00000000 COMMENT '期权业绩',
  `subscribe_rebate_rate` float(10, 4) NULL DEFAULT 0.0000 COMMENT '申购返佣比率',
  `contract_rebate_rate` float(10, 4) NULL DEFAULT 0.0000 COMMENT '合约返佣比率',
  `option_rebate_rate` float(10, 4) NULL DEFAULT 0.0000 COMMENT '期权返佣比率',
  `subscribe_rebate` decimal(20, 8) NULL DEFAULT 0.00000000 COMMENT '申购返佣',
  `contract_rebate` decimal(20, 8) NULL DEFAULT 0.00000000 COMMENT '合约返佣',
  `option_rebate` decimal(20, 8) NULL DEFAULT 0.00000000 COMMENT '期权返佣',
  `status` tinyint(1) UNSIGNED NULL DEFAULT 1 COMMENT '状态',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '业绩统计（按周）' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for pledge_order
-- ----------------------------
DROP TABLE IF EXISTS `pledge_order`;
CREATE TABLE `pledge_order`  (
  `id` int(10) UNSIGNED NOT NULL AUTO_INCREMENT,
  `order_no` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '订单号',
  `product_id` int(10) UNSIGNED NOT NULL DEFAULT 0 COMMENT '产品id',
  `user_id` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '用户id',
  `coin_id` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '币种id',
  `coin_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '币种',
  `cycle` int(10) UNSIGNED NULL DEFAULT NULL COMMENT '周期',
  `rate` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '利率',
  `num` decimal(20, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '数量',
  `reward` decimal(20, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '奖励',
  `total` decimal(20, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '到期返还总数',
  `status` tinyint(3) UNSIGNED NULL DEFAULT 1 COMMENT '状态 0到期 1质押中',
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  `two_coin_id` int(50) UNSIGNED NOT NULL,
  `two_coin_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL,
  `two_num` decimal(20, 4) UNSIGNED NOT NULL,
  `quotation` decimal(20, 4) UNSIGNED NOT NULL,
  `proportion` decimal(20, 4) UNSIGNED NOT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for pledge_product
-- ----------------------------
DROP TABLE IF EXISTS `pledge_product`;
CREATE TABLE `pledge_product`  (
  `id` int(10) UNSIGNED NOT NULL AUTO_INCREMENT,
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '项目名称',
  `content` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '内容',
  `cover` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '封面图',
  `spread_img` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '推广图',
  `coin_id` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '币种id',
  `coin_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '币种',
  `cycle` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '质押周期',
  `rate` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '利率',
  `status` tinyint(3) UNSIGNED NOT NULL DEFAULT 1 COMMENT '状态 0关闭 1开启 ',
  `min_amount` int(10) UNSIGNED NOT NULL DEFAULT 1 COMMENT '最低买入量',
  `max_amount` int(10) UNSIGNED NOT NULL DEFAULT 999999999 COMMENT '最高买入量',
  `can_buy_num` int(11) NOT NULL DEFAULT 1 COMMENT '用户购买次数',
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  `deleted_at` timestamp(0) NULL DEFAULT NULL,
  `proportion` int(255) NOT NULL,
  `is_invit_unlock` int(50) NOT NULL,
  `invit_num` bigint(255) NOT NULL,
  `two_coin_id` int(255) NOT NULL,
  `two_coin_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for recharge_manual
-- ----------------------------
DROP TABLE IF EXISTS `recharge_manual`;
CREATE TABLE `recharge_manual`  (
  `id` int(11) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `user_id` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT 'UID',
  `account` text CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '收款账户',
  `amount` decimal(20, 6) UNSIGNED NOT NULL DEFAULT 0.000000 COMMENT '充值USDT数量',
  `pay_currency` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '支付货币',
  `pay_money` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '支付金额',
  `exchange_rate` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '汇率',
  `image` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '图片凭证',
  `status` int(1) UNSIGNED NOT NULL DEFAULT 0 COMMENT '状态;0=审核中,1=成功,2=驳回',
  `created_at` timestamp(0) NULL DEFAULT NULL COMMENT '提交时间',
  `updated_at` timestamp(0) NULL DEFAULT NULL COMMENT '处理时间',
  `deleted_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '充值审核表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for recharge_manualrg
-- ----------------------------
DROP TABLE IF EXISTS `recharge_manualrg`;
CREATE TABLE `recharge_manualrg`  (
  `id` int(11) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `user_id` int(11) UNSIGNED NULL DEFAULT 0 COMMENT 'UID',
  `account` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '转币地址',
  `amount` decimal(20, 6) UNSIGNED NULL DEFAULT 0.000000 COMMENT '充值USDT数量',
  `pay_currency` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '支付货币',
  `pay_money` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '支付金额',
  `exchange_rate` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '汇率',
  `image` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '图片凭证',
  `status` int(1) UNSIGNED NOT NULL DEFAULT 0 COMMENT '状态;0=审核中,1=成功,2=驳回',
  `created_at` timestamp(0) NULL DEFAULT NULL COMMENT '提交时间',
  `updated_at` timestamp(0) NULL DEFAULT NULL COMMENT '处理时间',
  `deleted_at` timestamp(0) NULL DEFAULT NULL,
  `cbsj` decimal(20, 6) UNSIGNED NULL DEFAULT NULL,
  `jymm` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `coin_id` int(11) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '人工充值审核表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for subscribe_activity
-- ----------------------------
DROP TABLE IF EXISTS `subscribe_activity`;
CREATE TABLE `subscribe_activity`  (
  `id` int(11) UNSIGNED NOT NULL AUTO_INCREMENT,
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `start_time` timestamp(0) NULL DEFAULT NULL COMMENT '开始时间',
  `end_time` timestamp(0) NULL DEFAULT NULL COMMENT '结束时间',
  `params` json NULL COMMENT '活动参数设置',
  `status` tinyint(1) UNSIGNED NULL DEFAULT 1 COMMENT '状态 0-结束 1-启用',
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '申购活动表' ROW_FORMAT = Compact;

