  `count` int(11) NOT NULL DEFAULT 0 COMMENT '成交单数',
  `time` int(11) NOT NULL DEFAULT 0 COMMENT '时间点记录',
  INDEX `test_kline_1day_lvo_usdt_id_index`(`id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = Dynamic;

