-- ----------------------------
-- Table structure for time_orders
-- ----------------------------
DROP TABLE IF EXISTS `time_orders`;
CREATE TABLE `time_orders`  (
  `id` int(11) UNSIGNED NOT NULL AUTO_INCREMENT,
  `follow_id` int(11) UNSIGNED NULL DEFAULT 0 COMMENT '带单计划ID',
  `follow_record_id` int(10) UNSIGNED NULL DEFAULT 0 COMMENT '跟单记录ID',
  `user_id` int(11) UNSIGNED NULL DEFAULT 0 COMMENT '用户ID',
  `pair_id` int(11) UNSIGNED NULL DEFAULT 0 COMMENT '标的ID',
  `pair_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '交易对',
  `side` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '方向',
  `amount` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '金额',
  `open_price` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '建仓价格',
  `close_price` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '平仓价格',
  `order_time` timestamp(0) NULL DEFAULT NULL COMMENT '下单时间',
  `settle_time` timestamp(0) NULL DEFAULT NULL COMMENT '结算时间',
  `cycle` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '下单周期',
  `profit_ratio` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '盈亏比例',
  `is_win` tinyint(1) NULL DEFAULT 0 COMMENT '是否盈利 0-否 1-是',
  `kongyk` tinyint(1) NULL DEFAULT 0 COMMENT '控盈亏 1-盈利 2-亏本',
  `result` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '盈亏结果',
  `status` tinyint(1) UNSIGNED NULL DEFAULT 0 COMMENT '状态 0-待下单 1-进行中 2-已完成',
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_otime`(`order_time`) USING BTREE,
  INDEX `idx_stime`(`settle_time`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci ROW_FORMAT = Dynamic;

