-- ----------------------------
-- Table structure for user_dis_money
-- ----------------------------
DROP TABLE IF EXISTS `user_dis_money`;
CREATE TABLE `user_dis_money`  (
  `id` int(11) UNSIGNED NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NULL DEFAULT 0,
  `coin_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '',
  `account_type` int(11) NULL DEFAULT 0,
  `op_type` int(11) NULL DEFAULT 0,
  `money` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '',
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = MyISAM AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '冻结记录' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for user_grade
-- ----------------------------
DROP TABLE IF EXISTS `user_grade`;
CREATE TABLE `user_grade`  (
  `grade_id` int(11) UNSIGNED NOT NULL AUTO_INCREMENT,
  `grade_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '级别名称',
  `grade_name_en` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `grade_name_tw` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `grade_img` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '图标',
  `ug_self_vol` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '0' COMMENT '升级所需自身交易量',
  `ug_recommend_grade` int(11) UNSIGNED NULL DEFAULT 0 COMMENT '升级需推荐会员级别',
  `ug_recommend_num` int(11) UNSIGNED NULL DEFAULT 0 COMMENT '升级需推荐的会员数',
  `ug_total_vol` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '0' COMMENT '升级所需所有直推总交易量',
  `ug_direct_vol` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '0' COMMENT '升级所需单个直推用户交易量',
  `ug_direct_vol_num` int(11) UNSIGNED NULL DEFAULT 0 COMMENT '升级所需直推用户达到交易量用户数量',
  `ug_direct_recharge` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '0' COMMENT '升级所需单个直推用户充值量',
  `ug_direct_recharge_num` int(11) UNSIGNED NULL DEFAULT 0 COMMENT '升级所需直推用户达到充值量用户数量',
  `bonus` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '分红权益',
  `status` tinyint(2) UNSIGNED NULL DEFAULT 1 COMMENT '状态',
  `created_at` timestamp(0) NULL DEFAULT NULL COMMENT '创建时间',
  `updated_at` timestamp(0) NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`grade_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 7 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '用户等级' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of user_grade
-- ----------------------------

-- ----------------------------
-- Table structure for user_login_logs
-- ----------------------------
DROP TABLE IF EXISTS `user_login_logs`;
CREATE TABLE `user_login_logs`  (
  `id` int(11) UNSIGNED NOT NULL AUTO_INCREMENT,
  `user_id` int(11) UNSIGNED NULL DEFAULT 0 COMMENT '用户User_id',
  `username` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '登录用户名字',
  `login_time` int(11) UNSIGNED NULL DEFAULT 0 COMMENT '登录时间',
  `login_ip` varchar(16) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '登录IP地址',
  `login_site` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '登陆地点',
  `login_type` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '登录类型',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '用户登陆日志' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for user_payments
-- ----------------------------
DROP TABLE IF EXISTS `user_payments`;
CREATE TABLE `user_payments`  (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '会员支付方式表',
  `user_id` int(11) NOT NULL COMMENT '会员id',
  `pay_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'bank_card' COMMENT 'bank_card银行卡，alipay支付宝，wechat微信',
  `bank_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '银行名称',
  `real_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '持卡人姓名',
  `card_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'bank_card->卡号 wechat->账户名称  alipay->账户名称',
  `open_bank` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '开户支行',
  `code_img` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '微信/支付宝 二维码',
  `status` tinyint(1) UNSIGNED NOT NULL DEFAULT 1 COMMENT '状态 0禁用 1开启',
  `created_at` timestamp(0) NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP(0) COMMENT '添加时间',
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '收款账户表' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for user_subscribe
-- ----------------------------
DROP TABLE IF EXISTS `user_subscribe`;
CREATE TABLE `user_subscribe`  (
  `id` int(11) UNSIGNED NOT NULL AUTO_INCREMENT,
  `coin_name` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '0' COMMENT '币种英文名',
  `issue_price` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '0' COMMENT '发行价',
  `subscribe_currency` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '0' COMMENT '申购币种',
  `expected_time_online` timestamp(0) NULL DEFAULT NULL COMMENT '预计上线时间',
  `start_subscription_time` timestamp(0) NULL DEFAULT NULL COMMENT '开始申购时间',
  `end_subscription_time` timestamp(0) NULL DEFAULT NULL COMMENT '结束申购时间',
  `announce_time` timestamp(0) NULL DEFAULT NULL COMMENT '公布结果时间',
  `status` int(11) NULL DEFAULT 1 COMMENT '1 代表预热  2 开始申购 3结束申购 4 公布结果',
  `project_details` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '项目详情',
  `en_project_details` varchar(800) CHARACTER SET utf8mb4 COLLATE utf8mb4_german2_ci NULL DEFAULT NULL COMMENT '英文项目详情',
  `maximum_purchase` int(11) NULL DEFAULT NULL COMMENT '最大申购',
  `minimum_purchase` int(11) NULL DEFAULT NULL COMMENT '最少申购',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 5 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '项目币种申购表' ROW_FORMAT = Compact;

-- ----------------------------
-- Records of user_subscribe
-- ----------------------------

-- ----------------------------
-- Table structure for user_subscribe_record
-- ----------------------------
DROP TABLE IF EXISTS `user_subscribe_record`;
CREATE TABLE `user_subscribe_record`  (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL COMMENT '用户ID',
  `payment_amount` decimal(25, 4) NOT NULL COMMENT '认购付款的币种数量',
  `payment_currency` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '支付的币种',
  `subscription_time` int(11) NOT NULL COMMENT '申购时间',
  `subscription_currency_name` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '申购的币种名称',
  `subscription_currency_amount` decimal(25, 2) NOT NULL COMMENT '申购的币种数量',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for user_transfer_record
-- ----------------------------
DROP TABLE IF EXISTS `user_transfer_record`;
CREATE TABLE `user_transfer_record`  (
  `id` int(11) UNSIGNED NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL COMMENT '用户ID',
  `coin_id` int(11) NULL DEFAULT NULL COMMENT '币种ID',
  `coin_name` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '币种名称',
  `draw_out_direction` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '划出地址',
  `into_direction` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '划转方向',
  `amount` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '划转数量',
  `status` int(11) NOT NULL COMMENT '1代表成功,2代表失败',
  `datetime` int(11) NOT NULL COMMENT '划转时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '用户划转记录' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for user_transfer_translation
-- ----------------------------
DROP TABLE IF EXISTS `user_transfer_translation`;
CREATE TABLE `user_transfer_translation`  (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `en_direction_out` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '转出',
  `en_direction_in` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '转入',
  `tw_direction_out` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '台湾字体转出方向',
  `tw_direction_in` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '台湾字体转入方向',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8 COLLATE = utf8_general_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of user_transfer_translation
-- ----------------------------

-- ----------------------------
-- Table structure for user_upgrade_logs
-- ----------------------------
DROP TABLE IF EXISTS `user_upgrade_logs`;
CREATE TABLE `user_upgrade_logs`  (
  `id` int(11) UNSIGNED NOT NULL AUTO_INCREMENT,
  `user_id` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '用户id',
  `user_old_grade` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL DEFAULT '' COMMENT '用户级别',
  `user_new_grade` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '目标级别',
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '用户升级日志' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for user_wallet
-- ----------------------------
DROP TABLE IF EXISTS `user_wallet`;
CREATE TABLE `user_wallet`  (
  `wallet_id` int(10) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键',
  `user_id` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '用户id',
  `coin_id` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '虚拟货币钱包类型id',
  `coin_name` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '币种名称',
  `omni_wallet_address` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '钱包地址',
  `trx_wallet_address` varchar(100) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `wallet_address` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '钱包地址',
  `private_key` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `raw_data` text CHARACTER SET utf8 COLLATE utf8_bin NULL COMMENT '地址原始数据（存储公钥私钥密码等数据）',
  `usable_balance` decimal(20, 8) UNSIGNED NOT NULL DEFAULT 0.00000000 COMMENT '可用余额',
  `freeze_balance` decimal(20, 8) NOT NULL DEFAULT 0.00000000 COMMENT '冻结余额',
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`wallet_id`) USING BTREE,
  UNIQUE INDEX `user_coin`(`user_id`, `coin_id`) USING BTREE,
  INDEX `address`(`wallet_address`) USING BTREE,
  INDEX `user_id`(`user_id`) USING BTREE,
  INDEX `coin_id`(`coin_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_bin COMMENT = '钱包' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for user_wallet_address
-- ----------------------------
DROP TABLE IF EXISTS `user_wallet_address`;
CREATE TABLE `user_wallet_address`  (
  `user_id` int(11) UNSIGNED NOT NULL AUTO_INCREMENT,
  `omni_wallet_address` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '钱包地址',
  `trx_wallet_address` varchar(100) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `wallet_address` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '钱包地址',
  `w_create_at` datetime(0) NULL DEFAULT NULL,
  `o_create_at` datetime(0) NULL DEFAULT NULL,
  `t_create_at` datetime(0) NULL DEFAULT NULL,
  `w_sign` varchar(50) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `o_sign` varchar(50) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `t_sign` varchar(50) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `updated_at` datetime(0) NULL DEFAULT NULL,
  `status` tinyint(1) NULL DEFAULT 0 COMMENT '状态',
  PRIMARY KEY (`user_id`) USING BTREE,
  INDEX `address`(`wallet_address`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_bin COMMENT = '钱包' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for user_wallet_logs
-- ----------------------------
DROP TABLE IF EXISTS `user_wallet_logs`;
CREATE TABLE `user_wallet_logs`  (
  `id` int(11) UNSIGNED NOT NULL AUTO_INCREMENT,
  `user_id` int(11) UNSIGNED NOT NULL DEFAULT 0,
  `s_user_id` int(11) UNSIGNED NULL DEFAULT 0 COMMENT '下级id',
  `account_type` tinyint(4) UNSIGNED NOT NULL DEFAULT 1 COMMENT '账户类型(1账户资产 2合约账户)',
  `sub_account` int(10) NULL DEFAULT NULL COMMENT '子账户',
  `coin_id` int(10) UNSIGNED NOT NULL DEFAULT 0 COMMENT '币种ID',
  `coin_name` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `rich_type` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '资产类型',
  `amount` decimal(20, 8) NOT NULL DEFAULT 0.00000000 COMMENT '金额',
  `log_type` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '流水类型',
  `log_note` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '流水描述',
  `before_balance` decimal(20, 8) UNSIGNED NOT NULL DEFAULT 0.00000000 COMMENT '变更前余额',
  `after_balance` decimal(20, 8) UNSIGNED NOT NULL DEFAULT 0.00000000 COMMENT '变更后余额',
  `logable_id` int(10) NULL DEFAULT NULL,
  `logable_type` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `ts` int(13) NULL DEFAULT NULL,
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '钱包流水表' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for user_wallet_recharge
-- ----------------------------
DROP TABLE IF EXISTS `user_wallet_recharge`;
CREATE TABLE `user_wallet_recharge`  (
  `id` int(10) UNSIGNED NOT NULL AUTO_INCREMENT,
  `user_id` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '会员ID',
  `username` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '用户名称',
  `coin_id` int(10) NOT NULL,
  `coin_name` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '币名',
  `datetime` int(11) NOT NULL COMMENT '日期',
  `amount` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '数量',
  `status` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '0' COMMENT '0待审核 1通过 2拒绝',
  `remark` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '审核备注',
  `check_time` int(13) UNSIGNED NULL DEFAULT NULL COMMENT '审核时间',
  `address` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '充值地址',
  `txid` varchar(120) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '交易hash',
  `type` tinyint(1) UNSIGNED NULL DEFAULT 1 COMMENT '1-在线 2-后台',
  `account_type` tinyint(1) UNSIGNED NULL DEFAULT 1,
  `note` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '备注',
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  `cur_price` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '0',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '充币记录' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for user_wallet_withdraw
-- ----------------------------
DROP TABLE IF EXISTS `user_wallet_withdraw`;
CREATE TABLE `user_wallet_withdraw`  (
  `id` int(10) UNSIGNED NOT NULL AUTO_INCREMENT,
  `user_id` int(11) UNSIGNED NOT NULL DEFAULT 0,
  `username` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '用户名称',
  `address` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '提币地址',
  `address_type` tinyint(1) UNSIGNED NULL DEFAULT NULL COMMENT '地址类型',
  `total_amount` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '提币数量',
  `amount` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '实际到账数量',
  `withdrawal_fee` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '手续费',
  `status` tinyint(1) UNSIGNED NOT NULL DEFAULT 0 COMMENT '0待审核 1通过 2拒绝',
  `remark` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '审核备注',
  `check_time` int(13) NULL DEFAULT NULL COMMENT '审核时间',
  `coin_id` int(10) NOT NULL COMMENT '币种ID',
  `coin_name` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `address_note` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '钱包地址备注比如交易所 或者是什么钱包的地址',
  `datetime` int(11) NOT NULL COMMENT '日期',
  `hash` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  `cur_price` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '0',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '提币记录' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for user_withdrawal_management
-- ----------------------------
DROP TABLE IF EXISTS `user_withdrawal_management`;
CREATE TABLE `user_withdrawal_management`  (
  `id` int(10) UNSIGNED NOT NULL AUTO_INCREMENT,
  `user_id` int(11) UNSIGNED NOT NULL DEFAULT 0,
  `coin_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '用户名称',
  `address_note` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '钱包地址备注比如交易所 或者是什么钱包的地址',
  `address` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '提币地址',
  `datetime` int(11) NOT NULL,
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 15 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '提币账户管理' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for users
-- ----------------------------
DROP TABLE IF EXISTS `users`;
CREATE TABLE `users`  (
  `user_id` int(11) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键',
  `id` int(11) UNSIGNED NULL DEFAULT 0 COMMENT '代理商后台必须字段',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '代理商后台必须字段',
  `account` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '主账户',
  `account_type` tinyint(1) NULL DEFAULT NULL COMMENT '账户类型 1手机 2邮箱',
  `username` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '用户名',
  `referrer` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '推荐人ID 这里指代理',
  `pid` int(11) UNSIGNED NOT NULL DEFAULT 0 COMMENT '父级ID',
  `deep` int(10) UNSIGNED NOT NULL DEFAULT 0 COMMENT '推荐关系层级',
  `auth_level` tinyint(3) UNSIGNED NOT NULL DEFAULT 0 COMMENT '代理权限等级（1，实名认证，充币）',
  `path` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL,
  `country_id` int(11) NULL DEFAULT NULL,
  `country_code` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '国家代号',
  `phone` char(12) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '用户电话',
  `phone_status` tinyint(1) UNSIGNED NOT NULL DEFAULT 0,
  `email` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '用户邮箱',
  `email_status` tinyint(1) UNSIGNED NOT NULL DEFAULT 0,
  `avatar` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'head_image/head_default.png' COMMENT '用户头像',
  `google_token` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '谷歌验证',
  `google_status` tinyint(1) UNSIGNED NOT NULL DEFAULT 0,
  `second_verify` tinyint(1) UNSIGNED NOT NULL DEFAULT 0 COMMENT '是否二次验证',
  `password` varchar(80) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '用户登录密码',
  `payword` varchar(80) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '用户支付密码',
  `invite_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '邀请码',
  `purchase_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '申购码',
  `user_grade` tinyint(4) UNSIGNED NOT NULL DEFAULT 1 COMMENT '用户级别 默认1',
  `user_identity` tinyint(1) UNSIGNED NOT NULL DEFAULT 1 COMMENT '用户身份 默认1- 普通用户',
  `is_agency` tinyint(1) UNSIGNED NOT NULL DEFAULT 0 COMMENT '是否代理',
  `user_auth_level` tinyint(1) UNSIGNED NOT NULL DEFAULT 0 COMMENT '用户认证级别 0未认证 1初级认证 2高级认证',
  `is_system` tinyint(1) UNSIGNED NOT NULL DEFAULT 0 COMMENT '是否系统账户',
  `contract_deal` tinyint(1) UNSIGNED NULL DEFAULT 0,
  `login_code` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '登录码',
  `status` tinyint(4) UNSIGNED NOT NULL DEFAULT 1 COMMENT '用户状态 0冻结 1正常',
  `trade_status` tinyint(1) UNSIGNED NULL DEFAULT 1 COMMENT '交易状态 0锁定 1正常',
  `trade_verify` tinyint(1) UNSIGNED NULL DEFAULT 0 COMMENT '交易是否密码验证',
  `contract_anomaly` tinyint(1) UNSIGNED NULL DEFAULT 0,
  `reg_ip` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL DEFAULT '' COMMENT '注册ip',
  `last_login_time` timestamp(0) NULL DEFAULT NULL COMMENT '登录时间',
  `last_login_ip` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '登录IP',
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  `remember_token` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `subscribe_rebate_rate` float(10, 4) NULL DEFAULT NULL,
  `contract_rebate_rate` float(10, 4) NULL DEFAULT NULL,
  `option_rebate_rate` float(10, 4) NULL DEFAULT NULL,
  `security_issuse` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '安全问题',
  `security_answer` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '安全问题答案',
  `is_online` tinyint(1) NULL DEFAULT 0 COMMENT '是否在线 0-否 1-是',
  `last_seen_at` timestamp(0) NULL DEFAULT NULL COMMENT '最后活跃时间',
  PRIMARY KEY (`user_id`) USING BTREE,
  UNIQUE INDEX `username`(`username`) USING BTREE,
  INDEX `pid`(`pid`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 861957 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '用户表' ROW_FORMAT = Compact;

-- ----------------------------
-- Records of users
-- ----------------------------

-- ----------------------------
-- Table structure for vol_logs
-- ----------------------------
DROP TABLE IF EXISTS `vol_logs`;
CREATE TABLE `vol_logs`  (
  `id` int(11) UNSIGNED NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NULL DEFAULT 0 COMMENT '用户ID',
  `op` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '操作符',
  `number` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '操作数量',
  `remark` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '操作原因',
  `op_time` datetime(0) NULL DEFAULT NULL COMMENT '操作时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = MyISAM AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '交易量操作日志' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for wallet_collection
-- ----------------------------
DROP TABLE IF EXISTS `wallet_collection`;
CREATE TABLE `wallet_collection`  (
  `id` int(10) UNSIGNED NOT NULL AUTO_INCREMENT,
  `symbol` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'symbol',
  `from` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'from',
  `amount` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '数量',
  `to` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'to',
  `txid` varchar(120) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '交易hash',
  `datetime` int(11) NULL DEFAULT NULL COMMENT '日期',
  `note` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '备注',
  `status` tinyint(1) UNSIGNED NULL DEFAULT 0,
  `created_at` timestamp(0) NULL DEFAULT NULL,
  `updated_at` timestamp(0) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '归集记录' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for xy_bank
-- ----------------------------
DROP TABLE IF EXISTS `xy_bank`;
CREATE TABLE `xy_bank`  (
  `id` int(10) NOT NULL COMMENT 'xy_bank',
  `bank_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `ispb` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `code_number` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `nome_extenso` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `createtime` timestamp(0) NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP(0),
  `status` tinyint(4) NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `id`(`id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8 COLLATE = utf8_general_ci ROW_FORMAT = Dynamic;

SET FOREIGN_KEY_CHECKS = 1;
