INSERT INTO `admin_operation_log` VALUES (2319, 1, 'admin/article/173', 'PUT', '18.162.97.146', '{\"category_id\":\"8\",\"cover\":null,\"_file_\":null,\"status\":\"1\",\"order\":\"1\",\"is_recommend\":\"0\",\"created_at\":\"2025-07-30 15:37:18\",\"translations\":{\"478\":{\"locale\":\"zh-CN\",\"title\":\"\\u5e2e\\u52a9\\u4e2d\\u5fc3\",\"excerpt\":null,\"body\":\"<p>&nbsp;<\\/p>\\r\\n<p>\\u4ec0\\u9ebc\\u662f\\u4ea4\\u6613\\u91cf\\uff1f<\\/p>\\r\\n<p>\\u6839\\u64da\\u53cd\\u6d17\\u9322\\u6cd5\\u76f8\\u95dc\\u898f\\u5b9a\\uff0c\\u5404\\u4ea4\\u6613\\u6240\\u9700\\u9032\\u884c\\u50f9\\u683c\\u628a\\u63a7\\uff0c\\u9700\\u5b8c\\u6210\\u4e00\\u5b9a\\u4ea4\\u6613\\u91cf\\u65b9\\u53ef\\u63d0\\u5e63\\uff0c\\u907f\\u514d\\u7528\\u6236\\u5229\\u7528\\u4ea4\\u6613\\u6240\\u76f8\\u95dc\\u898f\\u5247\\u9032\\u884c\\u6d17\\u9322\\u64cd\\u4f5c\\uff0c\\u4f8b\\u5982\\u5145\\u5e6310000USDT\\uff0c\\u4ea4\\u6613\\u91d1\\u984d\\u9700\\u9054\\u5230\\u76f8\\u95dc\\u898f\\u5b9a\\u6578\\u91cf\\uff01<\\/p>\\r\\n<p>&nbsp;<\\/p>\\r\\n<p>\\u4ec0\\u9ebc\\u662f\\u671f\\u8ca8\\uff1f<\\/p>\\r\\n<p>\\u671f\\u8ca8\\u4ea4\\u6613\\u7c21\\u7a31\\u671f\\u8ca8\\uff0c\\u662f\\u4e00\\u7a2e\\u8de8\\u8d8a\\u6642\\u9593\\u7684\\u4ea4\\u6613\\u65b9\\u5f0f\\uff0c\\u8cb7\\u8ce3\\u96d9\\u65b9\\u900f\\u904e\\u7c3d\\u8a02\\u5408\\u7d04\\u689d\\u6b3e\\uff0c\\u540c\\u610f\\u6309\\u7167\\u6307\\u5b9a\\u7684\\u6642\\u9593\\uff0c\\u50f9\\u683c\\u8207\\u5176\\u4ed6\\u76f8\\u95dc\\u689d\\u4ef6\\uff0c\\u4ea4\\u6536\\u6307\\u5b9a\\u6578\\u91cf\\u7684\\u73fe\\u8ca8\\u3002\\u901a\\u5e38\\u671f\\u8ca8\\u4ea4\\u6613\\u96c6\\u4e2d\\u5728\\u671f\\u8ca8\\u4ea4\\u6613\\u6240\\uff0c\\u4ee5\\u6a19\\u6e96\\u5316\\u5408\\u7d04\\u9032\\u884c\\u8cb7\\u8ce3\\u3002\\u4ea4\\u6613\\u7684\\u8cc7\\u7522\\u901a\\u5e38\\u662f\\u5546\\u54c1\\u6216\\u8005\\u91d1\\u878d\\u7522\\u54c1\\u3002\\u96d9\\u65b9\\u540c\\u610f\\u8cfc\\u8cb7\\u6216\\u51fa\\u552e\\u8cc7\\u7522\\u7684\\u9810\\u5b9a\\u50f9\\u683c\\u88ab\\u7a31\\u70ba\\u9060\\u671f\\u50f9\\u683c\\u3002<\\/p>\\r\\n<p>&nbsp;<\\/p>\\r\\n<p>\\u8cc7\\u7522\\u4e2d\\u7684\\u6298\\u5408\\u91d1\\u984d\\u70ba\\u4ec0\\u9ebc\\u6703\\u7522\\u751f\\u8b8a\\u5316\\uff1f<\\/p>\\r\\n<p>\\u8cc7\\u7522\\u4e2d\\u6298\\u5408\\u91d1\\u984d\\u8a08\\u7b97\\u7684\\u662f\\u7576\\u524d\\u6301\\u6709\\u7684\\u6240\\u6709\\u6578\\u5b57\\u8ca8\\u5e63\\u6298\\u5408USDT\\u7684\\u50f9\\u503c\\uff0c\\u56e0\\u6578\\u5b57\\u8cc7\\u7522\\u7684\\u50f9\\u683c\\u6703\\u7522\\u751f\\u6ce2\\u52d5\\u800c\\u8b8a\\u5316\\uff0c\\u60a8\\u7684\\u6578\\u5b57\\u8cc7\\u7522\\u6578\\u91cf\\u4e26\\u6c92\\u6709\\u767c\\u751f\\u6539\\u8b8a\\u3002<\\/p>\\r\\n<p>&nbsp;<\\/p>\\r\\n<p>\\u70ba\\u4ec0\\u9ebc\\u8981\\u9032\\u884c\\u5be6\\u540d\\u8a8d\\u8b49\\uff1f<\\/p>\\r\\n<p>\\u901a\\u904e\\u9a57\\u8b49\\u7528\\u6236\\u771f\\u5be6\\u8eab\\u4efd\\uff0c\\u53ef\\u4ee5\\u6709\\u6548\\u6e1b\\u5c11\\u865b\\u5047\\u8cec\\u865f\\u64fe\\u4e82\\u4ea4\\u6613\\u5e02\\u5834\\uff0c\\u7db2\\u7d61\\u66b4\\u529b\\u7b49\\u533f\\u540d\\u5834\\u666f\\u4e0b\\u7684\\u9055\\u898f\\u884c\\u70ba\\u3002\\u4fdd\\u8b77\\u7528\\u6236\\u4eab\\u6709\\u61c9\\u5f97\\u7684\\u6b0a\\u76ca\\uff0c\\u5728\\u91d1\\u878d\\u652f\\u4ed8\\uff0c\\u4ea4\\u6613\\u7b49\\u5834\\u666f\\u4e2d\\uff0cKYC\\u5be6\\u540d\\u8a8d\\u8b49\\u53ef\\u4ee5\\u8ffd\\u6eaf\\u7570\\u5e38\\u64cd\\u4f5c\\uff0c\\u964d\\u4f4e\\u76dc\\u865f\\u3001\\u672a\\u6210\\u5e74\\u4eba\\u975e\\u7406\\u6027\\u6295\\u8cc7\\u7b49\\u98a8\\u96aa\\u3002<\\/p>\\r\\n<p>&nbsp;<\\/p>\\r\\n<p>\\u671f\\u8ca8\\u4ea4\\u6613\\u7684\\u898f\\u5247\\u662f\\u4ec0\\u9ebc\\uff1f<\\/p>\\r\\n<p>\\u901a\\u904e\\u9810\\u4f30\\u7576\\u524d\\u4ea4\\u6613\\u5c0d\\u63a5\\u4e0b\\u4f86\\u7684\\u50f9\\u683c\\u8d70\\u52e2\\uff08\\u6f32\\u8dcc\\uff09\\u7684\\u65b9\\u5f0f\\u53c3\\u8207\\u4ea4\\u6613\\uff0c\\u7d50\\u7b97\\u6642\\u4e0d\\u8a08\\u7b97\\u6f32\\u8dcc\\u50f9\\u683c\\u7684\\u5e45\\u5ea6\\uff0c\\u53ea\\u5c0d\\u6f32\\u8dcc\\u7684\\u7d50\\u679c\\u9032\\u884c\\u6536\\u76ca\\u8a08\\u7b97\\u3002\\u4e0d\\u540c\\u4ea4\\u5272\\u6642\\u9593\\u7d50\\u7b97\\u7684\\u76c8\\u5229\\u767e\\u5206\\u6bd4\\u4e0d\\u540c\\uff0c\\u76c8\\u5229\\u5c07\\u6e96\\u78ba\\u7684\\u5c55\\u793a\\u5728\\u4ea4\\u6613\\u4ecb\\u9762\\u4e2d\\u3002<\\/p>\",\"id\":\"478\",\"_remove_\":null},\"new_2\":{\"locale\":\"en\",\"title\":\"help center\",\"excerpt\":null,\"body\":\"<p>What is trading volume?<\\/p>\\r\\n<p>According to anti-money laundering regulations, each transaction requires price control, and a certain trading volume must be completed before withdrawal is allowed, to prevent users from using exchange rules for money laundering operations. For example, if 10,000 USDT is deposited, the trading amount must reach the relevant specified quantity!<\\/p>\\r\\n<p>&nbsp;<\\/p>\\r\\n<p>What is futures?<\\/p>\\r\\n<p>Futures trading, abbreviated as futures, is a type of trading that crosses time. The buyer and seller agree through a contract to deliver a specified quantity of the underlying asset at a specified time, price, and other related conditions. Futures trading is usually centralized on futures exchanges, where standardized contracts are traded. The traded assets are usually commodities or financial products. The agreed purchase or sale price of the asset is called the forward price.<\\/p>\\r\\n<p>&nbsp;<\\/p>\\r\\n<p>Why does the converted amount in assets change?<\\/p>\\r\\n<p>The converted amount in assets calculates the current value of all held cryptocurrencies converted to USDT. Since the prices of digital assets fluctuate, this amount changes, even though the quantity of your digital assets has not changed.<\\/p>\\r\\n<p>&nbsp;<\\/p>\\r\\n<p>Why is real-name authentication necessary?<\\/p>\\r\\n<p>Verifying the user\'s true identity can effectively reduce fake accounts disturbing the trading market, online violence, and other violations in anonymous scenarios. It protects users\' rightful interests. In financial payment and trading scenarios, KYC real-name authentication allows tracing of abnormal operations and reduces risks such as account theft and irrational investments by minors.<\\/p>\\r\\n<p>&nbsp;<\\/p>\\r\\n<p>What are the rules of futures trading?<\\/p>\\r\\n<p>By predicting the price trend (rise or fall) of the current trading pair, one participates in trading. The settlement only considers the result of the price movement (up or down) and does not calculate the magnitude of the price change. Different settlement times have different profit percentages, and profits will be accurately displayed on the trading interface.<\\/p>\",\"id\":null,\"_remove_\":null},\"new_3\":{\"locale\":\"spa\",\"title\":\"Centro de ayuda\",\"excerpt\":null,\"body\":\"<p>&iquest;Qu&eacute; es el volumen de negociaci&oacute;n?<\\/p>\\r\\n<p>De acuerdo con las regulaciones relacionadas con la ley contra el lavado de dinero, cada intercambio debe controlar los precios y se debe completar un cierto volumen de negociaci&oacute;n antes de poder retirar fondos, para evitar que los usuarios utilicen las reglas del intercambio para realizar operaciones de lavado de dinero. Por ejemplo, si se depositan 10,000 USDT, el monto de negociaci&oacute;n debe alcanzar la cantidad especificada relevante.<\\/p>\\r\\n<p>&nbsp;<\\/p>\\r\\n<p>&iquest;Qu&eacute; son los futuros?<\\/p>\\r\\n<p>El comercio de futuros, abreviado como futuros, es una forma de comercio que atraviesa el tiempo. Las partes compradora y vendedora acuerdan mediante la firma de un contrato entregar una cantidad espec&iacute;fica del activo subyacente en un momento, precio y otras condiciones relacionadas especificadas. Normalmente, el comercio de futuros se concentra en las bolsas de futuros, donde se negocian contratos estandarizados. Los activos negociados suelen ser productos b&aacute;sicos o productos financieros. El precio acordado para comprar o vender el activo se denomina precio a plazo.<\\/p>\\r\\n<p>&nbsp;<\\/p>\\r\\n<p>&iquest;Por qu&eacute; cambia el monto convertido en los activos?<\\/p>\\r\\n<p>El monto convertido en los activos calcula el valor actual de todas las criptomonedas en posesi&oacute;n convertidas a USDT. Debido a la fluctuaci&oacute;n de los precios de los activos digitales, este monto cambia, aunque la cantidad de sus activos digitales no ha cambiado.<\\/p>\\r\\n<p>&nbsp;<\\/p>\\r\\n<p>&iquest;Por qu&eacute; es necesario realizar la verificaci&oacute;n de identidad real?<\\/p>\\r\\n<p>Verificar la identidad real del usuario puede reducir eficazmente las cuentas falsas que perturban el mercado de negociaci&oacute;n, la violencia en l&iacute;nea y otras conductas ilegales en escenarios an&oacute;nimos. Protege los derechos que corresponden a los usuarios. En escenarios de pagos financieros y comercio, la verificaci&oacute;n de identidad real KYC permite rastrear operaciones anormales y reduce riesgos como el robo de cuentas y la inversi&oacute;n irracional de menores.<\\/p>\\r\\n<p>&nbsp;<\\/p>\\r\\n<p>&iquest;Cu&aacute;les son las reglas del comercio de futuros?<\\/p>\\r\\n<p>Se participa en el comercio mediante la predicci&oacute;n de la tendencia del precio (subida o bajada) del par de negociaci&oacute;n actual. En la liquidaci&oacute;n, no se calcula la magnitud del cambio de precio, solo se calcula el resultado del movimiento del precio para determinar la ganancia o p&eacute;rdida. Los porcentajes de ganancia var&iacute;an seg&uacute;n el tiempo de entrega y las ganancias se muestran con precisi&oacute;n en la interfaz de negociaci&oacute;n.<\\/p>\",\"id\":null,\"_remove_\":null},\"new_4\":{\"locale\":\"fra\",\"title\":\"Centre d\'aide\",\"excerpt\":null,\"body\":\"<p>Qu\'est-ce que le volume de transactions ?<\\/p>\\r\\n<p>Selon les r&eacute;glementations relatives &agrave; la lutte contre le blanchiment d\'argent, chaque plateforme d\'&eacute;change doit contr&ocirc;ler les prix et un certain volume de transactions doit &ecirc;tre atteint avant de pouvoir effectuer un retrait, afin d\'&eacute;viter que les utilisateurs n\'exploitent les r&egrave;gles de la plateforme pour effectuer des op&eacute;rations de blanchiment d\'argent. Par exemple, pour un d&eacute;p&ocirc;t de 10 000 USDT, le montant des transactions doit atteindre la quantit&eacute; r&eacute;glementaire correspondante !<\\/p>\\r\\n<p>&nbsp;<\\/p>\\r\\n<p>Qu\'est-ce que les contrats &agrave; terme ?<\\/p>\\r\\n<p>Le trading de contrats &agrave; terme, abr&eacute;g&eacute; en futures, est une forme de transaction qui s\'&eacute;tend dans le temps. Les deux parties, acheteur et vendeur, conviennent par la signature d\'un contrat de livrer une quantit&eacute; sp&eacute;cifi&eacute;e de l\'actif sous-jacent &agrave; une date, un prix et selon d\'autres conditions convenus. Le trading de contrats &agrave; terme se concentre g&eacute;n&eacute;ralement sur les march&eacute;s &agrave; terme, o&ugrave; les &eacute;changes se font via des contrats standardis&eacute;s. Les actifs n&eacute;goci&eacute;s sont g&eacute;n&eacute;ralement des marchandises ou des produits financiers. Le prix convenu pour acheter ou vendre l\'actif est appel&eacute; prix &agrave; terme.<\\/p>\\r\\n<p>&nbsp;<\\/p>\\r\\n<p>Pourquoi la valeur convertie des actifs change-t-elle ?<\\/p>\\r\\n<p>La valeur convertie des actifs correspond &agrave; la valeur actuelle de toutes les cryptomonnaies d&eacute;tenues converties en USDT. En raison des fluctuations des prix des actifs num&eacute;riques, cette valeur varie, m&ecirc;me si la quantit&eacute; de vos actifs num&eacute;riques n\'a pas chang&eacute;.<\\/p>\\r\\n<p>&nbsp;<\\/p>\\r\\n<p>Pourquoi faut-il effectuer une authentification d\'identit&eacute; ?<\\/p>\\r\\n<p>La v&eacute;rification de la v&eacute;ritable identit&eacute; des utilisateurs permet de r&eacute;duire efficacement les faux comptes qui perturbent le march&eacute;, la violence en ligne et d\'autres comportements illicites dans des contextes anonymes. Elle prot&egrave;ge les droits l&eacute;gitimes des utilisateurs. Dans les contextes de paiement financier et de trading, l&rsquo;authentification KYC permet de retracer les op&eacute;rations anormales et de r&eacute;duire les risques de piratage de compte et d\'investissements irr&eacute;fl&eacute;chis par des mineurs.<\\/p>\\r\\n<p>&nbsp;<\\/p>\\r\\n<p>Quelles sont les r&egrave;gles du trading &agrave; terme ?<\\/p>\\r\\n<p>Le trading se fait en pr&eacute;voyant la tendance future du prix (hausse ou baisse) de la paire de trading actuelle. Lors du r&egrave;glement, seule la direction du changement de prix (hausse ou baisse) est prise en compte pour calculer le gain, sans tenir compte de l&rsquo;amplitude du changement. Les pourcentages de gain varient selon le temps de r&egrave;glement, et les gains sont affich&eacute;s pr&eacute;cis&eacute;ment sur l&rsquo;interface de trading.<\\/p>\",\"id\":null,\"_remove_\":null},\"new_5\":{\"locale\":\"de\",\"title\":\"Hilfezentrum\",\"excerpt\":null,\"body\":\"<p>Was ist das Handelsvolumen?<\\/p>\\r\\n<p>Gem&auml;&szlig; den Vorschriften zur Geldw&auml;schebek&auml;mpfung m&uuml;ssen alle B&ouml;rsen die Preise kontrollieren, und es muss ein bestimmtes Handelsvolumen erreicht werden, bevor eine Abhebung m&ouml;glich ist, um zu verhindern, dass Nutzer die Regeln der B&ouml;rse zum Geldwaschen ausnutzen. Zum Beispiel muss bei einer Einzahlung von 10.000 USDT das Handelsvolumen die entsprechende vorgeschriebene Menge erreichen!<\\/p>\\r\\n<p>&nbsp;<\\/p>\\r\\n<p>Was sind Futures?<\\/p>\\r\\n<p>Der Futures-Handel, kurz Futures, ist eine &uuml;ber die Zeit gehende Handelsart, bei der K&auml;ufer und Verk&auml;ufer durch Vertragsbedingungen vereinbaren, zu einem bestimmten Zeitpunkt, zu einem bestimmten Preis und unter anderen vereinbarten Bedingungen eine festgelegte Menge des zugrundeliegenden Verm&ouml;genswertes zu liefern. Futures-Handel findet &uuml;blicherweise an Futures-B&ouml;rsen statt, wo standardisierte Kontrakte gehandelt werden. Die gehandelten Verm&ouml;genswerte sind &uuml;blicherweise Waren oder Finanzprodukte. Der vereinbarte Kauf- oder Verkaufspreis des Verm&ouml;genswertes wird als Terminkurs bezeichnet.<\\/p>\\r\\n<p>&nbsp;<\\/p>\\r\\n<p>Warum &auml;ndert sich der umgerechnete Betrag im Verm&ouml;gen?<\\/p>\\r\\n<p>Der umgerechnete Betrag im Verm&ouml;gen berechnet den aktuellen Wert aller gehaltenen Kryptow&auml;hrungen umgerechnet in USDT. Da die Preise digitaler Verm&ouml;genswerte Schwankungen unterliegen, &auml;ndert sich dieser Wert, obwohl sich die Menge Ihrer digitalen Verm&ouml;genswerte nicht ver&auml;ndert hat.<\\/p>\\r\\n<p>&nbsp;<\\/p>\\r\\n<p>Warum ist eine Identit&auml;tsverifizierung erforderlich?<\\/p>\\r\\n<p>Durch die &Uuml;berpr&uuml;fung der tats&auml;chlichen Identit&auml;t der Nutzer k&ouml;nnen gef&auml;lschte Konten, die den Handelsmarkt st&ouml;ren, Netzgewalt und andere Verst&ouml;&szlig;e in anonymen Szenarien effektiv reduziert werden. Es sch&uuml;tzt die berechtigten Rechte der Nutzer. In Finanzzahlungs- und Handelsszenarien erm&ouml;glicht die KYC-Identit&auml;tsverifizierung die Nachverfolgung ungew&ouml;hnlicher Vorg&auml;nge und verringert Risiken wie Kontodiebstahl und unvern&uuml;nftige Investitionen von Minderj&auml;hrigen.<\\/p>\\r\\n<p>&nbsp;<\\/p>\\r\\n<p>Was sind die Regeln f&uuml;r den Futures-Handel?<\\/p>\\r\\n<p>Man nimmt am Handel teil, indem man die zuk&uuml;nftige Preisentwicklung (Steigen oder Fallen) des aktuellen Handelspaars einsch&auml;tzt. Bei der Abrechnung wird nur das Ergebnis der Preisbewegung (Steigen oder Fallen) ber&uuml;cksichtigt, nicht die H&ouml;he der Preis&auml;nderung. Die Gewinnprozents&auml;tze unterscheiden sich je nach Abwicklungszeitpunkt, und die Gewinne werden genau in der Handelsoberfl&auml;che angezeigt.<\\/p>\",\"id\":null,\"_remove_\":null},\"new_6\":{\"locale\":\"it\",\"title\":\"Centro di assistenza\",\"excerpt\":null,\"body\":\"<p>Cos&rsquo;&egrave; il volume di scambi?<\\/p>\\r\\n<p>Secondo le normative relative alla legge anti-riciclaggio, ogni piattaforma di scambio deve controllare i prezzi e deve essere completato un certo volume di scambi prima di poter effettuare un prelievo, per evitare che gli utenti sfruttino le regole della piattaforma per operazioni di riciclaggio di denaro. Ad esempio, per un deposito di 10.000 USDT, l&rsquo;importo delle transazioni deve raggiungere la quantit&agrave; richiesta dalle normative!<\\/p>\\r\\n<p>&nbsp;<\\/p>\\r\\n<p>Cos&rsquo;&egrave; il futures?<\\/p>\\r\\n<p>Il trading futures, abbreviato in futures, &egrave; una modalit&agrave; di negoziazione che attraversa il tempo. Le due parti, compratore e venditore, tramite la sottoscrizione di un contratto, concordano di consegnare una quantit&agrave; specifica di merce al momento, prezzo e altre condizioni specificate. Di solito il trading futures si concentra sulle borse futures, dove si negoziano contratti standardizzati. Gli asset negoziati sono generalmente merci o prodotti finanziari. Il prezzo concordato per l&rsquo;acquisto o la vendita dell&rsquo;asset &egrave; chiamato prezzo a termine.<\\/p>\\r\\n<p>&nbsp;<\\/p>\\r\\n<p>Perch&eacute; cambia l&rsquo;importo convertito negli asset?<\\/p>\\r\\n<p>L&rsquo;importo convertito negli asset calcola il valore attuale di tutte le criptovalute detenute convertito in USDT. Poich&eacute; il prezzo degli asset digitali pu&ograve; fluttuare, questo valore cambia, anche se la quantit&agrave; dei tuoi asset digitali non &egrave; cambiata.<\\/p>\\r\\n<p>&nbsp;<\\/p>\\r\\n<p>Perch&eacute; &egrave; necessario effettuare la verifica dell&rsquo;identit&agrave; reale?<\\/p>\\r\\n<p>Attraverso la verifica dell&rsquo;identit&agrave; reale degli utenti si pu&ograve; ridurre efficacemente il numero di account falsi che disturbano il mercato, la violenza online e altri comportamenti irregolari in contesti anonimi. Protegge i diritti dovuti agli utenti. Nei contesti di pagamento finanziario e trading, la verifica KYC dell&rsquo;identit&agrave; reale permette di rintracciare operazioni anomale e ridurre i rischi di furto di account e investimenti irrazionali da parte di minori.<\\/p>\\r\\n<p>&nbsp;<\\/p>\\r\\n<p>Quali sono le regole del trading futures?<\\/p>\\r\\n<p>Si partecipa al trading stimando la tendenza del prezzo (salita o discesa) della coppia di trading attuale. Alla liquidazione non si calcola l&rsquo;entit&agrave; della variazione del prezzo, ma solo il risultato (salita o discesa) per calcolare il profitto. Le percentuali di guadagno variano in base ai diversi tempi di consegna e il profitto viene mostrato con precisione nell&rsquo;interfaccia di trading.<\\/p>\",\"id\":null,\"_remove_\":null},\"new_7\":{\"locale\":\"pt\",\"title\":\"Centro de ajuda\",\"excerpt\":null,\"body\":\"<p>O que &eacute; volume de negocia&ccedil;&atilde;o?<\\/p>\\r\\n<p>De acordo com as regulamenta&ccedil;&otilde;es relacionadas &agrave; lei contra lavagem de dinheiro, cada bolsa deve controlar os pre&ccedil;os e &eacute; necess&aacute;rio completar um determinado volume de negocia&ccedil;&atilde;o antes de poder realizar saques, para evitar que os usu&aacute;rios utilizem as regras da bolsa para opera&ccedil;&otilde;es de lavagem de dinheiro. Por exemplo, para um dep&oacute;sito de 10.000 USDT, o valor das negocia&ccedil;&otilde;es deve atingir a quantidade regulamentar correspondente!<\\/p>\\r\\n<p>&nbsp;<\\/p>\\r\\n<p>O que s&atilde;o futuros?<\\/p>\\r\\n<p>O trading de futuros, abreviado como futuros, &eacute; uma forma de negocia&ccedil;&atilde;o que atravessa o tempo. As partes compradora e vendedora, atrav&eacute;s da assinatura de um contrato, concordam em entregar uma quantidade especificada do ativo &agrave; vista em um tempo, pre&ccedil;o e outras condi&ccedil;&otilde;es determinados. Normalmente, o trading de futuros concentra-se nas bolsas de futuros, onde se negocia por contratos padronizados. Os ativos negociados geralmente s&atilde;o commodities ou produtos financeiros. O pre&ccedil;o acordado para comprar ou vender o ativo &eacute; chamado pre&ccedil;o a termo.<\\/p>\\r\\n<p>&nbsp;<\\/p>\\r\\n<p>Por que o valor convertido dos ativos muda?<\\/p>\\r\\n<p>O valor convertido dos ativos calcula o valor atual de todas as criptomoedas mantidas convertido em USDT. Como o pre&ccedil;o dos ativos digitais sofre varia&ccedil;&otilde;es, esse valor muda, mesmo que a quantidade dos seus ativos digitais n&atilde;o tenha alterado.<\\/p>\\r\\n<p>&nbsp;<\\/p>\\r\\n<p>Por que &eacute; necess&aacute;rio realizar a verifica&ccedil;&atilde;o de identidade real?<\\/p>\\r\\n<p>Ao verificar a identidade real dos usu&aacute;rios, &eacute; poss&iacute;vel reduzir efetivamente contas falsas que perturbam o mercado, viol&ecirc;ncia online e outras a&ccedil;&otilde;es irregulares em contextos an&ocirc;nimos. Protege os direitos leg&iacute;timos dos usu&aacute;rios. Em cen&aacute;rios de pagamentos financeiros e negocia&ccedil;&otilde;es, a verifica&ccedil;&atilde;o KYC da identidade real permite rastrear opera&ccedil;&otilde;es anormais e reduzir riscos como roubo de conta e investimentos irracionais de menores.<\\/p>\\r\\n<p>&nbsp;<\\/p>\\r\\n<p>Quais s&atilde;o as regras do trading de futuros?<\\/p>\\r\\n<p>Participa-se do trading estimando a tend&ecirc;ncia do pre&ccedil;o (alta ou baixa) do par de negocia&ccedil;&atilde;o atual. Na liquida&ccedil;&atilde;o, n&atilde;o se calcula a amplitude da varia&ccedil;&atilde;o do pre&ccedil;o, apenas o resultado da alta ou baixa para calcular os ganhos. As porcentagens de lucro variam conforme o tempo de liquida&ccedil;&atilde;o e os ganhos s&atilde;o exibidos com precis&atilde;o na interface de negocia&ccedil;&atilde;o.<\\/p>\",\"id\":null,\"_remove_\":null},\"new_8\":{\"locale\":\"ar\",\"title\":\"\\u0645\\u0631\\u0643\\u0632 \\u0627\\u0644\\u0645\\u0633\\u0627\\u0639\\u062f\\u0629\",\"excerpt\":null,\"body\":\"<p>\\u0648\\u0641\\u0642\\u064b\\u0627 \\u0644\\u0644\\u0648\\u0627\\u0626\\u062d \\u0645\\u0643\\u0627\\u0641\\u062d\\u0629 \\u063a\\u0633\\u0644 \\u0627\\u0644\\u0623\\u0645\\u0648\\u0627\\u0644\\u060c \\u064a\\u062c\\u0628 \\u0639\\u0644\\u0649 \\u0643\\u0644 \\u0628\\u0648\\u0631\\u0635\\u0629 \\u0627\\u0644\\u062a\\u062d\\u0643\\u0645 \\u0641\\u064a \\u0627\\u0644\\u0623\\u0633\\u0639\\u0627\\u0631\\u060c \\u0648\\u064a\\u062c\\u0628 \\u0625\\u062a\\u0645\\u0627\\u0645 \\u062d\\u062c\\u0645 \\u062a\\u062f\\u0627\\u0648\\u0644 \\u0645\\u0639\\u064a\\u0646 \\u0642\\u0628\\u0644 \\u0633\\u062d\\u0628 \\u0627\\u0644\\u0639\\u0645\\u0644\\u0627\\u062a\\u060c \\u0648\\u0630\\u0644\\u0643 \\u0644\\u0645\\u0646\\u0639 \\u0627\\u0644\\u0645\\u0633\\u062a\\u062e\\u062f\\u0645\\u064a\\u0646 \\u0645\\u0646 \\u0627\\u0633\\u062a\\u063a\\u0644\\u0627\\u0644 \\u0642\\u0648\\u0627\\u0639\\u062f \\u0627\\u0644\\u0628\\u0648\\u0631\\u0635\\u0629 \\u0644\\u063a\\u0633\\u0644 \\u0627\\u0644\\u0623\\u0645\\u0648\\u0627\\u0644\\u060c \\u0639\\u0644\\u0649 \\u0633\\u0628\\u064a\\u0644 \\u0627\\u0644\\u0645\\u062b\\u0627\\u0644\\u060c \\u0639\\u0646\\u062f \\u0625\\u064a\\u062f\\u0627\\u0639 10000 USDT\\u060c \\u064a\\u062c\\u0628 \\u0623\\u0646 \\u064a\\u0635\\u0644 \\u062d\\u062c\\u0645 \\u0627\\u0644\\u062a\\u062f\\u0627\\u0648\\u0644 \\u0625\\u0644\\u0649 \\u0627\\u0644\\u0643\\u0645\\u064a\\u0629 \\u0627\\u0644\\u0645\\u062d\\u062f\\u062f\\u0629 \\u0641\\u064a \\u0627\\u0644\\u0644\\u0648\\u0627\\u0626\\u062d \\u0630\\u0627\\u062a \\u0627\\u0644\\u0635\\u0644\\u0629!<\\/p>\\r\\n<p>&nbsp;<\\/p>\\r\\n<p>\\u0645\\u0627 \\u0647\\u0648 \\u0627\\u0644\\u0639\\u0642\\u062f \\u0627\\u0644\\u0622\\u062c\\u0644\\u061f<\\/p>\\r\\n<p>\\u0627\\u0644\\u0639\\u0642\\u062f \\u0627\\u0644\\u0622\\u062c\\u0644\\u060c \\u0648\\u064a\\u064f\\u062e\\u062a\\u0635\\u0631 \\u0639\\u0627\\u062f\\u0629 \\u0628\\u0627\\u0644\\u0639\\u0642\\u0648\\u062f \\u0627\\u0644\\u0622\\u062c\\u0644\\u0629\\u060c \\u0647\\u0648 \\u0646\\u0648\\u0639 \\u0645\\u0646 \\u0627\\u0644\\u062a\\u062f\\u0627\\u0648\\u0644 \\u0639\\u0628\\u0631 \\u0627\\u0644\\u0632\\u0645\\u0646\\u060c \\u062d\\u064a\\u062b \\u064a\\u062a\\u0641\\u0642 \\u0627\\u0644\\u0637\\u0631\\u0641\\u0627\\u0646 \\u