INSERT INTO `admin_operation_log` VALUES (2969, 1, 'admin/article/173', 'PUT', '18.162.168.211', '{\"category_id\":\"8\",\"cover\":null,\"_file_\":null,\"status\":\"1\",\"order\":\"1\",\"is_recommend\":\"0\",\"created_at\":\"2025-07-30 15:37:18\",\"translations\":{\"488\":{\"locale\":\"ar\",\"title\":\"\\u0645\\u0631\\u0643\\u0632 \\u0627\\u0644\\u0645\\u0633\\u0627\\u0639\\u062f\\u0629\",\"excerpt\":null,\"body\":\"<p>\\u0648\\u0641\\u0642\\u064b\\u0627 \\u0644\\u0644\\u0648\\u0627\\u0626\\u062d \\u0645\\u0643\\u0627\\u0641\\u062d\\u0629 \\u063a\\u0633\\u0644 \\u0627\\u0644\\u0623\\u0645\\u0648\\u0627\\u0644\\u060c \\u064a\\u062c\\u0628 \\u0639\\u0644\\u0649 \\u0643\\u0644 \\u0628\\u0648\\u0631\\u0635\\u0629 \\u0627\\u0644\\u062a\\u062d\\u0643\\u0645 \\u0641\\u064a \\u0627\\u0644\\u0623\\u0633\\u0639\\u0627\\u0631\\u060c \\u0648\\u064a\\u062c\\u0628 \\u0625\\u062a\\u0645\\u0627\\u0645 \\u062d\\u062c\\u0645 \\u062a\\u062f\\u0627\\u0648\\u0644 \\u0645\\u0639\\u064a\\u0646 \\u0642\\u0628\\u0644 \\u0633\\u062d\\u0628 \\u0627\\u0644\\u0639\\u0645\\u0644\\u0627\\u062a\\u060c \\u0648\\u0630\\u0644\\u0643 \\u0644\\u0645\\u0646\\u0639 \\u0627\\u0644\\u0645\\u0633\\u062a\\u062e\\u062f\\u0645\\u064a\\u0646 \\u0645\\u0646 \\u0627\\u0633\\u062a\\u063a\\u0644\\u0627\\u0644 \\u0642\\u0648\\u0627\\u0639\\u062f \\u0627\\u0644\\u0628\\u0648\\u0631\\u0635\\u0629 \\u0644\\u063a\\u0633\\u0644 \\u0627\\u0644\\u0623\\u0645\\u0648\\u0627\\u0644\\u060c \\u0639\\u0644\\u0649 \\u0633\\u0628\\u064a\\u0644 \\u0627\\u0644\\u0645\\u062b\\u0627\\u0644\\u060c \\u0639\\u0646\\u062f \\u0625\\u064a\\u062f\\u0627\\u0639 10000 USDT\\u060c \\u064a\\u062c\\u0628 \\u0623\\u0646 \\u064a\\u0635\\u0644 \\u062d\\u062c\\u0645 \\u0627\\u0644\\u062a\\u062f\\u0627\\u0648\\u0644 \\u0625\\u0644\\u0649 \\u0627\\u0644\\u0643\\u0645\\u064a\\u0629 \\u0627\\u0644\\u0645\\u062d\\u062f\\u062f\\u0629 \\u0641\\u064a \\u0627\\u0644\\u0644\\u0648\\u0627\\u0626\\u062d \\u0630\\u0627\\u062a \\u0627\\u0644\\u0635\\u0644\\u0629!<