INSERT INTO `admin_operation_log` VALUES (3358, 1, 'admin/dcat-api/tinymce/upload', 'POST', '38.92.27.74', '{\"_token\":\"GAvyFfalHkflR59lOApQmnFXj1Dn8fTBPi5y0VBm\",\"dir\":\"tinymce\\/images\"}', '2025-08-25 18:00:39', '2025-08-25 18:00:39');
INSERT INTO `admin_operation_log` VALUES (3359, 1, 'admin/article', 'POST', '38.92.27.74', '{\"category_id\":\"4\",\"cover\":null,\"_file_\":null,\"status\":\"1\",\"order\":\"1\",\"is_recommend\":\"1\",\"translations\":{\"new_1\":{\"locale\":\"en\",\"title\":\"WebX 2025 Roundtable: Stablecoin Regulation and Applications in the U.S. and Japan\",\"excerpt\":null,\"body\":\"<p>&nbsp;<\\/p>\\r\\n<p data-start=\\\"228\\\" data-end=\\\"631\\\">The WebX 2025 conference was held in Tokyo, Japan. Participants in a roundtable discussion on stablecoin regulation and applications included Heath Tarbert, former Chairman of the U.S. CFTC and current Chief Legal Officer and Head of Corporate Affairs at Circle, as well as Satsuki Katayama, a member of Japan&rsquo;s House of Councillors from the Liberal Democratic Party and Chair of the Budget Committee.<\\/p>\\r\\n<p data-start=\\\"633\\\" data-end=\\\"1349\\\"><img src=\\\"https:\\/\\/api.gemini-jp.cc\\/storage\\/tinymce\\/images\\/7269932fdd7f8ba760b50d8a119a60c068ac96b7ecbab.png\\\" alt=\\\"\\\" width=\\\"1038\\\" height=\\\"730\\\" \\/>During the discussion, Katayama expressed a cautious stance toward central bank digital currencies (CBDCs), while emphasizing her view that stablecoins are a key entry point for the broader adoption of the crypto industry. She noted that there are widespread international concerns about CBDCs, particularly around privacy and surveillance risks. Domestically, questions have also been raised about whether CBDCs can truly maintain decentralization. The Japanese House of Representatives even once proposed banning related explorations. At present, CBDC development in Japan remains in the research phase and has not entered commercial rollout. Instead, Japan is leaning toward prioritizing stablecoin development.<\\/p>\\r\\n<p data-start=\\\"1351\\\" data-end=\\\"2225\\\">Katayama further highlighted that Japan&rsquo;s younger generation makes up the main cohort of crypto asset holders. She explained that Japan is currently working to reclassify cryptocurrencies under the Financial Instruments and Exchange Act, shifting away from treatment as &ldquo;miscellaneous income.&rdquo; This would reduce the maximum tax rate from 55% to 20%, bringing it closer in line with the U.S. Such a move requires multiparty negotiations, with the goal of finalizing a framework by the end of the year. If the tax reform takes effect, stablecoin adoption in everyday transactions could accelerate, while CBDCs are unlikely to be a near-term priority. She also disclosed that Japan has conducted joint CBDC research with institutions such as the European Central Bank, but progress has been slow, and future directions will depend on market demand and technological maturity.<\\/p>\\r\\n<p data-start=\\\"2227\\\" data-end=\\\"3001\\\">Heath Tarbert pointed out that the U.S. regulatory environment for crypto has undergone a major shift, moving from a highly restrictive approach toward one of greater support. He emphasized the significance of the passage of the &ldquo;Genius Act,&rdquo; which, for the first time, effectively equates stablecoins with cash. This provides long-awaited regulatory clarity and establishes a foundation requiring stablecoins to be backed 1:1 by high-quality liquid assets. However, Tarbert noted that much work remains to be done in U.S. digital asset regulation, such as defining classifications for other digital assets, improving custody rules, and creating market structure legislation for exchanges. Moreover, the implementation details of the &ldquo;Genius Act&rdquo; have yet to be finalized.<\\/p>\\r\\n<p data-start=\\\"3003\\\" data-end=\\\"3566\\\">Speaking about stablecoins, Tarbert emphasized their broad range of use cases. Beyond facilitating efficient entry and exit within crypto markets, they can serve as a reliable U.S. dollar savings tool for citizens of non-G20 countries, help reduce remittance costs that often reach 6%&ndash;7%, and streamline corporate cross-border transactions by enabling instant settlement and avoiding foreign exchange fees. He highlighted how Circle&rsquo;s payment network, powered by USDC, connects global financial institutions and provides a model for efficient currency exchange.<\\/p>\\r\\n<p data-start=\\\"3568\\\" data-end=\\\"3969\\\">On CBDCs, Tarbert explained that the U.S. is taking a cautious stance. Many in the U.S. are concerned about the privacy and surveillance implications of CBDCs. He further noted that the &ldquo;Genius Act&rdquo; effectively prohibits the Federal Reserve from launching a CBDC in the near term. Instead, he suggested that the future of the U.S. dollar on blockchain is more likely to take the form of stablecoins.<\\/p>\\r\\n<p>&nbsp;<\\/p>\",\"id\":null,\"_remove_\":\"0\"}},\"_token\":\"GAvyFfalHkflR59lOApQmnFXj1Dn8fTBPi5y0VBm\",\"_previous_\":\"https:\\/\\/api.gemini-jp.cc\\/admin\\/article\"}', '2025-08-25 18:03:35', '2025-08-25 18:03:35');
