INSERT INTO `article_translations` VALUES (233, 108, 'zh-CN', '关于USDT合约7月14日14:30停服升级的公告', '<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">尊敬的<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>用户：</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">您好！</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">平台将于香港时间<strong style=\"box-sizing: border-box;\">7月14日14:30针对USDT合约进行停服升级，预计停服2小时，期间您将无法进行</strong><strong style=\"box-sizing: border-box;\">开平仓</strong><strong style=\"box-sizing: border-box;\">、委托、止盈止损等操作</strong>，请提前调整投资策略。混合合约、币本位合约、季度合约、币币交易等其他业务线不受影响，升级完成后我们将第一时间进行通知。</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\"><span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>交易所将继续秉承用户第一、安全、实力、信任的运营理念，为全球投资者打造一个安全、透明、可信赖的数字资产服务环境。</span></p>', NULL);
INSERT INTO `article_translations` VALUES (234, 109, 'zh-CN', '关于5月8日调整BSV合约指数价格成分的公告', '<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">尊敬的<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex </span>用户：</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">您好！</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">鉴于<strong style=\"box-sizing: border-box;\">OKEx</strong>将于<strong style=\"box-sizing: border-box;\">2020</strong>年<strong style=\"box-sizing: border-box;\">5</strong>月<strong style=\"box-sizing: border-box;\">8</strong>日<strong style=\"box-sizing: border-box;\">16:30（HKT）</strong>对现货系统进行技术升级，受此影响，平台BSV永续合约（BSVUSDT、BSVMIX）指数价格将于<strong style=\"box-sizing: border-box;\">香港时间5月8日16:30前</strong>由<strong style=\"box-sizing: border-box;\">&ldquo;火币50%、OKEx 50%&rdquo;</strong>临时调整为<strong style=\"box-sizing: border-box;\">&ldquo;火币100%&rdquo;</strong>。待<strong style=\"box-sizing: border-box;\">OKEx</strong>系统升级完毕后，将第一时间恢复原有成分。</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\"><span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex </span>平台将继续秉承用户第一、安全、实力、信任的运营理念，为全球投资者打造一个安全、透明、可信赖的数字资产服务环境。</span></p>', NULL);
INSERT INTO `article_translations` VALUES (235, 110, 'zh-CN', '关于场内极端行情与指数机制的再次说明', '<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #ecf0f1;\">尊<span style=\"color: #000000;\">敬的<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>用户：</span></span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">今日早间接用户反馈，永续合约场内交易市场出现上下影线即极端行情，并表示担心自己的仓位安全。就此，我们希望您不必担心，我们在亚洲地区首推的指数机制可以避免您的仓位受到场内极端行情的影响。<strong style=\"box-sizing: border-box;\">就场内极端行情与指数机制，我们再次做以下说明</strong>：</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\"><strong style=\"box-sizing: border-box;\">1</strong><strong style=\"box-sizing: border-box;\">、关于场内极端行情</strong></span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">极端行情在整个数字资产市场时有发生，是市场交投的反映。各种市场以区域、平台做划分的话，不计其数。早间用户所反映的极端行情其实就是存在于7平台场内交投，<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Hokiecoin</span>场内交易采用撮合机制，无论市价还是限价都是以当时市场上最优的价格成交，<strong style=\"box-sizing: border-box;\">出现极端行情，往往与场内买卖双方的定价、场内交投活跃度等息息相关。</strong></span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\"><strong style=\"box-sizing: border-box;\">2</strong><strong style=\"box-sizing: border-box;\">、关于指数机制&nbsp;</strong></span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">场内出现极端行情后，部分用户第一时间是担心自己的仓位，但在<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Hokiecoin</span>完全不必，<strong style=\"box-sizing: border-box;\">在指数机制的作用下，与您的仓位风险直接关联的并非场内价格的变化，而是锚定全球现货市场的</strong>&nbsp;<strong style=\"box-sizing: border-box;\">指数价格，即使场内出现极端行情，即最新成交价出现较大偏离，也不会给所持仓位带来风险。这是与传统竞品合约的核心差别。</strong></span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">指数机制系<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Hokiecoin</span>在亚洲地区首推，关键指标就是指数价格。<strong style=\"box-sizing: border-box;\">指数价格用来代表</strong><strong style=\"box-sizing: border-box;\">BTC</strong><strong style=\"box-sizing: border-box;\">、</strong><strong style=\"box-sizing: border-box;\">ETH</strong><strong style=\"box-sizing: border-box;\">等在全球现货市场上的合理价格</strong>，具有一定的指导意义，在判定仓位风险的同时，也作为永续合约计算浮动盈亏的依据。当前<strong style=\"box-sizing: border-box;\"><span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; font-weight: normal; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Hokiecoin</span>永续合约（</strong><strong style=\"box-sizing: border-box;\">USDT</strong><strong style=\"box-sizing: border-box;\">合约、币本位合约、混合合约）的指数价格取币安、火币现货价格的加权平均数。</strong></span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\"><strong style=\"box-sizing: border-box;\">3、调整K线</strong></span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">部分用户反馈K线看盘不方便，基于该K线是用户爆仓导致，且<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\"> Hokiecoin</span>采取指数机制判定强平，没有用户因此而爆仓，基于以上几点我们将采纳用户建议，对该跟K线进行调整以方便用户看盘。</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">以上，希望可以消除部分用户的疑虑，并加深您对<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Hokiecoin</span>永续合约的了解。永续合约是平台立身之本，从上线起就是为了给投资者提供更科学、透明、先进的数字资产玩法，我们会继续坚持用户第一、安全、实力、信任的运营理念，为您提供更一流的合约服务。</span></p>', NULL);
INSERT INTO `article_translations` VALUES (236, 111, 'zh-CN', '关于季度合约、USDT合约提前升级完毕的公告', '<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">尊敬的<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex </span>用户：</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">您好！</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\"><strong style=\"box-sizing: border-box;\">季度合约、USDT合约现已提前完成升级工作，并恢复服务</strong>，您可正常进行开平仓、计划委托、转账、止盈止损等系列操作。至此，四大合约停服升级工作已全面完成。暂停期间为您带来不便，还请谅解！</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\"><span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Hokiecoin</span>交易所将继续秉承用户第一、安全、实力、信任的运营理念，为全球投资者打造一个安全、透明、可信赖的数字资产服务环境。</span></p>', NULL);
INSERT INTO `article_translations` VALUES (237, 112, 'zh-CN', '关于2020春节假期照常运营的公告', '<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">尊敬的<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>用户：</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">新年快乐！</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">我们特别提醒您，平台于2020春节假期仍将保持正常运营：</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\"><strong style=\"box-sizing: border-box;\">1）</strong><strong style=\"box-sizing: border-box;\">USDT合约、混合合约、币本位合约</strong><strong style=\"box-sizing: border-box;\">、</strong><strong style=\"box-sizing: border-box;\">季度合约、</strong><strong style=\"box-sizing: border-box;\">抵押贷款、法币OTC、币币交易等各大业务线保持正常服务。</strong><strong style=\"box-sizing: border-box;\"><br style=\"box-sizing: border-box;\" /></strong><strong style=\"box-sizing: border-box;\">2）官网在线客服仍将为您提供24H专线服务，并支持中、英、日、韩、俄五国语言。</strong><strong style=\"box-sizing: border-box;\"><br style=\"box-sizing: border-box;\" /></strong><strong style=\"box-sizing: border-box;\">3）针对晚间或个别时间提现审核会稍慢，您可及时联系官网在线客服了解情况。</strong><strong style=\"box-sizing: border-box;\"><br style=\"box-sizing: border-box;\" /></strong><strong style=\"box-sizing: border-box;\">4）社群仍将继续为您提供</strong><strong style=\"box-sizing: border-box;\">动态提醒</strong><strong style=\"box-sizing: border-box;\">、业务咨询等服务。</strong></span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">以上如发现异常，请及时联系官网在线客服，我们将全力保障您在春节假期继续拥有安全、透明、一流的交易体验。</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\"><span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>交易所将继续秉承用户第一、安全、实力、信任的运营理念，为全球投资者打造一个安全、透明、可信赖的数字资产服务环境。</span></p>', NULL);
INSERT INTO `article_translations` VALUES (238, 113, 'zh-CN', '关于USDT合约扩容期间赔付工作全部处理完毕的公告', '<p style=\"box-sizing: border-box; color: #333333;\"><span style=\"color: #000000;\">尊敬的<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex </span>用户：</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333;\"><span style=\"color: #000000;\">您好！</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333;\"><span style=\"color: #000000;\">USDT合约扩容期间赔付工作已全部处理完毕，异常期间内（香港时间1月3日15:00~21:05）全部爆仓用户以及期间亏损用户已按相应规则如约赔付。以上所有赔付已全数发放完毕，如有疑问请咨询在线客服。</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333;\"><span style=\"color: #000000;\">因此为您带来的不便，我们再次致歉！&nbsp;</span></p>', NULL);
INSERT INTO `article_translations` VALUES (239, 114, 'zh-CN', '关于USDT合约停服扩容延长升级的公告', '<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">尊敬的<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex </span>用户：</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">&nbsp;您好！</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">非常抱歉，由于升级期间遇到了不可预知性问题，预计我们仍需1-2小时处理USDT合约扩容升级。给您带来不便，深表歉意，还请耐心等待。针对升级期间爆仓账户，将在升级结束后进行统计赔偿事宜。请勿过于担心，再次致歉，币本位合约、混合合约、季度合约不受影响。</span></p>', NULL);
INSERT INTO `article_translations` VALUES (240, 115, 'zh-CN', '领跑四年 继续强大 | 四周年数据报告', '<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">尊敬的<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>交易所用户：</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">您好！</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">今日恰逢<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>四周年，在平稳运行的1460天里，平台基础不断夯实、实力不断提升、国际化效益逐步凸显。四年后的今天，<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Hokiecoin</span>全站业务累计交易额已突破6000亿美金，注册用户突破300万，月度利润突破1亿。感谢您一路以来的信赖与支持。此刻，邀您共同见证<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>四周年的丰硕成果。</span></p>', NULL);
INSERT INTO `article_translations` VALUES (241, 116, 'zh-CN', 'USDT合约 |  关于BTCUSDT、XRPUSDT升级完成的公告', '<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">尊敬的<span style=\"caret-color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>用户：</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">您好！</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">USDT合约交易区BTC、XRP两大单品（BTCUSDT、XRPUSDT）现已升级完毕并恢复服务，您可正常进行开平仓、委托、止盈止损等操作。暂停期间，为您带来不便，还请谅解！</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\"><span style=\"caret-color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex </span>交易所将继续秉承用户第一、安全、实力、信任的运营理念，为全球投资者打造一个安全、透明、可信赖的数字资产服务环境。</span></p>', NULL);
INSERT INTO `article_translations` VALUES (242, 117, 'zh-CN', '关于合约交易区施行全网最低手续费率0.02%（万2）的公告', '<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">尊敬的<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex </span>用户：&nbsp;</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">您好！</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">合约交易区（数字合约、USDT合约、交割合约）将于香港时间6月17日18：00执行新的手续费率，具体将由原&ldquo;taker、maker均为0.015%（万1.5）&rdquo;调整为&ldquo;taker、maker均为0.02%（万2）&rdquo;。此次微调并不影响合约交易区的其他服务，依然不会收取持仓费、利息等其他任何费用。</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\"><strong style=\"box-sizing: border-box;\">补充说明：即刻至6月1</strong><strong style=\"box-sizing: border-box;\">7</strong><strong style=\"box-sizing: border-box;\">日1</strong><strong style=\"box-sizing: border-box;\">8</strong><strong style=\"box-sizing: border-box;\">：0</strong><strong style=\"box-sizing: border-box;\">0</strong><strong style=\"box-sizing: border-box;\">，合约交易仍为特惠期，taker、maker均为0</strong><strong style=\"box-sizing: border-box;\">.01</strong><strong style=\"box-sizing: border-box;\">%（万1）。</strong></span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\"><span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex </span>平台将继续秉承用户第一、安全、实力、信任的运营理念，为全球投资者打造一个安全、透明、可信赖的数字资产服务环境。</span></p>', NULL);
INSERT INTO `article_translations` VALUES (243, 118, 'zh-CN', '520活动 | 合约交易区开启手续费特惠', '<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">尊敬的<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex </span>用户：</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">您好！</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">继为期一周的合约Maker免手续费活动后，再遇520告白季，我们向一直支持、信赖和鼓励<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">PCICOIN</span>的朋友表示诚挚的感谢，为表心意，我们将推出本月第二波减免手续费活动，开启为期12天的手续费率万1的特惠，相关明细如下：</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">活动时间：香港时间5月20日18:00至6月1日18:00</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">活动范围：USDT合约、数字合约、交割合约</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">涉及币种：所有合约币种（BTC、EOS、ETH、BCH、LTC、XRP、ETC、DASH、BSV、TRX、BNB、HT）</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">活动规则：活动期间，三大合约交易中Maker、Taker手续费率均由原0.015%下调至0.01%。</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">邀您体验！投资顺意！</span></p>', NULL);
