INSERT INTO `article_translations` VALUES (245, 120, 'zh-CN', '关于恢复SPA充值并上线杠杆交易的公告', '<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">尊敬的<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>用户：</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\"><span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex </span>已恢复SPA充值，杠杆交易区将于14:00 (UTC+8) 上线SPA/USDT交易对，支持4倍杠杆，并且支持SPA融币交易，买入（做多）的24小时利息为0.1%，卖出（做空）的24小时利息为0.15%。</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">此前，<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex </span>币币交易区已经上线SPA/USDT交易对，欢迎交易体验。</span></p>', NULL);
