);
INSERT INTO `article_translations` VALUES (247, 122, 'zh-CN', '关于DOT拆分时间安排的提示公告', '<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">尊敬的<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>用户：</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">Polkadot (DOT) 的面额拆分将在区块号为1,248,328时进行（最早预计时间：2020年8月22日00:40 (UTC+8)），<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>的DOT拆分时间安排如下：</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt pap-hanging-indent-1.6em\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">1、2020年8月21日 21:00（UTC+8），暂停DOT的映射、充值和提币功能。</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt pap-hanging-indent-1.6em\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">2、2020年8月21日 21:30（UTC+8），暂停<span class=\"wysiwyg-color-red\" style=\"box-sizing: border-box;\"><strong style=\"box-sizing: border-box;\">DOT币币交易</strong></span>，已在DOT/USDT、DOT/BTC币币交易对挂单的用户，请及时撤单，如未撤单，系统将自动为您撤单，并将相关资产退回至您的币币账户。</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt pap-hanging-indent-1.6em\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">3、2020年8月21日 21:30（UTC+8），暂停<span class=\"wysiwyg-color-red\" style=\"box-sizing: border-box;\"><strong style=\"box-sizing: border-box;\">波卡生态组合交易</strong></span>，已进行持仓的用户，请及时平仓，如未平仓，将会损失波卡生态组合中DOT成分的资产。</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt pap-hanging-indent-1.6em\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">4、执行拆分时（最早预计时间：2020年8月22日00:40 (UTC+8)），暂停<span class=\"wysiwyg-color-red\" style=\"box-sizing: border-box;\"><strong style=\"box-sizing: border-box;\">DOT3L和DOT3S杠杆ETF交易</strong></span>，已进行挂单的用户，请及时撤单，如未撤单，系统将自动为您撤单，并将相关资产退回至您的币币账户。</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt pap-hanging-indent-1.6em\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">5、区块高度1,248,328时（最早预计时间：2020年8月22日00:40 (UTC+8)），<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex </span>将基于DOT智能合约升级进度，自动完成对DOT代币1:100的面额拆分，拆分后所有持币用户的持币量变为原持币量的100倍，拆分后价格约为拆分前价格的1/100，但不会影响用户DOT持仓的总价值。</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt pap-hanging-indent-1.6em\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">6、ETF、币币交易、指数交易、映射、充币和提币业务具体恢复时间将以公告形式另行通知，暂停期间给您带来的不便，敬请谅解！</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">&nbsp;</p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\"><strong style=\"box-sizing: border-box;\">其他须知：</strong></span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt pap-hanging-indent-1.6em\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">1、暂停交易期间，因无法通过行情端获取DOT实时价格，DOT估值可能不准确，您的实际资产不受影响。DOT交易恢复后将正常展示，请耐心等待。</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt pap-hanging-indent-1.6em\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">2、具体拆分时间可能会根据波卡 (Polkadot) 项目发布时间进行同步调整，交易、充值和提现功能具体时间如有调整，将第一时间以公告形式另行通知，给您带来的不便，敬请谅解。</span></p>', NULL);
INSERT INTO `article_translations` VALUES (248, 123, 'zh-CN', '关于上线Web端部分杠杆交易对市价交易功能的公告', '<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">尊敬的<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex </span>用户：</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">为了更好的提升用户的交易体验，<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex </span>已在Web端上线部分杠杆交易对的市价交易功能。具体详情如下：</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">1、支持市价交易功能的杠杆交易对：BTC/USDT、ETH/USDT、EOS/USDT、BCH/USDT、LTC/USDT、ONT/USDT、TRX/USDT、XRP/USDT、BSV/USDT、ETC/USDT、DOGE/USDT、ADA/USDT、DASH/USDT、NEO/USDT、QTUM/USDT、VET/USDT、XLM/USDT、XZC/USDT、BTM/USDT、XTZ/USDT、ZEC/USDT、ZIL/USDT、ELF/USDT。</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">2、用户在Web端杠杆交易区点击&ldquo;市价委托&rdquo;，则会以市场最优价买入或卖出。</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">3、市价委托是指用户以当前市场最优价格立即执行买入或者卖出，达到快速成交的目的。需要注意的是：若单笔市价总额过大，则会存在未成交部分撤销的情况。同时，市价委托会不计成本的在市场上进行扫单，您需要承担一定的风险，请您谨慎下单并注意风险。</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">&nbsp;</p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">欢迎广大用户交易体验，<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex </span>将不断努力为您提供更优秀的产品与服务。</span></p>', NULL);
INSERT INTO `article_translations` VALUES (249, 124, 'zh-CN', '关于开启2KEY、BART、BOT、BUIDL、DFS、GEN、NMR、TAU、TRADE、XRT充值上线活动的公告', '<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">尊敬的<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex </span>用户：</span></p>\r\n<p><span style=\"color: #000000;\">经社区用户推荐，为了方便更多的社区成员交易支持的项目，<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Hokiecoin</span>现推出新一期充值投票上线专场活动。本期充值参与充值上线的项目为：2KEY（2KEY）、BarterTrade（BART）、Bounce（BOT）、DFOhub（BUIDL）、DeFis Network（DFS）、DAOstack （GEN）、Numerai （NMR）、Lamden（TAU）、UniTrade（TRADE）和Robonomics Token (XRT)。</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\"><strong style=\"box-sizing: border-box;\">活动规则：</strong></span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">考核期间，用户充值2KEY、BART、BOT、BUIDL、DFS、GEN、NMR、TAU、TRADE和XRT任意考核币种到MXC抹茶，充值人数排名第一或充值人数不低于300人的项目，<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex </span>将会在完成技术对接后第一时间上线该项目。</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span class=\"wysiwyg-color-red\" style=\"box-sizing: border-box; color: #000000;\">考核期内，如项目达到充值人数要求，将第一时间上线并开通交易。</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">&nbsp;</p>', NULL);
INSERT INTO `article_translations` VALUES (250, 125, 'zh-CN', '关于上线LBA杠杆交易对的公告', '<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">尊敬的<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>用户：</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\"><span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>杠杆交易区将于<span class=\"wysiwyg-color-black\" style=\"box-sizing: border-box;\">16:30</span>(UTC+8)上线LBA/USDT交易对，支持3倍杠杆，并且支持LBA融币交易，买入（做多）的24小时利息为0.1%，卖出（做空）的24小时利息为0.15%，欢迎用户前来体验。</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">&nbsp;</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\"><strong style=\"box-sizing: border-box;\">【风险提示】&nbsp;</strong></span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">数字资产是一种高风险的投资方式，请投资者谨慎购买，并注意投资风险。<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>不对项目或投资行为承担担保、赔偿等责任。</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">&nbsp;&nbsp;</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">交易数字资产，上</span><span style=\"font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span></p>', NULL);
INSERT INTO `article_translations` VALUES (251, 126, 'zh-CN', '关于开通机构账户权益的公告', '<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">尊敬的<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Hokiecoin</span>用户：</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">&nbsp;为了更好地服务广大机构用户，<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Hokiecoin</span>现为机构用户提供一站式专业服务，具体如下：</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">&nbsp;</p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">1、机构用户可享受专属的出入金通道，保障资金安全、合规、快捷；</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">2、享受特权手续费折扣优惠；</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">3、绿色充提币专属通道、专属提币额度提升；</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">4、机构用户蓝V特权标识；</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">5、机构专属客服一对一服务；</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">6、<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Hokiecoin</span>研究院行业报告；</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">7、尊享<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Hokiecoin</span>线下活动优先邀请特权和定制私享会。</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">符合一定条件的机构用户，还有机会享受<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Hokiecoin</span>提供的其他专属福利权益。</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">&nbsp;</p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span class=\"ql-author-12567341\" style=\"box-sizing: border-box; color: #000000;\">交易数字资产，上<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Hokiecoin</span>！</span></p>', NULL);
INSERT INTO `article_translations` VALUES (252, 127, 'zh-CN', '杠杆ETF新增BAND3L、BAND3S、RLC3L和RLC3S的公告', '<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">尊敬的<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>用户：</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">为满足广大用户的交易需求，<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex </span>将于17:00(UTC+8)新增标的BAND3L、BAND3S、RLC3L和RLC3S。具体如下：</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">BAND3L--BAND三倍做多、BAND3S-BAND三倍做空，日管理费（每倍）为0.2%。</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">RLC3L--RLC三倍做多、RLC3S-RLC三倍做空，日管理费（每倍）为0.2%。</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">欢迎用户交易体验。</span></p>', NULL);
INSERT INTO `article_translations` VALUES (253, 128, 'zh-CN', '关于“合约新人三重礼”活动奖励发放公告', '<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span class=\"ql-font-microsoftyahei ql-author-12567341\" style=\"box-sizing: border-box; color: #000000; background-color: #ecf0f1;\">尊敬的<span style=\"caret-color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ecf0f1;\">Hokiecoin</span>用户：</span></p>\r\n<p class=\"ql-long-12567341 ql-align-left\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span class=\"ql-author-12567341\" style=\"box-sizing: border-box; color: #000000; background-color: #ecf0f1;\"><span style=\"caret-color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ecf0f1;\">Hokiecoin</span>&ldquo;合约新人三重礼&ldquo;活动已圆满结束，充值交易满足相应要求即可获得MX空投、周边礼品、复活卡三重礼包。</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">&nbsp;</p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000; background-color: #ecf0f1;\"><span class=\"ql-author-12567341\" style=\"box-sizing: border-box;\">&nbsp;</span><strong class=\"ql-author-12567341\" style=\"box-sizing: border-box;\">【奖励领取】</strong></span></p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span class=\"ql-author-12567341\" style=\"box-sizing: border-box; color: #000000; background-color: #ecf0f1;\">1、奖励领取流程：添加客服微信-向客服提供<span style=\"caret-color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ecf0f1;\">Hokiecoin</span>邮箱-确认获奖情况-进行KYC验证-等待奖励发放。</span></p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000; background-color: #ecf0f1;\"><span class=\"ql-author-12567341\" style=\"box-sizing: border-box;\">2</span>、因活动参与用户较多，用户获奖信息不一一公示。<span class=\"ql-author-12567341\" style=\"box-sizing: border-box;\">获奖用户需添加工作人员微信方可领取奖励，截至8月8日24:00仍未取得联系的，将视为自动放弃领奖资格。</span></span></p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span class=\"ql-author-12567341\" style=\"box-sizing: border-box; color: #000000; background-color: #ecf0f1;\">3、活动奖励将在活动结束后10日内统一发放，空投奖励请在【充提记录】-【其他记录】中查看。</span></p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span class=\"ql-author-12567341\" style=\"box-sizing: border-box; color: #000000; background-color: #ecf0f1;\">4、实物奖励由于物流原因发放时间较长，请耐心等待。</span></p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span class=\"ql-author-12567341\" style=\"box-sizing: border-box; color: #000000; background-color: #ecf0f1;\">5、部分用户由于划转时间、充值金额等不满足活动要求，未能领取奖励。</span></p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span class=\"ql-author-12567341\" style=\"box-sizing: border-box;\">&nbsp;</span></p>', NULL);
INSERT INTO `article_translations` VALUES (254, 129, 'zh-CN', '关于第12期合约交易日“王者晋级赛”活动的公告', '<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span class=\"ql-author-12567341 ql-size-10\" style=\"box-sizing: border-box; color: #000000;\">尊敬的<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>用户：</span></p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\"><span class=\"ql-author-12567341 ql-size-10\" style=\"box-sizing: border-box;\"><span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>已</span><span class=\"ql-author-13162025 ql-size-10\" style=\"box-sizing: border-box;\">陆续</span><span class=\"ql-author-12567341 ql-size-10\" style=\"box-sizing: border-box;\">对EOSUSDT、LTCUSDT、BCHUSDT、BSVUSDT永续合约交易对的</span><span class=\"ql-author-13162025 ql-size-10\" style=\"box-sizing: border-box;\">进行</span><span class=\"ql-author-12567341 ql-size-10\" style=\"box-sizing: border-box;\">优化，优化后交易深度、盘口价差、撮合效率均得到大幅提升</span><span class=\"ql-author-13162025 ql-size-10\" style=\"box-sizing: border-box;\">。为鼓励用户交易体验，现</span><span class=\"ql-author-12567341 ql-size-10\" style=\"box-sizing: border-box;\">开启</span><span class=\"ql-author-13162025 ql-size-10\" style=\"box-sizing: border-box;\">此次</span><span class=\"ql-author-12567341 ql-size-10\" style=\"box-sizing: border-box;\">“</span><span class=\"ql-author-13162025 ql-size-10\" style=\"box-sizing: border-box;\">王者</span><span class=\"ql-author-12567341 ql-size-10\" style=\"box-sizing: border-box;\">晋级赛”活动</span><span class=\"ql-author-13162025 ql-size-10\" style=\"box-sizing: border-box;\">，活动分为晋级赛与最强王者赛两轮比赛，总奖池8000MX、2000USDT等你瓜分。</span></span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"> </p>', NULL);
INSERT INTO `article_translations` VALUES (255, 130, 'zh-CN', '关于上线KAI/USDT杠杆交易对的公告', '<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">尊敬的<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>用户：</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\"><span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex </span>杠杆交易区现已上线KAI/USDT交易对，支持4倍杠杆，并且支持KAI融币交易，买入（做多）的24小时利息为0.1%，卖出（做空）的24小时利息为0.2%。</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">此前，<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>币币交易区已经上线KAI/USDT和KAI/ETH交易对，欢迎交易体验。</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"> </p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\"><strong style=\"box-sizing: border-box;\">【风险提示】 </strong></span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">数字资产是一种高风险的投资方式，请投资者谨慎购买，并注意投资风险。<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>不对项目或投资行为承担担保、赔偿等责任。</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"> </p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">交易数字资产，上<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>！</span></p>', NULL);
INSERT INTO `article_translations` VALUES (256, 131, 'zh-CN', '关于新增OTC委托挂单功能的公告', '<p class=\"ql-long-16544500\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span class=\"ql-author-16544500\" style=\"box-sizing: border-box; color: #000000;\">尊敬的</span><span style=\"font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span><span style=\"color: #000000;\">用户：</span></p>\r\n<p class=\"ql-long-16544500\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\"><span class=\"ql-author-16544500\" style=\"box-sizing: border-box;\">为满足广大用户的交易需求，<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span> </span><span class=\"ql-author-16342195\" style=\"box-sizing: border-box;\">Web端已上线</span><span class=\"ql-author-16544500\" style=\"box-sizing: border-box;\">OTC委托挂单功能</span><span class=\"ql-author-16342195\" style=\"box-sizing: border-box;\">。具体</span><span class=\"ql-author-16544500\" style=\"box-sizing: border-box;\">详情如下：</span></span></p>\r\n<p class=\"ql-align-justify ql-long-16544500\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\"><span class=\"ql-author-16342195\" style=\"box-sizing: border-box;\">1、</span><span class=\"ql-author-16544500\" style=\"box-sizing: border-box;\">OTC委托挂单是指用户在出入金时，若对当前价格不满意，可预先设置期望的价格和数量发布挂单，当市场价达到设置的价格时，商家可进行抢单。</span></span></p>\r\n<p class=\"ql-align-justify ql-long-16544500\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\"><span class=\"ql-author-16342195\" style=\"box-sizing: border-box;\">2</span><span class=\"ql-author-16544500\" style=\"box-sizing: border-box;\">、若您在发布委托挂单后，修改了选择的支付方式，当前委托挂单的支付方式也将随之修改。</span></span></p>\r\n<p class=\"ql-align-justify ql-long-16544500\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\"><span class=\"ql-author-16342195\" style=\"box-sizing: border-box;\">3</span><span class=\"ql-author-16544500\" style=\"box-sizing: border-box;\">、因委托挂单采用商家抢单机制，所以商家判断为存在风险隐患的订单将不会被成交。</span></span></p>\r\n<p class=\"ql-align-justify ql-long-16544500\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\"><span class=\"ql-author-16342195\" style=\"box-sizing: border-box;\">4</span><span class=\"ql-author-16544500\" style=\"box-sizing: border-box;\">、</span><span class=\"ql-author-16342195\" style=\"box-sizing: border-box;\">OTC委托挂单</span><span class=\"ql-author-16544500\" style=\"box-sizing: border-box;\">目前只支持出售。</span></span></p>', NULL);
INSERT INTO `article_translations` VALUES (257, 132, 'zh-CN', '关于下调部分杠杆ETF产品管理费提示的公告', '<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">尊敬的<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>用户：</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">由于对冲平台24小时资金费率下调，<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>已将部分杠杆ETF产品每倍日管理费调整为0.2%，请广大用户知晓并注意交易成本。</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">本次调整涉及调整的交易对包括：</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">ATOM3L/USDT、ATOM3S/USDT、DOGE3L/USDT、DOGE3S/USDT、VET3L/USDT、VET3S/USDT</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">&nbsp;此前<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>已将下述交易对每倍日管理费调整为0.2%，具体如下：</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">OKB3L/USDT 、OKB3S/USDT、DASH3L/USDT、DASH3S/USDT、BNB3L/USDT、BNB3S/USDT、ETC3L/USDT、ETC3S/USDT、ALGO3L/USDT、ALGO3S/USDT</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">&nbsp;</p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">后续平台将继续关注市场资金费率变化并及时作出相关调整，感谢您的理解与支持。</span></p>', NULL);
