INSERT INTO `article_translations` VALUES (260, 135, 'zh-CN', '关于上线多个主流币交易对的公告', '<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">尊敬的<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>用户：</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">为充分满足用户的交易需求，</span><span style=\"font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span><span style=\"color: #000000;\">平台将于7月2日15:00(UTC+8)上线多个主流币的BTC及ETH交易对，具体如下：</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">BTC：BCH/BTC</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">ETH：ETC/ETH、LTC/ETH</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">欢迎广大用户前来交易体验。</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">&nbsp;</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\"><strong style=\"box-sizing: border-box;\">【风险提示】&nbsp;</strong></span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">数字资产是一种高风险的投资方式，请投资者谨慎购买，并注意投资风险。<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Hokiecoin</span>不对项目或投资行为承担担保、赔偿等责任。</span></p>', NULL);
INSERT INTO `article_translations` VALUES (261, 136, 'zh-CN', '关于上线AMPL持仓PoS功能的公告', '<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span class=\"ql-size-12 ql-author-27836153\" style=\"box-sizing: border-box; color: #000000;\">尊敬的<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>用户：</span></p>\r\n<p class=\"ql-long-27836153\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\"><span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex </span>已上线AMPL持仓PoS功能，欢迎广大用户参与！详情如下：</span></p>\r\n<p class=\"ql-long-27836153\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">1.AMPL持仓POS的收益以AMPL进行结算，每日收益=持仓AMPL枚数*（年化收益率/365)；</span></p>\r\n<p class=\"ql-long-27836153\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">2.预期年化收益会根据矿池实际收益随时进行调整；</span></p>\r\n<p class=\"ql-long-27836153\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">3.开启PoS的1日后开始计算收益；</span></p>\r\n<p class=\"ql-long-27836153\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">4.每日随机进行快照，以每日快照最低持仓值进行结算(包括因rebase造成的持仓值减少，也视为当日最低值)；</span></p>\r\n<p class=\"ql-long-27836153\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">5.无需冻结抵押资产，随时可交易或提现；</span></p>\r\n<p class=\"ql-long-27836153\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">6.可随时取消PoS，资产余额小于最低起投值或用户主动取消协议，则自动退出PoS，收益结算至退出PoS前一日。</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">&nbsp;</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">交易数字资产，上<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>！</span></p>', NULL);
INSERT INTO `article_translations` VALUES (262, 137, 'zh-CN', '关于上线DOT/USDT杠杆交易对的公告', '<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">尊敬的<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Hokiecoin</span>用户：</span><br style=\"box-sizing: border-box;\" /><br style=\"box-sizing: border-box;\" /><span style=\"color: #000000;\"><span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Hokiecoin</span>杠杆交易区将于7月20日 22:00(UTC+8)上线DOT/USDT交易对，支持3倍杠杆，买入（做多）的24小时利息为0.1%，暂不支持DOT融币做空交易。</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">此前，<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Hokiecoin</span>币币交易区已经上线DOT/USDT和DOT/BTC交易对，欢迎交易体验。</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">&nbsp;</p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">交易数字资产，上<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Hokiecoin</span>！</span></p>', NULL);
INSERT INTO `article_translations` VALUES (263, 138, 'zh-CN', '关于杠杆ETF产品LINK3S、THETA3L进行份额合并的公告', '<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #9fa6b5;\">尊敬的<span style=\"caret-color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.16px;\">Bekonex</span>用户：</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #9fa6b5;\">由于当前杠杆ETF产品LINK3S、THETA3L的单价低于0.05USDT，触发了<span style=\"caret-color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.16px;\">Bekonex</span>杠杆ETF产品份额合并机制。我们将在7月17日15:00（UTC+8）启动份额合并机制，将LINK3S、THETA3L的份额进行合并操作。合并后用户的资产总额不会受到任何的影响。</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #9fa6b5;\">原有的10份LINK3S、THETA3L份额会变为1份新的LINK3S、THETA3L份额。同时新份额的净值变为原有份额的10倍。净值换算以合并时的净值为基准。</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #9fa6b5;\">新份额的名称，简称，交易对都与合并前相同。</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">&nbsp;</p>', NULL);
INSERT INTO `article_translations` VALUES (264, 139, 'zh-CN', '平台关于新增AR 、BAL 、COMP和DMG的ETH交易对公告', '<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">尊敬的<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>用户：</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">为充分满足用户的交易需求，<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex </span>平台将于6月24日10:30(UTC+8)新增AR/ETH、BAL/ETH、COMP/ETH和DMG/ETH交易对。</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">欢迎广大用户交易体验。</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">&nbsp;</p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\"><strong style=\"box-sizing: border-box;\">【风险提示】&nbsp;</strong></span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">数字资产是一种高风险的投资方式，请投资者谨慎购买，并注意投资风险。MXC不对项目或投资行为承担担保、赔偿等责任。</span></p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">&nbsp;</p>\r\n<p class=\"paragraph text-align-type-left pap-line-1.3 pap-line-rule-auto pap-spacing-before-0pt pap-spacing-after-6pt\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"color: #000000;\">交易数字资产，上<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>！</span></p>', NULL);
INSERT INTO `article_translations` VALUES (265, 140, 'zh-CN', 'Bekonex平台关于新增去中心化存储指数产品的公告', '<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span class=\"ql-author-12567341\" style=\"box-sizing: border-box; color: #9fa6b5;\">尊敬的<span style=\"caret-color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.16px; background-color: #ffffff;\">Bekonex</span>用户：</span></p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span class=\"ql-author-12567341\" style=\"box-sizing: border-box; color: #9fa6b5;\"><span style=\"caret-color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.16px; background-color: #ffffff;\">Bekonex</span>将于2020年6月18日18:00（UTC+8）新增去中心化存储指数产品。用户可登录网页端，在「ETF专区」区选择「指数交易」进行交易。去中心化储存指数产品详情如下：</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">&nbsp;</p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span class=\"ql-author-12567341\" style=\"box-sizing: border-box; color: #9fa6b5;\">简称：MX05</span></p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span class=\"ql-author-12567341\" style=\"box-sizing: border-box; color: #9fa6b5;\">中文名称：去中心化存储组合</span></p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span class=\"ql-author-12567341\" style=\"box-sizing: border-box; color: #9fa6b5;\">英文名称：Decentralized Storage Assets Index</span></p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span class=\"ql-author-12567341\" style=\"box-sizing: border-box; color: #9fa6b5;\">指数成分：STORJ 、BLZ、GNX、LAMB</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">&nbsp;</p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span class=\"ql-author-12567341\" style=\"box-sizing: border-box; color: #9fa6b5;\">什么是MXC指数产品？</span></p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span class=\"ql-author-12567341\" style=\"box-sizing: border-box; color: #9fa6b5;\">MXC指数产品是开放式的产品，支持用户实时买卖指数产品的份额，从而跟踪MXC指数的涨跌情况，获取该类资产组合的平均市场收益。</span></p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span class=\"ql-author-12567341\" style=\"box-sizing: border-box; color: #9fa6b5;\">MXC指数选取市场流通性较好的数字资产作为成分标的，并参考标的上月日均成交额占比，作为基准期初始市值权重，从而反映该类资产的整体市场表现。</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">&nbsp;</p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span class=\"ql-author-12567341\" style=\"box-sizing: border-box; color: #9fa6b5;\">MXC指数产品有哪些优点？</span></p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span class=\"ql-author-12567341\" style=\"box-sizing: border-box; color: #9fa6b5;\">分散风险。相对于单一币种的交易，MXC指数产品相当于是跟踪一个内部相关性较小的资产组合，而资产的相关性越小，越有利于分散投资风险。</span></p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span class=\"ql-author-12567341\" style=\"box-sizing: border-box; color: #9fa6b5;\">省心省力。投资指数产品等同于投资该产品所跟踪的所有指数成分币种，免去挑选投资品种的烦恼。</span></p>', NULL);
INSERT INTO `article_translations` VALUES (266, 141, 'zh-CN', 'Bekonex平台关于新增DeFi指数产品的公告', '<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; text-align: left;\"><span class=\"ql-author-12567341 ql-size-12\" style=\"box-sizing: border-box; color: #9fa6b5;\">尊敬的<span style=\"caret-color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.16px; background-color: #ffffff;\">Bekonex</span>用户：</span></p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; text-align: left;\"><span class=\"ql-author-12567341\" style=\"box-sizing: border-box; color: #9fa6b5;\"><span style=\"caret-color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.16px; background-color: #ffffff;\">Bekonex</span>已于18:20（UTC+8）新增DeFi指数产品。用户可登录网页端进行交易。DeFi指数产品详情如下：</span></p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; text-align: left;\"><span class=\"ql-author-12567341\" style=\"box-sizing: border-box; color: #9fa6b5;\">简称：MX04</span></p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; text-align: left;\"><span class=\"ql-author-12567341\" style=\"box-sizing: border-box; color: #9fa6b5;\">中文名称：DeFi组合</span></p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; text-align: left;\"><span class=\"ql-author-12567341\" style=\"box-sizing: border-box; color: #9fa6b5;\">英文名称：DeFi Assets Index</span></p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; text-align: left;\"><span class=\"ql-author-12567341\" style=\"box-sizing: border-box; color: #9fa6b5;\">指数成分：KNC、ZRX、KAVA、NEST</span></p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; text-align: left;\">&nbsp;</p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; text-align: left;\"><span style=\"color: #9fa6b5;\"><strong class=\"ql-author-12567341\" style=\"box-sizing: border-box;\">什么是MXC指数产品？</strong></span></p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; text-align: left;\"><span class=\"ql-author-12567341\" style=\"box-sizing: border-box; color: #9fa6b5;\">MXC指数产品是开放式的产品，支持用户实时买卖指数产品的份额，从而跟踪MXC指数的涨跌情况，获取该类资产组合的平均市场收益。</span></p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; text-align: left;\"><span class=\"ql-author-12567341\" style=\"box-sizing: border-box; color: #9fa6b5;\">MXC指数选取市场流通性较好的数字资产作为成分标的，并参考标的上月日均成交额占比，作为基准期初始市值权重，从而反映该类资产的整体市场表现。</span></p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; text-align: left;\"><span style=\"color: #9fa6b5;\"><strong class=\"ql-author-12567341\" style=\"box-sizing: border-box;\">MXC指数产品有哪些优点？</strong></span></p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; text-align: left;\"><span class=\"ql-author-12567341 ql-font-microsoftyahei\" style=\"box-sizing: border-box; color: #9fa6b5;\">分散风险。相对于单一币种的交易，MXC指数产品相当于是跟踪一个内部相关性较小的资产组合，而资产的相关性越小，越有利于分散投资风险。</span></p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; text-align: left;\"><span class=\"ql-author-12567341 ql-font-microsoftyahei\" style=\"box-sizing: border-box; color: #9fa6b5;\">省心省力。投资指数产品等同于投资该产品所跟踪的所有指数成分币种，免去挑选投资品种的烦恼。</span></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">&nbsp;</p>', NULL);
INSERT INTO `article_translations` VALUES (267, 142, 'zh-CN', '关于杠杆ETF体验升级的公告', '<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">尊敬的<span style=\"font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>用户：<br style=\"box-sizing: border-box;\" /><span style=\"font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex </span>已于2020年7月7日完成对杠杆ETF大部分交易对的优化，优化后杠杆ETF交易深度、盘口价差、撮合效率等均得到大幅提升，欢迎交易体验！<br style=\"box-sizing: border-box;\" /><br style=\"box-sizing: border-box;\" />后续平台将持续努力优化产品体验，为您提供更好的产品与服务，如有相关意见或建议，可联系官方客服。<br style=\"box-sizing: border-box;\" /><br style=\"box-sizing: border-box;\" />感谢您的关注与支持。</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">&nbsp;</p>\r\n<p class=\"ql-long-12567341\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span class=\"ql-author-12567341\" style=\"box-sizing: border-box;\">交易数字资产，上<span style=\"font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex </span>！</span></p>', NULL);
