INSERT INTO `article_translations` VALUES (272, 147, 'zh-CN', 'ETF合伙人招募令公告', '<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">尊敬的<span style=\"font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>用户：</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">杠杆ETF产品是一类在传统金融市场内非常受欢迎的金融衍生品。它是在给定标的资产(如BTC)的前提下，实现追踪目标每日资产收益率的一定倍数（如3倍）的交易型产品。目前每种通证支持3倍看多（3X Long）及3倍看空（3X Short），投资者可在任⼀时刻在⼆级市场买⼊或卖出，且不需要支付任何保证金，即可达到交易杠杆的目的。在此，特邀您加入ETF合伙人，与<span style=\"font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Hokiecoin</span>携手共赢，共同成长。</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><strong style=\"box-sizing: border-box;\">一、合伙人尊享权益：</strong></p>\r\n<ol style=\"box-sizing: border-box; padding-left: 20px; list-style-position: outside; margin: 20px 0px 20px 20px; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">\r\n<li style=\"box-sizing: border-box;\">50%-80％高额返佣</li>\r\n<li style=\"box-sizing: border-box;\">专属客户经理对接</li>\r\n<li style=\"box-sizing: border-box;\">节日礼遇</li>\r\n<li style=\"box-sizing: border-box;\">周边产品赞助</li>\r\n<li style=\"box-sizing: border-box;\">新项目空投</li>\r\n<li style=\"box-sizing: border-box;\">高端活动优先参与</li>\r\n</ol>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><strong style=\"box-sizing: border-box;\">二、交易手续费返佣说明：</strong></p>\r\n<table style=\"box-sizing: border-box; border-spacing: 0px; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\" width=\"491\">\r\n<tbody style=\"box-sizing: border-box;\">\r\n<tr style=\"box-sizing: border-box;\">\r\n<td style=\"box-sizing: border-box; padding: 0px; width: 98.8889px;\">\r\n<p style=\"box-sizing: border-box;\">代理等级</p>\r\n</td>\r\n<td style=\"box-sizing: border-box; padding: 0px; width: 114.444px;\">\r\n<p style=\"box-sizing: border-box;\">返佣比例</p>\r\n</td>\r\n<td style=\"box-sizing: border-box; padding: 0px; width: 154.444px;\">\r\n<p style=\"box-sizing: border-box;\"><span style=\"font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Hokiecoin</span>持仓用户</p>\r\n</td>\r\n<td style=\"box-sizing: border-box; padding: 0px; width: 121.111px;\">\r\n<p style=\"box-sizing: border-box;\">结算时间</p>\r\n</td>\r\n</tr>\r\n<tr style=\"box-sizing: border-box;\">\r\n<td style=\"box-sizing: border-box; padding: 0px; width: 98.8889px;\">\r\n<p style=\"box-sizing: border-box;\">黄金合伙人</p>\r\n</td>\r\n<td style=\"box-sizing: border-box; padding: 0px; width: 114.444px;\">\r\n<p style=\"box-sizing: border-box;\">50%</p>\r\n</td>\r\n<td style=\"box-sizing: border-box; padding: 0px; width: 154.444px;\">\r\n<p style=\"box-sizing: border-box;\">0-100人</p>\r\n</td>\r\n<td style=\"box-sizing: border-box; padding: 0px; width: 121.111px;\" rowspan=\"3\">\r\n<p style=\"box-sizing: border-box;\">&nbsp;</p>\r\n<p style=\"box-sizing: border-box;\">日结</p>\r\n</td>\r\n</tr>\r\n<tr style=\"box-sizing: border-box;\">\r\n<td style=\"box-sizing: border-box; padding: 0px; width: 98.8889px;\">\r\n<p style=\"box-sizing: border-box;\">白金合伙人</p>\r\n</td>\r\n<td style=\"box-sizing: border-box; padding: 0px; width: 114.444px;\">\r\n<p style=\"box-sizing: border-box;\">70%</p>\r\n</td>\r\n<td style=\"box-sizing: border-box; padding: 0px; width: 154.444px;\">\r\n<p style=\"box-sizing: border-box;\">100-300人</p>\r\n</td>\r\n</tr>\r\n<tr style=\"box-sizing: border-box;\">\r\n<td style=\"box-sizing: border-box; padding: 0px; width: 98.8889px;\">\r\n<p style=\"box-sizing: border-box;\">黑钻合伙人</p>\r\n</td>\r\n<td style=\"box-sizing: border-box; padding: 0px; width: 114.444px;\">\r\n<p style=\"box-sizing: border-box;\">80%</p>\r\n</td>\r\n<td style=\"box-sizing: border-box; padding: 0px; width: 154.444px;\">\r\n<p style=\"box-sizing: border-box;\">300-500人</p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">合伙人须知：</p>\r\n<ol style=\"box-sizing: border-box; padding-left: 20px; list-style-position: outside; margin: 20px 0px 20px 20px; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">\r\n<li style=\"box-sizing: border-box;\">推广期间，<span style=\"font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>专属社群持仓用户不低于50人；</li>\r\n<li style=\"box-sizing: border-box;\">用户每周累计交易量大于10000USDT；</li>\r\n<li style=\"box-sizing: border-box;\">返佣自开启日计算两年内有效。</li>\r\n</ol>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">*施行期间<span style=\"font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">Bekonex</span>平台将保留合伙人计划的最终解释权。</p>', NULL);
INSERT INTO `article_translations` VALUES (273, 148, 'zh-CN', '平台关于“交易新版杠杆，享限时超低息”活动公告', '<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">尊敬的</span></span>CoinALL用户：</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">CoinALL现货杠杆将于2020年4月1日12:00（UTC+8）起全新升级上线，为感谢广大用户的支持，4月1日MXC平台将上线为期一周的&ldquo;交易新版杠杆，享限时超低息！&rdquo;活动，参与交易即可享受低至0.05%/日的利息优惠。</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><strong style=\"box-sizing: border-box;\">一、活动时间</strong></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">2020年4月1日-2020年4月7日</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><strong style=\"box-sizing: border-box;\">二、活动规则与奖励</strong></p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">参与活动无需报名，活动时间内，交易Bekonex杠杆即可享受USDT和BTC区所有交易对低至0.05%/日的杠杆利息。</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">新版上线，欢迎体验！</p>', NULL);
INSERT INTO `article_translations` VALUES (274, 149, 'zh-CN', '平台永续合约部分交易对临时升级公告', '<p class=\"p1\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">尊敬的</span></span>CoinALL用户：</p>\r\n<p class=\"p1\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">为给您带来更好的交易体验，CoinALL平台将于2020年3月26日15:00(UTC+8)对BTCUSDT、ETHUSDT、EOSUSDT、LTCUSDT、ETCUSDT永续合约交易对临时升级维护，升级期间相关交易对将暂停交易约30分钟。其他合约交易对不受影响可正常交易。</p>\r\n<p class=\"p1\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">持有以上合约仓位的用户，根据市场情况提前进行平仓、撤单等处理，以免给您带来不必要的损失。</p>\r\n<p class=\"p1\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">给您带来的不便，敬请谅解。</p>', NULL);
INSERT INTO `article_translations` VALUES (275, 150, 'zh-CN', '平台杠杆交易新增部分交易对的公告', '<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">尊敬的</span></span>CoinALL用户：</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">为满足广大用户的交易需求，CoinALL平台杠杆交易将于2020年3月20日18:00 (UTC+8)新增PAX/USDT、TUSD/USDT交易对，支持5倍杠杆多空交易，并且开通PAX、TUSD融币功能，利息为日息0.1%，欢迎用户前来体验。</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">&nbsp;</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">交易数字资产，上</span></span>CoinALL！</p>', NULL);
INSERT INTO `article_translations` VALUES (276, 151, 'zh-CN', 'CoinALL杠杆ETF产品15个品种份额合并的公告', '<p class=\"p1\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">尊敬的</span></span>CoinALL用户：</p>\r\n<p class=\"p1\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">由于当前部分杠杆</span></span><span class=\"s1\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">ETF</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">产品的单价均低于</span></span><span class=\"s1\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">0.05USDT</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">，触发了Bekonex杠杆</span></span><span class=\"s1\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">ETF</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">产品份额合并机制。我们将在</span></span><span class=\"s1\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">2020</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">年</span></span><span class=\"s1\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">3</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">月</span></span><span class=\"s1\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">13</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">日（今天）</span></span><span class=\"s1\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">14:00</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">（</span></span><span class=\"s1\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">UTC+8</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">）启动份额合并机制，将单价低于</span></span><span class=\"s1\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">0.05USDT</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">的杠杆</span></span><span class=\"s1\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">ETF</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">产品品种份额进行合并操作。合并后用户的资产总额不会受到任何的影响。</span></span></p>\r\n<p class=\"p1\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">具体进行合并的品种和方案如下：</span></span></p>\r\n<p class=\"p1\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span class=\"s1\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">ALGO3L</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">、</span></span><span class=\"s1\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">ATOM3L</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">：原有的</span></span><span class=\"s1\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">100</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">份份额会变为新的</span></span><span class=\"s1\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">1</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">份份额，同时新份额的净值变为原有份额的</span></span><span class=\"s1\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">100</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">倍。</span></span></p>\r\n<p class=\"p1\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span class=\"s1\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">ADA3L</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">、</span></span><span class=\"s1\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">VET3L</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">、</span></span><span class=\"s1\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">DASH3L</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">、</span></span><span class=\"s1\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">IOST3L</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">：原有的</span></span><span class=\"s1\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">20</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">份份额会变为新的</span></span><span class=\"s1\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">1</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">份份额，同时新份额的净值变为原有份额的</span></span><span class=\"s1\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">20</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">倍。</span></span></p>\r\n<p class=\"p3\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">OKB3L</span></span><span class=\"s2\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">、</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">ONT3L</span></span><span class=\"s2\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">、</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">LINK3L</span></span><span class=\"s2\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">、</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">BSV3L</span></span><span class=\"s2\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">、</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">ZEC3L</span></span><span class=\"s2\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">、</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">NEO3L</span></span><span class=\"s2\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">、</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">BNB3L</span></span><span class=\"s2\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">、</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">QTUM3L</span></span><span class=\"s2\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">、</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">ETC3L</span></span><span class=\"s2\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">：</span></span></span>&nbsp;<span class=\"s2\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">原有的</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">10</span></span><span class=\"s2\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">份份额会变为新的</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">1</span></span><span class=\"s2\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">份份额，同时新份额的净值变为原有份额的</span></span></span><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">10</span></span><span class=\"s2\" style=\"box-sizing: border-box;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">倍。</span></span></span></p>\r\n<p class=\"p1\" style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">净值换算以合并时的净值为基准。新份额的名称、简称、交易对都与合并前相同。</span></span></p>', NULL);
INSERT INTO `article_translations` VALUES (277, 152, 'zh-CN', '平台关于DASHUSDT、XTZUSDT、LINKUSDT、BSVUSDT永续合约上线公告', '<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">尊敬的</span></span>CoinALL用户：</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">CoinALL将于2020年2月23日21:00(UTC+8)上线DASHUSDT、XTZUSDT、LINKUSDT、BSVUSDT永续合约交易对，最高支持100倍杠杆，同时开放全仓与逐仓保证金模式，欢迎交易体验。</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">&nbsp;</p>', NULL);
INSERT INTO `article_translations` VALUES (278, 153, 'zh-CN', '平台杠杆交易新增部分交易对的公告', '<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">尊敬的</span></span>CoinALL用户：</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">为满足广大用户的交易需求，CoinALL平台杠杆交易将于2020年2月10日15:00 (UTC+8)新增OGN/USDT、ANKR/USDT、GXC/USDT、XMX/USDT交易对，并且支持OGN、ANKR、GXC、XMX融币交易，利息为0.1%，欢迎用户前来体验。</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">&nbsp;</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">交易数字资产，上CoinALL！</p>', NULL);
INSERT INTO `article_translations` VALUES (279, 154, 'zh-CN', '平台杠杆ETF新增项目的公告', '<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">尊敬的用户：</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">为满足广大用户的交易需求CoinALL平台已于2020年1月9日20:00(UTC+8)新增以下标的:</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">1.BSV3L--BSV三倍做多、BSV3S--BSV三倍做空</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">2.BNB3L--BNB三倍做多、BNB3S--BNB三倍做空</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">3.ETC3L--ETC三倍做多、ETC3S--ETC三倍做空</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">欢迎广大用户前来体验。</p>', NULL);
INSERT INTO `article_translations` VALUES (280, 155, 'zh-CN', '将对现有平台项目进行重新评估打分的公告', '<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">尊敬的</span></span>CoinALL用户：</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">CoinALL平台严格遵守世界各国对数字资产及交易所方面的相关法律法规，始终选择向主流化合规化方向发展，为了响应相关政策，CoinALL区块链研究院将开始根据《CoinALL平台关于隐藏TOKEN及下线交易对的规则》对MXC平台上的项目重新进行评估打分，主要从如下几个维度进行：</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">1，项目的进度是否正常，是否有落地可能<br style=\"box-sizing: border-box;\" />2，项目真实交易量<br style=\"box-sizing: border-box;\" />3，项目的沉淀资金<br style=\"box-sizing: border-box;\" />4，负面舆论情况<br style=\"box-sizing: border-box;\" />5，新增用户数<br style=\"box-sizing: border-box;\" />6，项目程序代码更新情况和开发完成度</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">重新评估打分后，对于不符合标准的项目将会根据《CoinALL平台关于隐藏TOKEN及下线交易对的规则》进行处理。</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">同时，CoinALL研究院后续会加强项目的审查以及已上线项目的不定时复核。也欢迎CoinALL社区成员共同对MXC平台上的项目进行监督，并通过对有相关问题的项目进行建议和反馈CoinALL平台将及时核实跟进。</p>', NULL);
INSERT INTO `article_translations` VALUES (281, 156, 'zh-CN', '平台新增部分交易对API公告', '<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">尊敬的CoinALL用户：</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">MXC平台为了优化用户交易体验，现新增ADA/USDT、BSV/USDT、ZIL/USDT、AE/USDT、NAS/USDT的API申请，现广大用户可自主申请API操作。</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">&nbsp;</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">交易数字资产，上CoinALL就够了！</p>', NULL);
INSERT INTO `article_translations` VALUES (282, 157, 'zh-CN', '平台新增部分通证API公告', '<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">尊敬的Hokiecoin用户：</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">Hokiecoin平台为了提升交易深度，优化用户交易体验，现新增ONT/USDT、NEO/USDT、QTUM/USDT、VET/USDT、XLM/USDT、XTZ/USDT、IOST/USDT、ATOM/USDT、BTM/USDT的API申请。</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">&nbsp;</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">目前支持BTC/USDT、ETH/USDT、EOS/USDT、BCH/USDT、LTC/USDT、ONT/USDT、TRX/USDT、XRP/USDT、DASH/USDT、NEO/USDT、QTUM/USDT、VET/USDT、XLM/USDT、XTZ/USDT、ZEC/USDT、IOST/USDT、ATOM/USDT、BTM/USDT的API申请。</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">&nbsp;</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">交易数字资产，上Hokiecoin就够了！</p>', NULL);
INSERT INTO `article_translations` VALUES (283, 158, 'zh-CN', '平台上线杠杆交易并举行5天免息的活动公告', '<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">尊敬的CoinALL用户：</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">为满足广大用户的交易需求，CoinALL平台杠杆交易区已于11月7日14:00（UTC+8）上线杠杆交易，支持通证为：BTC、ETH、EOS、LTC、BCH、XRP、TRX通证。</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">为庆祝CoinALL上线杠杆交易，平台特举行&ldquo;5天免息活动&rdquo;，在活动期间，杠杆借贷所产生的利息费用为0，诚邀广大用户前往体验。</p>\r\n<p style=\"box-sizing: border-box; color: #333333; font-family: -apple-system, BlinkMacSystemFont,;\">活动时间：11月7日20:00（UTC+8）&mdash;&mdash;11月12日20:00（UTC+8）</p>', NULL);
INSERT INTO `article_translations` VALUES (284, 159, 'zh-CN', '开通合约账户', '<p><span style=\"color: #222222;\">合约交易属于高风险交易行为，在带来更多潜在利润的同时， 也蕴含巨大风险。请注意，当市场出现剧烈波动时， 您合约钱包中的余额有可能全部亏损。来自部分地区的 用户无法使用合约交易。</span></p>', NULL);
INSERT INTO `article_translations` VALUES (285, 159, 'zh-TW', '開通合約賬戶', '<p class=\"tgt\" style=\"box-sizing: border-box; margin: 0px; padding: 0px; min-height: 26px; line-height: 26px; color: #333333; font-family: Arial,;\" data-section=\"0\"><span style=\"color: #333333;\">合約交易屬於高風險交易行為，在帶來更多潛在利潤的同時， 也蘊含巨大風險。請注意，當市場出現劇烈波動時， 您合約錢包中的餘額有可能全部虧損。來自部分地區的 用戶無法使用合約交易。</span></p>', NULL);
INSERT INTO `article_translations` VALUES (286, 159, 'en', 'Open a contract account', '<p><span style=\"color: #222222;\">Contract transactions are high-risk transactions, which bring more potential profits, but also contain huge risks. Please note that when the market fluctuates drastically, the balance in your contract wallet may be completely lost. Users from some regions cannot use contract transactions.</span></p>', NULL);
INSERT INTO `article_translations` VALUES (287, 160, 'zh-CN', 'CoinALL关于双十一全场手续费打五折的活动', '<p><span style=\"color: #333333; font-family: -apple-system, BlinkMacSystemFont, \'Segoe UI\', Helvetica, Arial, sans-serif; font-size: 15px; background-color: #ffffff;\">尊敬的</span><span style=\"color: #333333; font-family: -apple-system, BlinkMacSystemFont, \'Segoe UI\', Helvetica, Arial, sans-serif; font-size: 15px; background-color: #ffffff;\">CoinALL</span><span style=\"background-color: #ffffff; color: #333333; font-family: -apple-system, BlinkMacSystemFont, \'Segoe UI\', Helvetica, Arial, sans-serif; font-size: 15px;\">用户：</span></p>\r\n<p><span style=\"color: #333333; font-family: -apple-system, BlinkMacSystemFont, \'Segoe UI\', Helvetica, Arial, sans-serif; font-size: 15px; background-color: #ffffff;\">&nbsp; &nbsp;您好：</span></p>\r\n<p><span style=\"color: #333333; font-family: -apple-system, BlinkMacSystemFont, \'Segoe UI\', Helvetica, Arial, sans-serif; font-size: 15px; background-color: #ffffff;\">&nbsp; CoinALL</span><span style=\"color: #333333; font-family: -apple-system, BlinkMacSystemFont, \'Segoe UI\', Helvetica, Arial, sans-serif; font-size: 15px; background-color: #ffffff;\">交易所双十一期间将开展全场交易手续费打五折的活动，并且交易前</span><span style=\"background-color: #f3f3f3; font-family: Avenir, Helvetica, Arial, sans-serif; font-size: 14px;\">100名领取100&mdash;1000usdt不等的随机红包。欢迎各位尊敬的用户踊跃交易。</span></p>\r\n<p><span style=\"background-color: #ffffff; color: #333333; font-family: -apple-system, BlinkMacSystemFont, \'Segoe UI\', Helvetica, Arial, sans-serif; font-size: 15px;\"><span style=\"font-family: Avenir, Helvetica, Arial, sans-serif;\">CoinALL</span></span><span style=\"background-color: #ffffff; color: #333333; font-family: -apple-system, BlinkMacSystemFont, \'Segoe UI\', Helvetica, Arial, sans-serif; font-size: 15px;\">交易所将继续秉承用户第一、安全、实力、信任的运营理念，为全球投资者打造一个安全、透明、可信赖的数字资产服务环境。</span></p>\r\n<p><span style=\"background-color: #ffffff; color: #333333; font-family: -apple-system, BlinkMacSystemFont, \'Segoe UI\', Helvetica, Arial, sans-serif; font-size: 15px;\">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</span></p>\r\n<p><span style=\"background-color: #ffffff; color: #333333; font-family: -apple-system, BlinkMacSystemFont, \'Segoe UI\', Helvetica, Arial, sans-serif; font-size: 15px;\">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; CoinALL</span><span style=\"background-color: #ffffff; color: #333333; font-family: -apple-system, BlinkMacSystemFont, \'Segoe UI\', Helvetica, Arial, sans-serif; font-size: 15px; text-align: right;\">交易所</span></p>\r\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 2020年11月10日</p>', NULL);
INSERT INTO `article_translations` VALUES (288, 162, 'zh-CN', '关于Bekonex钱包升级的公告', '<p>尊敬的Bekonex 用户：</p>\r\n<p>&nbsp; 您好：</p>\r\n<p>&nbsp; Bekonex为给用户一个快速 ，便捷 ，安全的出入金体验。现进行了钱包的重大升级改进。 请用户重置钱包到最新的地址里。</p>\r\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; Bekonex交易所</p>\r\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 2020年11月30日</p>', NULL);
INSERT INTO `article_translations` VALUES (289, 163, 'zh-TW', 'CoinALL最強福利來襲，趕快來參與吧！', '<p>&nbsp;</p>\r\n<p><span style=\"color: #333333; font-family: Arial, \'PingFang SC\', \'Hiragino Sans GB\', STHeiti, \'Microsoft YaHei\', sans-serif; font-size: 18px; white-space: pre-line; background-color: #ffffff;\">CoinALL最強福利來襲，趕快來參與吧！ 尊敬的CoinALL會員： CoinALL最強福利月開始了。 等了很久吧？ 不要著急，已經來了。 為了感謝廣大用戶的長期支援和信任，CoinALL官方準備了500萬GART格裡芬平臺幣作為大家的福利，悄悄告訴大家GART將在2020年四月正式登錄幣安交易所 我們剛發售時只有0.03USDT一個 現在已經快接近1個USDT了哦，快來看看那種活動更適合你 1：充值優惠 單筆充值3000USDT，GART 5個贈送 單筆充值5000USDT，GART 10枚贈送 單筆充值10888USDT，GART 25個贈送 單筆充值15880USDT，GART 35枚贈送 單筆充值20888USDT，GART 50個贈送 2：交易優惠 （充值優惠玩家專用） 活動期間累計交易手續費500USDT--1000USDT，活動結束後贈送GART 2枚 活動期間累計交易手續費1000USDT--3000USDT，活動結束後贈送GART 4枚 活動期間累計交易手續費3000USDT--5000USDT，活動結束後贈送GART 8枚 活動期間累計交易手續費5000USDT--10000USDT，活動結束後贈送GART 15枚 活動期間累計交易手續費1000USDT以上者，15枚GART超過2000u，每增加一個GART</span></p>', 'CoinALL最強福利來襲，趕快來參與吧！');
INSERT INTO `article_translations` VALUES (290, 164, 'jp', '关于合约单张面值细则改动的通知8888', '<p>尊敬的<span style=\"caret-color: #333333; color: #333333; font-family: Nunito, Montserrat, system-ui, BlinkMacSystemFont, -apple-system, sans-serif; font-size: 14px; letter-spacing: 0.1599999964237213px; background-color: #ffffff;\">PCICOIN</span>用户：</p>\r\n<p>&nbsp; &nbsp; &nbsp; &nbsp;经过市场的调研反馈，平台针对所有币种的合约单张面值做出一些细微调整，由之前的单张合约面值1000USDT，改为单张合约面值10000USDT。生效时间为2021年1月29号0点。请您提前平掉账户中的持仓，系统将在29日0点对未平仓的账户执行系统平仓操作，感谢您的支持。999</p>\r\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; PCICOIN交易所 2021年1月28号</p>', NULL);
INSERT INTO `article_translations` VALUES (291, 88, 'kor', '비트 코 인 이란 무엇 인가', '<p>비트 코 인 이란 무엇 인가?</p>\r\n<p> </p>\r\n<p>비트 코 인 은 하나의 공 통 된 네트워크 로 새로운 결제 시스템 과 완전한 디지털화 화 폐 를 만 들 었 다.이것 은 중앙 관리 기구 나 중개자 가 아 닌 사용자 가 통제 하 는 최초의 탈 중심 화 된 피 어 투 피 어 네트워크 이다.사용자 의 측면 에서 볼 때 비트 코 인 은 인터넷 의 현금 과 매우 비슷 하 다.비트 코 인 은 현재 가장 걸출 한 3 식 부기 시스템 으로 볼 수 있다.</p>\r\n<p> </p>\r\n<p>누가 비트 코 인 네트워크 를 제어 하고 있 습 니까?</p>\r\n<p> </p>\r\n<p>아무 도 전자 우편 뒤의 기술 을 가지 고 있 지 않 은 것 처럼 비트 코 인 네트워크 를 가지 고 있 지 않다.비트 코 인 은 세계 각지 의 모든 비트 코 인 사용자 에 의 해 제어 된다.개발 자 는 소프트웨어 를 개선 할 수 있 지만 비트 코 인 프로 토 콜 의 규칙 을 강제로 바 꿀 수 없습니다. 모든 사용자 가 원 하 는 소프트웨어 를 자 유 롭 게 선택 할 수 있 기 때 문 입 니 다.서로 호환성 을 유지 하기 위해 서 는 모든 사용자 가 같은 규칙 을 따 르 는 소프트웨어 를 선택해 야 한다.모든 사용자 가 완전한 공감 대 를 형성 해야만 비트 코 인 은 정상적으로 작 동 할 수 있다.그 렇 기 때문에 모든 사용자 와 개발 자 는 이 공감 대 를 받 아들 이 고 보호 하 는 데 동력 이 있다.</p>\r\n<p> </p>\r\n<p>비트 코 인 은 어떻게 작 동 합 니까?</p>\r\n<p> </p>\r\n<p>사용자 의 측면 에서 볼 때 비트 코 인 은 핸드폰 앱 이나 컴퓨터 프로그램 으로 개인 비트 코 인 지갑 을 제공 할 수 있 고 사용 자 는 이 를 통 해 비트 코 인 을 지불 하고 받 을 수 있다.이것 이 바로 비트 코 인 이 대부분의 사용자 에 대한 작 동 원리 이다.</p>\r\n<p> </p>\r\n<p>막후 에서 전체 비트 코 인 네트워크 는 \'블록 체인\' 이 라 고 불 리 는 공공 원장 을 공유 했다.이 원장 은 모든 처 리 된 거래 를 포함 하여 사용자 의 컴퓨터 가 모든 거래 의 유효성 을 확인 할 수 있 게 한다.모든 거래 의 진실성 은 전송 주소 에 해당 하 는 전자 서명 으로 보호 되 기 때문에 사용 자 는 자신 들 의 비트 코 인 주소 에서 전 환 된 비트 코 인 을 완전히 통제 할 수 있다.또한 누구든지 전문 적 인 하드웨어 의 컴 퓨 팅 능력 을 이용 하여 거래 를 처리 하고 이 를 위해 비트 코 인 보상 을 받 을 수 있다.이 서 비 스 는 흔히 채굴 이 라 고 불 린 다.</p>', '비트 코 인 은 하나의 공 통 된 네트워크 로 새로운 결제 시스템 과 완전한 디지털화 화 폐 를 만 들 었 다.이것 은 중앙 관리 기구 나 중개자 가 아 닌 사용자 가 통제 하 는 최초의 탈 중심 화 된 피 어 투 피 어 네트워크 이다.사용자 의 측면 에서 볼 때 비트 코 인 은 인터넷 의 현금 과 매우 비슷 하 다.비트 코 인 은 현재 가장 걸출 한 3 식 부기 시스템 으로 볼 수 있다.');
INSERT INTO `article_translations` VALUES (292, 88, NULL, NULL, NULL, NULL);
INSERT INTO `article_translations` VALUES (293, 87, 'kor', 'KYC 인증 이란?어떻게 KYC 인증 을 완성 합 니까?', '<p>KYC 가 뭐야?</p>\r\n<p> </p>\r\n<p>KYC (Know your customer) 정책 (즉, 당신 의 고객 을 충분히 이해 하 는 것) 이 계 정 소유자 에 대한 심 사 를 강화 하 는 것 은 돈 세탁 을 반대 하여 부패 예방 에 사용 하 는 제도 적 기반 입 니 다.</p>\r\n<p> </p>\r\n<p>왜 KYC 를 해?</p>\r\n<p> </p>\r\n<p>KYC 정책 은 금융 기구 가 계좌 실명 제 를 실시 하고 계좌 의 실제 통제 자 와 거래 의 실제 수익 자 를 파악 하도록 요구 할 뿐만 아니 라 고객 의 신분, 상주 주소 또는 기업 이 종사 하 는 업 무 를 충분히 파악 하고 이에 상응하는 조 치 를 취해 야 한다.</p>\r\n<p> </p>\r\n<p>어떻게 KYC 인증 을 진행 합 니까?</p>\r\n<p> </p>\r\n<p>계 정 에 등록 하고 소인 프로필 사진 을 클릭 하여 신분 인증 을 선택 하 십시오.</p>\r\n<p> </p>\r\n<p>절차 에 따라 1 급, 2 급, 3 급 인증 을 완성 합 니 다.</p>\r\n<p> </p>\r\n<p>1 급 인증 은 유효 증명서 정 보 를 작성 해 야 한다.</p>\r\n<p> </p>\r\n<p>2 급 인증 은 유효 증명서 의 앞 뒷면 사진 을 올 리 고 완성 한 후에 얼굴 인식 을 해 야 한다. 핸드폰 스 캔 화면 QR 코드 를 사용 해 야 한다 (핸드폰 에 알 리 페 이 가 있어 야 한다).</p>\r\n<p> </p>\r\n<p>3 급 인증 은 핸드폰 앱 을 통 해 인증 을 하고 인증 을 할 때 구술 문 서 를 작성 해 야 한다.</p>\r\n<p> </p>\r\n<p>모 바 일 앱 은 웹 사이트 와 일치 합 니 다.</p>\r\n<p> </p>\r\n<p>인증 사항:</p>\r\n<p> </p>\r\n<p>1. 제시 한 내용 에 따라 인증 영상의 녹 화 를 완성 하 십시오.녹화 중 에 신분증 이나 여권 을 찍 어 달라 고 요구 할 테 니 증 서 를 미리 준비 해 주 십시오. (국내 사용 자 는 신분증 으로 만 인증 할 수 있 고 여권 을 사용 할 수 없다)</p>\r\n<p> </p>\r\n<p>2. 촬영 할 때마다 문자 알림 이 있 으 니 문자 알림 에 따라 조작 하 십시오.</p>\r\n<p> </p>\r\n<p>3. 각 영상 을 촬영 한 후에 모두 열 어서 검 사 를 하 는 것 을 권장 합 니 다. 만약 에 촬영 효과 가 뚜렷 하지 않 으 면 다시 녹음 을 해 야 합 니 다.그렇지 않 으 면 동 영상 효과 가 뚜렷 하지 않 아 심 사 를 받 을 수 있 습 니 다.</p>\r\n<p> </p>\r\n<p>4. 동 영상 업로드 가 데이터 와 인터넷 속도 에 대한 요구 가 높 고 동 영상 업로드 가 20M 의 데 이 터 를 차지 할 예정 이 므 로 WIFI 환경 에서 동 영상 인증 을 하 는 것 을 강력 히 권장 합 니 다.</p>', 'KYC (Know your customer) 정책 (즉, 당신 의 고객 을 충분히 이해 하 는 것) 이 계 정 소유자 에 대한 심 사 를 강화 하 는 것 은 돈 세탁 을 반대 하여 부패 예방 에 사용 하 는 제도 적 기반 입 니 다.');
INSERT INTO `article_translations` VALUES (294, 81, 'kor', '블록 체인 이란 무엇 인가?', '<p>블록 체인 이란 무엇 인가? 본질 적 으로 보면 블록 체인 은 분포 식, 탈 중심 화 된 네트워크 데이터 베이스 시스템 으로 이 시스템 은 데이터 의 저장, 업데이트, 유지, 조작 을 다 르 게 만 들 수 있다.</p>\r\n<p> </p>\r\n<p>우리 가 오늘 말 하고 자 하 는 블록 체인 은 네 가지 없어 서 는 안 될 핵심 기술 이 있 는데 그것 이 바로 분포 식 저장, 공감 체제, 암호학 원리, 스마트 계약 이다.</p>\r\n<p> </p>\r\n<p>그러면 오늘 은 전통 적 인 데이터 처리 에 비해 블록 체인 이 어떤 차이 가 있 는 지 여러분 께 블록 체인 이 무엇 인지 알 리 고 블록 체인 에 대한 전체적인 인식 을 가지 도록 하 겠 습 니 다.</p>\r\n<p> </p>\r\n<p>1. 블록 체인 의 데이터 저장: 블록 체인 데이터 구조</p>\r\n<p> </p>\r\n<p>데이터 저장 에 있어 블록 체인 기술 은 \'블록 체인 데이터 구조\' 를 이용 하여 데 이 터 를 검증 하고 저장 합 니 다.블록 체인 구조 가 무슨 뜻 이 죠?쇠사슬 은 모두 가 본 적 이 있 죠. 서로 연결 되 어 있 는 것 과 같은 것 입 니 다. 사실은 모든 라운드 에서 우 리 는 하나의 블록 으로 볼 수 있 고 많은 부분 이 서로 연결 되 어 블록 체인 을 형성 할 수 있 습 니 다.</p>\r\n<p> </p>\r\n<p>블록 에 저 장 된 것 은 데이터 이 고 일반 저장 데이터 와 다른 점 은 블록 체인 에서 뒤의 블록 에 있 는 데 이 터 는 앞의 블록 에 있 는 데 이 터 를 포함 하 는 것 입 니 다.</p>\r\n<p> </p>\r\n<p>책 을 읽 는 것 으로 예 를 들 면 우 리 는 평소에 책 을 읽 고 첫 페이지 를 본 다음 에 두 번 째 페이지, 세 번 째 페이지 를 읽 습 니 다. 블록 체인 안에 있 습 니 다. 만약 에 모든 블록 에 페이지 를 표시 하면 두 번 째 페이지 의 내용 은 첫 페이지 의 내용 을 포함 하고 세 번 째 페이지 의 내용 은 첫 페이지 와 두 번 째 페이지 의 내용 을 포함 합 니 다.이렇게 겹겹이 묶 여 있 는 체인 입 니 다.이렇게 되면 가장 근본 적 인 데 이 터 를 거 슬러 올 라 갈 수 있다. 이것 이 바로 블록 체인 의 트 레이스 성 이다.</p>\r\n<p> </p>\r\n<p>2. 블록 체인 중의 데이터 업데이트: 분포 식 노드 공감 알고리즘</p>\r\n<p> </p>\r\n<p>데이터 업데이트 에 있어 블록 체인 기술 은 \'분포 식 노드 공감 알고리즘\' 을 이용 하여 데 이 터 를 생 성하 고 업데이트 하 는 것 입 니 다.</p>\r\n<p> </p>\r\n<p>모든 새로운 블록 (즉, 데 이 터 를 업데이트 할 때) 은 하나의 알고리즘 을 통 해 전체 네트워크 의 51% 이상 노드 의 인정 을 받 아야 새로운 블록 을 구성 할 수 있 습 니 다. 쉽게 말하자면 투 표를 하 는 것 입 니 다. 절반 이상 의 동의 가 있 으 면 생 성 될 수 있 습 니 다.이 때문에 블록 체인 의 데 이 터 는 변경 할 수 없습니다.</p>\r\n<p> </p>\r\n<p>우 리 는 블록 체인 을 하나의 장부 에 비유 해서 설명 합 니 다. 왜냐하면 모두 데 이 터 를 기록 하 는 것 이기 때 문 입 니 다.전통 적 인 세계 에서 기장 권 은 기장 인 에 게 있 고 장 부 는 기장 인 에 게 속 합 니 다.블록 체인 에서 모든 사람 이 이 장 부 를 가지 고 있 습 니 다. 모두 같이 장 부 를 기록 하고 장 부 를 갱신 하려 면 투 표를 해 야 합 니 다. 절반 이상 이 찬성 해 야 장부 데 이 터 를 업데이트 할 수 있 습 니 다.</p>\r\n<p> </p>\r\n<p>이 과정 에서 우 리 는 분포 식, 노드, 공감 대 알고리즘 과 관련 될 것 이다.</p>\r\n<p> </p>\r\n<p>모든 사람 이 장 부 를 기록한다 (즉, 모든 사람 이 장 부 를 가지 고 있 고 장 부 는 모든 사람의 손 에 분산 된다). 이것 이 바로 \'분포 식\' 이다.모두 가 토론 하고 투표 하 며 찬성 하 는 기장 방법 은 이른바 \'공감 알고리즘\' 이다.노드 가 더욱 간단 해 지고 장부 기록 에 참여 하 는 모든 사람 은 하나의 노드 로 볼 수 있다.</p>\r\n<p> </p>\r\n<p>3. 블록 체인 중의 데이터 유지: 암호학</p>\r\n<p> </p>\r\n<p>그 다음 에 데이터 유지 단계 에 이 르 러 블록 체인 의 차이 점 은 바로 암호학 의 방식 으로 데이터 전송 과 방문 의 안전 을 확보 하 는 데 있다.</p>\r\n<p> </p>\r\n<p>그러면 블록 체인 에 응 용 된 암호학 원 리 는 주로 다음 과 같은 몇 가지 가 있 습 니 다. 해시 알고리즘, Merkle 해시 트 리, 타원 곡선 알고리즘, Base 58.이러한 원 리 는 사실은 그들 은 일련의 복잡 한 연산 과 환산 을 통 해 블록 체인 의 데이터 안전 을 확보 하 는 것 이다.</p>\r\n<p> </p>\r\n<p>4. 블록 체인 중의 데이터 조작: 스마트 계약</p>\r\n<p> </p>\r\n<p>마지막 으로 데이터 의 조작 단계, 즉 우리 가 이어서 말 해 야 할 \'스마트 계약\' 에 들 어 갔다.</p>\r\n<p> </p>\r\n<p>스마트 계약 은 컴퓨터 프로그램 이 정 의 를 내리 고 자동 으로 실행 하 는 약속 협의 이다. 말하자면 코드 로 실행 하 는 거래 준칙 이다. 현재 의 신용카드 자동 상환 기능 과 비슷 하고 이 기능 을 작 동시 키 면 본인 은 아무 것 도 상관 하지 않 아 도 된다. 만기 가 되면 은행 은 귀하 가 진 돈 을 자동 으로 공제 할 것 이다.</p>\r\n<p> </p>\r\n<p>스마트 계약 의 뚜렷 한 장점 은 신뢰 에 의 한 일련의 문 제 를 어느 정도 피 한 다 는 것 이다.우 리 는 많은 사람들 이 돈 을 빌 리 는 일 을 당 한 적 이 있 습 니 다. 친구 가 돈 이 없어 서 2000 위안 을 빌 렸 습 니 다. 다음 달 에 월급 을 주 고 돈 을 갚 겠 다 고 약 속 했 습 니 다. 다음 달 에 그 는 또 다른 핑 계 를 대고 갚 지 않 아서 이 일 을 질질 끌 면 안 됩 니 다.돈 이 얼마 없 는데 친구 라 서 답답 하지만 이 일 은 그만 두 세 요.</p>\r\n<p> </p>\r\n<p>그러면 스마트 계약 이 있 으 면 그 는 돈 을 떼 먹 을 수 없다. 왜냐하면 스마트 계약 에서 계약 중의 조항 이 촉발 되면 코드 가 자동 으로 집행 되 기 때문이다. 그 가 원 하 든 원 하지 않 든 월급 을 주 고 계좌 에 돈 이 있 으 면 그 는 너 에 게 갚아 야 한다.</p>\r\n<p> </p>\r\n<p>마지막 으로 오늘 의 내용 을 정리 하고 오늘 은 저희 가 주로 데이터 저장 작업 의 이러한 절 차 를 통 해 블록 체인 의 기본 적 인 상황 을 소개 합 니 다.우 리 는 이 를 정리 하면 블록 체인 에 없어 서 는 안 될 네 가지 핵심 기술 이 있 는데 그것 이 바로 분포 식 저장, 공감 체제, 암호학 원리, 스마트 계약 이다.</p>\r\n<p> </p>\r\n<p>그러면 우 리 는 이렇게 이해 할 수 있다. 분포 식 저장 은 데이터 저장 이라는 단계 에 대응 하고 공감 체 제 는 데이터 의 처리 와 업데이트 단계 에 대응 하 며 암호학 은 데이터 안전 에 대응 하고 스마트 계약 은 데이터 의 조작 문제 에 대응 된다.</p>', '블록 체인 이란 무엇 인가? 본질 적 으로 보면 블록 체인 은 분포 식, 탈 중심 화 된 네트워크 데이터 베이스 시스템 으로 이 시스템 은 데이터 의 저장, 업데이트, 유지, 조작 을 다 르 게 만 들 수 있다.');
INSERT INTO `article_translations` VALUES (295, 78, 'kor', '어떻게 비트 코 인 을 구 매 합 니까?', '<p>비트 코 인 을 구 매 하기 전에 다음 과 같은 작업 을 완성 해 야 합 니 다.</p>\r\n<p> </p>\r\n<p>1. 반드시 핸드폰 번 호 를 연결 해 야 합 니 다.</p>\r\n<p> </p>\r\n<p>2. 적어도 KYC 1 인증 완료</p>\r\n<p> </p>\r\n<p>만약 에 귀하 가 동전 을 팔 아서 조작 을 해 야 한다 면 상기 두 가지 조건 을 만족 시 키 는 토대 에서 본인 의 실명 인증 을 받 은 은행 카드 를 연결 해 야 합 니 다.</p>\r\n<p> </p>\r\n<p>법정 화 폐 는 세 가지 거래 유형 을 포함 하 는데 그것 이 바로 빠 른 거래, C2C 거래 와 대형 거래 이다.</p>', NULL);
INSERT INTO `article_translations` VALUES (316, 91, 'de', 'Dieser Vertrag', '<p>Diese Website ist eine Plattform, die Nutzern den Handel mit digitalen Vermögenswerten sowie damit verbundene Dienstleistungen anbietet (im Folgenden als \"diese Dienstleistung\" oder \"Dienstleistung\" bezeichnet). Zur Vereinfachung der Darstellung in dieser Vereinbarung verwenden wir in dieser Vereinbarung für diese Website die Begriffe „wir“ oder andere Pronomen der ersten Person. Jede natürliche Person oder juristische Einheit, die diese Website besucht, gilt als Nutzer der Website; zur Vereinfachung der Darstellung verwenden wir im Folgenden die Anrede „Sie“ oder andere Pronomen der zweiten Person. Zur Vereinfachung der Darstellung werden wir und Sie gemeinsam als „die Parteien“ und jeweils einzeln als „eine Partei“ bezeichnet.</p>\r\n<p> </p>\r\n<p>Wichtiger Hinweis:</p>\r\n<p> </p>\r\n<p>Wir weisen Sie hiermit ausdrücklich darauf hin:</p>\r\n<p> </p>\r\n<p>Digitale Vermögenswerte werden nicht von einer Finanzinstitution, einem Unternehmen oder dieser Website herausgegeben.</p>\r\n<p> </p>\r\n<p>Der Markt für digitale Vermögenswerte ist neu, unbestätigt und es ist möglich, dass er sich nicht weiterentwickelt.</p>\r\n<p> </p>\r\n<p>Digitale Vermögenswerte werden hauptsächlich von Spekulanten genutzt; der Einsatz im Einzelhandel und im Geschäftsbereich ist relativ gering. Der Handel mit digitalen Vermögenswerten ist mit äußerst hohen Risiken verbunden, erfolgt rund um die Uhr ohne Preisober- oder -untergrenzen und die Preise können durch Marktmanipulation, globale Regierungspolitik usw. stark schwanken.</p>\r\n<p> </p>\r\n<p>Wenn das Unternehmen nach eigenem Ermessen feststellt, dass Sie gegen diese Vereinbarung verstoßen, oder wenn die von dieser Website bereitgestellten Dienstleistungen oder Ihre Nutzung dieser Dienstleistungen nach dem Recht Ihrer Gerichtsbarkeit rechtswidrig sind, ist das Unternehmen berechtigt, Ihr Konto jederzeit zu sperren oder zu kündigen bzw. Ihre Nutzung dieser Website-Dienste oder den Handel mit digitalen Vermögenswerten auszusetzen oder zu beenden. Personen aus folgenden Ländern oder Regionen ist es untersagt, die auf dieser Website angebotenen Vertragshandelsdienste zu nutzen: [Festlandchina, Taiwan (China), Israel, Irak, Bangladesch, Bolivien, Ecuador, Kirgisistan, Sewastopol]. Diese Liste von Ländern oder Regionen kann sich je nach den unterschiedlichen politischen Richtlinien und Produkttypen ändern, ohne dass wir Sie gesondert informieren. Bitte achten Sie auf die Aktualisierung dieser Vereinbarung.</p>\r\n<p> </p>\r\n<p>Der Handel mit digitalen Vermögenswerten ist äußerst riskant und für die meisten Personen nicht geeignet. Sie verstehen, dass solche Geschäfte zu einem teilweisen oder vollständigen Verlust führen können, und sollten den Umfang Ihrer Investitionen nach Ihrem Verlustrisiko bestimmen. Sie verstehen, dass digitale Vermögenswerte zusätzliche Risiken bergen und sollten daher im Zweifelsfall professionellen Rat einholen. Darüber hinaus können weitere unvorhersehbare Risiken bestehen. Sie sollten daher Ihre finanzielle Situation sorgfältig abwägen und aufgrund Ihrer klaren Urteilsfähigkeit alle Entscheidungen über den Kauf oder Verkauf digitaler Vermögenswerte treffen und alle daraus resultierenden Verluste selbst tragen. Wir übernehmen dafür keine Verantwortung.</p>\r\n<p> </p>\r\n<p>Hinweis an Sie:</p>\r\n<p> </p>\r\n<p>Sie verstehen, dass diese Website lediglich eine Plattform ist, um Informationen über digitale Vermögenswerte zu erhalten, Handelspartner zu finden, über Transaktionen zu verhandeln und diese durchzuführen. Diese Website beteiligt sich nicht an Ihren Transaktionen. Daher sollten Sie eigenverantwortlich die Echtheit, Rechtmäßigkeit und Gültigkeit der entsprechenden digitalen Vermögenswerte und/oder Informationen prüfen und alle sich daraus ergebenden Verantwortlichkeiten und Verluste selbst tragen.</p>\r\n<p> </p>\r\n<p>Alle Meinungen, Informationen, Analysen, Preise, Ratschläge und sonstigen Inhalte dieser Website stellen lediglich allgemeine Marktkommentare dar und keine Anlageberatung. Wir übernehmen keine Verantwortung für Verluste, die direkt oder indirekt aus dem Vertrauen auf diese Informationen entstehen, einschließlich, aber nicht beschränkt auf Gewinneinbußen.</p>\r\n<p> </p>\r\n<p>Diese Website behält sich das Recht vor, Inhalte jederzeit nach eigenem Ermessen zu ändern oder anzupassen. Wir haben angemessene Maßnahmen getroffen, um die Genauigkeit der Informationen auf dieser Website sicherzustellen, können jedoch keine Garantie für deren Genauigkeit geben und übernehmen keine Verantwortung für Verluste, die direkt oder indirekt aufgrund von Informationen auf dieser Website oder durch Verzögerungen oder Fehler beim Senden oder Empfangen von Mitteilungen im Internet entstehen.</p>\r\n<p> </p>\r\n<p>Der Handel über internetbasierte Systeme birgt ebenfalls Risiken, einschließlich, aber nicht beschränkt auf Ausfälle von Software, Hardware oder Internetverbindungen. Da wir die Zuverlässigkeit und Verfügbarkeit des Internets nicht kontrollieren können, übernehmen wir keine Verantwortung für Verzerrungen, Verzögerungen oder Verbindungsfehler.</p>\r\n<p> </p>\r\n<p>Jegliche illegale Handelsaktivitäten wie Geldwäsche, Schmuggel, Bestechung usw. sind auf dieser Website verboten. Wenn ein solcher Verdacht festgestellt wird, wird diese Website Maßnahmen ergreifen, einschließlich, aber nicht beschränkt auf das Einfrieren von Konten und die Benachrichtigung der zuständigen Behörden. Wir übernehmen keine Verantwortung für Verluste und behalten uns das Recht vor, rechtliche Schritte gegen die betreffenden Personen einzuleiten.</p>\r\n<p> </p>\r\n<p>Es ist verboten, auf dieser Website marktmanipulative oder unlautere Handelsaktivitäten vorzunehmen. Sollte solches Verhalten festgestellt werden, wird diese Website präventive Maßnahmen gegen alle unethischen Verhaltensweisen wie Preismanipulation oder Störung des Handelssystems ergreifen, einschließlich, aber nicht beschränkt auf Verwarnungen, Handelsbeschränkungen oder Kontosperrungen. Wir übernehmen keine Verantwortung für Verluste und behalten uns das Recht vor, rechtliche Schritte gegen die betreffenden Personen einzuleiten.</p>\r\n<p> </p>\r\n<p>I. Allgemeine Bestimmungen</p>\r\n<p>1.1 Diese Nutzungsvereinbarung (im Folgenden \"diese Vereinbarung\" oder „diese Allgemeinen Geschäftsbedingungen“) besteht aus dem Haupttext, der Datenschutzrichtlinie, der KYC- und Anti-Geldwäsche-Richtlinie sowie allen anderen Regeln, Erklärungen und Hinweisen, die von dieser Website veröffentlicht wurden oder künftig veröffentlicht werden.</p>\r\n<p>1.2 Bevor Sie die Dienste dieser Website in Anspruch nehmen, sollten Sie diese Vereinbarung sorgfältig lesen. Wenn Sie Fragen oder Unklarheiten haben, wenden Sie sich bitte an einen Rechtsanwalt. Wenn Sie mit dieser Vereinbarung oder deren Änderungen nicht einverstanden sind, stellen Sie die Nutzung der Website sofort ein. Mit dem Einloggen, der Nutzung der Dienste oder ähnlichem Verhalten erklären Sie, dass Sie diese Vereinbarung vollständig verstanden und akzeptiert haben, einschließlich aller Änderungen, die jederzeit vorgenommen werden können.</p>\r\n<p>1.3 Sie werden durch Ausfüllen der erforderlichen Informationen und nach Durchführung weiterer Verfahren ein registriertes Mitglied dieser Website (im Folgenden „Mitglied“ genannt). Wenn Sie während des Registrierungsprozesses auf „Zustimmen“ klicken, schließen Sie diese Vereinbarung elektronisch mit dem Unternehmen. Auch wenn keine handschriftliche Unterschrift vorliegt, hat diese Vereinbarung volle Rechtskraft.</p>\r\n<p>1.4 Nach der Registrierung erhalten Sie ein Mitgliedskonto mit Passwort, das Sie selbst verwalten müssen. Sie tragen die rechtliche Verantwortung für alle Aktivitäten, die unter Ihrem Konto durchgeführt werden.</p>\r\n<p>1.5 Nur Mitglieder können auf der Handelsplattform für digitale Vermögenswerte handeln und andere exklusive Dienste nutzen. Nicht-Mitglieder haben lediglich Zugriff auf öffentliche Funktionen wie das Durchsuchen der Website.</p>\r\n<p>1.6 Durch Registrierung und Nutzung der Dienste und Funktionen dieser Website gelten Sie als:</p>\r\n<p>1.6.1 an alle Bedingungen dieser Vereinbarung gebunden;</p>\r\n<p>1.6.2 Sie bestätigen, dass Sie mindestens 18 Jahre alt oder nach den Gesetzen Ihrer Gerichtsbarkeit volljährig und geschäftsfähig sind, und dass Sie rechtlich zur Nutzung der Dienste dieser Website befugt sind;</p>\r\n<p>1.6.3 Sie garantieren, dass alle digitalen Vermögenswerte in Ihren Transaktionen rechtmäßig erworben wurden und Sie über deren Eigentum verfügen;</p>\r\n<p>1.6.4 Sie übernehmen volle Verantwortung für alle Transaktionen und Handlungen, die Sie auf dieser Website vornehmen, sowie für etwaige Gewinne oder Verluste;</p>\r\n<p>1.6.5 Sie bestätigen, dass alle bei der Registrierung gemachten Angaben wahrheitsgemäß und korrekt sind;</p>\r\n<p>1.6.6 Sie verpflichten sich zur Einhaltung aller steuerrechtlichen Vorschriften, einschließlich der Offenlegung von Gewinnen;</p>\r\n<p>1.6.7 Sie verpflichten sich, keine Handlungen vorzunehmen, die den Interessen der Website oder des Unternehmens schaden könnten;</p>\r\n<p>1.6.8 Diese Vereinbarung regelt nur das Rechtsverhältnis zwischen Ihnen und uns, nicht jedoch zwischen Ihnen und anderen Nutzern oder Websites.</p>\r\n<p> </p>\r\n<p>II. Änderungen der Vereinbarung</p>\r\n<p>Wir behalten uns das Recht vor, diese Vereinbarung regelmäßig zu ändern und auf der Website bekannt zu machen, ohne Sie gesondert zu benachrichtigen. Änderungen treten sofort mit Veröffentlichung in Kraft. Bitte prüfen Sie regelmäßig, ob es Aktualisierungen gibt. Wenn Sie nicht einverstanden sind, beenden Sie die Nutzung umgehend. Wenn Sie die Dienste weiterhin nutzen, erklären Sie sich mit den Änderungen einverstanden.</p>\r\n<p> </p>\r\n<p>III. Registrierung</p>\r\n<p>3.1 Registrierungsberechtigung</p>\r\n<p>Sie erklären, dass Sie beim Abschluss des Registrierungsprozesses oder bei der Nutzung unserer Dienste voll geschäftsfähig sind. Bei Zuwiderhandlung behalten wir uns das Recht vor, Ihr Konto zu kündigen oder zu sperren.</p>\r\n<p>3.2 Registrierungszweck</p>\r\n<p>Sie versichern, dass Ihre Registrierung nicht dem Ziel dient, Gesetze zu verletzen oder die Ordnung des Handels mit digitalen Vermögenswerten zu stören.</p>\r\n<p>3.3 Registrierungsprozess</p>\r\n<p>3.3.1 Sie erklären sich bereit, eine gültige E-Mail-Adresse, Telefonnummer usw. anzugeben. Je nach Gesetzgebung Ihrer Region müssen Sie gegebenenfalls Ihren echten Namen, Identitätsnachweis u.a. angeben und diese Daten aktuell halten.</p>\r\n<p>3.3.2 Wenn das Recht Ihrer Gerichtsbarkeit die Angabe einer registrierten Telefonnummer verlangt, stellen Sie sicher, dass Ihre Nummer ordnungsgemäß registriert ist.</p>\r\n<p>3.3.3 Nach erfolgreicher Verifizierung erhalten Sie ein Konto und Passwort und können sich als Mitglied einloggen.</p>\r\n<p>3.3.4 Sie stimmen dem Erhalt von E-Mails und/oder SMS-Nachrichten zur Verwaltung der Website zu.</p>\r\n<p> </p>\r\n<p>IV. Dienstleistungen</p>\r\n<p>Diese Website bietet ausschließlich eine Plattform für den Handel mit digitalen Vermögenswerten (einschließlich, aber nicht beschränkt auf Transaktionen) über das Internet.</p>\r\n<p> </p>\r\n<p>4.1 Leistungsinhalt</p>\r\n<p>4.1.1 Sie dürfen Marktinformationen einsehen, Transaktionen einreichen und durchführen.</p>\r\n<p>4.1.2 Sie dürfen Ihre Kontoinformationen und Website-Funktionen einsehen und nutzen.</p>\r\n<p>4.1.3 Sie dürfen an Werbeaktionen der Website teilnehmen.</p>\r\n<p>4.1.4 Andere Dienstleistungen nach Ankündigung durch die Website.</p>\r\n<p> </p>\r\n<p>4.2 Nutzungsregeln</p>\r\n<p>4.2.1 Sie verpflichten sich, Gesetze einzuhalten, die Herkunft Ihrer Vermögenswerte zu garantieren, keine illegalen Aktivitäten durchzuführen oder Rechte Dritter zu verletzen.</p>\r\n<p>4.2.2 Sie sind für die Sicherheit Ihrer Anmeldedaten, Passwörter und verknüpften Geräte verantwortlich. Im Falle eines Missbrauchs benachrichtigen Sie uns unverzüglich.</p>\r\n<p>4.2.3 Sie übernehmen die Verantwortung für alle Aktivitäten unter Ihrem Konto.</p>\r\n<p>4.2.4 Sie dürfen den Handel nicht böswillig stören oder falsche Informationen verbreiten.</p>\r\n<p>4.2.5 Streitigkeiten mit anderen Nutzern dürfen nicht außerhalb juristischer Wege mit unserer Hilfe gelöst werden.</p>\r\n<p>4.2.6 Alle Steuern, Gebühren und Kosten im Zusammenhang mit der Nutzung der Dienste sind von Ihnen zu tragen.</p>\r\n<p>4.2.7 Sie verpflichten sich, alle geltenden Nutzungsbedingungen und Regeln einzuhalten.</p>\r\n<p> </p>\r\n<p>4.3 Produktregeln</p>\r\n<p>4.3.1 Einsicht in Handelsinformationen</p>\r\n<p>4.3.2 Einsicht in Transaktionsverlauf</p>\r\n<p>Sie können über Ihr Konto Ihre Handelsaufzeichnungen einsehen.</p>\r\n<p>V. Rechte und Pflichten dieser Website</p>\r\n<p>5.1 Wenn Sie nicht über die in dieser Vereinbarung festgelegten Registrierungsqualifikationen verfügen, ist diese Website berechtigt, Ihre Registrierung abzulehnen. Bereits registrierte Konten können gelöscht werden. Die Website behält sich das Recht vor, Sie oder Ihren bevollmächtigten Vertreter zur Verantwortung zu ziehen. Die Website behält sich zudem in allen anderen Fällen das Recht vor, nach eigenem Ermessen über die Annahme Ihrer Registrierung zu entscheiden.</p>\r\n<p>5.2 Stellt die Website nach eigenem Ermessen fest, dass Sie oder mit Ihnen verbundene Konten für risikoreiche Investitionen ungeeignet sind, ist sie berechtigt, Ihr Konto sowie alle verbundenen Konten zu sperren oder zu kündigen.</p>\r\n<p>5.3 Stellt die Website fest, dass der Kontonutzer nicht der ursprüngliche registrierte Nutzer ist, ist sie berechtigt, das Konto zu sperren oder zu kündigen.</p>\r\n<p>5.4 Wenn die Website durch technische oder manuelle Überprüfung den begründeten Verdacht hat, dass von Ihnen bereitgestellte Informationen falsch, unwahr, ungültig oder unvollständig sind, ist sie berechtigt, Sie zur Korrektur oder Aktualisierung aufzufordern bzw. die Dienste auszusetzen oder zu beenden.</p>\r\n<p>5.5 Bei offensichtlichen Fehlern in den auf der Website dargestellten Informationen ist die Website berechtigt, diese zu korrigieren.</p>\r\n<p>5.6 Die Website behält sich das Recht vor, die Dienste jederzeit zu ändern, auszusetzen oder zu beenden. Die Ausübung dieses Rechts bedarf keiner vorherigen Ankündigung. Bei Beendigung einzelner oder aller Dienste tritt diese mit der Veröffentlichung auf der Website in Kraft.</p>\r\n<p>5.7 Die Website wird angemessene technische Maßnahmen und Managementmethoden ergreifen, um den normalen Betrieb sicherzustellen, eine zuverlässige Handelsumgebung zu bieten und die Ordnung des digitalen Vermögenshandels zu wahren.</p>\r\n<p>5.8 Wenn Sie sich ein Jahr lang nicht mit Ihrem Mitgliedskonto und Passwort auf der Website anmelden, ist die Website berechtigt, Ihr Konto zu löschen und den Benutzernamen anderen zur Registrierung freizugeben.</p>\r\n<p>5.9 Die Website wird durch technische Maßnahmen und Sicherheitsvorkehrungen den Schutz Ihrer digitalen Vermögenswerte gewährleisten und Sie im Fall vorhersehbarer Sicherheitsrisiken rechtzeitig benachrichtigen.</p>\r\n<p>5.10 Die Website ist berechtigt, ohne vorherige Mitteilung Inhalte zu löschen, die gegen Gesetze, Vorschriften oder die Website-Regeln verstoßen.</p>\r\n<p>5.11 Die Website ist berechtigt, entsprechend den Anforderungen des Rechtsraums Ihres Heimatlandes oder -gebiets zusätzliche Informationen von Ihnen zu verlangen und angemessene Maßnahmen zu ergreifen, um den lokalen Vorschriften zu entsprechen. Sie sind zur Zusammenarbeit verpflichtet. Die Website kann den Dienst für Sie ganz oder teilweise vorübergehend oder dauerhaft einstellen.</p>\r\n<p>5.12 Die Website behält sich das Recht vor, Ihr Konto nach einer Frist von sieben Werktagen nach Ankündigung zu schließen. Sie haben innerhalb dieser Zeit Ihre Aufträge zu stornieren oder Positionen zu schließen. Nach Ablauf dieser Frist wird die Website dies erzwingen und Ihnen die verbleibenden digitalen Vermögenswerte zurückerstatten.</p>\r\n<p>5.13 Zum Schutz der Händlerrechte ist die Website in besonderen Fällen (z. B. Systemausfall, Netzwerkausfall, extreme Marktbedingungen usw.) berechtigt, bereits gelistete Produkte anzupassen, z. B. vorzeitige Abrechnung von Kontrakten. Die Details hierzu richten sich nach der Ankündigung auf der Website.</p>\r\n<p> </p>\r\n<p>VI. Entschädigung</p>\r\n<p>6.1 Unsere Haftung für direkte Schäden ist in jedem Fall auf die von Ihnen in einem Zeitraum von drei (3) Monaten gezahlten Gesamtservicegebühren beschränkt.</p>\r\n<p>6.2 Bei Verstoß gegen diese Vereinbarung oder gesetzliche Bestimmungen sind Sie verpflichtet, uns mindestens 2 Millionen US-Dollar sowie alle daraus entstehenden Kosten (einschließlich Anwaltskosten) zu ersetzen. Reicht dies nicht zur Deckung des tatsächlichen Schadens aus, müssen Sie die Differenz begleichen.</p>\r\n<p> </p>\r\n<p>VII. Recht auf Unterlassung</p>\r\n<p>Beide Parteien erkennen an, dass gewöhnliche Rechtsmittel möglicherweise nicht ausreichen, um unsere Verluste bei einem (drohenden) Vertragsbruch Ihrerseits zu kompensieren. Daher behalten wir uns das Recht vor, neben anderen Rechtsmitteln eine einstweilige Verfügung zu beantragen.</p>\r\n<p> </p>\r\n<p>VIII. Haftungsbeschränkung und Haftungsausschluss</p>\r\n<p>8.1 Sie erkennen an und stimmen zu, dass wir unter keinen Umständen für Folgendes haften:</p>\r\n<p>8.1.1 Einkommensverluste;</p>\r\n<p>8.1.2 Verlust von Handelsgewinnen oder Verträgen;</p>\r\n<p>8.1.3 Verluste durch Geschäftsunterbrechung;</p>\r\n<p>8.1.4 Verlust erwarteter Einsparungen;</p>\r\n<p>8.1.5 Verluste durch fehlerhafte Informationen;</p>\r\n<p>8.1.6 Verlust von Chancen, Goodwill oder Ruf;</p>\r\n<p>8.1.7 Beschädigung oder Verlust von Daten;</p>\r\n<p>8.1.8 Kosten für den Erwerb von Ersatzprodukten oder -diensten;</p>\r\n<p>8.1.9 Indirekte, besondere oder beiläufige Verluste oder Schäden, unabhängig davon, ob diese vorhersehbar waren oder uns mitgeteilt wurden.</p>\r\n<p>8.1.1 bis 8.1.9 sind voneinander unabhängig.</p>\r\n<p>8.2 Sie stimmen zu, dass wir keine Haftung übernehmen bei:</p>\r\n<p>8.2.1 Groben Rechtsverstößen in Ihren Transaktionen;</p>\r\n<p>8.2.2 Gesetzeswidrigem oder unethischem Verhalten Ihrerseits;</p>\r\n<p>8.2.3 Verlusten durch Käufe, Informationen oder Handlungen über die Website;</p>\r\n<p>8.2.4 Missverständnissen Ihrerseits in Bezug auf die Website-Dienste;</p>\r\n<p>8.2.5 Verlusten durch nicht von uns verschuldete Umstände.</p>\r\n<p>8.3 Wir haften nicht bei Dienstunterbrechungen oder -verzögerungen durch z. B. Wartung, Netzwerkprobleme, Systemausfälle, Naturkatastrophen, Streiks, Unruhen, Kriege, Marktcrashs, staatliche Maßnahmen oder andere unkontrollierbare Ereignisse.</p>\r\n<p>8.4 Wir garantieren nicht, dass die Informationen, Programme oder Inhalte der Website frei von Viren oder anderen schädlichen Komponenten sind. Die Nutzung erfolgt auf eigenes Risiko.</p>\r\n<p>8.5 Wir übernehmen keine Verantwortung für Inhalte, Produkte oder Dienstleistungen auf verlinkten Drittanbieter-Websites.</p>\r\n<p>8.6 Wir übernehmen keine ausdrücklichen oder stillschweigenden Garantien in Bezug auf die Website-Dienste, einschließlich Markttauglichkeit, Fehlerfreiheit, Zuverlässigkeit oder Eignung für bestimmte Zwecke.</p>\r\n<p>8.7 Unsere in dieser Vereinbarung enthaltenen Garantien und Zusagen stellen unsere einzigen Zusicherungen dar und ersetzen alle anderen mündlichen oder schriftlichen, ausdrücklichen oder stillschweigenden Zusicherungen.</p>\r\n<p>8.8 Wir behalten uns sämtliche gesetzlich zulässigen Rechte zur Beschränkung oder Aufhebung unserer Haftung vor, die nicht in dieser Vereinbarung aufgeführt sind.</p>\r\n<p>8.9 Mit der Registrierung erkennen Sie an, dass alle Risiken aus unseren Handlungen gemäß dieser Vereinbarung von Ihnen getragen werden.</p>\r\n<p> </p>\r\n<p>IX. Vertragsbeendigung</p>\r\n<p>9.1 Die Website ist berechtigt, gemäß dieser Vereinbarung sämtliche Dienste zu beenden. Die Vereinbarung endet mit dem Tag der Beendigung aller Dienste.</p>\r\n<p>9.2 Nach Vertragsbeendigung haben Sie keinen Anspruch auf weitere Dienste oder Pflichten unsererseits, einschließlich Datenzugang oder Weiterleitung von Informationen.</p>\r\n<p>9.3 Die Beendigung dieser Vereinbarung berührt nicht das Recht der nicht vertragsbrüchigen Partei auf weitere Schadensersatzansprüche.</p>\r\n<p> </p>\r\n<p>X. Geistiges Eigentum</p>\r\n<p>10.1 Alle Inhalte auf dieser Website, einschließlich Logos, Datenbanken, Designs, Texte, Bilder, Software, Musik, Quellcodes etc., unterliegen unserem geistigen Eigentum. Eine gewerbliche Nutzung ist untersagt.</p>\r\n<p>10.2 Alle Rechte an den im Namen der Website enthaltenen Marken und Logos gehören der Firma.</p>\r\n<p>10.3 Mit Annahme dieser Vereinbarung übertragen Sie alle urheberrechtlichen Nutzungsrechte an auf der Website veröffentlichten Inhalten unentgeltlich und exklusiv auf die Website. Die Website ist berechtigt, bei Verletzungen Klage zu erheben.</p>\r\n<p>10.4 Sie dürfen geistige Eigentumsrechte der Website oder Dritter nicht unrechtmäßig nutzen oder veräußern und veröffentlichte Inhalte nicht anderweitig verbreiten.</p>\r\n<p> </p>\r\n<p>XI. Datenschutz</p>\r\n<p>Es gilt die separat veröffentlichte Datenschutzerklärung.</p>\r\n<p> </p>\r\n<p>XII. Berechnungen</p>\r\n<p>Alle Transaktionen werden von uns überprüft, die Berechnungsmethoden sind öffentlich. Störungen oder Fehlerfreiheit können nicht garantiert werden.</p>\r\n<p> </p>\r\n<p>XIII. Exportkontrolle</p>\r\n<p>Sie erklären, die Website-Materialien nicht unter Verstoß gegen geltende Exportgesetze zu exportieren oder zu übertragen, und verpflichten sich, Verstöße unverzüglich zu melden.</p>\r\n<p> </p>\r\n<p>XIV. Abtretung</p>\r\n<p>Die Rechte und Pflichten dieser Vereinbarung gelten auch für Rechtsnachfolger. Sie dürfen Rechte nicht ohne unsere Zustimmung abtreten, wir hingegen dürfen dies jederzeit tun.</p>\r\n<p> </p>\r\n<p>XV. Salvatorische Klausel</p>\r\n<p>Sollte eine Klausel dieser Vereinbarung unwirksam sein, bleibt die Wirksamkeit der übrigen unberührt.</p>\r\n<p> </p>\r\n<p>XVI. Kein Vertretungsverhältnis</p>\r\n<p>Keine Bestimmung dieser Vereinbarung begründet ein Vertretungs-, Treuhand- oder ähnliches Verhältnis, es sei denn, dies ist ausdrücklich vorgesehen.</p>\r\n<p> </p>\r\n<p>XVII. Verzicht</p>\r\n<p>Ein Verzicht auf Rechte stellt keinen Verzicht auf andere Rechte oder zukünftige Geltendmachung dar.</p>\r\n<p> </p>\r\n<p>XVIII. Überschriften</p>\r\n<p>Die Überschriften dienen nur der Übersichtlichkeit und haben keinen Einfluss auf die Auslegung.</p>\r\n<p> </p>\r\n<p>XIX. Anwendbares Recht</p>\r\n<p>19.1 Vor gerichtlicher Geltendmachung verpflichten Sie sich zur gütlichen Streitbeilegung per E-Mail.</p>\r\n<p>19.2 Streitigkeiten über diese Vereinbarung unterliegen den jeweils gültigen ICC-Schiedsregeln. Schiedsort ist Belize, Sprache ist Englisch, und es gilt das durch die ICC-Regeln bestimmte Recht. Es gibt nur einen Schiedsrichter, dessen Entscheidung endgültig und in allen zuständigen Gerichten vollstreckbar ist.</p>\r\n<p>Zwanzig. Inkrafttreten und Auslegung der Vereinbarung</p>\r\n<p>20.1 Diese Vereinbarung tritt in Kraft, wenn Sie auf der Registrierungsseite dieser Website auf „Registrieren“ klicken und den Registrierungsprozess abgeschlossen sowie ein Konto und Passwort erhalten haben. Ab diesem Zeitpunkt ist sie sowohl für die Website als auch für Sie bindend.</p>\r\n<p>20.2 Das endgültige Auslegungsrecht dieser Vereinbarung liegt bei dieser Website.</p>\r\n<p> </p>\r\n<p>KYC- und Anti-Geldwäsche-Richtlinie</p>\r\n<p> </p>\r\n<p>I. Einleitung</p>\r\n<p>1.1 Wir verpflichten uns, die relevanten Gesetze und Vorschriften im Zusammenhang mit „Know Your Customer“ (KYC) und der Bekämpfung von Geldwäsche (AML) gewissenhaft einzuhalten und werden diese KYC- und Anti-Geldwäsche-Richtlinie keinesfalls vorsätzlich verletzen. Im Rahmen unserer zumutbaren Kontrolle werden wir die erforderlichen Maßnahmen und Technologien ergreifen, um Ihnen einen sicheren Service zu bieten und Sie bestmöglich vor Verlusten durch Geldwäscheaktivitäten krimineller Verdächtiger zu schützen.</p>\r\n<p>1.2 Unsere KYC- und Anti-Geldwäsche-Richtlinie ist ein umfassendes internationales Regelwerk, das die jeweiligen KYC- und AML-Vorschriften der verschiedenen Rechtssysteme umfasst, unter die Sie fallen.</p>\r\n<p> </p>\r\n<p>II. Die KYC- und Anti-Geldwäsche-Richtlinie umfasst Folgendes:</p>\r\n<p>2.1 Veröffentlichung und regelmäßige Aktualisierung der KYC- und AML-Richtlinie zur Einhaltung der geltenden gesetzlichen Standards;</p>\r\n<p>2.2 Veröffentlichung und Aktualisierung interner Richtlinien und Regeln für den Betrieb dieser Website, an die sich unsere Mitarbeiter bei der Servicebereitstellung halten;</p>\r\n<p>2.3 Entwicklung und Implementierung interner Kontroll- und Überwachungsverfahren für Transaktionen, einschließlich strenger Identitätsprüfungen und Bildung eines spezialisierten AML-Teams;</p>\r\n<p>2.4 Anwendung risikobasierter Verfahren zur Sorgfaltspflichtprüfung und laufender Überwachung von Kunden;</p>\r\n<p>2.5 Überprüfung und regelmäßige Prüfung bereits durchgeführter Transaktionen;</p>\r\n<p>2.6 Meldung verdächtiger Transaktionen an die zuständigen Behörden;</p>\r\n<p>2.7 Aufbewahrung von Identitätsnachweisen, Adressnachweisen und Transaktionsunterlagen für mindestens sechs Jahre. Diese können den Aufsichtsbehörden ohne vorherige Mitteilung an Sie zur Verfügung gestellt werden.</p>\r\n<p> </p>\r\n<p>III. Identitätsinformationen und Verifizierung</p>\r\n<p>3.1 Identitätsinformationen</p>\r\n<p>3.1.1 Abhängig von der jeweiligen Gerichtsbarkeit und der Art der juristischen Person können die von uns erhobenen Informationen variieren. In der Regel erfassen wir von registrierten natürlichen Personen folgende Informationen:</p>\r\n<p> </p>\r\n<p>Grundlegende persönliche Informationen: Ihr Name, Ihre Adresse (und permanente Adresse, falls abweichend), Geburtsdatum, Staatsangehörigkeit sowie sonstige verfügbare Informationen. Die Identitätsverifizierung erfolgt anhand offizieller oder gleichwertig autorisierter Dokumente, z. B. Reisepass, Personalausweis oder anderer von der jeweiligen Rechtsordnung verlangter Nachweise. Ihre angegebene Adresse wird durch geeignete Mittel überprüft, etwa durch Fahrkartenbelege, Rechnungen oder Wählerverzeichnisse.</p>\r\n<p> </p>\r\n<p>Gültiges Foto: Vor der Registrierung müssen Sie ein Foto vorlegen, auf dem Sie Ihr Ausweisdokument vor der Brust halten.</p>\r\n<p> </p>\r\n<p>Kontaktdaten: Telefonnummer/Handynummer und/oder gültige E-Mail-Adresse.</p>\r\n<p> </p>\r\n<p>3.1.2 Wenn Sie ein Unternehmen oder eine andere juristische Person sind, erheben wir folgende Informationen, um den wirtschaftlich Berechtigten Ihres oder eines Treuhandkontos zu identifizieren:</p>\r\n<p> </p>\r\n<p>Handelsregisterauszug und Gründungsurkunde;</p>\r\n<p> </p>\r\n<p>Kopie der Satzung und des Gesellschaftsvertrags;</p>\r\n<p> </p>\r\n<p>Nachweis über die Eigentumsstruktur und Beteiligungsverhältnisse des Unternehmens sowie der Vorstandsbeschluss zur Kontoeröffnung und zur Ernennung eines Bevollmächtigten;</p>\r\n<p> </p>\r\n<p>Identitätsnachweise der Geschäftsführer, Hauptanteilseigner und zeichnungsberechtigten Personen für das Website-Konto;</p>\r\n<p> </p>\r\n<p>Hauptgeschäftssitz des Unternehmens; falls abweichend: auch Postanschrift. Weichen diese voneinander ab, wird der Kunde als risikoreich eingestuft und muss zusätzliche Unterlagen vorlegen.</p>\r\n<p> </p>\r\n<p>Je nach Gerichtsbarkeit und Unternehmensform können weitere Nachweise oder von Behörden ausgestellte Dokumente verlangt werden, die wir für erforderlich halten.</p>\r\n<p> </p>\r\n<p>3.1.3 Wir akzeptieren nur Identitätsinformationen auf Englisch oder Chinesisch. Liegen diese nicht in einer dieser Sprachen vor, sind sie ins Englische zu übersetzen und notariell zu beglaubigen.</p>\r\n<p> </p>\r\n<p>3.2 Verifizierung</p>\r\n<p>3.2.1 Sie müssen alle Seiten Ihres Ausweisdokuments vorlegen.</p>\r\n<p>3.2.2 Sie müssen ein Foto vorlegen, auf dem Sie Ihr Ausweisdokument vor der Brust halten.</p>\r\n<p>3.2.3 Kopien von Nachweisdokumenten müssen grundsätzlich mit dem Original abgeglichen werden. Ist dies nicht möglich, genügt eine beglaubigte Kopie, sofern der Beglaubigende vertrauenswürdig und geeignet ist – z. B. Botschafter, Friedensrichter, örtlicher Sheriff etc.</p>\r\n<p>3.2.4 Zur Feststellung des wirtschaftlich Berechtigten und der Kontrollinhaber eines Kontos ist zu klären, welche Personen das Unternehmen letztlich besitzen oder kontrollieren und/oder ob Transaktionen im Auftrag anderer durchgeführt werden. Bei Unternehmen müssen insbesondere Hauptanteilseigner identifiziert werden (z. B. solche mit 10 % oder mehr Stimmrechten). Ein Anteil von 25 % gilt als normales Risiko und der Inhaber muss identifiziert werden; ein Anteil von 10 % oder mehr wird als erhöhtes Risiko angesehen, die Identität des Inhabers muss dann verifiziert werden.</p>\r\n<p> </p>\r\n<p>IV. Transaktionsüberwachung</p>\r\n<p>4.1 Wir legen je nach Sicherheitslage und tatsächlichem Transaktionsverhalten tägliche Transaktions- und Auszahlungslimits fest und passen sie laufend an.</p>\r\n<p>4.2 Wenn bei einem registrierten Nutzer übermäßig viele Transaktionen oder ungewöhnliches Verhalten auftreten, wird unser Fachteam diese bewerten und entscheiden, ob ein Verdacht besteht.</p>\r\n<p>4.3 Wenn wir eine Transaktion nach unserem Ermessen als verdächtig einstufen, können wir einschränkende Maßnahmen ergreifen, etwa die Transaktion auszusetzen oder abzulehnen oder sie gegebenenfalls rückgängig zu machen. Darüber hinaus wird eine Meldung an die zuständigen Behörden erfolgen, ohne dass Sie darüber informiert werden.</p>\r\n<p>4.4 Wir behalten uns das Recht vor, Anträge von Personen aus Ländern, die nicht den internationalen AML-Standards entsprechen, oder von politisch exponierten Personen abzulehnen. Wir behalten uns ferner das Recht vor, verdächtige Transaktionen jederzeit auszusetzen oder zu beenden. Dies stellt keinen Verstoß gegen unsere Verpflichtungen Ihnen gegenüber dar.</p>', 'Dieser Vertrag wird zwischen Ihnen (\" Sie\" oder\" Sie\") und Coterminal abgeschlossen.');
INSERT INTO `article_translations` VALUES (317, 91, 'it', 'Accordo utente', '<p>Sito web specializzato nella fornitura agli utenti di una piattaforma per il trading di asset digitali e servizi correlati (di seguito denominati “i Servizi” o “Servizio”). Ai fini della presente Convenzione, il sito è indicato collettivamente come “noi” o con altri riferimenti alla prima persona. Qualsiasi persona fisica o altro soggetto che acceda al sito sarà considerato utente del sito, e ai fini della presente Convenzione, verrà indicato come “voi” o altri riferimenti alla seconda persona. Per semplicità espressiva, “noi” e “voi” saranno indicati congiuntamente come “le Parti”, e individualmente come “la Parte”.</p>\r\n<p> </p>\r\n<p>Avviso importante:</p>\r\n<p> </p>\r\n<p>Richiamiamo la vostra particolare attenzione su quanto segue:</p>\r\n<p> </p>\r\n<p>Gli asset digitali non sono emessi da alcuna istituzione finanziaria, azienda o dal sito web.</p>\r\n<p> </p>\r\n<p>Il mercato degli asset digitali è nuovo, non confermato e potrebbe non crescere.</p>\r\n<p> </p>\r\n<p>Gli asset digitali sono principalmente utilizzati da speculatori, mentre l’uso nei mercati al dettaglio e commerciali è relativamente limitato; il trading di asset digitali comporta rischi elevati, viene effettuato 24 ore su 24 senza limiti di fluttuazione, e i prezzi sono soggetti a forti oscillazioni a causa di fattori come i manipolatori del mercato e le politiche governative globali.</p>\r\n<p> </p>\r\n<p>Se la Società, a propria esclusiva discrezione, ritiene che abbiate violato la presente Convenzione, oppure se le leggi della vostra giurisdizione rendono illegali i Servizi forniti dal sito o il vostro utilizzo degli stessi, la Società ha il diritto di sospendere o terminare il vostro account o l\'accesso al Servizio. È vietato a qualsiasi persona proveniente da [Cina continentale, Taiwan, Israele, Iraq, Bangladesh, Bolivia, Ecuador, Kirghizistan, Sebastopoli] utilizzare i servizi di contratti offerti dal sito. L\'elenco può variare in base alle politiche locali e ai tipi di prodotto; tali modifiche possono avvenire senza preavviso, pertanto siete invitati a consultare regolarmente gli aggiornamenti della presente Convenzione.</p>\r\n<p> </p>\r\n<p>Il trading di asset digitali comporta rischi elevati ed è inadatto alla maggior parte delle persone. Comprendete e accettate che tali operazioni potrebbero comportare perdite parziali o totali, pertanto dovreste investire solo ciò che siete disposti a perdere. Esistono anche rischi derivati non prevedibili. Se avete dubbi, consultate un consulente professionale. Assumetevi ogni responsabilità per le perdite derivanti dalle vostre decisioni, e non potremo essere ritenuti responsabili.</p>\r\n<p> </p>\r\n<p>Avviso:</p>\r\n<p> </p>\r\n<p>Comprendete che il sito è solo una piattaforma per l’accesso alle informazioni sugli asset digitali, ricerca di controparti, negoziazione e conclusione di operazioni. Il sito non partecipa a nessuna delle vostre transazioni, perciò siete tenuti a valutare autonomamente l’autenticità, legalità ed efficacia delle informazioni e degli asset digitali e ad assumervi tutte le responsabilità e perdite.</p>\r\n<p> </p>\r\n<p>Qualsiasi opinione, notizia, analisi, prezzo, consiglio o informazione presente sul sito costituisce solo un commento generale di mercato e non rappresenta un consiglio di investimento. Non siamo responsabili per perdite derivanti direttamente o indirettamente da tali informazioni.</p>\r\n<p> </p>\r\n<p>Il sito si riserva il diritto di modificare i contenuti in qualsiasi momento. Sebbene vengano adottate misure ragionevoli per garantirne l’accuratezza, non possiamo assicurarla e non ci assumiamo alcuna responsabilità per perdite derivanti da ritardi o errori di comunicazione.</p>\r\n<p> </p>\r\n<p>L\'uso di sistemi di trading via Internet comporta rischi, inclusi guasti software, hardware e di connessione. Non siamo responsabili per distorsioni, ritardi o interruzioni di connessione.</p>\r\n<p> </p>\r\n<p>È vietato utilizzare il sito per attività illegali come riciclaggio di denaro, contrabbando, corruzione commerciale. In caso di attività sospette, il sito adotterà misure, come il blocco dell’account e la notifica alle autorità competenti. Non ci assumiamo alcuna responsabilità e ci riserviamo il diritto di rivalerci sugli autori.</p>\r\n<p> </p>\r\n<p>È vietato manipolare il mercato o eseguire operazioni scorrette. In caso di comportamenti non etici, il sito potrà adottare misure preventive, come avvisi, restrizioni, sospensione degli account. Non ci assumiamo responsabilità e ci riserviamo il diritto di rivalerci sugli autori.</p>\r\n<p> </p>\r\n<p>I. Disposizioni generali</p>\r\n<p> </p>\r\n<p>1.1 Il presente “Accordo per l’Utente” (di seguito “il presente Accordo” o “le presenti Condizioni”) è costituito dal presente testo, dall’“Informativa sulla privacy”, dalla “Politica Know Your Customer e Antiriciclaggio” e da tutti gli altri regolamenti, dichiarazioni e linee guida pubblicati dal sito attualmente o in futuro.</p>\r\n<p>1.2 Prima di utilizzare i Servizi, leggete attentamente il presente Accordo. Se non lo comprendete o avete dubbi, consultate un avvocato. Se non accettate il presente Accordo o le sue modifiche, interrompete immediatamente l’uso del sito. L’accesso o l’utilizzo del sito equivale all’accettazione completa dell’Accordo, incluse eventuali modifiche future.</p>\r\n<p>1.3 Diventate membri del sito compilando le informazioni richieste e completando le relative procedure, e facendo clic su “Accetto”, stipulate un accordo con valore di firma elettronica. Qualsiasi uso dei Servizi implica piena accettazione dell’Accordo, anche in assenza di una firma autografa.</p>\r\n<p>1.4 Una volta registrati, riceverete un account e una password, di cui sarete responsabili. Siete responsabili di tutte le attività effettuate tramite il vostro account.</p>\r\n<p>1.5 Solo i membri registrati possono utilizzare i Servizi di trading del sito. I non membri possono solo accedere e visualizzare alcune informazioni.</p>\r\n<p>1.6 Registrandovi e utilizzando i Servizi, dichiarate di:</p>\r\n<p> </p>\r\n<p>Accettare tutte le condizioni dell’Accordo.</p>\r\n<p> </p>\r\n<p>Avere almeno 18 anni o l’età legale secondo le leggi applicabili, ed essere capaci di stipulare contratti.</p>\r\n<p> </p>\r\n<p>Possedere legalmente gli asset digitali coinvolti.</p>\r\n<p> </p>\r\n<p>Assumervi piena responsabilità per le operazioni e i relativi profitti o perdite.</p>\r\n<p> </p>\r\n<p>Fornire informazioni veritiere.</p>\r\n<p> </p>\r\n<p>Conformarvi alle normative fiscali applicabili.</p>\r\n<p> </p>\r\n<p>Non intraprendere attività dannose per il sito.</p>\r\n<p> </p>\r\n<p>Riconoscere che l’Accordo regola solo il rapporto tra voi e il sito, non tra utenti.</p>\r\n<p> </p>\r\n<p>II. Modifica dell’accordo</p>\r\n<p> </p>\r\n<p>Ci riserviamo il diritto di modificare l’Accordo pubblicandone la nuova versione sul sito, senza notifica individuale. La modifica entrerà in vigore al momento della pubblicazione. Siete invitati a consultare regolarmente l’Accordo; l’uso continuato dei Servizi equivale all’accettazione delle modifiche.</p>\r\n<p> </p>\r\n<p>III. Registrazione</p>\r\n<p> </p>\r\n<p>3.1 Requisiti: Completando la registrazione o utilizzando i Servizi, dichiarate di essere legalmente capaci, o rappresentati da persona legittimata, a stipulare il presente Accordo.</p>\r\n<p>3.2 Finalità: Registrandovi, dichiarate che non lo fate per violare leggi o disturbare l’ordine del mercato.</p>\r\n<p>3.3 Procedura:</p>\r\n<p> </p>\r\n<p>Fornite email e numero di telefono validi; potete usare tali credenziali per accedere. A seconda delle leggi locali, potrebbe esservi richiesto di fornire nome reale, documenti di identità e aggiornarli.</p>\r\n<p> </p>\r\n<p>Se richiesto dalla normativa locale, dichiarate che il numero di telefono fornito è stato registrato con nome reale.</p>\r\n<p> </p>\r\n<p>Una volta forniti i dati e verificati, riceverete account e password.</p>\r\n<p> </p>\r\n<p>Accettate di ricevere email e SMS relativi alla gestione del sito.</p>\r\n<p> </p>\r\n<p>IV. Servizi</p>\r\n<p> </p>\r\n<p>Il sito fornisce una piattaforma per il trading di asset digitali e altri servizi correlati.</p>\r\n<p> </p>\r\n<p>4.1 Contenuto dei servizi:</p>\r\n<p> </p>\r\n<p>Potete visualizzare i prezzi in tempo reale e le informazioni di mercato.</p>\r\n<p> </p>\r\n<p>Potete inviare ordini e completare transazioni.</p>\r\n<p> </p>\r\n<p>Potete accedere alle informazioni del vostro account e usare le funzionalità.</p>\r\n<p> </p>\r\n<p>Potete partecipare alle attività promozionali.</p>\r\n<p> </p>\r\n<p>Il sito fornisce altri servizi a sua discrezione.</p>\r\n<p> </p>\r\n<p>4.2 Regole di utilizzo:</p>\r\n<p> </p>\r\n<p>Rispettate tutte le leggi e garantite la legalità degli asset presenti nel vostro account.</p>\r\n<p> </p>\r\n<p>Proteggete i vostri dati di accesso (account, password, codici di verifica) e assumetevi la responsabilità di tutte le attività svolte.</p>\r\n<p> </p>\r\n<p>In caso di accesso non autorizzato, avvisate il sito tempestivamente.</p>\r\n<p> </p>\r\n<p>Non trasferite l’account a terzi senza autorizzazione.</p>\r\n<p> </p>\r\n<p>Assumetevi la responsabilità per tutte le attività del vostro account.</p>\r\n<p> </p>\r\n<p>Non interferite con le operazioni di mercato, non disturbate altri utenti, non danneggiate la reputazione del sito.</p>\r\n<p> </p>\r\n<p>In caso di controversie con altri utenti, non richiedete al sito la divulgazione di dati personali tramite mezzi extra-giudiziali.</p>\r\n<p> </p>\r\n<p>Vi assumete le spese e tasse derivanti dall’uso del sito.</p>\r\n<p> </p>\r\n<p>Rispettate tutte le regole pubblicate dal sito e ci riserviamo il diritto di terminare i Servizi in qualsiasi momento.</p>\r\n<p> </p>\r\n<p>4.3 Regole dei prodotti:</p>\r\n<p> </p>\r\n<p>Potete visualizzare le informazioni sulle operazioni.</p>\r\n<p> </p>\r\n<p>Potete accedere allo storico delle transazioni attraverso il vostro account.</p>\r\n<p>V. Diritti e Obblighi di Questo Sito Web</p>\r\n<p>5.1 Se non possiedi i requisiti di registrazione previsti dal presente accordo, questo sito web ha il diritto di rifiutare la tua registrazione; se sei già registrato, il sito web ha il diritto di annullare il tuo account membro. Il sito si riserva il diritto di perseguire la responsabilità nei tuoi confronti o nei confronti del tuo rappresentante autorizzato. Allo stesso tempo, il sito web si riserva il diritto di decidere in qualsiasi momento se accettare la tua registrazione.</p>\r\n<p>5.2 In base al proprio giudizio, qualora il sito rilevi che tu o utenti con account correlati non siete adatti a investimenti ad alto rischio, ha il diritto di sospendere o terminare l’uso del tuo account e di tutti gli account correlati.</p>\r\n<p>5.3 Se il sito scopre che l’utente dell’account non è il registrante originario, ha il diritto di sospendere o terminare l’uso dell’account.</p>\r\n<p>5.4 Se tramite controlli tecnici o controlli manuali, il sito sospetta ragionevolmente che le informazioni fornite siano errate, false, non valide o incomplete, ha il diritto di notificarti per correggerle o aggiornarle, oppure di sospendere o terminare i servizi forniti.</p>\r\n<p>5.5 Il sito ha il diritto di correggere qualsiasi informazione visualizzata che presenti evidenti errori.</p>\r\n<p>5.6 Il sito si riserva il diritto di modificare, sospendere o terminare i servizi in qualsiasi momento senza preavviso; l’interruzione dei servizi entra in vigore dalla pubblicazione dell’annuncio sul sito web.</p>\r\n<p>5.7 Il sito adotterà le misure tecniche e gestionali necessarie per garantire il funzionamento normale e fornire un ambiente e servizi di trading sicuri, mantenendo l’ordine del trading di asset digitali.</p>\r\n<p>5.8 Se non accedi con nome utente e password per un anno consecutivo, il sito può cancellare il tuo account. Dopo la cancellazione, il nome utente potrà essere registrato da altri utenti.</p>\r\n<p>5.9 Il sito rafforzerà la sicurezza tecnica per proteggere i tuoi asset digitali e ti informerà in anticipo in caso di rischi di sicurezza prevedibili per il tuo account.</p>\r\n<p>5.10 Il sito ha il diritto di eliminare in qualsiasi momento contenuti non conformi alla legge o ai regolamenti del sito, senza preavviso.</p>\r\n<p>5.11 Il sito ha il diritto di richiedere ulteriori informazioni o documenti in base alle leggi del tuo Stato o territorio e può adottare misure per conformarsi alle normative locali. Il sito ha il diritto di sospendere o terminare parzialmente o totalmente i servizi per te.</p>\r\n<p>5.12 Il sito si riserva il diritto di chiudere il tuo account con sette giorni lavorativi di preavviso, durante i quali potrai annullare ordini o chiudere posizioni. Trascorso tale termine, il sito potrà forzare tali operazioni e restituirti gli asset digitali rimanenti.</p>\r\n<p>5.13 Per proteggere gli interessi dei trader, il sito può, in circostanze eccezionali (guasti di sistema, di rete, eventi estremi), modificare prodotti già attivi, ad esempio effettuare regolamenti anticipati, in base agli annunci ufficiali.</p>\r\n<p> </p>\r\n<p>VI. Risarcimenti</p>\r\n<p>6.1 In ogni caso, la nostra responsabilità risarcitoria diretta non supererà le tariffe da te pagate nei tre (3) mesi precedenti per l’uso del sito.</p>\r\n<p>6.2 Se violi l’accordo o la legge, devi risarcirci almeno 2 milioni di dollari americani e sostenere tutte le spese (inclusi onorari legali). Se il danno reale supera tale importo, sei tenuto a compensarlo integralmente.</p>\r\n<p> </p>\r\n<p>VII. Diritto a Misure Cautelari</p>\r\n<p>Entrambe le parti riconoscono che i rimedi legali potrebbero non essere sufficienti in caso di violazione o rischio di violazione del presente accordo. Pertanto, ci riserviamo il diritto di richiedere misure cautelari e altri rimedi previsti dalla legge.</p>\r\n<p> </p>\r\n<p>VIII. Limitazione di Responsabilità ed Esclusione di Garanzia</p>\r\n<p>8.1 In nessun caso saremo responsabili per:</p>\r\n<p>8.1.1 Perdita di reddito;</p>\r\n<p>8.1.2 Perdita di profitti o contratti;</p>\r\n<p>8.1.3 Interruzioni di attività;</p>\r\n<p>8.1.4 Perdita di risparmi previsti;</p>\r\n<p>8.1.5 Problemi informativi;</p>\r\n<p>8.1.6 Perdita di opportunità, reputazione o immagine;</p>\r\n<p>8.1.7 Danni o perdita di dati;</p>\r\n<p>8.1.8 Costi per prodotti o servizi alternativi;</p>\r\n<p>8.1.9 Perdite indirette, speciali o accessorie, previste o meno.</p>\r\n<p>Ogni punto da 8.1.1 a 8.1.9 è indipendente.</p>\r\n<p>8.2 Non siamo responsabili per:</p>\r\n<p>8.2.1 Atti illeciti o inadempimenti nelle tue transazioni;</p>\r\n<p>8.2.2 Atti illeciti o immorali sul sito;</p>\r\n<p>8.2.3 Costi/perdite derivanti da uso del sito;</p>\r\n<p>8.2.4 Incomprensioni sul servizio;</p>\r\n<p>8.2.5 Altre perdite non imputabili a noi.</p>\r\n<p>8.3 Non siamo responsabili per interruzioni dovute a eventi fuori dal nostro controllo (es. disastri naturali, guerre, ordini governativi, crolli di mercato, ecc.).</p>\r\n<p>8.4 Non garantiamo che il sito sia privo di virus o minacce, usi il sito a tuo rischio.</p>\r\n<p>8.5 Non garantiamo né ci assumiamo responsabilità per contenuti, prodotti o servizi di terzi collegati al sito.</p>\r\n<p>8.6 Non forniamo garanzie esplicite o implicite sull’idoneità, accuratezza, affidabilità, qualità o continuità del servizio e del mercato di asset digitali. Usare il sito è tua decisione e responsabilità.</p>\r\n<p>8.7 Le nostre garanzie derivano solo dal presente accordo, non da altri mezzi (scritti o orali, espliciti o impliciti).</p>\r\n<p>8.8 Non rinunciamo a nessun diritto di limitazione o esclusione della nostra responsabilità legale non menzionato in questo accordo.</p>\r\n<p>8.9 Con la registrazione, accetti che ogni operazione effettuata secondo questo accordo è a tuo rischio.</p>\r\n<p> </p>\r\n<p>IX. Termine del Contratto</p>\r\n<p>9.1 Il sito può terminare i servizi come da accordo. L’accordo termina alla data di cessazione dei servizi.</p>\r\n<p>9.2 Dopo la cessazione, non hai diritto a richiedere ulteriori servizi o obblighi dal sito.</p>\r\n<p>9.3 Il termine dell’accordo non pregiudica il diritto della parte adempiente a chiedere risarcimento.</p>\r\n<p> </p>\r\n<p>X. Proprietà Intellettuale</p>\r\n<p>10.1 Tutti i contenuti del sito (loghi, database, testi, software, immagini, suoni, codici sorgente ecc.) sono proprietà del sito. È vietato usarli per scopi commerciali.</p>\r\n<p>10.2 Tutti i diritti relativi al nome del sito (inclusi marchi e reputazione) appartengono alla società.</p>\r\n<p>10.3 Accettando l’accordo, concedi gratuitamente e in esclusiva al sito tutti i diritti d’autore sulle informazioni che pubblichi (inclusi diritti di riproduzione, distribuzione, adattamento, ecc.). Il sito può intraprendere azioni legali contro eventuali violazioni.</p>\r\n<p>10.4 Non puoi utilizzare o trattare illegalmente diritti di proprietà intellettuale del sito o di altri. Non puoi ripubblicare altrove contenuti del sito senza autorizzazione.</p>\r\n<p> </p>\r\n<p>XI. Protezione delle Informazioni</p>\r\n<p>Fare riferimento all’“Informativa sulla Privacy” pubblicata separatamente sul sito.</p>\r\n<p> </p>\r\n<p>XII. Calcoli</p>\r\n<p>Tutti i risultati delle transazioni sono stati verificati. I metodi di calcolo sono pubblicati sul sito, ma non si garantisce che il sito sia esente da errori o interruzioni.</p>\r\n<p> </p>\r\n<p>XIII. Controllo delle Esportazioni</p>\r\n<p>Comprendi e accetti che non puoi esportare o trasferire materiali del sito (inclusi software) in violazione delle leggi applicabili. Devi segnalare eventuali violazioni e collaborare.</p>\r\n<p> </p>\r\n<p>XIV. Cessione</p>\r\n<p>I diritti e gli obblighi previsti da questo accordo vincolano i beneficiari e i successori. Non puoi trasferire i tuoi diritti senza il nostro consenso. Noi possiamo trasferire i nostri diritti e obblighi a terzi dandoti notifica.</p>\r\n<p> </p>\r\n<p>XV. Divisibilità</p>\r\n<p>Se una clausola viene giudicata inapplicabile, invalida o illegale, ciò non influirà sulla validità delle altre clausole.</p>\r\n<p> </p>\r\n<p>XVI. Nessun Rapporto di Agenzia</p>\r\n<p>Nessuna disposizione del presente accordo costituisce un rapporto di agenzia, fiduciario o rappresentanza, salvo diversa indicazione.</p>\r\n<p> </p>\r\n<p>XVII. Rinuncia</p>\r\n<p>La rinuncia a un diritto o responsabilità non costituisce rinuncia ad altri diritti o responsabilità; l’inerzia nell’esercizio di un diritto non ne comporta la rinuncia.</p>\r\n<p> </p>\r\n<p>XVIII. Intestazioni</p>\r\n<p>Le intestazioni sono solo per comodità e non influenzano il contenuto o l’ambito delle clausole.</p>\r\n<p> </p>\r\n<p>XIX. Legge Applicabile</p>\r\n<p>19.1 Prima di procedere con una controversia, concordi di contattarci via email per tentare una risoluzione informale. Le trattative saranno confidenziali.</p>\r\n<p>19.2 In caso di controversia relativa all’accordo, le parti la sottoporranno alla Corte Arbitrale Internazionale della Camera di Commercio Internazionale (ICC), secondo le sue regole vigenti. Sede dell’arbitrato: Belize. Lingua: inglese. Salvo diverso accordo, ci sarà un solo arbitro. Il lodo arbitrale sarà definitivo e vincolante e potrà essere eseguito da qualsiasi tribunale con giurisdizione.</p>\r\n<p>Venti, Entrata in vigore e interpretazione dell’Accordo</p>\r\n<p>20.1 Il presente accordo entra in vigore nel momento in cui l\'utente clicca su \"Accetto\" nella pagina di registrazione del sito web, completa la procedura di registrazione e ottiene un account e una password. Da quel momento, l\'accordo è vincolante sia per il sito web che per l\'utente.</p>\r\n<p>20.2 Il diritto di interpretazione finale del presente accordo appartiene esclusivamente a questo sito web.</p>\r\n<p> </p>\r\n<p>Politica “Conosci il tuo cliente” e antiriciclaggio</p>\r\n<p> </p>\r\n<p>I. Introduzione</p>\r\n<p>1.1 Ci impegniamo a rispettare diligentemente le leggi e i regolamenti relativi alle politiche \"Conosci il tuo cliente\" (KYC) e antiriciclaggio, e non violeremo intenzionalmente tali politiche. Entro i limiti del nostro ragionevole controllo, adotteremo le misure e le tecnologie necessarie per fornirti servizi sicuri, cercando di proteggerti da eventuali perdite causate da attività di riciclaggio di denaro da parte di soggetti criminali.</p>\r\n<p>1.2 La nostra politica KYC e antiriciclaggio è un sistema integrato internazionale che comprende anche le normative applicabili nel tuo specifico ambito giuridico.</p>\r\n<p> </p>\r\n<p>II. Politica KYC e antiriciclaggio:</p>\r\n<p>2.1 Promulgare e aggiornare la politica KYC e antiriciclaggio per soddisfare gli standard delle leggi e dei regolamenti pertinenti;</p>\r\n<p>2.2 Promulgare e aggiornare i principi guida e le regole operative del sito web, secondo cui il nostro personale fornirà i servizi;</p>\r\n<p>2.3 Progettare e attuare procedure interne di monitoraggio e controllo delle transazioni, come metodi rigorosi di verifica dell\'identità e la costituzione di team professionali incaricati del lavoro antiriciclaggio;</p>\r\n<p>2.4 Applicare un approccio basato sul rischio per effettuare due diligence e monitoraggio continuo dei clienti;</p>\r\n<p>2.5 Esaminare e verificare regolarmente le transazioni già effettuate;</p>\r\n<p>2.6 Segnalare le transazioni sospette alle autorità competenti;</p>\r\n<p>2.7 Conservare per almeno sei anni i documenti di prova relativi all’identità, alla residenza e alla registrazione delle transazioni, che potranno essere consegnati alle autorità di regolamentazione senza preavviso all’utente.</p>\r\n<p> </p>\r\n<p>III. Informazioni sull’identità e verifica</p>\r\n<p>3.1 Informazioni sull’identità</p>\r\n<p>3.1.1 A seconda della giurisdizione e del tipo di entità, le informazioni richieste possono variare. In generale, raccoglieremo dai singoli registrati le seguenti informazioni:</p>\r\n<p> </p>\r\n<p>Informazioni personali di base: nome, indirizzo (e indirizzo permanente, se diverso), data di nascita, nazionalità e altre informazioni pertinenti. L\'identità dovrà essere verificata tramite documenti rilasciati da autorità ufficiali, come passaporto, carta d\'identità o altri documenti richiesti a seconda della giurisdizione. L\'indirizzo fornito sarà verificato tramite metodi appropriati, come la verifica di bollette o registri elettorali.</p>\r\n<p> </p>\r\n<p>Foto valida: prima della registrazione, è necessario fornire una foto con il documento d\'identità tenuto davanti al petto;</p>\r\n<p> </p>\r\n<p>Dati di contatto: numero di telefono/cellulare e/o indirizzo e-mail valido.</p>\r\n<p> </p>\r\n<p>3.1.2 Se sei un’azienda o un altro soggetto giuridico, raccoglieremo le seguenti informazioni per identificare l’effettivo beneficiario del conto fiduciario o aziendale:</p>\r\n<p> </p>\r\n<p>Certificato di registrazione dell’azienda;</p>\r\n<p> </p>\r\n<p>Copia dello statuto e dell’atto costitutivo della società;</p>\r\n<p> </p>\r\n<p>Documentazione che descriva la struttura azionaria e di proprietà;</p>\r\n<p> </p>\r\n<p>Verbale del consiglio di amministrazione che autorizza l’apertura del conto sul nostro sito e la designazione del/dei firmatario/i autorizzato/i;</p>\r\n<p> </p>\r\n<p>Documenti di identificazione dei direttori, principali azionisti e firmatari autorizzati;</p>\r\n<p> </p>\r\n<p>Indirizzo principale dell’azienda e indirizzo postale, se diverso. In caso di discrepanze tra l\'indirizzo locale e quello principale, l\'azienda sarà considerata a rischio elevato e sarà necessario fornire documentazione aggiuntiva.</p>\r\n<p> </p>\r\n<p>Ulteriori documenti certificati o rilasciati da autorità competenti, come richiesto dalla giurisdizione o ritenuti necessari.</p>\r\n<p> </p>\r\n<p>3.1.3 Accettiamo solo documenti d’identità in lingua inglese o cinese. In caso contrario, devono essere tradotti in inglese e autenticati.</p>\r\n<p> </p>\r\n<p>3.2 Verifica</p>\r\n<p>3.2.1 È necessario fornire tutte le pagine del documento d\'identità.</p>\r\n<p>3.2.2 È necessario fornire una foto in cui il documento d\'identità è tenuto davanti al petto.</p>\r\n<p>3.2.3 Le copie dei documenti devono essere verificate rispetto all’originale. Tuttavia, se un soggetto affidabile può certificare che la copia è una riproduzione accurata e completa del documento originale, sarà accettata. I certificatori riconosciuti includono ambasciatori, giudici di pace, sceriffi locali, ecc.</p>\r\n<p>3.2.4 Per identificare i beneficiari finali e i controllori del conto, è necessario determinare le persone fisiche che possiedono o controllano effettivamente il cliente diretto e/o le persone per conto delle quali sono effettuate le transazioni. Se si tratta di un\'azienda, è necessario verificare l\'identità degli azionisti principali (ad esempio, quelli che detengono il 10% o più dei diritti di voto). In generale, una quota del 25% è considerata a rischio normale e richiede verifica; una quota del 10% o superiore è considerata ad alto rischio e deve essere verificata.</p>\r\n<p> </p>\r\n<p>IV. Monitoraggio delle transazioni</p>\r\n<p>4.1 In base alla sicurezza e alla situazione effettiva delle transazioni, stabiliamo e adeguiamo i limiti massimi giornalieri per le transazioni e i prelievi;</p>\r\n<p>4.2 Se un utente effettua transazioni concentrate in modo frequente o in circostanze irragionevoli, il nostro team professionale valuterà se si tratta di operazioni sospette;</p>\r\n<p>4.3 In base al nostro giudizio, se una transazione è considerata sospetta, potremmo adottare misure restrittive come la sospensione, il rifiuto o, se possibile, l’annullamento della transazione. Potremo inoltre segnalare la transazione alle autorità competenti senza darne preavviso all’utente;</p>\r\n<p>4.4 Ci riserviamo il diritto di rifiutare le richieste di registrazione provenienti da persone residenti in giurisdizioni non conformi agli standard internazionali antiriciclaggio o da persone politicamente esposte. Ci riserviamo inoltre il diritto di sospendere o terminare in qualsiasi momento le transazioni sospette secondo il nostro giudizio, senza che ciò costituisca una violazione di alcun obbligo o responsabilità nei confronti dell’utente.</p>', NULL);
INSERT INTO `article_translations` VALUES (319, 91, 'pt', 'Contrato de utilizador', '<p>Este site é uma plataforma especializada para que os usuários realizem transações de ativos digitais e forneçam serviços relacionados (doravante denominados \"os serviços\" ou \"serviço\"). Para conveniência de expressão deste acordo, o site é referido neste acordo como “nós” ou outras formas de primeira pessoa. Qualquer pessoa física ou outra entidade que acesse este site é considerada usuário do site. Para facilitar a redação deste acordo, a seguir usa-se “você” ou outra forma de segunda pessoa. Para conveniência de expressão neste acordo, nós e você somos coletivamente denominados \"as partes\", e individualmente denominados \"uma parte\".</p>\r\n<p> </p>\r\n<p>Aviso importante:</p>\r\n<p> </p>\r\n<p>Gostaríamos de alertá-lo especialmente que:</p>\r\n<p> </p>\r\n<p>Os ativos digitais não são emitidos por nenhuma instituição financeira, empresa ou este site;</p>\r\n<p> </p>\r\n<p>O mercado de ativos digitais é novo, não confirmado e pode não se desenvolver;</p>\r\n<p> </p>\r\n<p>Os ativos digitais são amplamente utilizados por especuladores, com uso limitado nos mercados de varejo e comercial. A negociação de ativos digitais envolve riscos extremamente altos, funciona 24 horas por dia, não possui limites de alta ou baixa, e os preços podem sofrer grandes flutuações devido a influências de grandes operadores ou políticas governamentais globais;</p>\r\n<p> </p>\r\n<p>Se a empresa julgar, a seu exclusivo critério, que você violou este acordo, ou se for ilegal, conforme as leis de sua jurisdição, utilizar ou acessar os serviços deste site, a empresa terá o direito de suspender ou encerrar sua conta a qualquer momento, ou suspender ou encerrar o uso dos serviços ou transações de ativos digitais fornecidos por este site. É proibido que qualquer pessoa da [China continental, Taiwan (China), Israel, Iraque, Bangladesh, Bolívia, Equador, Quirguistão, Sebastopol] utilize os serviços de contrato fornecidos por este site. Esta lista de países ou regiões pode mudar de acordo com diferentes políticas ou tipos de produtos de diferentes países ou regiões, e talvez não forneçamos avisos específicos — recomendamos que você acompanhe as atualizações deste acordo em tempo hábil.</p>\r\n<p> </p>\r\n<p>A negociação de ativos digitais envolve riscos extremamente elevados e não é adequada para a maioria das pessoas. Você entende que essa negociação pode levar a perdas parciais ou totais, portanto, deve decidir o valor das transações com base em sua capacidade de suportar essas perdas. Você entende que os ativos digitais podem gerar riscos derivados. Em caso de dúvida, é recomendável procurar assessoria profissional. Além dos riscos mencionados acima, também existem riscos imprevisíveis. Você deve considerar cuidadosamente e com julgamento claro avaliar sua situação financeira e os riscos mencionados antes de tomar qualquer decisão de compra ou venda de ativos digitais e assumir todas as perdas decorrentes. Não nos responsabilizamos por isso.</p>\r\n<p> </p>\r\n<p>Avisos:</p>\r\n<p> </p>\r\n<p>Você entende que este site serve apenas como local para obtenção de informações sobre ativos digitais, busca de partes para negociação, negociação e realização de transações. Este site não participa de nenhuma de suas transações. Portanto, você deve julgar cuidadosamente a veracidade, legalidade e validade dos ativos digitais e/ou informações relacionadas e assumir sozinho as responsabilidades e perdas resultantes;</p>\r\n<p> </p>\r\n<p>Qualquer opinião, notícia, discussão, análise, preço, sugestão e outra informação contida neste site é apenas um comentário geral de mercado e não constitui aconselhamento de investimento. Não nos responsabilizamos por quaisquer perdas diretas ou indiretas resultantes da confiança nessas informações, incluindo, mas não se limitando à perda de lucros;</p>\r\n<p> </p>\r\n<p>Reservamo-nos o direito de modificar ou alterar o conteúdo deste site a qualquer momento, a nosso exclusivo critério. Tomamos medidas razoáveis para garantir a precisão das informações no site, mas não garantimos sua precisão nem assumimos qualquer responsabilidade por perdas diretas ou indiretas resultantes das informações ou da falha na conexão à internet, no envio ou recebimento de notificações e informações;</p>\r\n<p> </p>\r\n<p>O uso de sistemas de transação via internet também envolve riscos, incluindo, mas não se limitando a falhas de software, hardware e conexão de internet. Como não podemos controlar a confiabilidade e disponibilidade da internet, não seremos responsáveis por distorções, atrasos ou falhas de conexão;</p>\r\n<p> </p>\r\n<p>É proibido utilizar este site para lavagem de dinheiro, contrabando, suborno comercial e quaisquer outras atividades ilegais. Se forem detectadas suspeitas de transações ou atividades ilegais, tomaremos todas as medidas disponíveis, incluindo, mas não se limitando ao congelamento da conta e notificação às autoridades competentes. Não nos responsabilizamos por quaisquer consequências resultantes e reservamo-nos o direito de buscar responsabilidade junto aos envolvidos;</p>\r\n<p> </p>\r\n<p>É proibido utilizar este site para manipulação mal-intencionada do mercado, transações inadequadas ou outras atividades comerciais antiéticas. Em caso de detecção, tomaremos medidas preventivas, como advertência, restrição de transações, encerramento de contas, contra todos os comportamentos antiéticos que manipulem preços ou afetem maliciosamente o sistema de negociação. Não nos responsabilizamos pelas consequências e reservamo-nos o direito de buscar responsabilidade junto aos envolvidos.</p>\r\n<p> </p>\r\n<p>I. Disposições Gerais</p>\r\n<p>1.1 Este “Acordo do Usuário” (doravante denominado “este Acordo” ou “estes Termos e Condições”) consiste no corpo do texto, “Política de Privacidade”, “Conheça Seu Cliente e Política Antilavagem de Dinheiro” e outras regras, declarações e instruções que já foram ou poderão ser publicadas por este site no futuro.</p>\r\n<p>1.2 Antes de utilizar os serviços fornecidos por este site, você deve ler cuidadosamente este Acordo. Em caso de dúvidas ou necessidade, consulte um advogado profissional. Se você não concordar com este Acordo e/ou quaisquer modificações futuras, interrompa imediatamente o uso dos serviços deste site ou não acesse mais este site. Ao acessar este site, usar qualquer serviço do site ou realizar qualquer ação similar, você indica que compreendeu e concorda integralmente com os termos deste Acordo, incluindo quaisquer modificações futuras feitas por este site.</p>\r\n<p>1.3 Ao preencher as informações necessárias conforme exigido por este site e passar pelos demais procedimentos relevantes, você pode se registrar como membro deste site (doravante “membro”). Ao clicar no botão “Concordo” durante o processo de registro, você firma este Acordo eletronicamente com a empresa; ou ao clicar em qualquer botão indicando “concordo” ou similar ou utilizar efetivamente os serviços fornecidos pelo site, você concorda em se submeter a todos os termos deste Acordo, mesmo sem assinatura manuscrita, este Acordo tem força vinculativa legal.</p>\r\n<p>1.4 Após se tornar membro do site, você receberá uma conta de membro e senha correspondente, sendo responsável por sua guarda. Você é legalmente responsável por todas as atividades realizadas por meio de sua conta.</p>\r\n<p>1.5 Somente membros podem realizar transações de ativos digitais por meio desta plataforma e desfrutar dos serviços exclusivos aos membros conforme definido pelo site; não-membros têm acesso apenas à navegação e outros serviços limitados.</p>\r\n<p>1.6 Ao se registrar e utilizar quaisquer serviços e funcionalidades fornecidos por este site, você será considerado como tendo lido, compreendido e:</p>\r\n<p>1.6.1 Aceitado todos os termos e condições deste Acordo;</p>\r\n<p>1.6.2 Confirmado que tem pelo menos 18 anos de idade ou a idade legal exigida pelas leis aplicáveis de sua jurisdição para firmar contratos, e que sua conduta no site está em conformidade com a legislação aplicável do seu país/região, com plena capacidade para aceitar estes termos e realizar transações;</p>\r\n<p>1.6.3 Garantido que os ativos digitais utilizados em suas transações são de sua propriedade legal;</p>\r\n<p>1.6.4 Concordado em assumir total responsabilidade por suas ações, sejam transacionais ou não, e por quaisquer lucros ou perdas;</p>\r\n<p>1.6.5 Confirmado que as informações fornecidas no registro são verdadeiras e precisas;</p>\r\n<p>1.6.6 Concordado em cumprir a legislação aplicável, incluindo obrigações fiscais sobre lucros de transações;</p>\r\n<p>1.6.7 Concordado em não realizar ou participar de quaisquer ações que prejudiquem os interesses deste site, independentemente de estarem relacionadas aos serviços fornecidos;</p>\r\n<p>1.6.8 Reconhecido que este Acordo rege apenas a relação entre você e nós, não afetando as relações legais entre usuários e terceiros decorrentes de transações de ativos digitais.</p>\r\n<p> </p>\r\n<p>II. Modificações do Acordo</p>\r\n<p>Reservamo-nos o direito de revisar este Acordo periodicamente, com divulgação via aviso no site, sem notificação individual. A versão revisada será identificada com a [data da última atualização], entrando em vigor imediatamente após a publicação. Você deve acompanhar as atualizações. Se não concordar com as alterações, pare de usar os serviços imediatamente. A continuidade do uso será considerada aceitação dos termos revisados.</p>\r\n<p> </p>\r\n<p>III. Registro</p>\r\n<p>3.1 Qualificação para Registro</p>\r\n<p>Você confirma que, ao concluir o registro ou utilizar efetivamente os serviços permitidos por este site, você é uma pessoa física, jurídica ou organização com capacidade legal para firmar este Acordo. Caso contrário, você ou seu agente autorizado arcará com todas as consequências, e a empresa poderá cancelar ou congelar permanentemente sua conta e buscar responsabilização.</p>\r\n<p>3.2 Finalidade do Registro</p>\r\n<p>Você confirma que seu registro no site não tem como objetivo violar leis ou perturbar a ordem das transações de ativos digitais.</p>\r\n<p>3.3 Processo de Registro</p>\r\n<p>3.3.1 Você concorda em fornecer e manter informações válidas (e-mail, número de celular, etc.). Caso exigido por leis locais, você deverá fornecer nome verdadeiro e documento de identidade. Você é responsável pela veracidade, integridade e exatidão das informações e pelas perdas decorrentes;</p>\r\n<p>3.3.2 Se sua jurisdição exigir registro de número de celular com nome real, você concorda em fornecer número válido e registrado. Caso contrário, arcará com as perdas;</p>\r\n<p>3.3.3 Ao fornecer legalmente as informações de registro e após verificação, você obterá conta e senha do site. Com isso, o registro será concluído e você poderá acessar o site;</p>\r\n<p>3.3.4 Você concorda em receber e-mails e/ou mensagens do site relacionados à administração e operação do mesmo.</p>\r\n<p> </p>\r\n<p>IV. Serviços</p>\r\n<p>Este site fornece apenas a plataforma online para transações de ativos digitais (incluindo, mas não se limitando a, serviços de negociação).</p>\r\n<p> </p>\r\n<p>4.1 Conteúdo dos Serviços</p>\r\n<p>4.1.1 Você pode visualizar cotações e informações em tempo real, enviar ordens de transação e concluir negociações;</p>\r\n<p>4.1.2 Você pode consultar informações de sua conta de membro e utilizar as funções fornecidas pelo site;</p>\r\n<p>4.1.3 Você pode participar de atividades promovidas pelo site conforme as regras publicadas;</p>\r\n<p>4.1.4 Outros serviços prometidos pelo site.</p>\r\n<p> </p>\r\n<p>4.2 Regras de Serviço</p>\r\n<p>Você se compromete a:</p>\r\n<p>4.2.1 Cumprir leis e regulamentos, garantir a legalidade da origem dos ativos e não utilizar o site para atividades ilegais ou prejudiciais;</p>\r\n<p>4.2.2 Proteger suas credenciais de acesso (conta, senhas, número de celular, códigos de verificação). Você é responsável por todas as operações sob sua conta. Em caso de uso não autorizado, notifique o site imediatamente. O site tomará medidas dentro de tempo razoável, mas não se responsabiliza por consequências anteriores;</p>\r\n<p>4.2.3 Você é responsável por todas as atividades realizadas com sua conta;</p>\r\n<p>4.2.4 Não interferir maliciosamente nas transações, manipular o sistema ou difamar o site;</p>\r\n<p>4.2.5 Em disputas com outros usuários, não exigir informações do site por vias extrajudiciais;</p>\r\n<p>4.2.6 Assumir encargos fiscais e outros custos decorrentes do uso do serviço;</p>\r\n<p>4.2.7 Cumprir este Acordo e outras regras do site, podendo encerrar o uso a qualquer momento.</p>\r\n<p> </p>\r\n<p>4.3 Regras do Produto</p>\r\n<p>4.3.1 Visualizar informações de transações;</p>\r\n<p>4.3.2 Consultar registros de transações;</p>\r\n<p>Você pode visualizar seus registros de transações por meio de sua conta.</p>\r\n<p>V. Direitos e Obrigações deste Site</p>\r\n<p> </p>\r\n<p>5.1 Se você não possuir a qualificação de registro conforme estipulado neste Acordo, este site terá o direito de recusar seu registro; para os já registrados, este site terá o direito de cancelar sua conta de membro. Este site reserva-se o direito de responsabilizá-lo, a você ou a seu representante autorizado. Ao mesmo tempo, este site reserva-se o direito de decidir, sob qualquer circunstância, se aceita seu registro.</p>\r\n<p> </p>\r\n<p>5.2 Se este site, com base em seu próprio julgamento, descobrir que você ou o usuário de contas relacionadas não é adequado para investimentos de alto risco, terá o direito de suspender ou encerrar sua conta e todas as contas relacionadas.</p>\r\n<p> </p>\r\n<p>5.3 Se este site descobrir que o usuário da conta não é o registrante original da conta, terá o direito de suspender ou encerrar o uso da conta.</p>\r\n<p> </p>\r\n<p>5.4 Se este site suspeitar razoavelmente, por meio de verificação técnica, amostragem manual ou outros métodos, que as informações fornecidas por você estão incorretas, falsas, inválidas ou incompletas, terá o direito de notificá-lo para corrigir ou atualizar as informações, ou suspender/encerrar os serviços fornecidos a você.</p>\r\n<p> </p>\r\n<p>5.5 Este site terá o direito de corrigir informações exibidas com erros evidentes.</p>\r\n<p> </p>\r\n<p>5.6 Este site reserva-se o direito de modificar, suspender ou encerrar os serviços a qualquer momento, sem necessidade de notificação prévia. A rescisão de um ou mais serviços entra em vigor na data de publicação do aviso de encerramento no site.</p>\r\n<p> </p>\r\n<p>5.7 Este site tomará as medidas técnicas e de gestão necessárias para garantir seu funcionamento normal e fornecer um ambiente de negociação confiável, mantendo a ordem no mercado de ativos digitais.</p>\r\n<p> </p>\r\n<p>5.8 Se você não acessar sua conta por um ano consecutivo, este site terá o direito de cancelar sua conta. Após o cancelamento, o nome de membro poderá ser disponibilizado para outros usuários.</p>\r\n<p> </p>\r\n<p>5.9 Este site adotará medidas como aumento de investimento em tecnologia e aprimoramento de segurança para proteger seus ativos digitais, e o notificará antecipadamente caso haja riscos previsíveis de segurança na sua conta.</p>\r\n<p> </p>\r\n<p>5.10 Este site terá o direito de excluir, a qualquer momento, conteúdos que violem leis, regulamentos ou normas do próprio site, sem necessidade de aviso prévio.</p>\r\n<p> </p>\r\n<p>5.11 Este site tem o direito de exigir informações adicionais suas com base nas leis e normas de seu país ou região soberana, e de tomar medidas razoáveis para cumprir tais exigências. Você é obrigado a cooperar. Este site também poderá suspender ou encerrar total ou parcialmente seus serviços com base nessas normas.</p>\r\n<p> </p>\r\n<p>5.12 Este site reserva-se o direito de encerrar sua conta após aviso com sete dias úteis de antecedência. Durante esse período, você poderá cancelar ordens e fechar posições. Caso não o faça, o site o fará compulsoriamente e devolverá os ativos digitais restantes da sua conta.</p>\r\n<p> </p>\r\n<p>5.13 Para proteger os interesses dos negociadores, este site poderá, em circunstâncias especiais (como falhas de sistema, falhas de rede, eventos extremos), ajustar produtos online, como realizar liquidação antecipada. Os contratos, ciclos e preços de liquidação seguirão o que for anunciado pelo site.</p>\r\n<p> </p>\r\n<p>VI. Indenização</p>\r\n<p> </p>\r\n<p>6.1 Em qualquer circunstância, nossa responsabilidade por danos diretos será limitada ao total das taxas de serviço cobradas de você nos últimos três (3) meses.</p>\r\n<p> </p>\r\n<p>6.2 Se você violar este Acordo ou qualquer lei/regulamento, deverá nos indenizar em pelo menos 2 milhões de dólares americanos, além de cobrir todas as despesas decorrentes (incluindo honorários advocatícios). Caso não seja suficiente para cobrir os danos reais, você deverá completar a indenização.</p>\r\n<p> </p>\r\n<p>VII. Direito de Solicitar Medidas Cautelares</p>\r\n<p> </p>\r\n<p>Ambas as partes reconhecem que medidas legais comuns podem não ser suficientes para reparar danos causados por violações ou possíveis violações deste Acordo. Portanto, temos o direito de buscar medidas cautelares, além de outras medidas permitidas por lei ou equidade.</p>\r\n<p> </p>\r\n<p>VIII. Limitação e Isenção de Responsabilidade</p>\r\n<p> </p>\r\n<p>8.1 Você entende e concorda que, em nenhuma circunstância, seremos responsáveis por:</p>\r\n<p>8.1.1 Perda de receita;</p>\r\n<p>8.1.2 Lucros ou perdas contratuais;</p>\r\n<p>8.1.3 Interrupção de negócios;</p>\r\n<p>8.1.4 Economias previstas;</p>\r\n<p>8.1.5 Problemas de informação;</p>\r\n<p>8.1.6 Perda de oportunidades, reputação ou boa fé;</p>\r\n<p>8.1.7 Danos ou perda de dados;</p>\r\n<p>8.1.8 Custos com produtos ou serviços substitutos;</p>\r\n<p>8.1.9 Quaisquer perdas indiretas, especiais ou incidentais por qualquer motivo, mesmo se previsíveis ou avisadas com antecedência.</p>\r\n<p>Cada item de 8.1.1 a 8.1.9 é independente.</p>\r\n<p> </p>\r\n<p>8.2 Não nos responsabilizamos por danos decorrentes das seguintes situações:</p>\r\n<p>8.2.1 Transações ilegais ou em descumprimento;</p>\r\n<p>8.2.2 Atos ilegais ou antiéticos no site;</p>\r\n<p>8.2.3 Custos e perdas com uso ou substituição de serviços do site;</p>\r\n<p>8.2.4 Má interpretação dos serviços do site;</p>\r\n<p>8.2.5 Outras perdas não causadas por nós.</p>\r\n<p> </p>\r\n<p>8.3 Não somos responsáveis por falhas ou atrasos de serviço causados por eventos fora do nosso controle, incluindo: manutenção, falhas de conexão, desastres naturais, greves, tumultos, guerras, falências, colapsos de mercado, atos governamentais, etc.</p>\r\n<p> </p>\r\n<p>8.4 Não garantimos que todas as informações e programas do site sejam livres de vírus ou programas maliciosos. O uso é por sua conta e risco.</p>\r\n<p> </p>\r\n<p>8.5 Não garantimos informações, produtos ou serviços de sites terceiros vinculados ao nosso.</p>\r\n<p> </p>\r\n<p>8.6 Não oferecemos garantias, expressas ou implícitas, sobre adequação, exatidão ou confiabilidade dos serviços. Você assume o risco e perdas de uso. Não garantimos valor ou estabilidade dos ativos digitais.</p>\r\n<p> </p>\r\n<p>8.7 As garantias neste Acordo substituem todas as outras, verbais ou escritas.</p>\r\n<p> </p>\r\n<p>8.8 Não renunciamos a quaisquer direitos de limitação ou isenção de responsabilidade permitidos por lei.</p>\r\n<p> </p>\r\n<p>8.9 O registro indica que você reconhece e assume os riscos de qualquer operação realizada conforme este Acordo.</p>\r\n<p> </p>\r\n<p>IX. Rescisão do Acordo</p>\r\n<p> </p>\r\n<p>9.1 Este site poderá encerrar todos os serviços conforme este Acordo. O Acordo termina com o fim dos serviços.</p>\r\n<p> </p>\r\n<p>9.2 Após a rescisão, você não poderá exigir qualquer serviço ou obrigação do site, incluindo manter ou transferir informações da conta.</p>\r\n<p> </p>\r\n<p>9.3 A rescisão não afeta o direito da parte cumpridora de exigir responsabilidade da parte inadimplente.</p>\r\n<p> </p>\r\n<p>X. Propriedade Intelectual</p>\r\n<p> </p>\r\n<p>10.1 Toda propriedade intelectual do site, incluindo logotipo, banco de dados, design, textos, software, imagens, códigos, pertence ao site. É proibido copiar ou usar para fins comerciais.</p>\r\n<p> </p>\r\n<p>10.2 Todos os direitos sobre o nome e marca do site pertencem à empresa.</p>\r\n<p> </p>\r\n<p>10.3 Ao aceitar o Acordo, você transfere gratuitamente ao site os direitos autorais de qualquer conteúdo publicado, incluindo direitos de reprodução, distribuição, adaptação etc. O site tem direito exclusivo de ação judicial por violação.</p>\r\n<p> </p>\r\n<p>10.4 É proibido usar indevidamente propriedade intelectual do site ou de terceiros. Também é proibido republicar ou licenciar conteúdos publicados no site.</p>\r\n<p> </p>\r\n<p>XI. Proteção de Informações</p>\r\n<p> </p>\r\n<p>Sujeito aos termos do \"Termo de Privacidade\" publicado separadamente pelo site.</p>\r\n<p> </p>\r\n<p>XII. Cálculo</p>\r\n<p> </p>\r\n<p>Todos os resultados de cálculo de transações são verificados por nós. Os métodos estão publicados, mas não garantimos ausência de falhas.</p>\r\n<p> </p>\r\n<p>XIII. Controle de Exportação</p>\r\n<p> </p>\r\n<p>Você concorda que não exportará, reexportará ou transferirá materiais do site de forma ilegal. Se for detectada violação, deverá nos informar e cooperar.</p>\r\n<p> </p>\r\n<p>XIV. Transferência</p>\r\n<p> </p>\r\n<p>Os direitos e obrigações deste Acordo vinculam sucessores e representantes legais. Você não poderá transferi-los sem nosso consentimento, mas nós poderemos transferir nossos direitos a terceiros mediante aviso.</p>\r\n<p> </p>\r\n<p>XV. Divisibilidade</p>\r\n<p> </p>\r\n<p>Se qualquer cláusula for considerada inválida por um tribunal competente, isso não afetará as demais cláusulas.</p>\r\n<p> </p>\r\n<p>XVI. Relação de Agência</p>\r\n<p> </p>\r\n<p>Nenhuma disposição cria relação de agência, salvo se expressamente estipulado.</p>\r\n<p> </p>\r\n<p>XVII. Renúncia</p>\r\n<p> </p>\r\n<p>A renúncia a qualquer responsabilidade não implica renúncia a outras. A não execução de direitos não significa renúncia.</p>\r\n<p> </p>\r\n<p>XVIII. Títulos</p>\r\n<p> </p>\r\n<p>Os títulos são apenas para conveniência e não afetam o conteúdo.</p>\r\n<p> </p>\r\n<p>XIX. Lei Aplicável</p>\r\n<p> </p>\r\n<p>19.1 Antes de qualquer disputa, você concorda em nos contatar via e-mail para tentativa de solução amigável. A negociação será confidencial e não usada como prova.</p>\r\n<p> </p>\r\n<p>19.2 Qualquer disputa relacionada a este Acordo será submetida à Câmara de Comércio Internacional (CCI) para arbitragem conforme seu regulamento vigente, com sede em Belize, em inglês, com um único árbitro (salvo acordo em contrário). A decisão será final e obrigatória, podendo ser executada por qualquer tribunal com jurisdição.</p>\r\n<p>Vigésimo – Entrada em vigor e interpretação do Acordo</p>\r\n<p>20.1 Este acordo entra em vigor quando você clica em \"Concordo\" na página de registro deste site, conclui o processo de registro e obtém uma conta e senha do site, sendo vinculativo tanto para o site quanto para você.</p>\r\n<p>20.2 O direito final de interpretação deste acordo pertence exclusivamente ao site.</p>\r\n<p> </p>\r\n<p>Política de Conheça Seu Cliente (KYC) e Anti-Lavagem de Dinheiro (AML)</p>\r\n<p> </p>\r\n<p>I. Introdução</p>\r\n<p>1.1 Comprometemo-nos a cumprir com rigor as leis e regulamentos relacionados à política de \"Conheça Seu Cliente\" e à prevenção contra lavagem de dinheiro, e a não violar intencionalmente esta Política de Conheça Seu Cliente e Anti-Lavagem de Dinheiro. Dentro dos limites razoáveis de nosso controle, tomaremos as medidas e tecnologias necessárias para lhe oferecer serviços seguros, buscando ao máximo protegê-lo contra perdas causadas por atividades de lavagem de dinheiro por criminosos.</p>\r\n<p>1.2 Nossa política de Conheça Seu Cliente e Anti-Lavagem de Dinheiro é um sistema internacional abrangente que inclui as políticas KYC e AML aplicáveis às jurisdições legais às quais você pertence.</p>\r\n<p> </p>\r\n<p>II. Nossa política de Conheça Seu Cliente e Anti-Lavagem de Dinheiro inclui:</p>\r\n<p>2.1 Promulgação e constante atualização da política de KYC e AML para atender aos padrões exigidos por leis e regulamentos aplicáveis;</p>\r\n<p>2.2 Emissão e atualização de diretrizes operacionais e regras do site, sendo que nossos funcionários prestarão serviços de acordo com essas diretrizes e regras;</p>\r\n<p>2.3 Elaboração e implementação de procedimentos internos para monitorar e controlar transações, incluindo verificação rigorosa de identidade e formação de uma equipe profissional dedicada à prevenção da lavagem de dinheiro;</p>\r\n<p>2.4 Aplicação de uma abordagem baseada em risco para realizar diligência devida nos clientes e monitoramento contínuo;</p>\r\n<p>2.5 Revisão e inspeção periódica de transações realizadas;</p>\r\n<p>2.6 Comunicação de transações suspeitas às autoridades competentes;</p>\r\n<p>2.7 Manutenção de registros de documentos de identidade, comprovantes de endereço e registros de transações por no mínimo seis anos, podendo ser entregues às autoridades reguladoras sem aviso prévio.</p>\r\n<p> </p>\r\n<p>III. Informações de Identidade e Verificação</p>\r\n<p> </p>\r\n<p>3.1 Informações de Identidade</p>\r\n<p>3.1.1 De acordo com as regulamentações de diferentes jurisdições e tipos de entidades, as informações que coletamos podem variar. Em princípio, as seguintes informações serão coletadas de indivíduos registrados:</p>\r\n<p> </p>\r\n<p>Informações básicas pessoais: Nome, endereço (e endereço permanente, se diferente), data de nascimento, nacionalidade e outras informações relevantes. A verificação de identidade deverá ser feita com base em documentos emitidos por autoridades oficiais ou similares, como passaporte, carteira de identidade ou outros documentos exigidos por jurisdições específicas. O endereço fornecido será verificado por meios adequados, como verificação de contas de transporte ou serviços públicos, ou registros de eleitor.</p>\r\n<p> </p>\r\n<p>Foto válida: Antes do registro, você deve fornecer uma foto sua segurando o documento de identidade à frente do seu peito;</p>\r\n<p> </p>\r\n<p>Informações de contato: Número de telefone/celular e/ou endereço de e-mail válido.</p>\r\n<p> </p>\r\n<p>3.1.2 Se você for uma empresa ou outra entidade legal, coletaremos as seguintes informações para identificar o beneficiário final da conta fiduciária ou da empresa:</p>\r\n<p> </p>\r\n<p>Registro e certificado de constituição da empresa;</p>\r\n<p> </p>\r\n<p>Cópia do estatuto social e memorando da empresa;</p>\r\n<p> </p>\r\n<p>Documentação detalhada explicando a estrutura de propriedade e participação da empresa;</p>\r\n<p> </p>\r\n<p>Resolução do conselho de administração autorizando a abertura da conta no site e designando os representantes autorizados;</p>\r\n<p> </p>\r\n<p>Documentos de identidade dos diretores, principais acionistas e pessoas autorizadas a assinar na conta do site;</p>\r\n<p> </p>\r\n<p>Endereço principal da empresa, e endereço postal, se diferente. Se o endereço local da empresa for diferente do endereço principal, a empresa será considerada de alto risco e deverá fornecer documentação adicional.</p>\r\n<p> </p>\r\n<p>Outros documentos certificados e emitidos por autoridades que sejam exigidos de acordo com jurisdições ou considerados necessários por nós.</p>\r\n<p> </p>\r\n<p>3.1.3 Aceitamos apenas informações de identidade em inglês ou chinês. Caso contrário, será necessário providenciar tradução juramentada para o inglês.</p>\r\n<p> </p>\r\n<p>3.2 Verificação de Identidade</p>\r\n<p>3.2.1 Exigimos que você forneça todas as páginas dos documentos de identidade.</p>\r\n<p>3.2.2 Exigimos uma foto sua segurando o documento de identidade à frente do seu peito.</p>\r\n<p>3.2.3 As cópias dos documentos devem ser comparadas com os originais. No entanto, se uma autoridade confiável e adequada puder certificar que a cópia é uma reprodução precisa e completa do original, essa cópia será aceita. Tais autoridades incluem embaixadores, juízes de paz, delegados locais, entre outros.</p>\r\n<p>3.2.4 Os requisitos para identificar o beneficiário final e o controle da conta visam identificar indivíduos que possuem ou controlam diretamente o cliente, e/ou determinar se as transações em andamento estão sendo realizadas em nome de terceiros. No caso de empresas, a identidade dos principais acionistas (por exemplo, aqueles que detêm 10% ou mais dos direitos de voto) deve ser verificada. Geralmente, uma participação de 25% é considerada de risco normal, e a identidade do acionista deve ser verificada; participações de 10% ou mais com direito a voto ou ações são consideradas de alto risco, e a identidade dos acionistas deve ser verificada.</p>\r\n<p> </p>\r\n<p>IV. Monitoramento de Transações</p>\r\n<p>4.1 Ajustamos os limites máximos diários de transações e saques com base na segurança e nas circunstâncias reais das transações;</p>\r\n<p>4.2 Se um usuário realizar transações frequentes ou apresentarem situações anormais, nossa equipe especializada avaliará se essas transações são suspeitas;</p>\r\n<p>4.3 Se, a nosso exclusivo critério, uma transação for considerada suspeita, podemos adotar medidas restritivas como a suspensão ou recusa da transação, e até mesmo, se possível, reverter a transação. Também reportaremos às autoridades competentes sem notificá-lo;</p>\r\n<p>4.4 Reservamo-nos o direito de recusar registros provenientes de jurisdições que não estejam em conformidade com padrões internacionais de AML, ou de pessoas consideradas politicamente expostas. Também nos reservamos o direito de suspender ou encerrar, a qualquer momento, transações que considerarmos suspeitas, sem que isso constitua violação de qualquer obrigação ou responsabilidade perante você.</p>', NULL);
INSERT INTO `article_translations` VALUES (320, 91, 'spa', 'Protocolo de usuario', '<p>Niniejsza strona internetowa jest platformą specjalnie przeznaczoną do dokonywania transakcji aktywów cyfrowych oraz świadczenia powiązanych usług (dalej zwanych „niniejszą usługą” lub „usługą”). Dla wygody wyrażenia w niniejszej umowie, niniejsza strona internetowa jest określana w niniejszej umowie łącznie jako „my” lub innymi zaimkami pierwszej osoby. Każda osoba fizyczna lub podmiot, który zaloguje się na tę stronę internetową, jest użytkownikiem tej strony internetowej. Dla wygody wyrażenia w niniejszej umowie, dalej nazywamy „Panem/Panią” lub innymi zaimkami drugiej osoby. Dla wygody wyrażenia, my i Pan/Pani są łącznie nazywani „stronami”, a każda ze stron osobno „stroną”.</p>\r\n<p> </p>\r\n<p>Ważna uwaga:</p>\r\n<p> </p>\r\n<p>Szczególnie przypominamy:</p>\r\n<p> </p>\r\n<p>Aktywa cyfrowe nie są emitowane przez żadne instytucje finansowe, firmy ani tę stronę internetową.</p>\r\n<p> </p>\r\n<p>Rynek aktywów cyfrowych jest nowy, niepotwierdzony i może nie rosnąć.</p>\r\n<p> </p>\r\n<p>Aktywa cyfrowe są głównie używane przez spekulantów; zastosowanie na rynku detalicznym i komercyjnym jest stosunkowo niewielkie. Transakcje aktywami cyfrowymi niosą bardzo wysokie ryzyko, odbywają się bez przerwy przez całą dobę, nie mają ograniczeń wzrostu lub spadku ceny, a ceny łatwo podlegają dużym wahaniom pod wpływem głównych graczy i globalnych polityk rządowych.</p>\r\n<p> </p>\r\n<p>Jeśli firma według własnego uznania stwierdzi, że naruszył Pan/Pani tę umowę lub jeśli działalność świadczona przez stronę internetową lub korzystanie z usług strony jest nielegalne w jurysdykcji, w której się Pan/Pani znajduje, firma ma prawo w każdej chwili zawiesić lub zakończyć Państwa konto lub zawiesić lub zakończyć świadczenie usług lub transakcji aktywów cyfrowych. Zabronione jest korzystanie z usług kontraktowych tej strony internetowej przez osoby z [Chin kontynentalnych, Tajwanu, Izraela, Iraku, Bangladeszu, Boliwii, Ekwadoru, Kirgistanu, Sewastopola]. Lista wymienionych krajów lub regionów może ulec zmianie w zależności od polityk i rodzajów produktów w różnych krajach lub regionach, i w takim przypadku możemy nie powiadomić Pana/Pani osobno; prosimy o regularne śledzenie aktualizacji niniejszej umowy.</p>\r\n<p> </p>\r\n<p>Transakcje aktywami cyfrowymi niosą bardzo wysokie ryzyko i nie są odpowiednie dla większości osób. Rozumie Pan/Pani i rozumie, że takie transakcje mogą prowadzić do częściowej lub całkowitej utraty kapitału, dlatego powinien Pan/Pani ustalić kwotę transakcji zgodnie z poziomem możliwych do poniesienia strat. Rozumie Pan/Pani, że aktywa cyfrowe generują ryzyko pochodne, dlatego w przypadku jakichkolwiek wątpliwości zaleca się skonsultowanie się z profesjonalnym doradcą. Ponadto oprócz wyżej wymienionych ryzyk mogą istnieć nieprzewidziane ryzyka. Prosimy o ostrożne rozważenie i ocenę swojej sytuacji finansowej oraz powyższych ryzyk z jasnym rozumowaniem przed podjęciem decyzji o jakimkolwiek kupnie lub sprzedaży aktywów cyfrowych i wzięcie na siebie wszelkich wynikających z tego strat; nie ponosimy za to żadnej odpowiedzialności.</p>\r\n<p> </p>\r\n<p>Uwaga:</p>\r\n<p> </p>\r\n<p>Rozumie Pan/Pani, że niniejsza strona internetowa służy wyłącznie jako miejsce do pozyskiwania informacji o aktywach cyfrowych, poszukiwania kontrahentów oraz negocjowania i zawierania transakcji aktywów cyfrowych. Strona nie uczestniczy w żadnej transakcji, dlatego powinien Pan/Pani samodzielnie ostrożnie ocenić prawdziwość, legalność i ważność powiązanych aktywów cyfrowych i/lub informacji oraz ponosić wszelkie z tego tytułu powstałe odpowiedzialności i straty.</p>\r\n<p> </p>\r\n<p>Wszelkie opinie, wiadomości, dyskusje, analizy, ceny, sugestie i inne informacje na tej stronie internetowej mają charakter ogólnego komentarza rynkowego i nie stanowią porady inwestycyjnej. Nie ponosimy odpowiedzialności za jakiekolwiek straty bezpośrednie lub pośrednie wynikające z polegania na tych informacjach, w tym utratę zysków.</p>\r\n<p> </p>\r\n<p>Zastrzegamy sobie prawo do samodzielnego decydowania, modyfikowania lub zmiany treści niniejszej strony, podjęliśmy rozsądne środki, aby zapewnić dokładność informacji, ale nie gwarantujemy ich dokładności i nie ponosimy odpowiedzialności za straty wynikające z informacji na stronie ani za opóźnienia lub niepowodzenia w połączeniu internetowym, przesyłaniu lub odbiorze powiadomień i informacji.</p>\r\n<p> </p>\r\n<p>Korzystanie z systemu transakcyjnego online wiąże się z ryzykiem, w tym awariami oprogramowania, sprzętu oraz połączenia internetowego. Ponieważ nie możemy kontrolować niezawodności i dostępności internetu, nie ponosimy odpowiedzialności za zniekształcenia, opóźnienia i awarie połączenia.</p>\r\n<p> </p>\r\n<p>Zabrania się używania tej strony do prania pieniędzy, przemytu, korupcji i innych nielegalnych działań lub naruszeń prawa. Jeśli zostanie wykryta podejrzana nielegalna działalność, podejmiemy wszelkie dostępne środki, w tym zamrożenie konta i powiadomienie odpowiednich organów, nie ponosząc odpowiedzialności i zastrzegając sobie prawo do dochodzenia odpowiedzialności wobec odpowiednich osób.</p>\r\n<p> </p>\r\n<p>Zabrania się wykorzystywania tej strony do manipulacji rynkiem, nieuczciwych transakcji i innych niemoralnych działań handlowych. W przypadku wykrycia takich działań, podejmiemy środki prewencyjne, takie jak ostrzeżenia, ograniczenia handlu i zamknięcie kont, nie ponosząc odpowiedzialności i zastrzegając sobie prawo do dochodzenia odpowiedzialności wobec odpowiednich osób.</p>\r\n<p> </p>\r\n<p>I. Postanowienia ogólne</p>\r\n<p>1.1 „Umowa użytkownika” (dalej „niniejsza umowa” lub „warunki i zasady”) składa się z niniejszego tekstu, „Polityki prywatności”, „Polityki KYC i AML” oraz wszelkich obecnych i przyszłych zasad, oświadczeń i wyjaśnień publikowanych na stronie.</p>\r\n<p>1.2 Przed korzystaniem z usług strony, prosimy o uważne zapoznanie się z niniejszą umową. W razie wątpliwości prosimy o konsultację z profesjonalnym prawnikiem. Jeżeli nie zgadzasz się z umową lub jej zmianami, prosimy o natychmiastowe zaprzestanie korzystania z usług strony lub rezygnację z logowania. Logowanie, korzystanie z usług lub inne podobne działania oznaczają pełną akceptację wszystkich warunków umowy oraz jej zmian.</p>\r\n<p>1.3 Po pomyślnym zarejestrowaniu się zgodnie z wymaganiami strony uzyskujesz status członka („Członek”). Kliknięcie przycisku „Akceptuję” podczas rejestracji oznacza zawarcie umowy w formie elektronicznej; każde kliknięcie przycisku „Zgadzam się” lub podobnego podczas korzystania z usług strony oznacza pełną akceptację i związanie się umową, nawet bez podpisu własnoręcznego.</p>\r\n<p>1.4 Po rejestracji otrzymasz konto członkowskie oraz hasło, które powinieneś chronić. Jesteś odpowiedzialny prawnie za wszelkie działania podejmowane na Twoim koncie.</p>\r\n<p>1.5 Tylko członkowie mogą korzystać z platformy transakcji aktywów cyfrowych i innych usług dostępnych tylko dla członków; nieczłonkowie mogą tylko logować się, przeglądać i korzystać z innych dozwolonych funkcji.</p>\r\n<p>1.6 Rejestrując się i korzystając z usług, potwierdzasz, że:</p>\r\n<p>1.6.1 akceptujesz wszystkie warunki umowy;</p>\r\n<p>1.6.2 masz ukończone 18 lat lub wymaganą prawem zdolność do zawierania umów w swojej jurysdykcji;</p>\r\n<p>1.6.3 aktywa cyfrowe będące przedmiotem transakcji są legalnie nabyte i posiadasz do nich prawa;</p>\r\n<p>1.6.4 ponosisz pełną odpowiedzialność za własne działania handlowe i inne działania oraz wynikające z nich zyski lub straty;</p>\r\n<p>1.6.5 podane podczas rejestracji informacje są prawdziwe i dokładne;</p>\r\n<p>1.6.6 przestrzegasz obowiązujących przepisów prawa dotyczących podatków, w tym raportowania dochodów z transakcji;</p>\r\n<p>1.6.7 nie będziesz uczestniczyć w działaniach szkodzących stronie lub firmie, niezależnie od powiązania z usługami strony;</p>\r\n<p>1.6.8 niniejsza umowa reguluje stosunki między Tobą a nami, a nie stosunki prawne ani spory między użytkownikami strony czy innymi stronami w związku z transakcjami aktywów cyfrowych.</p>\r\n<p> </p>\r\n<p>II. Zmiany umowy</p>\r\n<p>Zastrzegamy sobie prawo do okresowej aktualizacji niniejszej umowy poprzez publikację na stronie bez osobnego powiadomienia. Nowe wersje umowy stają się skuteczne natychmiast po opublikowaniu. Prosimy o regularne śledzenie aktualizacji; dalsze korzystanie z usług oznacza akceptację zmienionej umowy.</p>\r\n<p> </p>\r\n<p>III. Rejestracja</p>\r\n<p>3.1 Kwalifikacje rejestracyjne: potwierdzasz, że masz zdolność prawną do zawarcia niniejszej umowy i korzystania z usług strony jako osoba fizyczna, prawna lub inna organizacja. Kliknięcie przycisku zgody oznacza, że Ty lub Twój upoważniony przedstawiciel akceptujecie warunki i dokonujecie rejestracji. Jeśli nie spełniasz tych warunków, Ty i Twój przedstawiciel ponosicie odpowiedzialność za wszelkie konsekwencje; firma może anulować lub zablokować konto i dochodzić odpowiedzialności.</p>\r\n<p>3.2 Cel rejestracji: potwierdzasz, że rejestracja nie służy naruszaniu prawa ani zakłócaniu porządku transakcji na stronie.</p>\r\n<p>3.3 Proces rejestracji:</p>\r\n<p>3.3.1 Zgadzasz się podać ważny adres e-mail, numer telefonu i inne dane zgodnie z wymaganiami rejestracji; możesz korzystać z nich do logowania. Jeśli prawo wymaga, musisz podać prawdziwe imię i nazwisko, dokumenty tożsamości i inne dane wymagane przez przepisy dotyczące prywatności i AML oraz aktualizować je na bieżąco. Jesteś odpowiedzialny za prawdziwość i dokładność danych oraz ewentualne szkody wynikłe z błędnych danych.</p>\r\n<p>3.3.2 Jeśli prawo wymaga realnego zarejestrowania numeru telefonu, zgadzasz się, że podany numer jest zgodny z tym wymogiem; ponosisz odpowiedzialność za wszelkie straty wynikające z nieprzestrzegania.</p>\r\n<p>3.3.3 Po prawidłowym i kompletnym podaniu danych oraz ich weryfikacji uzyskujesz konto i hasło, co oznacza pomyślną rejestrację i możliwość logowania.</p>\r\n<p>3.3.4 Zgadzasz się otrzymywać od strony e-maile i/lub SMS-y dotyczące zarządzania i operacji strony.</p>\r\n<p> </p>\r\n<p>IV. Usługi</p>\r\n<p>Strona oferuje platformę transakcyjną do dokonywania transakcji aktywów cyfrowych (w tym m.in. usługi handlu aktywami cyfrowymi).</p>\r\n<p> </p>\r\n<p>4.1 Zakres usług:</p>\r\n<p>4.1.1 Masz prawo przeglądać aktualne notowania i informacje o transakcjach aktywów cyfrowych oraz składać zlecenia transakcyjne i zawierać transakcje.</p>\r\n<p>4.1.2 Masz prawo przeglądać informacje na swoim koncie i korzystać z funkcji udostępnianych przez stronę.</p>\r\n<p>4.1.3 Masz prawo uczestniczyć w akcjach organizowanych przez stronę zgodnie z zasadami tych akcji.</p>\r\n<p>4.1.4 Strona zobowiązuje się do świadczenia innych usług.</p>\r\n<p> </p>\r\n<p>4.2 Zasady korzystania z usług:</p>\r\n<p>4.2.1 Powinieneś przestrzegać prawa oraz wymagań regulacji i polityk, zapewniając legalne pochodzenie wszystkich aktywów na koncie; nie wolno używać strony do działalności nielegalnej lub szkodzącej stronie lub osobom trzecim, w tym rozsyłania informacji niezgodnych z prawem, piramidalnych, szkodliwych lub naruszających prawa innych, fałszowania nagłówków e-mail strony itp.</p>\r\n<p>4.2.2 Powinieneś przestrzegać prawa oraz prawidłowo zarządzać i chronić konto, hasło, hasło do środków, numer telefonu oraz kody weryfikacyjne; nie udostępniać ich osobom trzecim; ponosić odpowiedzialność za wszelkie szkody wynikłe z niewłaściwego zarządzania; w razie kradzieży lub nieuprawnionego użycia powinieneś niezwłocznie powiadomić stronę w celu zablokowania.</p>\r\n<p>4.2.3 Powinieneś korzystać z usług zgodnie z przeznaczeniem, nie zakłócając systemu, nie ingerując w system lub usługi, nie wykonując działań zagrażających bezpieczeństwu informacji.</p>\r\n<p>4.2.4 Zabronione jest przeprowadzanie działań manipulacyjnych i oszustw, w tym wash trading, manipulacji cenami, powtarzających się i bezproduktywnych transakcji, naruszania zasad strony i prawa.</p>\r\n<p>4.2.5 Zgadzasz się, że wszelkie transakcje i działania na koncie, nawet jeśli nieautoryzowane przez Ciebie, są wiążące, jeśli zostaną zatwierdzone przez stronę zgodnie z procedurami.</p>\r\n<p>4.2.6 Zgadzasz się na monitorowanie przez stronę działań na koncie i blokowanie w razie wykrycia naruszeń.</p>\r\n<p>4.2.7 Zgadzasz się na przestrzeganie innych zasad i polityk opublikowanych przez stronę.</p>\r\n<p>V. Prawa i obowiązki niniejszej strony internetowej</p>\r\n<p>5.1 Jeśli nie posiadasz kwalifikacji rejestracyjnych określonych w niniejszej umowie, strona internetowa ma prawo odmówić rejestracji, a w przypadku już zarejestrowanych, ma prawo anulować Twoje konto członkowskie. Strona internetowa zastrzega sobie prawo dochodzenia odpowiedzialności od Ciebie lub Twojego uprawnionego przedstawiciela. Jednocześnie strona internetowa zastrzega sobie prawo do decydowania o przyjęciu lub odmowie Twojej rejestracji w innych sytuacjach.</p>\r\n<p>5.2 Na podstawie własnego uznania, jeśli strona internetowa stwierdzi, że Ty lub użytkownicy powiązanych kont nie nadajecie się do inwestycji wysokiego ryzyka, ma prawo zawiesić lub zakończyć korzystanie z Twojego konta oraz wszystkich powiązanych kont.</p>\r\n<p>5.3 Jeśli strona internetowa stwierdzi, że użytkownik konta nie jest pierwotnym rejestratorem konta, ma prawo zawiesić lub zakończyć korzystanie z tego konta.</p>\r\n<p>5.4 Gdy strona internetowa na podstawie wykrycia technicznego, losowej kontroli manualnej lub innych metod uzasadnione podejrzy, że podane przez Ciebie informacje są błędne, nieprawdziwe, nieważne lub niepełne, ma prawo powiadomić Cię o konieczności poprawy lub aktualizacji informacji, lub zawiesić bądź zakończyć świadczenie usług na stronie internetowej.</p>\r\n<p>5.5 Strona internetowa ma prawo do poprawiania wszelkich oczywistych błędów w wyświetlanych na stronie informacjach.</p>\r\n<p>5.6 Strona internetowa zastrzega sobie prawo do wprowadzania zmian, zawieszenia lub zakończenia usług w dowolnym czasie bez uprzedniego powiadomienia. W przypadku zakończenia jednej lub kilku usług, zakończenie wchodzi w życie z dniem ogłoszenia zakończenia na stronie.</p>\r\n<p>5.7 Strona internetowa podejmie niezbędne środki techniczne i zarządcze, aby zapewnić prawidłowe funkcjonowanie strony oraz dostarczyć niezbędne i wiarygodne środowisko transakcyjne i usługi, chroniąc porządek handlu aktywami cyfrowymi.</p>\r\n<p>5.8 Jeśli przez rok nie zalogujesz się na konto strony internetowej, strona ma prawo anulować Twoje konto. Po anulowaniu konto może zostać udostępnione innym użytkownikom do rejestracji.</p>\r\n<p>5.9 Strona internetowa podejmie działania techniczne i bezpieczeństwa, aby chronić bezpieczeństwo Twoich aktywów cyfrowych, i poinformuje Cię z wyprzedzeniem, jeśli pojawią się przewidywalne zagrożenia bezpieczeństwa Twojego konta.</p>\r\n<p>5.10 Strona internetowa ma prawo usuwać wszelkie treści na stronie, które są sprzeczne z prawem lub regulacjami strony, bez konieczności wcześniejszego powiadomienia.</p>\r\n<p>5.11 Strona internetowa ma prawo wymagać od Ciebie dodatkowych informacji lub dokumentów w celu spełnienia wymogów prawnych, regulacji lub nakazów w Twoim kraju lub regionie, a także podjąć odpowiednie działania, w tym zawiesić lub trwale zablokować dostęp do części lub całości usług. Masz obowiązek współpracować.</p>\r\n<p>5.12 Strona internetowa zastrzega sobie prawo do zamknięcia Twojego konta po uprzednim siedmiodniowym okresie powiadomienia, w którym możesz dokonać anulowania zleceń i zamknięcia pozycji. Po tym terminie, jeśli nie wykonasz tych czynności, zostaną one przeprowadzone przymusowo, a pozostałe aktywa cyfrowe zostaną zwrócone na Twoje konto.</p>\r\n<p>5.13 Aby chronić interesy traderów, strona internetowa ma prawo w szczególnych okolicznościach (np. awarie systemu, przerwy w sieci, ekstremalne warunki rynkowe) wprowadzać zmiany w produktach już uruchomionych, w tym wcześniejsze rozliczenia kontraktów zgodnie z ogłoszeniami na stronie.</p>\r\n<p> </p>\r\n<p>VI. Odszkodowania</p>\r\n<p>6.1 W żadnym przypadku nasza odpowiedzialność za bezpośrednie szkody nie przekroczy łącznej opłaty za usługi pobranej od Ciebie za trzy (3) miesiące korzystania z serwisu.</p>\r\n<p>6.2 Jeśli naruszysz niniejszą umowę lub inne przepisy prawa, zobowiązujesz się do zapłaty odszkodowania w wysokości co najmniej 2 milionów USD oraz pokrycia wszelkich kosztów związanych (w tym kosztów prawnych). Jeśli kwota ta nie pokryje rzeczywistych strat, zobowiązujesz się do uzupełnienia różnicy.</p>\r\n<p> </p>\r\n<p>VII. Prawo do dochodzenia środków zabezpieczających</p>\r\n<p>Uznajemy, że zwykłe środki prawne mogą nie wystarczyć do naprawienia wszystkich strat, w związku z czym mamy prawo do dochodzenia środków zabezpieczających, w tym zakazu działań naruszających umowę, oraz innych środków prawnych dozwolonych przez prawo zwyczajowe i equity.</p>\r\n<p> </p>\r\n<p>VIII. Ograniczenie odpowiedzialności i wyłączenie odpowiedzialności</p>\r\n<p>8.1 Rozumiesz i zgadzasz się, że w żadnym przypadku nie ponosimy odpowiedzialności za:</p>\r\n<p>8.1.1 Utracone dochody;</p>\r\n<p>8.1.2 Straty z tytułu zysków z transakcji lub kontraktów;</p>\r\n<p>8.1.3 Przerwy w działalności gospodarczej;</p>\r\n<p>8.1.4 Oszczędności, które miały być osiągnięte;</p>\r\n<p>8.1.5 Straty wynikające z problemów informacyjnych;</p>\r\n<p>8.1.6 Utracone szanse, reputację lub goodwill;</p>\r\n<p>8.1.7 Uszkodzenie lub utratę danych;</p>\r\n<p>8.1.8 Koszty zakupu zamiennych produktów lub usług;</p>\r\n<p>8.1.9 Jakiekolwiek pośrednie, specjalne lub przypadkowe szkody wynikające z naruszeń, w tym z niedbalstwa, bez względu na to, czy były one przewidywalne i czy zostaliśmy o nich uprzedzeni.</p>\r\n<p>8.1.10 Powyższe podpunkty są niezależne od siebie.</p>\r\n<p>8.2 Nie ponosimy odpowiedzialności za szkody wynikłe z:</p>\r\n<p>8.2.1 Twoich nielegalnych lub naruszających umowę działań;</p>\r\n<p>8.2.2 Działań naruszających prawo lub moralność;</p>\r\n<p>8.2.3 Kosztów i strat wynikłych z korzystania z danych, informacji lub usług strony;</p>\r\n<p>8.2.4 Twojego niezrozumienia usług strony;</p>\r\n<p>8.2.5 Innych strat niezwiązanych bezpośrednio z naszą winą.</p>\r\n<p>8.3 Nie odpowiadamy za szkody wynikające z awarii sieci, sprzętu, zasilania, warunków pogodowych, wypadków, strajków, zamieszek, braku surowców, katastrof, działań wojennych, nakazów władz, krachu rynku aktywów cyfrowych, działań stron trzecich i innych okoliczności poza naszą kontrolą.</p>\r\n<p>8.4 Nie gwarantujemy, że informacje, programy, teksty na stronie są wolne od wirusów i innych złośliwych programów. Korzystanie z usług i pobieranie treści odbywa się na własne ryzyko.</p>\r\n<p>8.5 Nie odpowiadamy za treści, produkty i usługi stron trzecich dostępne przez linki na stronie. Korzystanie z nich odbywa się na własne ryzyko.</p>\r\n<p>8.6 Nie udzielamy żadnych gwarancji, wyraźnych ani dorozumianych, dotyczących dokładności, niezawodności, ciągłości, jakości czy przydatności usług oraz informacji technicznych związanych ze stroną, w tym wartości i cen aktywów cyfrowych, które są niestabilne i podlegają gwałtownym wahaniom.</p>\r\n<p>8.7 Gwarancje i zobowiązania zawarte w niniejszej umowie są jedynymi gwarancjami i zastępują wszelkie inne, niezależnie od formy. Nie gwarantujemy, że strony trzecie będą przestrzegać tych postanowień.</p>\r\n<p>8.8 Nie zrzekamy się prawa do ograniczania, zwalniania lub kompensacji odpowiedzialności na maksymalnym poziomie dozwolonym przez prawo.</p>\r\n<p>8.9 Rejestrując się, akceptujesz wszystkie ryzyka wynikające z działań zgodnie z niniejszą umową.</p>\r\n<p> </p>\r\n<p>IX. Zakończenie umowy</p>\r\n<p>9.1 Strona internetowa ma prawo zakończyć wszystkie usługi zgodnie z umową; umowa wygasa w dniu zakończenia wszystkich usług.</p>\r\n<p>9.2 Po zakończeniu umowy nie masz prawa żądać dalszych usług ani zachowania jakichkolwiek danych konta czy przesłania informacji.</p>\r\n<p>9.3 Zakończenie umowy nie wpływa na obowiązek ponoszenia odpowiedzialności za naruszenia.</p>\r\n<p> </p>\r\n<p>X. Własność intelektualna</p>\r\n<p>10.1 Wszystkie prawa własności intelektualnej do materiałów zawartych na stronie, w tym logo, bazy danych, projekty, teksty, grafiki, oprogramowanie, zdjęcia, nagrania audio i wideo należą do strony. Nie wolno ich kopiować, modyfikować ani wykorzystywać w celach komercyjnych.</p>\r\n<p>10.2 Nazwa i znaki towarowe strony należą do firmy.</p>\r\n<p>10.3 Publikując na stronie jakiekolwiek treści, dobrowolnie przekazujesz stronie nieodpłatną, wyłączną licencję na wszystkie prawa autorskie do tych treści, włączając prawa do kopiowania, dystrybucji, adaptacji i innych, zarówno w przeszłości jak i przyszłości. Strona ma prawo samodzielnie dochodzić praw autorskich w przypadku naruszeń.</p>\r\n<p>10.4 Nie wolno nielegalnie używać ani dysponować prawami własności intelektualnej strony lub innych osób, ani udostępniać opublikowanych informacji innym serwisom bez zgody strony.</p>\r\n<p> </p>\r\n<p>XI. Ochrona informacji</p>\r\n<p>Podlega oddzielnym „Zasadom prywatności” publikowanym przez stronę.</p>\r\n<p> </p>\r\n<p>XII. Obliczenia</p>\r\n<p>Wyniki obliczeń transakcyjnych są zweryfikowane przez nas i metody obliczeń są opublikowane na stronie, lecz nie gwarantujemy braku błędów czy zakłóceń w działaniu strony.</p>\r\n<p> </p>\r\n<p>XIII. Kontrola eksportu</p>\r\n<p>Zobowiązujesz się nie eksportować, reeksportować, importować ani przekazywać materiałów strony (w tym oprogramowania) niezgodnie z obowiązującym prawem i poinformować nas o wszelkich naruszeniach.</p>\r\n<p> </p>\r\n<p>XIV. Cesja</p>\r\n<p>Prawa i obowiązki umowy wiążą także następców prawnych, spadkobierców i wykonawców testamentów. Nie możesz przenieść swoich praw na osoby trzecie bez zgody strony, która jednak może przenieść swoje prawa i obowiązki i powiadomić Cię o tym.</p>\r\n<p> </p>\r\n<p>XV. Rozdzielność postanowień</p>\r\n<p>Jeśli jakiekolwiek postanowienie umowy zostanie uznane za nieważne lub niewykonalne przez sąd, pozostałe postanowienia pozostają w mocy.</p>\r\n<p> </p>\r\n<p>XVI. Brak stosunku agencyjnego</p>\r\n<p>Umowa nie tworzy ani nie sugeruje relacji agenta, powiernika lub reprezentanta między stronami, chyba że postanowiono inaczej.</p>\r\n<p> </p>\r\n<p>XVII. Zrzeczenie się</p>\r\n<p>Brak dochodzenia odpowiedzialności z tytułu naruszenia umowy nie oznacza rezygnacji z prawa do dochodzenia w innych przypadkach.</p>\r\n<p> </p>\r\n<p>XVIII. Nagłówki</p>\r\n<p>Nagłówki mają charakter wyłącznie informacyjny i nie rozszerzają ani nie ograniczają zakresu umowy.</p>\r\n<p> </p>\r\n<p>XIX. Prawo właściwe</p>\r\n<p>19.1 Przed zgłoszeniem sporu zgadzasz się najpierw skontaktować się z nami drogą mailową w celu polubownego rozwiązania konfliktu; obie strony zobowiązują się do poufności rozmów.</p>\r\n<p>19.2 W przypadku sporu zgadzasz się na arbitraż na podstawie obowiązujących zasad Międzynarodowej Izby Handlowej (ICC) w Międzynarodowym Trybunale Arbitrażowym ICC, którego miejscem jest Belize, a językiem arbitrażu jest angielski. Wyznaczony jest jeden arbiter z wyłącznym prawem do rozstrzygania wszelkich kwestii jurysdykcji. Decyzja arbitrażu jest ostateczna, wiążąca i możliwa do wyegzekwowania przez właściwy sąd.</p>\r\n<p>Dwudziesty punkt: Wejście w życie i interpretacja umowy</p>\r\n<p>20.1 Niniejsza umowa wchodzi w życie w momencie kliknięcia przez Ciebie zgody na rejestrację na stronie internetowej oraz zakończenia procesu rejestracji, uzyskania konta i hasła na stronie, i jest wiążąca zarówno dla strony internetowej, jak i Ciebie.</p>\r\n<p>20.2 Ostateczne prawo do interpretacji niniejszej umowy przysługuje stronie internetowej.</p>\r\n<p> </p>\r\n<p>Polityka poznaj swojego klienta (KYC) oraz przeciwdziałania praniu pieniędzy (AML)</p>\r\n<p> </p>\r\n<p>I. Wprowadzenie</p>\r\n<p>1.1 Gwarantujemy staranne przestrzeganie przepisów prawa dotyczących „poznaj swojego klienta” oraz przeciwdziałania praniu pieniędzy i nie będziemy celowo naruszać niniejszej „Polityki poznaj swojego klienta i przeciwdziałania praniu pieniędzy”. W ramach rozsądnej kontroli podejmiemy niezbędne środki i technologie, aby zapewnić Ci bezpieczne usługi, minimalizując ryzyko poniesienia strat spowodowanych działaniami przestępców związanych z praniem pieniędzy.</p>\r\n<p>1.2 Nasza polityka KYC i AML to kompleksowy międzynarodowy system polityk obejmujący różne jurysdykcje prawne, do których należysz.</p>\r\n<p> </p>\r\n<p>II. Polityka poznaj swojego klienta i przeciwdziałania praniu pieniędzy</p>\r\n<p>2.1 Wydanie i ciągła aktualizacja polityki KYC i AML, aby spełniała odpowiednie standardy prawne;</p>\r\n<p>2.2 Wydanie i aktualizacja zasad oraz reguł operacyjnych dotyczących działania strony, które będą stosowane przez naszych pracowników;</p>\r\n<p>2.3 Zaprojektowanie i wdrożenie procedur wewnętrznego monitorowania i kontroli transakcji, takich jak rygorystyczna weryfikacja tożsamości oraz utworzenie zespołu specjalistów odpowiedzialnych za kwestie AML;</p>\r\n<p>2.4 Zastosowanie podejścia opartego na ryzyku do przeprowadzania należytej staranności wobec klientów oraz ciągłego nadzoru;</p>\r\n<p>2.5 Przegląd i okresowe kontrole dokonanych transakcji;</p>\r\n<p>2.6 Raportowanie podejrzanych transakcji odpowiednim organom nadzorczym;</p>\r\n<p>2.7 Dokumenty potwierdzające tożsamość, adres oraz zapisy transakcji będą przechowywane co najmniej przez sześć lat, a ich przekazanie organom nadzoru może nastąpić bez dodatkowego powiadomienia.</p>\r\n<p> </p>\r\n<p>III. Informacje o tożsamości i weryfikacja</p>\r\n<p>3.1 Informacje o tożsamości</p>\r\n<p>3.1.1 W zależności od jurysdykcji oraz rodzaju podmiotu, zakres zbieranych informacji może się różnić. Zasadniczo zbieramy od zarejestrowanych osób następujące dane:</p>\r\n<p>Dane podstawowe: imię i nazwisko, adres zamieszkania (oraz stały adres, jeśli różny), data urodzenia, obywatelstwo i inne dostępne informacje. Weryfikacja tożsamości opiera się na dokumentach wydanych przez oficjalne lub podobne instytucje, takich jak paszport, dowód osobisty lub inne dokumenty tożsamości wymagane przez odpowiednie jurysdykcje. Podany adres będzie weryfikowany za pomocą odpowiednich metod, np. sprawdzenia biletów na środki transportu pasażerskiego, rachunków za media, rejestrów wyborców itp.</p>\r\n<p>Aktualne zdjęcie: przed rejestracją musisz dostarczyć zdjęcie, na którym trzymasz dokument tożsamości na wysokości klatki piersiowej;</p>\r\n<p>Dane kontaktowe: numer telefonu/komórki i/lub ważny adres e-mail.</p>\r\n<p>3.1.2 Jeśli jesteś firmą lub innym podmiotem prawnym, zbieramy następujące informacje, aby ustalić ostatecznych beneficjentów rzeczywistych Ciebie lub rachunku powierniczego:</p>\r\n<p>Rejestracja firmy, certyfikaty rejestracyjne; kopie statutu i memorandum spółki; szczegółowe dokumenty opisujące strukturę właścicielską i udziałowców, decyzje zarządu upoważniające do założenia konta na stronie oraz do wykonywania uprawnień przez pełnomocników; dokumenty tożsamości członków zarządu, głównych akcjonariuszy i osób uprawnionych do podpisu na koncie; główna siedziba firmy oraz adres korespondencyjny, jeśli różni się od siedziby. Jeśli lokalny adres firmy różni się od głównej siedziby, klient zostanie uznany za wysokiego ryzyka i konieczne będą dodatkowe dokumenty.</p>\r\n<p>Inne dokumenty potwierdzające i certyfikaty wymagane przez różne jurysdykcje oraz inne dokumenty uznane za niezbędne przez naszą firmę.</p>\r\n<p>3.1.3 Akceptujemy tylko dokumenty w wersji angielskiej lub chińskiej; jeśli nie, prosimy o tłumaczenie na język angielski wraz z poświadczeniem notarialnym.</p>\r\n<p> </p>\r\n<p>3.2 Weryfikacja</p>\r\n<p>3.2.1 Wymagamy dostarczenia wszystkich stron dokumentów tożsamości.</p>\r\n<p>3.2.2 Wymagamy zdjęcia, na którym trzymasz dokument tożsamości na wysokości klatki piersiowej.</p>\r\n<p>3.2.3 Kopie dokumentów powinny być porównane z oryginałami; jednak kopie potwierdzone przez zaufanych i odpowiednich urzędników (np. ambasadorów, sędziów, lokalnych szeryfów) są akceptowane.</p>\r\n<p>3.2.4 W celu identyfikacji ostatecznych beneficjentów i kontroli nad kontem ustalamy, które osoby fizyczne ostatecznie posiadają lub kontrolują bezpośrednio klienta oraz czy transakcje są wykonywane przez inne osoby. W przypadku firm należy zweryfikować tożsamość głównych akcjonariuszy (np. tych posiadających 10% lub więcej praw głosu). Posiadanie 25% akcji jest uznawane za normalne ryzyko i wymaga weryfikacji, natomiast posiadanie 10% lub więcej udziałów lub praw głosu uznaje się za ryzyko wysokie i wymaga dodatkowej weryfikacji.</p>\r\n<p> </p>\r\n<p>IV. Monitorowanie transakcji</p>\r\n<p>4.1 Ustawiamy i dostosowujemy limity dzienne na transakcje i wypłaty w oparciu o bezpieczeństwo i rzeczywiste warunki transakcyjne;</p>\r\n<p>4.2 W przypadku częstych lub nienormalnych transakcji przez danego użytkownika, nasz zespół specjalistów oceni, czy są one podejrzane;</p>\r\n<p>4.3 Jeśli transakcje zostaną uznane za podejrzane, możemy podjąć środki ograniczające, takie jak wstrzymanie lub odmowa realizacji transakcji, a w razie potrzeby ich szybkie odwrócenie, a także zgłoszenie ich odpowiednim organom, bez powiadamiania użytkownika;</p>\r\n<p>4.4 Zastrzegamy sobie prawo do odrzucenia rejestracji osób z jurysdykcji niespełniających międzynarodowych standardów AML lub uznawanych za osoby publiczne o charakterze politycznym. Zastrzegamy sobie również prawo do zawieszenia lub zakończenia transakcji uznanych za podejrzane według własnego uznania, co nie narusza naszych zobowiązań wobec Ciebie.</p>', NULL);
