INSERT INTO `article_translations` VALUES (343, 93, 'uk', 'Privacy agreement', '<p><span style=\"color: #333333; font-family: Arial, \'PingFang SC\', \'Hiragino Sans GB\', STHeiti, \'Microsoft YaHei\', sans-serif; font-size: 18px; white-space: pre-line; background-color: #ffffff;\">Політика конфіденційності та заява I. Вступ Ця Політика конфіденційності та Заява пояснює Coinall Global Company Limited (\"COINALL\"), як компанію, зареєстровану та зареєстровану на Мальті відповідно до положень Закону про мальтійські компанії 1995 року (номер компанії C76567), використовуючи вашу особисту інформацію, оскільки ми надаємо вам доступ та комунальні послуги через нашу торгову платформу Digital Assets (не за участю фіатної валюти). Під час надання наших послуг ми збираємо та зберігаємо особисту інформацію. Загалом, ми ніколи не будемо розкривати будь-яку особисту інформацію про наших клієнтів будь-якій неприєднаній третій стороні, за винятком обставин, описаних нижче. Отримуйте доступ або використовуючи coinall.com та пов\'язані з ними інтерфейси додатків або мобільні додатки (\"Сайт\"), ви погоджуєтеся з політикою та практикою нашої Політики конфіденційності (\"Політика конфіденційності\"), тому, будь ласка, уважно прочитайте її. Ця Політика конфіденційності пояснює, як COINALL використовує ваші персональні дані (як визначено нижче), оскільки ми надаємо вам доступ та утиліти через програмне забезпечення, API (інтерфейси додатків), технології, продукти та / або функції (\"Послуги\") через нашу платформу торгівлі цифровими активами. Під час надання наших послуг ми збираємо та зберігаємо особисту інформацію. Загалом, ми ніколи не будемо розкривати будь-яку особисту інформацію про наших клієнтів будь-якій неприєднаній третій стороні, за винятком обставин, описаних нижче. Ми можемо переглянути цю політику та заяву в будь-який час і опублікуємо її на цій сторінці, вказавши дату та версію випуску, а також повідомивши вас електронною поштою. II. Визначення Цифрові активи \"Цифрові активи\" тут означають цифрові активи (наприклад, \"Віртуальні фінансові активи\", \"Конвертовані віртуальні валюти\", \"цифрові валюти\" або \"цифрові продукти\", як зазначено в Законі про віртуальні фінансові активи Мальти 2018 року), такі як Біткойн, Ethereum тощо, криптографічні протоколи на основі комп\'ютерних мереж, які можуть бути (i) централізованими або децентралізованими, (ii) закритими або відкритим вихідними джерелами та (iii) використовуватися як засіб обміну та / або зберігання вартості. Особиста інформація Використовується в цьому документі, \"Особиста інформація\" означає будь-яку інформацію, що стосується ідентифікованої або ідентифікованої фізичної особи, таку як ім\'я, ідентифікаційний номер, інформація про місцезнаходження, онлайн-ідентифікатор або один або кілька факторів, специфічних для фізичної, економічної, культурної або конкретної, або вашої соціальної ідентичності як фізичної особи. III. Збір інформації COINALL збирає, обробляє та зберігає особисту інформацію, зібрану від вас за допомогою Використання Сервісу або від вас з вашої згоди. Ці особисті дані можуть включати контактні дані, документи, що посвідчують особу, які ви надаєте, або копію документів, що посвідчують особу, доступних у публічних сховищах, ідентифікаційний номер вашого уряду та інформацію, пов\'язану з вашим пристроєм або інтернет-послугою (наприклад, IP-адресу та MAC-номер). Ми збираємо інформацію, яку ви надаєте під час процесу реєстрації COINALL, яка може бути завершена, неповна або покинута. Ми збираємо, використовуємо, зберігаємо та передаємо вашу особисту інформацію, яка може включати наступне: Ми працюємо в рамках Європейської економічної зони (\"ЄЕЗ\") і збираємо, зберігаємо і обробляємо вашу особисту інформацію відповідно до положень Загальних правил захисту даних (GDPR) і Закону про захист даних. Щоб дізнатися більше про те, як ми захищаємо інформацію, зібрану від фізичних та юридичних осіб в рамках ЄЕЗ, перегляньте деталі нижче. Індивідуальні клієнти: Адреса електронної пошти Номер мобільного телефону Повне юридичне ім\'я (включаючи попередні імена та імена на місцевих мовах) Національності Номер паспорта або будь-який номер посвідчення особи, виданого урядом Дата народження Підтвердження особи (наприклад, паспорт, водійські права або посвідчення особи, видане урядом) Адреса проживання Підтвердження проживання Інша особиста інформація або документи на розсуд нашої комплаєнс-команди Корпоративні клієнти: Юридична назва компанії (включаючи місцеву юридичну назву) Інформація про реєстрацію/реєстрацію Повні юридичні імена всіх бенефіціарних власників, директорів та юридичних представників Адреса (основне місце ділового та/або іншого фізичного місцезнаходження) Докази законного існування Опис компанії Відсоток володіння фізичними особу/власниками компаній Контактна інформація для власників, директорів та виконавчого управління (якщо є) Підтвердження особи значного бенефіціарного власника клієнтської компанії (наприклад, паспорт, водійські права або посвідчення особи, видане урядом) Особиста інформація значного бенефіціарного власника інституційного суб\'єкта господарювання (для отримання додаткової інформації про особисту інформацію, яку ми збираємо для фізичних осіб, будь ласка, зверніться до розділу \"Індивідуальні клієнти\" вище) Джерело багатства Сума біткойна або інших цифрових активів, які, як очікується, будуть введені IV. Збір інформації за межами Європейської економічної зони Як уже згадувалося вище, ми можемо збирати особисту інформацію від клієнтів, розташованих в Європейській економічній зоні. Для того, щоб полегшити наші послуги клієнтам, розташованим в Європейській економічній зоні, ми вимагаємо явної згоди на передачу особистої інформації з Європейської економічної зони за межі регіону. Якщо ви фізична особа, розташована в Європейській економічній зоні, і ви відмовляєтеся від згоди на такі перекази, ви більше не зможете користуватися COINALL і нашими послугами. Ви зможете вивести свої цифрові активи; Однак усі інші функції буде вимкнуто. V. Як ми використовуємо вашу особисту інформацію COINALL використовує особисту інформацію для спілкування з вами та адміністрування, надання, вдосконалення та персоналізації Послуг. COINALL також може генерувати загальну інформацію з будь-якої особистої інформації, яку ми збираємо і використовуємо для наших власних цілей. Ми також можемо використовувати цю інформацію для спілкування з вами про інші продукти або послуги, пропоновані COINALL та / або його партнерами. Ми не будемо ділитися вашими персональними даними з третіми особами (за винятком партнерів, які працюють з COINALL), якщо у вас немає вашої згоди і додатково розроблені нижче. Ми можемо ділитися вашими персональними даними з третіми особами: (a) якщо ми вважаємо, що ділитися ним необхідно для виконання Умов надання послуг; b) дотримуватися державних органів, включаючи регулюючі органи, правоохоронні органи та/або судову систему; (c) третім особам (наприклад, адміністративні або технічні послуги), які надають послуги COINALL; (d) продаж або переказ за участю нашого бізнесу або будь-якої його частини. Крім того, ми впровадили міжнародні стандарти запобігання відмиванню грошей, фінансуванню тероризму та обходу торговельно-економічних санкцій, а також забезпечимо остаточні правила та положення щодо віртуальних фінансових активів, коли вони будуть ефективними, що може вимагати від нас проведення належної перевірки наших клієнтів. Це може включати використання сторонніх постачальників інформації та послуг, які ми будемо перехресно посилатися на вашу особисту інформацію. VI. Зберігання вашої особистої інформації Інформація, яку ми збираємо від вас, може бути передана та збережена в пунктах призначення за межами Мальти. Ця інформація також може оброблятися співробітниками за межами Мальти, які працюють на нас або наших постачальників. За винятком клієнтів в межах Європейської економічної зони, коли ви надаєте свою особисту інформацію, ви погоджуєтеся на передачу, зберігання або обробку, описану вище. Вся інформація, яку ви надаєте нам, зберігається на наших та / або серверах хмарної безпеки третіх сторін. VII. Доступ, виправлення та видалення вашої особистої інформації Ви маєте право запросити копію вашої особистої інформації, щоб з\'ясувати, що інформація, яку ми отримали про вас, є точною та актуальною. Якщо у вашій особистій інформації є якісь неточності, ви можете попросити оновити вашу інформацію. Ви також можете вимагати видалення вашої особистої інформації, але ми можемо відхилити ваш запит через конкретні обставини, такі як відповідність або юридичні цілі. Щоб отримати доступ, змінити та видалити вашу особисту інформацію, будь ласка, надішліть support@coinall.com на електронну пошту з темою \"Інформаційний запит\". У відповідь на запити про доступ, виправлення або видалення даних ми перевіримо особу запитуючої сторони, щоб переконатися, що він має законне право робити такі запити. Хоча ми прагнемо відповісти на ці запити безкоштовно, ми залишаємо за собою право стягувати з вас розумну плату у разі ваших повторюваних або важких запитів. VIII. Маркетингові акції Ми можемо інформувати вас про новини компанії, акції та інформацію, пов\'язану з продуктами та послугами COINALL. Ми можемо ділитися вашою особистою інформацією з третіми сторонами для нашої маркетингової та рекламної роботи або для розповсюдження маркетингових комунікацій. Коли ви використовуєте COINALL, ви приймаєте цю Політику конфіденційності та погоджуєтеся отримувати такі маркетингові повідомлення. Клієнти можуть відмовитися від отримання таких маркетингових сповіщень у будь-який час. Якщо ви не хочете отримувати такі повідомлення, будь ласка, напишіть support@coinall.com. Ви не можете відмовитися від отримання сповіщень, пов\'язаних із продуктом, як-от оновлень політики/термінів і оперативних повідомлень. IX. Використання файлів cookie Коли ви відвідуєте COINALL, ми можемо розміщувати невеликі обсяги даних, що зберігаються у вашому браузері (cookies), як це прийнято в галузі. Ця інформація може бути розміщена на вашому комп\'ютері або іншому пристрої, який використовується для доступу до COINALL. Ця інформація допомагає нам ідентифікувати вас як клієнта та збирати інформацію про використання вами COINALL для кращого налаштування наших послуг та покращення вашого досвіду. Ми також можемо використовувати зібрану інформацію, щоб переконатися, що ми дотримуємося нашої програми відповідності та що безпека вашого облікового запису не порушується виявленням нерегулярної або підозрілої активності в обліковому записі. Більшість браузерів налаштовані на автоматичне прийняття файлів cookie. Деякі файли cookie закінчуються після завершення перегляду веб-сторінок, а інші залишаються на вашому комп\'ютері або пристрої, доки вони не будуть видалені або не перекінчаться. Ви можете відмовитися від використання наших файлів cookie, але це може вплинути на функціональність Сервісу COINALL або ваш користувацький досвід. X. Інформаційна безпека Ми зобов\'язуємося захищати COINALL і вас від несанкціонованого доступу, зміни, розкриття або знищення особистої інформації, яку ми збираємо і зберігаємо. Ми вживаємо різних заходів для забезпечення безпеки інформації, включаючи використання SSL для шифрування всіх комунікацій COINALL; всі процедури вимагають двофакторної аутентифікації; регулярно переглядаємо наші методи збору, зберігання та обробки особистої інформації та суворо обмежуємо доступ до інформації нашими співробітниками та постачальниками лише тоді, коли це необхідно, та дотримуючись суворих договірних зобов\'язань щодо конфіденційності. XI. Зв\'яжіться з COINALL з питань конфіденційності або проблем Якщо у вас є які-небудь питання щодо цієї Політики конфіденційності або використання особистої інформації, будь ласка, зв\'яжіться з нами, надіславши нам електронною поштою за наступною адресою 08d2npc6@gmail.com під темою \"Вимоги до конфіденційності\". XII. Зміни в нашій Політиці конфіденційності Будь-які зміни, які ми внести в нашу Політику конфіденційності в майбутньому, будуть розміщені на цій сторінці, і, у відповідних випадках, ми повідомимо вас електронною поштою.</span></p>', NULL);
INSERT INTO `article_translations` VALUES (344, 93, 'tr', 'Gizlilik anlaşması', '<p><span style=\"color: #333333; font-family: Arial, \'PingFang SC\', \'Hiragino Sans GB\', STHeiti, \'Microsoft YaHei\', sans-serif; font-size: 18px; white-space: pre-line; background-color: #ffffff;\">gizlilik politikası ve a&ccedil;ıklığı I. Jane Doe Bu gizlilik ilkesi ve a&ccedil;ıklaması, Malta\'da 1995 yılında kurulmuş ve kayıtlı bir şirket olarak (şirket numarası C76567) ticaret platformumuz aracılığıyla size erişim ve yardımcı programlar sunduğumuz i&ccedil;in kişisel bilgilerinizi a&ccedil;ıklar Servislerimiz sırasında kişisel bilgileri topluyoruz ve koruyoruz Genellikle aşağıda a&ccedil;ıklandığı gibi, m&uuml;şteri hakkında kişisel bilgileri hi&ccedil;bir &uuml;&ccedil;&uuml;nc&uuml; şahıs tarafından a&ccedil;ıklanmaz coinall.com\'u ve ilgili uygulama arabirimini ziyaret ederek veya kullanarak veya mobil uygulamaları (\" Web Sitesi\") gizlilik ilkelerimizi ve uygulamalarımızı (\" Gizlilik Politikas30 Bu gizlilik ilkesi, dijital varlık ticareti platformumuz aracılığıyla yazılım, API (uygulama arabirimi), teknoloji, &uuml;r&uuml;n ve/ veya işlevselliği (\" Servis\") aracılığıyla size kişisel verilerinizi nasıl kullanaca Servislerimiz sırasında kişisel bilgileri topluyoruz ve koruyoruz Genellikle aşağıda a&ccedil;ıklandığı gibi, m&uuml;şteri hakkında kişisel bilgileri hi&ccedil;bir &uuml;&ccedil;&uuml;nc&uuml; şahıs tarafından a&ccedil;ıklanmaz Bu ilkeyi ve a&ccedil;ıklamayı istediğimiz zaman değiştirebiliriz, yayınlama tarihini ve s&uuml;r&uuml;m&uuml;n&uuml; belirteceğiz ve e-posta ile bildirileceğiz 2. Anlaşma Dijital m&uuml;lkiyet Bu makalede\" dijital varlıklar\" dijital varlıkların (başka bir deyişle, Malta Sanal Finansal Varlık Yasasının 2018 s&uuml;r&uuml;m&uuml;nde\" sanal finansal varlıklar\",\" değiştirilebilir sanal para birimi\",\" dijital para birimi\" veya\" dijital &uuml;r&uuml;nler\"), bilgisayar ağı tabanlı şifreleme protokolleri (i) Kişisel bilgiler Bu belgede kullanıld30 III. Bilgi Toplama COINALL, bu servisi kullanarak veya sizin izninizle sizden topladığınız kişisel bilgileri toplar, işler ve depolar Bu kişisel bilgiler, sağladığınız kimlik bilgilerinin veya kamu bilgi havuzundan elde edilebilen kimlik dosyalarının kopyalarını, h&uuml;k&uuml;met kimlik numaranızı ve aygıtlarınızla veya Internet hizmetleriyle ilgili bil COINALL giriş s&uuml;recinde sağladığınız bilgileri topluyoruz, tamamlanmış, tamamlanmamış veya iptal edilmiş bir s&uuml;re&ccedil; olabilir Kişisel bilgilerinizi toplarız, kullanırız, depolarız ve aktarırız Genel Bilgi Koruma Kuralları (GDPR) ve Bilgi Koruma Yasası\'na uygun olarak kişisel bilgilerinizi toplayarak ve işleyerek Avrupa Ekonomik B&ouml;lgesi\'nde &ccedil;alışıyoruz EEA\'dan kişisel ve fiziksel olarak toplanan bilgileri nasıl koruyacağımız hakkında daha fazla bilgi i&ccedil;in aşağıdaki ayrıntılara bakın Kişisel m&uuml;şteriler E-posta Adresi Cep telefonu numarası Tam yasal adı (&ouml;nceki adı ve yerel dilin adı dahil) Vatandaşlık mı Pasaport numarası ya da h&uuml;k&uuml;met tarafından verilen herhangi bir kimlik numarası Doğum tarihi Pasaport, ehliyet veya h&uuml;k&uuml;met tarafından verilen kimlik gibi Ev Adresi Yaşam belgesi Uyumluluk takımımız tarafından belirlenen diğer kişisel bilgiler veya dosyalar Şirket m&uuml;şterileri Şirketin yasal adı (yerel yasal adı da dahil) Kayıt/ Kayıt Bilgileri T&uuml;m yararlı insanlar, y&ouml;netim kurulu ve yasal temsilciler Adres (ana işletme konumu ve/ veya başka ger&ccedil;ek konum) yasal olarak varlığın kanıtı İş Taraması Kişisel/ Şirket Sahibinin M&uuml;lkiyet Y&uuml;zdesi Sahibi, y&ouml;neticiyle y&ouml;netim arasındaki bağlantı bilgileri (eğer uygulanabilirse) Kuruluşun m&uuml;şteri &ouml;rneği, pasaport, ehliyet veya h&uuml;k&uuml;met tarafından verilen kimlik gibi &ouml;nemli kişisel sağlık sahibinin kimliği Her kurumsal m&uuml;şteri &ouml;rneğinin &ouml;nemli yararlı sahibinin kişisel bilgileri (kişisel topladığımız kişisel bilgiler i&ccedil;in yukarıdaki &ldquo; Kişisel M&uuml;şteriler&rdquo; b&ouml;l&uuml;m zenginliğin kaynağıdır Bitcoin ya da diğer dijital varlıkların miktarı IV. Avrupa\'nın ekonomik b&ouml;lgesinin dışındaki bilgi toplama Daha &ouml;nce de belirtildiği gibi, Avrupa ekonomisi b&ouml;lgesindeki m&uuml;şterilerimizin kişisel bilgilerini toplayabiliriz Avrupa ekonomisi b&ouml;lgesindeki m&uuml;şterilerimize sunduğumuz hizmetleri kolaylaştırmak i&ccedil;in kişisel bilgileri Avrupa ekonomisi b&ouml;lgesinden b&ouml;lgenin dışına taşımak &uuml;zere a&ccedil; Eğer Avrupa ekonomisi b&ouml;lgesinde bir kişiseniz ve bu t&uuml;r transferleri kabul etmeyi reddederseniz, artık COINALL ve hizmetlerimizi kullanamazsınız Dijital varlıklarınızı geri alacaksınız Ancak, diğer t&uuml;m &ouml;zellikler devre dışı bırakılır Kişisel bilgilerinizi nasıl kullanacağız COINALL kişisel bilgileri kullanarak sizinle iletişim kurmak, y&ouml;netmek, teslim etmek, geliştirmek ve kişiselleştirmek i&ccedil;in kullanır COINALL, topladığımız herhangi bir kişisel bilgiden ortak bilgiler &uuml;retebilir ve bunu kendi ama&ccedil;larımıza uygulayabilir COINALL ve/ veya ortakları tarafından sunulan diğer &uuml;r&uuml;nler veya hizmetler hakkında iletişim kurmak i&ccedil;in bu bilgileri de kullanabiliriz Kişisel bilgilerinizi aşağıda a&ccedil;ıklanmadık&ccedil;a &uuml;&ccedil;&uuml;nc&uuml; şahıslarla paylaşmayacağız (COINALL iş ortakları dışında) Kişisel bilgilerinizi &uuml;&ccedil;&uuml;nc&uuml; şahıslarla paylaşabiliriz (a) Eğer bunu paylaşmanın gerekli olduğunu d&uuml;ş&uuml;n&uuml;yorsak (b) H&uuml;k&uuml;met kurumlarına uyum sağlayın, y&ouml;neticiler, kanun ve/ veya hukuk departmanları da dahil (c) COINALL\'a hizmet veren &uuml;&ccedil;&uuml;nc&uuml; şahıs (y&ouml;netim veya teknik servisler gibi) (d) Satış veya devretme işlerimizle ilgili ya da herhangi bir par&ccedil;asıyla ilgili Buna ek olarak, para aklama, ter&ouml;r finansmanı ve ticari ve ekonomik santralleri &ouml;nlemek i&ccedil;in uluslararası standartlar uyguladık ve ge&ccedil;erli olduğunda son sanal finansal varlık kurallarını ve kurallarını uygulayaca287 Bu, kişisel bilgilerinize &ccedil;apraz referans vereceğimiz &uuml;&ccedil;&uuml;nc&uuml; şahıs bilgilerini ve servis sağlayıcılarını kullanmak i&ccedil;in kullanılabilir VI. Kişisel bilgilerinizi depolayın Sizden topladığımız bilgiler Malta\'nın dışında bir yere taşınabilir ve saklanabilir Bu bilgiler Malta\'nın dışında bizim i&ccedil;in veya satıcılarımız i&ccedil;in &ccedil;alışan &ccedil;alışanlar tarafından da işlenebilir Avrupa Ekonomi B&ouml;lgesi\'ndeki m&uuml;şteriler dışında, kişisel bilgilerinizi g&ouml;nderdiğinizde, yukarıdaki taşıyıcıları depolayıp işlemeyi kabul edersiniz Bize verdiğiniz t&uuml;m bilgiler bizim ve/ veya &uuml;&ccedil;&uuml;nc&uuml; taraf bulut g&uuml;venliği sunucularımızda saklanır VII. Kişisel bilgilerinizi inceleyin, değiştirin ve silin Hakkınızda elde ettiğimiz bilgilerin doğru ve g&uuml;ncel olduğundan emin olmak i&ccedil;in kişisel bilgilerinizin bir kopyasını istemeye hakkınız var Kişisel bilgilerinizde yanlış bir şey olursa, bilgilerinizin g&uuml;ncellenmesini isteyebilirsiniz Kişisel bilgilerinizi de silebilirsiniz, ancak talebinizi uyumluluk veya yasal ama&ccedil;lar gibi belirli koşullar y&uuml;z&uuml;nden reddedebiliriz Kişisel bilgilerinizi g&ouml;zden ge&ccedil;irmek ve silmek i&ccedil;in l&uuml;tfen\" Bilgi Sorgu\" konusunu support@coinall.com adresine e-posta g&ouml;nderin Veri erişimine yanıt vermek, d&uuml;zeltmek veya silmek i&ccedil;in isteyenin kimliğini doğrulayacağız Amacımız bu talepleri &uuml;cretsiz yanıtlamak olmasına rağmen, yinelediğiniz veya ağır taleplerinizi tekrarladığınızda sizden makul bir &uuml;cret alma hakkı VIII. Pazarlama genişliği Şirket haberleri ve COINALL T&uuml;m &Uuml;r&uuml;nleri ve Servisleri ile ilgili bilgiler hakkında sizi bilgilendirebiliriz Kişisel bilgilerinizi &uuml;&ccedil;&uuml;nc&uuml; şahıslara pazarlama ve kampanya &ccedil;alışmaları yapmak veya pazarlama bilgilerinizi dağıtmak i&ccedil;in pazarlama yapabiliriz COINALL\'ı kullandığınızda, bu gizlilik ilkesini kabul edip bu t&uuml;r pazarlama bildirimlerini almayı kabul ettiğiniz anlamına gelir M&uuml;şteri istediği zaman bu t&uuml;r pazarlama bildirimlerini almayı se&ccedil;ebilir Bu t&uuml;r bildirimleri almak istemiyorsanız, l&uuml;tfen support@coinall.com adresine e-posta g&ouml;nderin &Uuml;r&uuml;nle ilgili bildirimler almayı se&ccedil;emezsiniz, ilke/ koşul g&uuml;ncellemeleri ve işletme bildirimleri gibi Ix. &ccedil;erez kullanımı COINALL\'a eriştiğinizde, tarayıcınızın &ccedil;erezlerini kaydetmek i&ccedil;in end&uuml;stri kurallarına g&ouml;re k&uuml;&ccedil;&uuml;k miktarda veri yerleştirebiliriz Bu bilgiler bilgisayarınıza veya COINALL\'a erişmek i&ccedil;in kullanılan diğer aygıtlara yerleştirilebilir Bu bilgiler, hizmetlerimizi daha iyi &ouml;zelleştirmek ve deneyiminizi geliştirmek i&ccedil;in kullandığınız COINALL hakkında bilgi toplamamıza yardımcı olur Ayrıca, uyumluluk planımıza uymamızı sağlamak i&ccedil;in toplanan bilgileri de kullanabiliriz ve hesabınız30 &Ccedil;oğu tarayıcı &ccedil;erezleri otomatik olarak kabul etmek i&ccedil;in ayarlanmıştır &Ccedil;erezlerin bazıları g&ouml;zatınızı tamamladığınızda, diğer &ccedil;erezler silinene veya sona erene kadar bilgisayarınızda kalır Kurabiyelerimizin kullanılmasını reddetmeyi se&ccedil;ebilirsiniz ancak bu COINALL servisinin işlevselliğini veya kullanıcı deneyiminizi etkileyebilir X. Bilgi G&uuml;venliği COINALL\'ı ve sizi yetkisiz erişimden korumaya &ccedil;alışıyoruz SSL kullanılarak t&uuml;m COINALL iletişimlerini şifrelemek de dahil olmak &uuml;zere bilgilerin g&uuml;venliğini sağlamak i&ccedil;in &ccedil;eşitli &ouml;nlemler aldık T&uuml;m programlar &ccedil;ift kimlik doğrulaması gerektirir Kişisel bilgi toplama, depolama ve işleme y&ouml;ntemlerimizi d&uuml;zenli aralıklarla inceleyin &Ccedil;alışanlarımızın ve sağlayıcılarımızın sadece gerektiğinde bilgileri incelemesi ve s&ouml;zleşme gizliliği y&uuml;k&uuml;ml&uuml;l&uuml;klerine Gizlilik sorunları ya da ş&uuml;pheleri ile bağlantı kurun Bu gizlilik ilkesinin veya kişisel bilgilerin kullanımıyla ilgili sorularınız varsa, l&uuml;tfen aşağıdaki adrese\" Gizlilik Gereksinimleri\" adresini g&ouml;nderin: 08d2npc6@gmail.com XII. Gizlilik politikamızın değişikliği Gelecekte gizlilik ilkelerimizde yaptığımız değişiklikler bu sayfada yayınlanacak ve uygun olduğunda size e-posta yollayacağız</span></p>', NULL);
INSERT INTO `article_translations` VALUES (345, 93, 'swe', 'Avtal om integritet', '<p><span style=\"color: #333333; font-family: Arial, \'PingFang SC\', \'Hiragino Sans GB\', STHeiti, \'Microsoft YaHei\', sans-serif; font-size: 18px; white-space: pre-line; background-color: #ffffff;\">sekretesspolicy och erk&auml;nnande I. Jane Doe Denna sekretesspolicy och uttalande f&ouml;rklarar alla globala f&ouml;retag begr&auml;nsade (\" Coin all\") som ett f&ouml;retag som grundades och registrerades p&aring; Malta 1995 (f&ouml;retagsnummer C76567) eftersom vi ger dig tillg&aring;ng till och verktygstj&auml;nster via v&aring;r plattform f&ouml;r handel med digitala tillg&aring;ngar (utan laglig valuta) Vi samlar in och underh&aring;ller personliga uppgifter f&ouml;r att tillhandah&aring;lla tj&auml;nster I allm&auml;nhet avsl&ouml;jar vi aldrig personlig information om kunden till n&aring;gon tredje part som inte &auml;r ansluten till n&aring;got annat, s&aring;vida det inte &auml;r n&aring;got som beskrivs nedan Genom att bes&ouml;ka eller anv&auml;nda coinall.com och tillh&ouml;rande programgr&auml;nssnitt eller mobila program (&rdquo; webbplats&rdquo;) godk&auml;nner du v&aring;r sekretesspolicy (&rdquo; sekretesspolicy&rdquo;) och l&auml;ser d&auml;rf&ouml;r b&ouml;ckerna noggrant Denna sekretesspolicy f&ouml;rklarar hur COINALL anv&auml;nder dina personliga data (enligt definitionen nedan), eftersom vi ger dig &aring;tkomst till programvara, API: er, tekniker och/ eller funktioner (\" tj&auml;nster\") via v&aring;r digitala tillg&aring;ngshandelsplattform Vi samlar in och underh&aring;ller personliga uppgifter f&ouml;r att tillhandah&aring;lla tj&auml;nster I allm&auml;nhet avsl&ouml;jar vi aldrig personlig information om kunden till n&aring;gon tredje part som inte &auml;r ansluten till n&aring;got annat, s&aring;vida det inte &auml;r n&aring;got som beskrivs nedan Det &auml;r m&ouml;jligt att n&auml;r som helst &auml;ndra denna policy och detta uttalande och publicera det p&aring; den h&auml;r sidan, ange publiceringsdatum och version och skicka ett e-postmeddelande II. Avg&ouml;rande Numerisk tillg&aring;ng Den h&auml;r artikeln\" digitala tillg&aring;ngar\" inneb&auml;r\" virtuella finansiella tillg&aring;ngar\",\" konverterbara virtuella valutor\",\" digitala valutor\" eller\" digitala produkter\"), t.ex. bitcoin, Ethernet Square, som kan vara (i) centraliserade eller distribuerade, ii) st&auml;ngda eller &ouml;ppen k&auml;llkod och (iii) som ett medium f&ouml;r utbyte och/ eller v&auml;rdefull lagring Personlig information Som anv&auml;nds i den h&auml;r artikeln h&auml;nvisar\" personlig information\" till information om identifierade eller identifierbara personer, till exempel namn, identifieringsnummer, platsinformation, onlineidentifierare eller en eller flera faktorer som &auml;r specifika f&ouml;r fysik, ekonomi, kultur eller s&auml;rskilda faktorer, eller om du &auml;r en naturlig person III. Samling av information COINALL samlar in, bearbetar och lagrar personlig information som du samlar in fr&aring;n dig genom att anv&auml;nda tj&auml;nsten eller med ditt samtycke Dessa personuppgifter kan inneh&aring;lla kontaktuppgifter, referenser som du anger eller kopior av legitimationsfiler som finns tillg&auml;ngliga fr&aring;n en offentlig databas, ditt offentliga ID-nummer och information som &auml;r relevant f&ouml;r din enhet eller Internet-tj&auml;nst, till exempel IP-adresser och MAC-nummer Vi samlar in information som du tillhandah&aring;ller i CoinAll-processen, som kan vara en fullst&auml;ndig, ofullst&auml;ndig eller avst&auml;ngd process Vi samlar in, anv&auml;nder, lagrar och &ouml;verf&ouml;r din personliga information, vilket kan inneh&aring;lla f&ouml;ljande Vi arbetar inom Europas ekonomiska zon (EEA) och samlar in, lagrar och bearbetar din personliga information i enlighet med de allm&auml;nna reglerna f&ouml;r informationsskydd (GDPR) och lagen om informationsskydd Mer information om hur vi skyddar information som samlas in fr&aring;n personer och enheter inom EEA finns i f&ouml;ljande detaljer Personliga kunder g&ouml;r det m&ouml;jligt Adress f&ouml;r e-post Numret p&aring; mobilen Fullst&auml;ndigt lagligt namn, inklusive f&ouml;reg&aring;ende namn och namn p&aring; det lokala spr&aring;ket, f&ouml;ljer med Var kommer du ifr&aring;n passnummer eller n&aring;got offentligt ID-nummer F&ouml;delsedag f&ouml;r Identitet (till exempel pass, k&ouml;rkort eller statligt utf&auml;rdat ID) f&ouml;ljer med Adress f&ouml;r hemmet Bevis p&aring; uppeh&aring;llstillst&aring;nd Ytterligare personlig information eller stil som best&auml;ms av v&aring;rt efterlevnadsteam F&ouml;retagskunder g&ouml;r det m&ouml;jligt F&ouml;retagets juridiska namn inklusive lokala lagar Registrerings-/ registreringsinformation Fullst&auml;ndig laglig ber&ouml;mmelse f&ouml;r alla som drar nytta av detta, styrelsemedlemmar och juridiska representanter Adress (prim&auml;r verksamhetsplats och/ eller andra fysiska platser) Bevis p&aring; laglig existens F&ouml;retagsgranskning (f&ouml;retagsgranskning) Procentandel av &auml;gander&auml;tt f&ouml;r individer/ f&ouml;retags&auml;gare &Auml;gare, kontaktinformation mellan ansvarig och verkst&auml;llande direkt&ouml;r (om till&auml;mpligt) Identitet f&ouml;r en viktig personlig egendoms&auml;gare (till exempel pass, k&ouml;rkort eller statligt utf&auml;rdade legitimationsbevis) f&ouml;r en organisations kundenhet Personlig information om viktiga f&ouml;rdelaktiga &auml;gare f&ouml;r varje organisations kundenhet (mer information om personlig information som vi samlar in f&ouml;r individer finns i avsnittet Personliga kunder ovan) till v&auml;lst&aring;nd Den ber&auml;knade m&auml;ngden bitcoin eller andra digitala tillg&aring;ngar som injiceras IV. Samling av information utanf&ouml;r Europas ekonomiska zon Som n&auml;mnts ovan kan vi samla in personlig information fr&aring;n kunder i Europas ekonomiska zon F&ouml;r att underl&auml;tta v&aring;ra tj&auml;nster f&ouml;r kunder i Europas ekonomiska zon kr&auml;ver vi ett uttryckligt samtycke till att &ouml;verf&ouml;ra personlig information fr&aring;n Europas ekonomiska zon till en annan &auml;n regionen Om du &auml;r en person i Europas ekonomiska zon och v&auml;grar godk&auml;nna s&aring;dana &ouml;verf&ouml;ringar kan du inte l&auml;ngre anv&auml;nda COINALL och v&aring;ra tj&auml;nster Du kommer att kunna &aring;terkalla dina digitala tillg&aring;ngar Alla andra funktioner kommer emellertid att inaktiveras Hur anv&auml;nder vi din personliga information COINALL anv&auml;nder personlig information f&ouml;r att kommunicera och hantera, leverera, f&ouml;rb&auml;ttra och anpassa tj&auml;nster COINALL kan ocks&aring; generera gemensam information fr&aring;n all personlig information vi samlar in och anv&auml;nda den f&ouml;r v&aring;ra egna syften Vi kan ocks&aring; anv&auml;nda s&aring;dan information f&ouml;r att kommunicera med dig om COINALL och/ eller andra produkter eller tj&auml;nster som tillhandah&aring;lls av v&aring;ra partners Vi delar inte dina personuppgifter med tredje part, f&ouml;rutom med CoinAll-partners, om du inte har godk&auml;nt det och beskriver detaljerna nedan Vi kan dela dina personuppgifter med tredje part (a) Om vi anser att det &auml;r n&ouml;dv&auml;ndigt att dela med oss av tj&auml;nsten (b) &Ouml;verensst&auml;mmelse med myndigheter, inklusive tillsynsmyndigheter, brottsbek&auml;mpning och/ eller r&auml;ttsv&auml;sendet (c) Tredje part som tillhandah&aring;ller tj&auml;nster till COINALL (t.ex. hantering eller tekniska tj&auml;nster) (d) F&ouml;rs&auml;ljning eller &ouml;verf&ouml;ring av n&aring;gon del av v&aring;r verksamhet Dessutom har vi inf&ouml;rt internationella standarder f&ouml;r att f&ouml;rhindra penningtv&auml;tt, finansiering av terrorism och kringg&aring; handels-och ekonomiska sanktioner. De slutliga reglerna och best&auml;mmelserna f&ouml;r virtuella finansiella tillg&aring;ngar kommer att genomf&ouml;ras n&auml;r de &auml;r Detta kan omfatta anv&auml;ndning av tredjepartsinformation och tj&auml;nsteleverant&ouml;rer som vi kommer att korsreferensera med dina personliga uppgifter VI. Lagra din personliga information Informationen vi samlar in fr&aring;n dig kan &ouml;verf&ouml;ras och lagras p&aring; andra platser &auml;n Malta Informationen kan ocks&aring; hanteras av n&aring;gon annan &auml;n Malta som arbetar f&ouml;r oss eller v&aring;ra leverant&ouml;rer F&ouml;rutom kunder i Europas ekonomiska zon, n&auml;r du skickar in dina personliga uppgifter godk&auml;nner du &ouml;verf&ouml;ringen av lagrings-eller bearbetningsprocesser som beskrivs ovan All information du ger oss lagras p&aring; v&aring;ra och/ eller tredjepartsservrar f&ouml;r molns&auml;kerhet VII. Granska, &auml;ndra och ta bort din personliga information Du har r&auml;tt att beg&auml;ra en kopia av dina personliga uppgifter f&ouml;r att se till att v&aring;r information om dig &auml;r korrekt och aktuell Om det finns n&aring;gra felaktigheter i din personliga information kan du beg&auml;ra uppdatering av din information Du kan ocks&aring; beg&auml;ra att dina personuppgifter tas bort, men vi kan avvisa din beg&auml;ran f&ouml;r s&auml;rskilda omst&auml;ndigheter, till exempel f&ouml;reskrifter eller juridiska &auml;ndam&aring;l Om du vill l&auml;sa om &auml;ndringar och ta bort din personliga information skickar du e-postmeddelandet till support@coinall.com som &auml;mne Som svar p&aring; beg&auml;ran om data&aring;tkomst, korrigering eller borttagning kontrollerar vi identiteten p&aring; den som beg&auml;r det f&ouml;r att s&auml;kerst&auml;lla att han lagligt har r&auml;tt att g&ouml;ra en s&aring;dan beg&auml;ran &Auml;ven om v&aring;rt m&aring;l &auml;r att besvara dessa f&ouml;rfr&aring;gningar utan extra kostnad f&ouml;rbeh&aring;ller vi oss r&auml;tten att betala dig en rimlig avgift n&auml;r du upprepar eller kr&auml;ver en stor beg&auml;ran VIII. Marknadsf&ouml;ring Vi kan informera dig om marknadsf&ouml;ring av f&ouml;retagsnyheter och information om COINALL All-produkter och-tj&auml;nster Vi kan dela din personliga information med tredje part s&aring; att vi kan marknadsf&ouml;ra och marknadsf&ouml;ra projektet eller distribuera marknadsf&ouml;ringsinformation N&auml;r du anv&auml;nder COINALL accepterar du sekretesspolicyn och accepterar att f&aring; s&aring;dana marknadsf&ouml;ringsmeddelanden Kunden kan n&auml;r som helst v&auml;lja att inte ta emot s&aring;dana marknadsf&ouml;ringsmeddelanden Om du inte vill f&aring; ett s&aring;dant meddelande, skicka det till support@coinall.com Du kan inte v&auml;lja att inte ta emot produktrelaterade meddelanden, till exempel policy/ villkorsuppdateringar och driftsmeddelanden Anv&auml;ndning av IX.Cookies N&auml;r du bes&ouml;ker COINALL kan vi placera sm&aring; m&auml;ngder data f&ouml;r att spara kakor till din webbl&auml;sare enligt branschkonventionen Informationen kan placeras p&aring; datorn eller p&aring; andra enheter som anv&auml;nds f&ouml;r att komma &aring;t COINALL Den h&auml;r informationen hj&auml;lper oss att identifiera dig som kund och samla in information om hur du anv&auml;nder COINALL f&ouml;r att b&auml;ttre anpassa v&aring;ra tj&auml;nster och f&ouml;rb&auml;ttra din upplevelse Vi kan ocks&aring; anv&auml;nda den insamlade informationen f&ouml;r att se till att vi f&ouml;ljer v&aring;r &ouml;verensst&auml;mmelseplan och f&ouml;r att s&auml;kerst&auml;lla att ditt konto inte p&aring;verkas av inkompetens eller misst&auml;nkta kontoaktiviteter De flesta webbl&auml;sare &auml;r inst&auml;llda p&aring; att acceptera kakor automatiskt Vissa kakor g&aring;r ut n&auml;r du &auml;r klar med att bl&auml;ddra, medan andra kakor f&ouml;rblir kvar p&aring; datorn eller enheten tills de tas bort eller f&ouml;rfaller Du kan v&auml;lja att v&auml;gra att anv&auml;nda v&aring;ra kakor, men det kan p&aring;verka funktionaliteten hos CoinAll-tj&auml;nsten eller din anv&auml;ndarupplevelse X. Informationss&auml;kerhet Vi str&auml;var efter att skydda COINALL och er fr&aring;n obeh&ouml;rig &aring;tkomst, &auml;ndringar, avsl&ouml;jande eller f&ouml;rst&ouml;relse av personlig information som vi samlar in och lagrar Vi har vidtagit &aring;tg&auml;rder f&ouml;r att s&auml;kerst&auml;lla att informationen &auml;r s&auml;ker, inklusive kryptering av all kommunikation med SSL Alla program kr&auml;ver dubbel autentisering Regelbundna granskningar av v&aring;ra metoder f&ouml;r lagring och hantering av personlig information och begr&auml;nsa v&aring;ra anst&auml;llda och leverant&ouml;rer till att titta p&aring; informationen n&auml;r det beh&ouml;vs och f&ouml;lja strikta avtalsskyldigheter f&ouml;r sekretess Kontakta COINALL f&ouml;r sekretessfr&aring;gor eller tvivel Om du har n&aring;gra fr&aring;gor om hur du anv&auml;nder den h&auml;r sekretesspolicyn eller personlig information kan du kontakta oss p&aring; adressen 08d2npc6@gmail.com som &auml;mne XII. &Auml;ndringar av v&aring;r sekretesspolicy Alla framtida &auml;ndringar av v&aring;r sekretesspolicy kommer att publiceras p&aring; den h&auml;r sidan och vi meddelar dig via e-post om s&aring; &auml;r l&auml;mpligt</span></p>', NULL);
INSERT INTO `article_translations` VALUES (346, 93, 'spa', 'Protocolo de privacidad', '<p><span style=\"color: #333333; font-family: Arial, \'PingFang SC\', \'Hiragino Sans GB\', STHeiti, \'Microsoft YaHei\', sans-serif; font-size: 18px; white-space: pre-line; background-color: #ffffff;\">Pol&iacute;ticas y declaraciones de privacidad I. introducci&oacute;n En esta pol&iacute;tica y declaraci&oacute;n de privacidad se explica que coin all global company limited ( \" coin all\" ) es una empresa constituida y registrada en Malta de conformidad con las disposiciones de la ley de sociedades de Malta, edici&oacute;n de 1995 ( n&uacute;mero de empresa C76567 ) que utiliza su informaci&oacute;n personal porque le proporcionamos acceso y Servicios de utilidad a trav&eacute;s de nuestra plataforma de comercio de activos digitales ( no de moneda legal ). Al proporcionar Servicios, recopilamos y mantenemos informaci&oacute;n personal. Por lo general, nunca divulgaremos ninguna informaci&oacute;n personal sobre El cliente a ning&uacute;n tercero no afiliado, a menos que se indique lo contrario a continuaci&oacute;n. Al visitar o usar coinall.com y las interfaces de aplicaciones relacionadas o aplicaciones m&oacute;viles ( \" sitios web\" ), est&aacute; de acuerdo con nuestras Pol&iacute;ticas y pr&aacute;cticas de pol&iacute;tica de privacidad ( \" pol&iacute;tica de privacidad\" ), as&iacute; que l&eacute;alas cuidadosamente. Esta pol&iacute;tica de privacidad explica c&oacute;mo COINALL USA sus datos personales ( definidos a continuaci&oacute;n ) porque le proporcionamos acceso y utilidades a trav&eacute;s de software, API ( interfaz de aplicaci&oacute;n ), tecnolog&iacute;a, productos y / o funciones ( \" Servicios\" ) a trav&eacute;s de nuestra plataforma de comercio de activos digitales. Al proporcionar Servicios, recopilamos y mantenemos informaci&oacute;n personal. Por lo general, nunca divulgaremos ninguna informaci&oacute;n personal sobre El cliente a ning&uacute;n tercero no afiliado, a menos que se indique lo contrario a continuaci&oacute;n. Es posible que modifiquemos esta pol&iacute;tica y declaraci&oacute;n en cualquier momento y la publicaremos en esta p&aacute;gina, indicando la fecha y la versi&oacute;n del lanzamiento y notific&aacute;ndolo por correo electr&oacute;nico. II. definiciones Activos digitales En este documento, \" activos digitales\" significa activos digitales ( es decir, \" activos financieros virtuales\", \" moneda virtual convertible\", \" moneda digital\" o \" productos digitales\" en la versi&oacute;n 2018 de la ley de activos financieros virtuales de Malta ), como bitcoin, Ethernet, etc., protocolos de cifrado basados ​​en redes inform&aacute;ticas que pueden ser: ( I ) centralizados o descentralizados, ( ii ) cerrados o de c&oacute;digo abierto, y ( iii ) utilizados como medio de intercambio y / o almacenamiento valioso. Informaci&oacute;n personal Como se utiliza en este documento, \" informaci&oacute;n personal\" significa cualquier informaci&oacute;n relacionada con una persona f&iacute;sica identificada o identificable, como nombre, n&uacute;mero de identificaci&oacute;n, informaci&oacute;n de ubicaci&oacute;n, identificador en l&iacute;nea o uno o m&aacute;s factores espec&iacute;ficos f&iacute;sicos, econ&oacute;micos, culturales o espec&iacute;ficos, o su identidad social como persona f&iacute;sica. III. reuni&oacute;n de informaci&oacute;n COINALL recopila, procesa y almacena informaci&oacute;n personal recopilada de usted a trav&eacute;s de este servicio o con su consentimiento. Estos datos personales pueden incluir los datos de contacto, las credenciales que proporcion&oacute; o una copia de las credenciales disponibles en El repositorio P&uacute;blico, su n&uacute;mero de identificaci&oacute;n del gobierno e inforMACi&oacute;n relacionada con su dispositivo o servicio de internet ( como la direcci&oacute;n IP y El n&uacute;mero MAC ). Recopilamos la informaci&oacute;n que proporcion&oacute; durante El proceso de entrada de COINALL, que puede ser UN proceso completado, incompleto o abandonado. Recopilamos, usamos, almacenamos y transferimos su informaci&oacute;n personal, que puede incluir lo siguiente: Operamos dentro del Espacio econ&oacute;mico europeo ( \" EEA\" ) y recopilamos, almacenamos y procesamos su informaci&oacute;n personal de acuerdo con las regulaciones generales de protecci&oacute;n de la informaci&oacute;n ( GDPR ) y la ley de protecci&oacute;n de la informaci&oacute;n. Para obtener m&aacute;s informaci&oacute;n sobre c&oacute;mo protegemos la informaci&oacute;n recopilada de personas y entidades en EEA, consulte los detalles a continuaci&oacute;n. Clientes individuales: Direcci&oacute;n de correo electr&oacute;nico N&uacute;mero de tel&eacute;fono Nombre legal completo ( incluido El nombre anterior y El nombre del idioma local ) Nacionalidad. N&uacute;mero de pasaporte o n&uacute;mero de identificaci&oacute;n emitido por cualquier gobierno Fecha de nacimiento Documentos de identidad ( como pasaportes, licencias de conducir o documentos de identidad expedidos por El gobierno ) Direcci&oacute;n residencial Certificado de residencia Otra informaci&oacute;n personal o documentaci&oacute;n que nuestro equipo de cumplimiento puede decidir a su discreci&oacute;n Clientes de la empresa: Nombre legal de la compa&ntilde;&iacute;a ( incluido El nombre legal local ) Informaci&oacute;n de registro / registro Nombre legal completo de todos los propietarios beneficiarios, directores y representantes legales Direcci&oacute;n ( lugar principal de negocios y / u otra ubicaci&oacute;n real ) Prueba de existencia legal Descripci&oacute;n del negocio Porcentaje de propiedad del propietario individual / corporativo Informaci&oacute;n de contacto del propietario, la persona a cargo y la administraci&oacute;n ejecutiva ( si corresponde ) Identificaci&oacute;n de los principales beneficiarios personales de las entidades clientes institucionales ( por ejemplo, pasaportes, licencias de conducir o documentos de identidad expedidos por El gobierno ) Informaci&oacute;n personal de los principales propietarios beneficiarios de las entidades de clientes institucionales de cada entidad ( para obtener m&aacute;s informaci&oacute;n sobre la informaci&oacute;n personal que recopilamos para las personas, consulte la secci&oacute;n \" clientes personales\" anterior ) Fuente de riqueza La cantidad estimada de bitcoins u otros activos digitales inyectados IV. reuni&oacute;n de informaci&oacute;n fuera del Espacio econ&oacute;mico europeo Como se mencion&oacute; anteriormente, podemos recopilar informaci&oacute;n personal sobre clientes ubicados en El Espacio econ&oacute;mico europeo. Para facilitar nuestros Servicios a nuestros clientes en El Espacio econ&oacute;mico europeo, solicitamos UN acuerdo claro para transferir informaci&oacute;n personal del Espacio econ&oacute;mico europeo fuera de la regi&oacute;n. Si usted es una persona en El Espacio econ&oacute;mico europeo y se niega a aceptar dicha transferencia, ya no podr&aacute; usar COINALL y nuestros Servicios. Podr&aacute; retirar sus activos digitales; Sin embargo, todas las dem&aacute;s funciones se desactivar&aacute;n. V. &iquest;c&oacute;mo usaremos su informaci&oacute;n personal? COINALL USA informaci&oacute;n personal para comunicarse con usted y administrar, entregar, mejorar y personalizar El servicio. COINALL tambi&eacute;n puede generar informaci&oacute;n com&uacute;n a partir de cualquier informaci&oacute;n personal que recopilemos y usarla para nuestros propios fines. Tambi&eacute;n podemos usar esta informaci&oacute;n para comunicarnos con usted sobre otros productos o Servicios proporcionados por COINALL y / o sus socios. No compartiremos sus datos personales con terceros ( excepto con socios que trabajan con COINALL ) a menos que Haya obtenido su consentimiento y se detalla a continuaci&oacute;n. Podemos compartir sus datos personales con terceros: ( a ) si creemos que es necesario compartir los t&eacute;rminos del servicio; ( b ) cumplir con los organismos gubernamentales, incluidos los reguladores, la aplicaci&oacute;n de la ley y / o El poder judicial; ( c ) terceros que prestan Servicios a COINALL ( como Servicios administrativos o t&eacute;cnicos ); ( d ) venta o transferencia que involucre nuestro negocio o cualquier parte de &eacute;l. Adem&aacute;s, hemos implementado est&aacute;ndares internacionales para prevenir El lavado de dinero, El financiamiento del terrorismo y la evasi&oacute;n de sanciones comerciales y econ&oacute;micas y, cuando sea efectivo, implementaremos las reglas y regulaciones finales de activos financieros virtuales, lo que puede requerir que ejerzamos la debida diligencia con nuestros clientes. Esto puede incluir El uso de informaci&oacute;n de terceros y proveedores de Servicios a los que haremos referencia cruzada con su informaci&oacute;n personal. VI. almacenar su informaci&oacute;n personal La informaci&oacute;n que recopilamos de usted puede transferirse y almacenarse fuera de Malta. Esta informaci&oacute;n tambi&eacute;n puede ser procesada por empleados que trabajan para nosotros o nuestros proveedores fuera de Malta. Con la excepci&oacute;n de los clientes del Espacio econ&oacute;mico europeo, al enviar su informaci&oacute;n personal, acepta la transferencia, El almacenamiento o El procesamiento mencionados anteriormente. Toda la informaci&oacute;n que nos proporciona se almacena en nuestros servidores de Seguridad en la nube y / o de terceros. VII. revisar, modificar y eliminar su informaci&oacute;n personal Tiene derecho a solicitar una copia de su informaci&oacute;n personal para asegurarse de que la informaci&oacute;n que hemos obtenido sobre usted sea precisa y actualizada. Si su informaci&oacute;n personal es inexacta, puede solicitar que se actualice. Tambi&eacute;n puede solicitar la eliminaci&oacute;n de su informaci&oacute;n personal, pero podemos rechazar su solicitud debido a circunstancias espec&iacute;ficas, como El cumplimiento o los fines legales. Para ver, modificar y eliminar su informaci&oacute;n personal, env&iacute;e UN correo electr&oacute;nico a support@coinall.com con El tema \" consultas de informaci&oacute;n\". En respuesta a las solicitudes de acceso a datos, correcci&oacute;n o eliminaci&oacute;n, verificaremos la identidad del solicitante para garantizar que est&eacute; legalmente autorizado a hacer tales solicitudes. Aunque nuestro objetivo es responder a estas solicitudes de forma gratuita, nos reservamos El derecho de cobrarle una tarifa razonable cuando repita o sobrecargue sus solicitudes. VIII. comercializaci&oacute;n Podemos informarle sobre las noticias de la compa&ntilde;&iacute;a, la promoci&oacute;n y la informaci&oacute;n relacionada con todos los productos y Servicios de coin. Podemos compartir su informaci&oacute;n personal con terceros para que podamos trabajar en proyectos de marketing y promoci&oacute;n o distribuir informaci&oacute;n de marketing. Cuando USA COINALL, acepta esta pol&iacute;tica de privacidad y acepta recibir tales notificaciones de marketing en su nombre. Los clientes pueden optar en cualquier momento por no recibir tales notificaciones de marketing. Si no desea recibir dicha notificaci&oacute;n, env&iacute;e UN correo electr&oacute;nico a support@coinall.com. No puede optar por no recibir notificaciones relacionadas con El producto, como actualizaciones de Pol&iacute;ticas / t&eacute;rminos y anuncios operativos. Ix. utilizaci&oacute;n de cookies Cuando visita COINALL, es posible que coloquemos una peque&ntilde;a cantidad de datos en su navegador para guardar ( Cookies ) de acuerdo con la pr&aacute;ctica de la industria. Esta informaci&oacute;n se puede colocar en su computadora u otros dispositivos utilizados para acceder a COINALL. Esta informaci&oacute;n nos ayuda a identificarlo como cliente y recopilar informaci&oacute;n sobre su uso de COINALL para personalizar mejor nuestros Servicios y mejorar su experiencia. Tambi&eacute;n podemos usar la informaci&oacute;n recopilada para garantizar que cumplimos con nuestro plan de cumplimiento y para garantizar que la Seguridad de su cuenta no se vea afectada por la detecci&oacute;n de actividades de cuenta no est&aacute;ndar o sospechosas. La mayor&iacute;a de los navegadores est&aacute;n configurados para aceptar autom&aacute;ticamente Cookie. Algunas Cookies caducar&aacute;n cuando termine de navegar, mientras que otras cookies permanecer&aacute;n en su computadora o dispositivo hasta que se eliminen o caduquen. Puede optar por rechazar nuestras Cookie, pero esto puede afectar la funcionalidad del servicio COINALL o su experiencia de usuario. X. Seguridad de la informaci&oacute;n Nos comprometemos a proteger a COINALL y a usted del acceso no autorizado, los cambios, la divulgaci&oacute;n o la destrucci&oacute;n de la informaci&oacute;n personal que recopilamos y almacenamos. Tomamos varias medidas para garantizar la Seguridad de la informaci&oacute;n, incluido El uso de SSL para encriptar todas las comunicaciones de COINALL; Todos los programas requieren autenticaci&oacute;n dual; Revise regularmente nuestros m&eacute;todos de recopilaci&oacute;n, almacenamiento y procesamiento de informaci&oacute;n personal; Adem&aacute;s de restringir estrictamente El acceso de nuestros empleados y proveedores a la informaci&oacute;n solo cuando sea necesario y cumplir con las estrictas obligaciones de confidencialidad contractual. XI. p&oacute;ngase en contacto con COINALL sobre problemas o dudas de privacidad Si tiene alguna pregunta sobre esta pol&iacute;tica de privacidad o El uso de informaci&oacute;n personal, cont&aacute;ctenos por correo electr&oacute;nico a 08d2npc6@gmail.com con El tema \" requisitos de privacidad\". XII. cambios en nuestra pol&iacute;tica de privacidad Cualquier cambio futuro en nuestra pol&iacute;tica de privacidad se publicar&aacute; en esta p&aacute;gina y, cuando corresponda, le notificaremos por correo electr&oacute;nico.</span></p>', NULL);
INSERT INTO `article_translations` VALUES (347, 93, 'pt', 'Acordo de privacidade', '<p><span style=\"color: #333333; font-family: Arial, \'PingFang SC\', \'Hiragino Sans GB\', STHeiti, \'Microsoft YaHei\', sans-serif; font-size: 18px; white-space: pre-line; background-color: #ffffff;\">Pol&iacute;ticas e declara&ccedil;&otilde;es de privacidade I. introdu&ccedil;&atilde;o Esta pol&iacute;tica e declara&ccedil;&atilde;o de privacidade explica a coinall global company limited ( \" coirmal\" ), uma empresa estabelecida e registrada em Malta em 1995, com o n&uacute;mero da empresa C76567, que utiliza suas informa&ccedil;&otilde;es pessoais porque fornecemos servi&ccedil;os de acesso e utilit&aacute;rios atrav&eacute;s de nossa plataforma de negocia&ccedil;&atilde;o de ativos digitais, SEM nenhuma moeda legal. Coletamos e mantemos informa&ccedil;&otilde;es pessoais durante o fornecimento de servi&ccedil;os. Normalmente, n&atilde;o divulgamos nenhuma informa&ccedil;&atilde;o pessoal sobre o cliente a terceiros n&atilde;o afiliados, exceto nos casos descritos abaixo. Ao acessar ou usar o coinall.com e as interfaces de aplicativos relacionadas ou OS aplicativos m&oacute;veis ( \" sites\" ), voc&ecirc; concorda com as Pol&iacute;ticas e pr&aacute;ticas da nossa pol&iacute;tica de privacidade ( \" pol&iacute;tica de privacidade\" ), Leia com aten&ccedil;&atilde;o. Esta pol&iacute;tica de privacidade explica como o COINALL USA seus dados pessoais ( conforme definido abaixo ) porque fornecemos acesso e utilit&aacute;rios atrav&eacute;s de software, APIs ( interfaces de aplicativos ), tecnologias, produtos e / ou Recursos ( OS \" servi&ccedil;os\" ) atrav&eacute;s de nossa plataforma de negocia&ccedil;&atilde;o de ativos digitais. Coletamos e mantemos informa&ccedil;&otilde;es pessoais durante o fornecimento de servi&ccedil;os. Normalmente, n&atilde;o divulgamos nenhuma informa&ccedil;&atilde;o pessoal sobre o cliente a terceiros n&atilde;o afiliados, exceto nos casos descritos abaixo. Podemos alterar esta pol&iacute;tica e declara&ccedil;&atilde;o a qualquer momento e public&aacute; - la Nesta p&aacute;gina, indicando a data e a vers&atilde;o do lan&ccedil;amento e notificando - a por e - mail. II. defini&ccedil;&atilde;o Ativos digitais Neste documento, \" ativos digitais\" referem - se a ativos digitais ( ou seja, \" ativos financeiros virtuais\", \" moeda virtual convert&iacute;vel\", \" moeda digital\" ou \" produtos digitais\", conforme definido na vers&atilde;o 2018 da lei de ativos financeiros virtuais de Malta ), como bitcoin, Ethernet, etc., que podem ser ( I ) centralizados ou descentralizados, ( ii ) fechados ou de c&oacute;digo aberto e ( iii ) meios para troca e / ou armazenamento de valor. Informa&ccedil;&otilde;es pessoais No que se refere ao uso deste artigo, \" informa&ccedil;&otilde;es pessoais\" refere - se a qualquer informa&ccedil;&atilde;o relacionada a uma pessoa singular reconhecida ou reconhecida, como nome, n&uacute;mero de identifica&ccedil;&atilde;o, informa&ccedil;&otilde;es de localiza&ccedil;&atilde;o, identificador on - line ou um ou mais fatores espec&iacute;ficos, f&iacute;sicos, econ&ocirc;micos, culturais ou espec&iacute;ficos, ou SUA identidade social como pessoa f&iacute;sica. III. coleta de informa&ccedil;&otilde;es COINALL coleta, processa e armazena informa&ccedil;&otilde;es pessoais coletadas de voc&ecirc; com o uso deste servi&ccedil;o ou com SUA permiss&atilde;o. Esses dados pessoais podem incluir informa&ccedil;&otilde;es de contato, um documento de identifica&ccedil;&atilde;o fornecido por voc&ecirc; ou uma c&oacute;pia do documento de identifica&ccedil;&atilde;o dispon&iacute;vel em um reposit&oacute;rio P&uacute;blico, seu n&uacute;mero de identifica&ccedil;&atilde;o do governo e informa&ccedil;&otilde;es sobre seu dispositivo ou servi&ccedil;o de internet ( por exemplo, endere&ccedil;o IP e n&uacute;mero MAC ). Coletamos as informa&ccedil;&otilde;es que voc&ecirc; forneceu no processo de ingresso em COINALL, que pode ser um processo conclu&iacute;do, incompleto ou abandonado. Coletamos, usamos, armazenamos e transferimos suas informa&ccedil;&otilde;es pessoais, que podem incluir o seguinte: Operamos na zona econ&ocirc;mica europ&eacute;ia ( \" EEA\" ) para coletar, armazenar e processar suas informa&ccedil;&otilde;es pessoais de acordo com as diretrizes do GDPR ( general information protection act, regulamento geral de prote&ccedil;&atilde;o das informa&ccedil;&otilde;es ) e da lei de prote&ccedil;&atilde;o das informa&ccedil;&otilde;es. Para obter mais informa&ccedil;&otilde;es sobre como protegemos as informa&ccedil;&otilde;es coletadas de pessoas e entidades no EEA, consulte OS detalhes abaixo. Clientes individuais: Endere&ccedil;o de e - mail N&uacute;mero do celular O nome legal completo ( incluindo o nome anterior e o nome do idioma local ) Nacionalidade? nacionalidade N&uacute;mero do passaporte ou qualquer n&uacute;mero de identifica&ccedil;&atilde;o emitido pelo governo Data de Nascimento Documento de identifica&ccedil;&atilde;o ( por exemplo, passaporte, carta de condu&ccedil;&atilde;o ou documento de identifica&ccedil;&atilde;o emitido pelo governo ) Endere&ccedil;o residencial Certificado de resid&ecirc;ncia Outras informa&ccedil;&otilde;es pessoais ou documentos conforme apropriado pela nossa equipe de conformidade Clientes corporativos: Nome legal da empresa ( incluindo o nome legal local ) Informa&ccedil;&otilde;es de registro / registro Nome legal completo de todos OS propriet&aacute;rios benefici&aacute;rios, diretores e representantes legais Endere&ccedil;o ( local comercial principal e / ou outro local f&iacute;sico ) Prova da exist&ecirc;ncia legal Descri&ccedil;&atilde;o do neg&oacute;cio Porcentagem de propriedade de indiv&iacute;duos / propriet&aacute;rios de empresas Propriet&aacute;rio, informa&ccedil;&otilde;es de contato do propriet&aacute;rio e da administra&ccedil;&atilde;o executiva, se aplic&aacute;vel Documento de identifica&ccedil;&atilde;o do principal benefici&aacute;rio pessoal da entidade cliente da institui&ccedil;&atilde;o ( por exemplo, passaporte, carta de condu&ccedil;&atilde;o ou documento de identifica&ccedil;&atilde;o emitido pelo governo ) Informa&ccedil;&otilde;es pessoais sobre OS principais propriet&aacute;rios benefici&aacute;rios da entidade do cliente para cada entidade ( consulte a se&ccedil;&atilde;o clientes individuais acima para obter mais informa&ccedil;&otilde;es sobre as informa&ccedil;&otilde;es pessoais que coletamos para cada indiv&iacute;duo ) A fonte da riqueza O n&uacute;mero esperado de bitcoins ou outros ativos digitais injetados IV. recolha de informa&ccedil;&otilde;es fora da zona econ&oacute;mica europeia Como mencionado acima, podemos coletar informa&ccedil;&otilde;es pessoais de clientes localizados na zona econ&ocirc;mica europ&eacute;ia. Para facilitar OS servi&ccedil;os que prestamos AOS clientes localizados na zona econ&ocirc;mica europ&eacute;ia, exigimos o consentimento expresso para transferir informa&ccedil;&otilde;es pessoais da zona econ&ocirc;mica europ&eacute;ia para fora da regi&atilde;o. Se voc&ecirc; for um indiv&iacute;duo localizado na zona econ&ocirc;mica europ&eacute;ia e se recusar a concordar com essa transfer&ecirc;ncia, voc&ecirc; n&atilde;o poder&aacute; mais usar o COINALL e nossos servi&ccedil;os. Voc&ecirc; poder&aacute; retirar seus ativos digitais; No entanto, todos OS outros Recursos ser&atilde;o desativados. V. como podemos usar suas informa&ccedil;&otilde;es pessoais COINALL USA informa&ccedil;&otilde;es pessoais para se comunicar e gerenciar com voc&ecirc;, fornecer, aprimorar e personalizar servi&ccedil;os. O COINALL tamb&eacute;m pode Gerar informa&ccedil;&otilde;es gen&eacute;ricas de qualquer informa&ccedil;&atilde;o pessoal que coletamos e us&aacute; - las para nossos pr&oacute;prios fins. Tamb&eacute;m podemos usar essas informa&ccedil;&otilde;es para nos comunicarmos com voc&ecirc; sobre o COINALL e / ou outros produtos ou servi&ccedil;os oferecidos por seus parceiros. N&atilde;o compartilharemos seus dados pessoais com terceiros ( exceto com parceiros da COINALL ), a menos que voc&ecirc; concorde com eles e OS explique mais detalhadamente abaixo. Podemos compartilhar seus dados pessoais com terceiros: ( a ) se considerarmos necess&aacute;rio compartilhar OS termos de servi&ccedil;o; B ) cumprir as institui&ccedil;&otilde;es governamentais, incluindo OS &oacute;rg&atilde;os de fiscaliza&ccedil;&atilde;o, a aplica&ccedil;&atilde;o da lei e / ou OS servi&ccedil;os judiciais; ( c ) terceiros ( por exemplo, servi&ccedil;os de gest&atilde;o ou t&eacute;cnicos ) que prestam servi&ccedil;os ao COINALL; ( d ) venda ou transfer&ecirc;ncia que envolvam a nossa empresa ou qualquer parte dela. Al&eacute;m disso, implementamos padr&otilde;es internacionais que impedem a lavagem de dinheiro, o financiamento do terrorismo e a evas&atilde;o das san&ccedil;&otilde;es comerciais e econ&ocirc;micas, e implementamos as regras e regulamentos finais de ativos financeiros virtuais, quando aplic&aacute;veis, o que pode exigir a realiza&ccedil;&atilde;o de dilig&ecirc;ncias devidas AOS nossos clientes. Isso pode incluir provedores de servi&ccedil;os e informa&ccedil;&otilde;es de terceiros que usar&atilde;o suas informa&ccedil;&otilde;es pessoais como refer&ecirc;ncia cruzada. VI. armazene suas informa&ccedil;&otilde;es pessoais As informa&ccedil;&otilde;es que coletamos de voc&ecirc; podem ser transferidas para um destino diferente de Malta. Essas informa&ccedil;&otilde;es tamb&eacute;m podem ser processadas por funcion&aacute;rios que trabalham para n&oacute;s ou para nossos fornecedores fora de Malta. Com exce&ccedil;&atilde;o dos clientes da zona econ&ocirc;mica europ&eacute;ia, ao enviar suas informa&ccedil;&otilde;es pessoais, voc&ecirc; estar&aacute; concordando com a transfer&ecirc;ncia acima para armazenamento ou processamento. Todas as informa&ccedil;&otilde;es que voc&ecirc; nos fornece s&atilde;o armazenadas em nossos servidores de seguran&ccedil;a em nuvem e / ou em servidores de terceiros. VII. revise, modifique e exclua suas informa&ccedil;&otilde;es pessoais Voc&ecirc; tem o Direito de solicitar uma c&oacute;pia de suas informa&ccedil;&otilde;es pessoais para ter certeza de que as informa&ccedil;&otilde;es que recebemos sobre voc&ecirc; s&atilde;o precisas e atualizadas. Se houver alguma imprecis&atilde;o em suas informa&ccedil;&otilde;es pessoais, voc&ecirc; poder&aacute; solicitar que elas sejam atualizadas. Voc&ecirc; tamb&eacute;m pode solicitar a exclus&atilde;o de suas informa&ccedil;&otilde;es pessoais, MAS podemos rejeitar SUA solicita&ccedil;&atilde;o devido a circunst&acirc;ncias espec&iacute;ficas, como conformidade ou fins legais. Para revisar e excluir suas informa&ccedil;&otilde;es pessoais, envie um e - mail para support@coinall.com com com o assunto \" consulta de informa&ccedil;&otilde;es\". Em resposta &agrave;s solicita&ccedil;&otilde;es de acesso a dados, corrigiremos ou excluiremos as solicita&ccedil;&otilde;es e verificaremos a identidade do solicitante para garantir que ele tenha o Direito legal de fazer tais solicita&ccedil;&otilde;es. Embora nosso objetivo seja responder a essas solicita&ccedil;&otilde;es gratuitamente, reservamo - nos o Direito de cobrar uma taxa razo&aacute;vel quando voc&ecirc; as repete ou FAZ solicita&ccedil;&otilde;es pesadas. VIII. promo&ccedil;&atilde;o de marketing Podemos inform&aacute; - lo sobre a promo&ccedil;&atilde;o de not&iacute;cias da empresa e informa&ccedil;&otilde;es relacionadas AOS produtos e servi&ccedil;os da COINALL. Podemos compartilhar suas informa&ccedil;&otilde;es pessoais com terceiros para fins de marketing e promo&ccedil;&atilde;o ou distribui&ccedil;&atilde;o de informa&ccedil;&otilde;es de marketing. Ao usar o COINALL, voc&ecirc; aceita essa pol&iacute;tica de privacidade e concorda em receber essas notifica&ccedil;&otilde;es de marketing. Os clientes podem optar por n&atilde;o receber tais notifica&ccedil;&otilde;es de marketing a qualquer momento. Se n&atilde;o quiser receber tais notifica&ccedil;&otilde;es, envie um e - mail para support@coinall.com. Voc&ecirc; n&atilde;o tem a op&ccedil;&atilde;o de n&atilde;o receber notifica&ccedil;&otilde;es relacionadas ao produto, como atualiza&ccedil;&otilde;es de pol&iacute;tica / termos e avisos operacionais. Ix. uso de cookies Ao visitar o COINALL, podemos colocar pequenas quantidades de dados no seu navegador para salvar OS Cookies, de acordo com as pr&aacute;ticas do setor. Essas informa&ccedil;&otilde;es podem ser colocadas no seu computador ou em qualquer outro dispositivo usado para acessar o COINALL. Essas informa&ccedil;&otilde;es nos ajudam a identificar voc&ecirc; como um cliente, coletar informa&ccedil;&otilde;es sobre seu uso do COINALL para personalizar melhor nossos servi&ccedil;os e aprimorar SUA experi&ecirc;ncia. Tamb&eacute;m podemos usar as informa&ccedil;&otilde;es coletadas para garantir que estamos em conformidade com nosso Programa de conformidade e para garantir que SUA conta n&atilde;o seja afetada por irregularidades ou atividades suspeitas da conta. A maioria dos navegadores est&aacute; definida para aceitar Cookie automaticamente. Alguns Cookies expiram quando voc&ecirc; termina de navegar, enquanto outros permanecem no seu computador ou dispositivo at&eacute; que voc&ecirc; OS exclua ou expire. Voc&ecirc; pode optar por recusar OS nossos Cookie, MAS isso pode afetar a funcionalidade do servi&ccedil;o COINALL ou a experi&ecirc;ncia do usu&aacute;rio. X. seguran&ccedil;a das informa&ccedil;&otilde;es Estamos comprometidos em proteger COINALL e SUA excel&ecirc;ncia de acesso n&atilde;o autorizado a altera&ccedil;&otilde;es, divulga&ccedil;&otilde;es ou destrui&ccedil;&atilde;o de informa&ccedil;&otilde;es pessoais coletadas e armazenadas. Tomamos medidas para proteger as informa&ccedil;&otilde;es, inclusive criptografar todas as comunica&ccedil;&otilde;es de COINALL com SSL; Todos OS procedimentos exigem autentica&ccedil;&atilde;o dupla; Revise regularmente nossa coleta de informa&ccedil;&otilde;es pessoais e como armazen&aacute; - las e process&aacute; - las; Al&eacute;m disso, restrinja rigorosamente nossos funcion&aacute;rios e fornecedores a consultar informa&ccedil;&otilde;es somente quando necess&aacute;rio e cumpra as rigorosas obriga&ccedil;&otilde;es de confidencialidade contratual. XI. entre em contato com COINALL sobre quest&otilde;es de privacidade ou d&uacute;vidas Em caso de d&uacute;vidas sobre o uso desta pol&iacute;tica de privacidade ou informa&ccedil;&otilde;es pessoais, entre em contato conosco no endere&ccedil;o 08d2npc6@gmail.com, com o assunto \" requisitos de privacidade\". XII. altera&ccedil;&otilde;es &agrave; nossa pol&iacute;tica de privacidade Quaisquer altera&ccedil;&otilde;es futuras &agrave; nossa pol&iacute;tica de privacidade ser&atilde;o publicadas Nesta p&aacute;gina e, se apropriado, voc&ecirc; ser&aacute; notificado por e - mail.</span></p>', NULL);
INSERT INTO `article_translations` VALUES (348, 93, 'pl', 'Umowa prywatności', '<p><span style=\"color: #333333; font-family: Arial, \'PingFang SC\', \'Hiragino Sans GB\', STHeiti, \'Microsoft YaHei\', sans-serif; font-size: 18px; white-space: pre-line; background-color: #ffffff;\">Polityka prywatności i oświadczenie I. Jane Doe Ta polityka prywatności i oświadczenie wyjaśniają, że firma utworzona i zarejestrowana na Maltie zgodnie z wydaniem Maltańskiego Prawa Publicznego w 1995 roku (numer firmy C76567) wykorzystuje dane osobowe, ponieważ zapewniamy dostęp do usług narzędziowych za pośrednictwem naszej platformy handlu zasobami cyfrowymi ( Podczas świadczenia usług zbieramy i utrzymujemy informacje osobiste Zazwyczaj nie ujawniamy żadnych danych osobowych dotyczących Klienta żadnej osobie trzeciej, kt&oacute;ra nie jest podmiotem zależnym, chyba że w następujących okolicznościach Uzyskując dostęp do witryny coinall.com i powiązanych aplikacji lub aplikacji przenośnych (&bdquo; Witryna internetowa&rdquo;), zgadzasz się na zasady i praktyki dotyczące prywatności (&bdquo; Zasady prywatności&rdquo;), więc należy dokładni Ta zasada prywatności wyjaśnia, w jaki spos&oacute;b COINALL korzysta z danych osobowych (zdefiniowanych poniżej), ponieważ zapewniamy dostęp do oprogramowania, interfejsu API, technologii, produkt&oacute;w i/ lub funkcji (&bdquo; Usługi&rdquo;) za pośrednictwem naszej platformy handlu zasobami cyfrowymi Podczas świadczenia usług zbieramy i utrzymujemy informacje osobiste Zazwyczaj nie ujawniamy żadnych danych osobowych dotyczących Klienta żadnej osobie trzeciej, kt&oacute;ra nie jest podmiotem zależnym, chyba że w następujących okolicznościach W dowolnym momencie możemy zmienić tę zasadę i oświadczenie, a następnie opublikować na tej stronie datę wydania i wersję oraz powiadomić o tym pocztą elektroniczną II. Sprawiedliwość Informacje o produkcji cyfrowej Artykuł\" Zasoby cyfrowe\" odnosi się do zasob&oacute;w cyfrowych (tj.\" Wirtualnych aktyw&oacute;w finansowych\",\" wymiennych walut wirtualnych\",\" cyfrowych walut\" lub\" produkt&oacute;w cyfrowych\"), takich jak bitcoiny, Ethernet Square itp., kt&oacute;re mogą być (i) centralne lub rozproszone, (ii) zamknięte lub otwarte oraz (iii) używane jako medium wymiany i/ lub wartości pamięci Informacje osobiste W niniejszym dokumencie &bdquo; informacje osobiste&rdquo; odnoszą się do dowolnych informacji związanych z identyfikowaną lub rozpoznawalną osobą fizyczną, takich jak nazwisko, numer identyfikacyjny, informacja o lokalizacji, identyfikator online lub jeden lub więcej czynnik&oacute;w specyficznych dla fizyki, ekonomii, kultury lub konkretnej tożsamo III. Zbieranie informacji COINALL zbiera, przetwarza i przechowuje dane osobowe, kt&oacute;re zostały zebrane od Ciebie za pośrednictwem Usługi lub za Twoją zgodą Te dane osobowe mogą zawierać informacje kontaktowe, podane przez użytkownika dokumenty tożsamości lub kopie dokument&oacute;w dostępnych z publicznego repozytorium informacji, numer identyfikacyjny rządu oraz informacje związane z urządzeniem lub usługą internetową, takie jak adres IP i numer MAC Zbieramy informacje przekazane w procesie wejścia COINALL, kt&oacute;re mogą być ukończone, niekompletne lub zrezygnowane Zbieramy, używamy, przechowujemy i przesyłamy dane osobowe, kt&oacute;re mogą obejmować Działamy w Europejskiej Strefie Gospodarczej (&bdquo; EEA&rdquo;) i zbieramy, przechowujemy i przetwarzamy dane osobowe zgodnie z przepisami og&oacute;lnych przepis&oacute;w dotyczących ochrony informacji (GDPR) i ustaw o ochronie informacji Więcej informacji na temat ochrony os&oacute;b i podmiot&oacute;w zgromadzonych w ramach EEA można znaleźć w poniższej sekcji Klienci indywidualni Adres e-mail Numer telefonu kom&oacute;rkowego Pełna nazwa prawna, w tym poprzednia nazwa i nazwa języka lokalnego Skąd pochodzisz numer paszportu lub dowolny numer identyfikacyjny wydany przez rząd Data urodzenia Dow&oacute;d tożsamości, taki jak paszport, prawo jazdy lub dow&oacute;d wydany przez rząd Adres domowy Świadectwo pobytu Dodatkowe dane osobowe lub style określone przez nasz zesp&oacute;ł ds. zgodności Klienci firmy Nazwa prawna firmy (w tym lokalna nazwa prawna) Informacje o rejestracji/ rejestracji Pełne prawne imię wszystkich korzystających, dyrektor&oacute;w i przedstawicieli prawnych Adres (gł&oacute;wne miejsce prowadzenia działalności i/ lub inne miejsce rzeczywiste) kt&oacute;re są prawnie dostępne Przegląd biznesowy Procent własności indywidualnej/ właściciela firmy Właściciel, informacje kontaktowe kierownika i kierownictwa wykonawczego (jeśli dotyczy) Identyfikacja kluczowego właściciela instytucji (np. paszport, prawo jazdy lub dow&oacute;d tożsamości wystawiony przez rząd) Informacje osobiste kluczowych właścicieli korzyści dla każdej instytucji (szczeg&oacute;łowe informacje na temat danych osobowych zebranych dla os&oacute;b indywidualnych można znaleźć w powyższej sekcji &bdquo; Klienci indywidualni&rdquo; Źr&oacute;dło bogactwa Liczba przewidywanych wstrzyknięć bitcoin&oacute;w lub innych zasob&oacute;w cyfrowych IV. Zbieranie informacji poza europejską strefą ekonomiczną Jak wspomniano wcześniej, możemy zbierać dane osobowe klient&oacute;w znajdujących się w strefie ekonomicznej Europy Aby ułatwić świadczenie usług klientom w Europejskiej Strefie Gospodarczej, prosimy o wyraźną zgodę na przeniesienie danych osobowych z Europejskiej Strefy Gospodarczej do innych Jeśli jesteś osobą w Europejskiej Strefie Ekonomicznej i odmawiasz zgody na takie transfery, nie będziesz już m&oacute;gł korzystać z COINALL i naszych usług Będziesz m&oacute;gł wycofać swoje zasoby cyfrowe Jednak wszystkie inne funkcje zostaną wyłączone W jaki spos&oacute;b będziemy używać twoich danych osobowych COINALL wykorzystuje dane osobowe do komunikowania się z Tobą i zarządzania nimi, dostarczania, udoskonalania i personalizacji usług COINALL może r&oacute;wnież generować wsp&oacute;lne informacje z dowolnych danych osobowych, kt&oacute;re zbieramy i używać ich do własnych cel&oacute;w Informacje te mogą być r&oacute;wnież używane do komunikowania się z Tobą w sprawie produkt&oacute;w i/ lub usług oferowanych przez partner&oacute;w Twoje dane osobowe nie będą udostępniane innym firmom, z wyjątkiem partner&oacute;w COINALL, chyba że uzyskasz zgodę i podasz poniższe szczeg&oacute;ły Możemy udostępnić dane osobowe innym firmom (a) Jeśli uważamy, że konieczne jest wykonanie warunk&oacute;w świadczenia usług dzielenia się nimi (b) zgodność z instytucjami rządowymi, w tym z organami regulacyjnymi, organami ścigania i/ lub wymiarem sprawiedliwości (c) podmiot trzeci świadczący usługi COINALL (takie jak zarządzanie lub usługi techniczne) (d) Sprzedaż lub cesja związana z naszą działalnością lub jakąkolwiek jej częścią Ponadto wdrożyliśmy międzynarodowe standardy zapobiegania praniu pieniędzy, finansowaniu terroryzmu i unikaniu sankcji handlowych i gospodarczych oraz, w miarę możliwości, wprowadziliśmy ostateczne reguły i przepisy dotyczące wirtualn Może to obejmować korzystanie z informacji innych firm i usługodawc&oacute;w, do kt&oacute;rych będziemy odwoływać się do danych osobowych VI. Przechowuj dane osobowe Informacje, kt&oacute;re zebraliśmy od pana, mogą zostać przeniesione i przechowywane w innych miejscach niż Malta Informacje te mogą być r&oacute;wnież obsługiwane przez pracownik&oacute;w poza Maltą, kt&oacute;rzy pracują dla nas lub naszych dostawc&oacute;w Po przesłaniu danych osobowych, opr&oacute;cz klient&oacute;w w Europejskiej Strefie Ekonomicznej, zgadzasz się na powyższe przeniesienie pamięci masowej lub przetwarzania Wszystkie przekazane nam informacje są przechowywane na serwerze zabezpieczeń chmury dla nas i/ lub firm trzecich VII. Przejrzyj, zmodyfikuj i usuń dane osobowe Masz prawo poprosić o kopię danych osobowych, aby upewnić się, że informacje o tobie są dokładne i aktualne Jeśli dane osobowe są niedokładne, można poprosić o aktualizację informacji Można r&oacute;wnież poprosić o usunięcie danych osobowych, ale możemy odrzucić żądanie w określonych okolicznościach, takich jak zgodność z przepisami lub cele prawne Aby zapoznać się z modyfikacją i usunięciem danych osobowych, wyślij wiadomość e-mail pod adresem support@coinall.com W odpowiedzi na żądania dotyczące dostępu do danych, poprawienia lub usunięcia sprawdzamy tożsamość żądającego, aby upewnić się, że jest prawnie uprawniony do złożenia takich wniosk&oacute;w Chociaż naszym celem jest bezpłatna odpowiedź na te żądania, zastrzeżamy prawo do zapłacenia odpowiedniej opłaty w przypadku powtarzania lub ciężkiego żądania VIII. Promocja marketingu Możemy poinformować cię o promocji wiadomości firmy i informacjach związanych z produktami i usługami COINALL Możemy udostępnić dane osobowe innym firmom, aby mogli prowadzić działania marketingowe i promocyjne lub przekazywać informacje marketingowe Użycie polecenia COINALL oznacza, że akceptujesz tę zasadę prywatności i zgadzasz się na otrzymywanie takich powiadomień marketingowych Klienci mogą w dowolnym momencie nie otrzymywać takich powiadomień marketingowych Jeśli nie chcesz otrzymywać takich powiadomień, wyślij wiadomość e-mail na adres support@coinall.com Nie można wybrać, aby nie otrzymywać powiadomień dotyczących produkt&oacute;w, takich jak aktualizacje zasad/ warunk&oacute;w i powiadomienia operacyjne Ix. ciasteczka Podczas uzyskiwania dostępu do COINALL możemy umieścić niewielką ilość danych w przeglądarce, aby zapisać ciasteczka Informacje te można umieścić na komputerze lub na innym urządzeniu używanym do uzyskiwania dostępu do COINALL Informacje te pomagają zidentyfikować Ciebie jako klienta i zbierać informacje na temat korzystania z COINALL, aby lepiej dostosować nasze usługi i poprawić Twoje doświadczenie Możemy r&oacute;wnież korzystać z zebranych informacji, aby zapewnić zgodność z naszym planem zgodności i upewnić się, że bezpieczeństwo konta nie zostanie naruszone przez wykrywanie niezgodności lub podejrzanych dzia Większość przeglądarek jest skonfigurowana tak, aby automatycznie akceptować ciasteczka Niekt&oacute;re ciasteczka wygasają po zakończeniu przeglądania, a pozostałe pozostają na komputerze lub urządzeniu do momentu usunięcia lub wygaśnięcia Możesz odm&oacute;wić użycia naszych ciasteczek, ale może to wpłynąć na funkcjonalność usługi COINALL lub doświadczenie użytkownika X. Bezpieczeństwo informacji Staramy się chronić COINALL i pana przed nieautoryzowanym dostępem, ujawnianiem lub niszczeniem informacji osobistych, kt&oacute;re zbieramy i przechowujemy Podjęliśmy wszelkie działania, aby zapewnić bezpieczeństwo informacji, w tym szyfrowanie wszystkich komunikat&oacute;w za pomocą protokołu SSL Wszystkie programy wymagają podw&oacute;jnego uwierzytelniania Regularne przeglądanie zbierania danych osobowych, przechowywania i przetwarzania danych osobowych oraz ścisłe ograniczenia dotyczące dostępu do informacji przez pracownik&oacute;w i dostawc&oacute;w tylko wtedy, gdy jest to konieczne i przestrzegania ścisłych zobowiązań dotyczących poufności COINALL w sprawie prywatności lub wątpliwości W przypadku pytań dotyczących korzystania z tej zasady prywatności lub informacji osobistych należy skontaktować się z nami pod adresem 08d2npc6@gmail.com pod hasłem Wymagania dotyczące prywatności XII. Zmiana naszej polityki prywatności Wszelkie zmiany wprowadzone w naszej polityce prywatności zostaną opublikowane na tej stronie i, jeśli to konieczne, zostaną wysłane do Ciebie wiadomości e-mail</span></p>', NULL);
INSERT INTO `article_translations` VALUES (349, 93, 'nl', 'Privacy overeenkomst', '<p><span style=\"color: #333333; font-family: Arial, \'PingFang SC\', \'Hiragino Sans GB\', STHeiti, \'Microsoft YaHei\', sans-serif; font-size: 18px; white-space: pre-line; background-color: #ffffff;\">&nbsp;privacybeleid en duidelijkheid I. Jane Doe In dit privacybeleid en-verklaring worden uw persoonlijke gegevens gebruikt als een bedrijf dat is opgericht en geregistreerd op Malta volgens de uitgave van 1995 (het bedrijf met nummer C76567), omdat wij u toegang tot en hulpprogramma\'s bieden via ons platform voor digitale bedrijfsmiddelen (zonder inbegrip van juridische valuta) Tijdens het leveren van services verzamelen en onderhouden we persoonlijke gegevens Normaal gesproken geven we geen persoonlijke gegevens over de klant aan een derde die niet aan een derde is gekoppeld, tenzij de onderstaande omstandigheden worden beschreven Door coinall.com en de bijbehorende toepassingsinterface of mobiele toepassingen (&ldquo; website&rdquo;) te bezoeken of te gebruiken, bent u het eens met ons privacybeleid en-praktijken (&ldquo; privacybeleid&rdquo;) dus lees de curator zorgvuldig Dit privacybeleid legt uit hoe COINALL uw persoonlijke gegevens gebruikt (zoals hieronder gedefinieerd) omdat wij u via onze digitale handelsplatform toegang bieden tot software, API\'s (Application Interface), technologie, producten en/ of functionaliteit (&ldquo; Services&rdquo;) Tijdens het leveren van services verzamelen en onderhouden we persoonlijke gegevens Normaal gesproken geven we geen persoonlijke gegevens over de klant aan een derde die niet aan een derde is gekoppeld, tenzij de onderstaande omstandigheden worden beschreven We kunnen dit beleid en deze verklaring op elk gewenst moment wijzigen en op deze pagina publiceren met de datum en versie van de publicatie en een e-mailmelding II. Bevestiging Digitale bezittingen In dit artikel worden &ldquo; digitale bedrijfsmiddelen&rdquo; verwezen naar &ldquo; virtuele financi&euml;le middelen&rdquo;, &ldquo; omwisselbare virtuele munteenheden&rdquo;, &ldquo; digitale munteenheden&rdquo; of &ldquo; digitale producten&rdquo;), zoals Bitcoin, Ethernet Square, gebaseerde coderingsprotokollen die (i) gecentraliseerd of gedistribueerd kunnen zijn, (ii) gesloten of open source en (iii) als media voor uitwisseling en/ of waardevolle opslag Persoonlijke informatie Zoals in dit document wordt gebruikt, verwijst &ldquo; persoonlijke gegevens&rdquo; naar informatie over een ge&iuml;dentificeerde of herkenbare natuurlijke persoon, zoals naam, identificatienummer, locatie, online identificatie of een of meer factoren die specifiek zijn voor fysieke, economische, culturele of specifieke factoren, of naar uw sociale identiteit als een natu III. Informatie verzamelen COINALL verzamelt, verwerkt en opslaat persoonlijke gegevens die door u worden verzameld via deze service of met uw toestemming Deze persoonlijke gegevens kunnen contactpersonen bevatten die u opgeeft, of kopie&euml;n van referentiebestanden die beschikbaar zijn in een openbare database, uw overheidsid-nummer en informatie over uw apparaat of internetservice, zoals IP-adres en MAC-nummer Wij verzamelen informatie die u in het CoinAll-proces hebt opgegeven, die mogelijk een voltooid, incompetent of verlaten proces is Wij verzamelen, gebruiken, opslaan en overdragen uw persoonlijke gegevens, waaronder Wij werken in de Europese Economische Zone (EEA) en verzamelen, opslaan en verwerken uw persoonlijke gegevens in overeenstemming met de GDPR (General Information Protection Act) en de wet voor informatiebescherming Raadpleeg de volgende details voor meer informatie over hoe we informatie verzamelen die wordt verzameld van individuen en entiteiten binnen EEA Persoonlijke klanten Adres van e-mail Het nummer van de mobiele telefoon Volledige juridische naam, inclusief de vorige naam en de naam van de lokale taal Waar komt hij vandaan paspoortnummers of een overheidscode De geboortedatum Identiteit, zoals paspoort, rijbewijs of overheidspapieren Adres van huis Bevestiging van verblijfplaats Aanvullende persoonlijke gegevens of bestanden die door ons nalevingsteam worden bepaald Klanten van het bedrijf De wettelijke naam van het bedrijf (inclusief de lokale wettelijke naam van het bedrijf) Informatie over inschrijving/ inschrijving De volledige wettelijke naam van iedereen die profiteert, de directeur en de wettelijke vertegenwoordiger Adres (primaire bedrijfslocatie en/ of andere fysieke locatie) Legale aanwezigheid Bedrijfsbeschrijving van Percentage van eigendom van individuele/ bedrijfseigenaar Eigenaar, contactgegevens van de verantwoordelijkheid en het uitvoerende management (indien van toepassing) voor verwijdering Identiteit van de belangrijkste persoonlijke eigenaar van de instantie van de klant (bijvoorbeeld paspoort, rijbewijs of door de overheid uitgegeven legitimatie) begeleiden Persoonlijke gegevens van belangrijke voordelen van de instantie van de klant van de organisatie (zie de bovenstaande sectie Persoonlijke klanten voor meer informatie over de persoonlijke gegevens die wij voor elke individuele persoon verzamelen) de bron van rijkdom De verwachte hoeveelheid Bitcoin of andere digitale bezittingen IV. Informatie verzamelen buiten de Europese economische zone Zoals eerder is beschreven, kunnen we persoonlijke gegevens verzamelen van klanten in de Europese economische zone Om onze services voor klanten in de Europese economische zone te vergemakkelijken, vragen we duidelijk toestemming om persoonlijke gegevens van de Europese economische zone naar de buitenwereld te verplaatsen Als u een persoon bent in de Europese Economische Zone en u weigert dergelijke overdrachten te accepteren, kunt u niet langer COINALL en onze diensten gebruiken U kunt uw digitale bedrijfsmiddelen terugtrekken Alle andere functies worden echter uitgeschakeld V. Hoe gaan we uw persoonlijke informatie gebruiken COINALL gebruikt persoonlijke gegevens om met u te communiceren en te beheren, te leveren, te verbeteren en aan te passen COINALL kan ook algemene informatie genereren van alle persoonlijke gegevens die we verzamelen en gebruiken voor onze eigen doeleinden We kunnen deze informatie ook gebruiken om te communiceren met u over COINALL en/ of andere producten of diensten die door onze partners worden geleverd Wij delen uw persoonlijke gegevens niet met andere leveranciers, behalve met COINALL, tenzij u uw toestemming hebt gegeven en hieronder verder wordt uitgelegd We kunnen uw persoonlijke gegevens met andere leveranciers delen (a) Als we denken dat het nodig is om de servicevoorwaarden te delen (b) naleving van overheidsinstellingen, inclusief toezichthouders, rechtshandhaving en/ of rechtshandhaving (c) Een derde partij die COINALL dient (bijvoorbeeld beheer of technische services) (d) Verkoop of overdracht van onze bedrijven of enig deel ervan Bovendien hebben we internationale standaarden voor het voorkomen van witwassen, terroristische financiering en het vermijden van handel-en economische sancties ge&iuml;mplementeerd en, wanneer deze geldig zijn, de definitieve regels en voorschriften voor virtuele financi&euml;le middelen uitgevoer Dit kan betrekking hebben op het gebruik van informatie van externe leveranciers en serviceproviders waarnaar wij verwijzen naar uw persoonlijke gegevens VI. Sla uw persoonlijke gegevens op De informatie die we van u verzamelen, kan worden overgedragen en opgeslagen naar een andere bestemming dan Malta Deze informatie kan ook worden verwerkt door werknemers buiten Malta die voor ons of onze leveranciers werken Wanneer u uw persoonlijke gegevens invoert, behalve klanten in de Europese economische zone, stemt u ermee in dat u de hierboven beschreven overdracht voor opslag of verwerking van de overdracht toe Alle informatie die u ons geeft, wordt opgeslagen op onze cloudbeveiligingsservers van derden VII. Bekijk, wijzig en verwijder uw persoonlijke gegevens U hebt het recht om een kopie van uw persoonlijke gegevens te vragen om te controleren of onze informatie over u nauwkeurig en recent is Als uw persoonlijke gegevens onnauwkeurig zijn, kunt u vragen uw gegevens bij te werken U kunt ook uw persoonlijke gegevens verwijderen, maar we kunnen uw verzoek afwijzen voor specifieke omstandigheden, zoals naleving of juridische doeleinden Als u uw persoonlijke gegevens wilt wijzigen en verwijderen, mailt u deze naar support@coinall.com als onderwerp Als antwoord op de toegang tot gegevens, corrigeren of verwijderen, controleren we de identiteit van de aanvrager om ervoor te zorgen dat hij wettelijk het recht heeft om dergelijke verzoeken in te dienen Ons doel is deze verzoeken gratis te beantwoorden, maar wij behouden ons recht om u een redelijke prijs te betalen wanneer u deze verzoeken herhaalt of zwaar vraagt VIII. Marketing We kunnen u inlichten over de promotie van bedrijfsnieuws en informatie over COINALL All-producten en-diensten Wij kunnen uw persoonlijke gegevens met andere leveranciers delen zodat wij kunnen marketingprojecten en promoties kunnen uitvoeren of marketinginformatie kunnen verspreiden Wanneer u COINALL gebruikt, accepteert u dit privacybeleid en stemt u ermee in om dergelijke marketingmeldingen te ontvangen Klanten kunnen op elk gewenst moment kiezen om dergelijke marketingmeldingen niet te ontvangen Als u dergelijke meldingen niet wilt ontvangen, stuur dan een e-mail naar support@coinall.com U kunt niet kiezen om productgerelateerde meldingen te ontvangen, zoals updates van beleid/ voorwaarden en operationele aankondigingen IX.Cookies gebruiken Wanneer u COINALL bezoekt, kunnen we een kleine hoeveelheid gegevens voor uw browser opslaan (Cookies) op basis van industri&euml;le conventies plaatsen Deze informatie kan op uw computer of op andere apparaten worden geplaatst om toegang te krijgen tot COINALL Met deze informatie kunnen we u identificeren als klant en informatie verzamelen over uw gebruik van COINALL om onze services beter aan te passen en uw ervaring te verbeteren We kunnen ook de verzamelde informatie gebruiken om ervoor te zorgen dat we ons aan onze nalevingsplannen voldoen en om ervoor te zorgen dat uw accountbeveiliging niet wordt be&iuml;nvloed door het detecteren van onregelmatige of verdachte rekeningactiviteit De meeste browsers zijn ingesteld om Cookie automatisch te accepteren Sommige Cookies verlopen wanneer u klaar bent met bladeren, terwijl andere cookies op uw computer of apparaat blijven staan totdat de cookies worden verwijderd of verlopen U kunt ervoor kiezen om onze Cookie te weigeren, maar dit kan de functionaliteit van CoinAll-service be&iuml;nvloeden of uw gebruikerservaring X. Beveiliging van informatie Wij streven ernaar om COINALL en u te beschermen tegen ongeoorloofde toegang, onthulling of vernietiging van persoonlijke gegevens die we verzamelen en opslaan We hebben allerlei maatregelen genomen om de informatie veilig te houden, inclusief het versleutelen van alle communicatie via SSL Alle programma\'s vereisen dubbele verificatie Regelmatig onze methoden voor het verzamelen en verwerken van persoonlijke gegevens controleren Onze medewerkers en leveranciers zijn streng beperkt tot het openen van informatie wanneer dat nodig is en aan de strikte verplichtingen voor vertrouwelijkheid van contracten Contact opnemen met COINALL over privacy of twijfels Als u vragen hebt over het gebruik van dit privacybeleid of persoonlijke gegevens, kunt u contact opnemen met ons op 08d2npc6@gmail.com als onderwerp voor privacyvereisten XII. Wijzigingen in ons privacybeleid Wijzigingen die wij in ons privacybeleid in de toekomst aanbrengen, worden op deze pagina gepubliceerd en, indien van toepassing, worden u op de hoogte gesteld via e-mail</span></p>', NULL);
INSERT INTO `article_translations` VALUES (350, 93, 'it', 'Accordo sulla privacy', '<p><span style=\"color: #333333; font-family: Arial, \'PingFang SC\', \'Hiragino Sans GB\', STHeiti, \'Microsoft YaHei\', sans-serif; font-size: 18px; white-space: pre-line; background-color: #ffffff;\">Informativa e informativa sulla privacy I. introduzione La presente policy e dichiarazione sulla privacy si riferisce a coinall global company limited ( \" coinall\" ) come azienda con sede a Malta ( numero di societ&agrave; C76567 ) in conformit&agrave; con la normativa sul diritto societario di Malta nel 1995, in quanto Dell offre servizi di accesso e utility tramite la piattaforma di trading delle risorse digitali ( escluse le valute legali ). I dati personali vengono raccolti e gestiti durante il processo di fornitura dei servizi. In genere, Intel non divulgher&agrave; alcuna informazione personale sui clienti di terze parti non affiliate, a meno che non sia diversamente specificato di seguito. Leggere attentamente le norme e le pratiche Dell\' informativa sulla privacy accedendo o utilizzando coinall.com con l\' interfaccia Dell\' applicazione o l\' applicazione mobile associata ( \" sito web\" ). L\' informativa sulla privacy spiega in che modo bitcoin utilizza I dati personali ( definiti di seguito ) in quanto fornisce accesso e utility tramite software, API ( application interface ), tecnologia, prodotti e / o funzionalit&agrave; ( \" servizi\" ). I dati personali vengono raccolti e gestiti durante il processo di fornitura dei servizi. In genere, Intel non divulgher&agrave; alcuna informazione personale sui clienti di terze parti non affiliate, a meno che non sia diversamente specificato di seguito. Intel si riserva il diritto di modificare le direttive e le dichiarazioni in qualsiasi momento e di comunicarle tramite e - mail con la data e la versione della pubblicazione. II. definizione Risorse digitali Per \" risorse digitali\" si intendono le risorse digitali ( ossia, le \" risorse finanziarie virtuali\", le valute virtuali convertibili, le valute digitali \" o I\" prodotti digitali \" a Cui fa riferimento la legge sulle attivit&agrave; finanziarie virtuali di Malta ( versione 2018 ), I protocolli di crittografia basati su reti di computer come bitcoin, ether e cos&igrave; via, che possono essere ( I ) centralizzati o decentralizzati, ( ii ) chiusi o open source e ( iii ) utilizzati come mezzo di scambio e / o memorizzazione di valore. Informazioni personali Ai fini della presente documentazione, il termine \" informazioni personali\" si riferisce a qualsiasi informazione relativa a una persona fisica identificata o riconosciuta, ad esempio il nome, il numero di identificazione, le informazioni sulla posizione, l\' identificativo online o uno o pi&ugrave; fattori specifici per l\' entit&agrave; fisica, economica, culturale o specifica, oppure all\' identit&agrave; sociale della persona stessa. III. raccolta delle informazioni COINALL raccoglie, elabora e memorizza le informazioni personali raccolte attraverso l\' uso del servizio o, se si accetta di farlo. Tali dati personali possono includere informazioni di contatto, I documenti di identificazione forniti o una copia dei documenti di identit&agrave; disponibili in UN archivio pubblico, il numero di identificazione del governo e le informazioni relative al dispositivo o al servizio internet ( ad esempio, l\' indirizzo IP e il numero MAC ). Vengono raccolte le informazioni fornite nel processo di incorporazione, che possono essere completate, incomplete o eliminate. Emc raccoglie, utilizza, memorizza e trasferisce I dati personali, tra Cui: Operiamo nell\' area economica europea ( \" EEA\" ) per raccogliere, memorizzare ed elaborare I dati personali in conformit&agrave; alle normative GDPR ( general information protection regulations ) e gdpr ( information protection act ). Per ulteriori informazioni su come proteggere le informazioni raccolte da persone ed entit&agrave; all\' interno Dell\' EEA, vedere I dettagli riportati di seguito. Clienti singoli: Indirizzo e - mail Numero di cellulare Nome legale completo, incluso il nome precedente e il nome della lingua locale La nazionalit&agrave; Il numero del passaporto o qualsiasi numero di carta d\' identit&agrave; emesso dal governo Data di nascita Un documento di identit&agrave; ( ad esempio UN passaporto, una patente di guida o UN certificato rilasciato dal governo ) Indirizzo di casa Prova di residenza Altri dati personali o documenti determinati dal team di adempienza alle normative Clienti aziendali: Nome legale della societ&agrave;, incluso il nome legale locale Informazioni di registrazione / registrazione Nome legale completo di tutti I beneficiari, amministratori e rappresentanti legali Indirizzo ( principale e / o altra ubicazione fisica ) Prova di esistenza legale Descrizione Dell\' attivit&agrave; Percentuale di propriet&agrave; della persona o del proprietario della societ&agrave; Il proprietario, il responsabile e le informazioni di contatto per la gestione esecutiva ( se applicabile ) Certificato di identit&agrave; del proprietario Dell\' entit&agrave; cliente Dell\' istituzione, ad esempio UN passaporto, una patente di guida o UN certificato di identit&agrave; emesso dal governo Informazioni personali sui principali proprietari di beneficiari Dell\' entit&agrave; cliente istituzionale per ciascuna entit&agrave; ( per ulteriori informazioni sui dati personali raccolti per singoli utenti, vedere la sezione precedente relativa AI singoli clienti ) La fonte della ricchezza Il numero di bitcoin o altre risorse digitali che si prevede di iniettare IV. raccolta di informazioni al di fuori della zona economica europea Come accennato in precedenza, &egrave; possibile raccogliere informazioni personali sui clienti residenti nell\' area economica europea. Per semplificare I servizi offerti AI clienti che si trovano nella zona economica europea, &egrave; necessario concordare con il trasferimento dei dati personali Dall\' area economica europea al di fuori di tale area. Se si lavora da soli nella zona economica europea e si rifiuta di accettare tali trasferimenti, non sar&agrave; pi&ugrave; possibile utilizzare bitcoin e I nostri servizi. Sarete in grado di ritirare le vostre risorse digitali; Tuttavia, tutte le altre funzioni saranno disattivate. V. come useremo I tuoi dati personali Bitcoin utilizza informazioni personali per comunicare e gestire, consegnare, migliorare e personalizzare I servizi. COINALL pu&ograve; anche generare informazioni generiche da qualsiasi informazione personale raccolta e utilizzarle per I propri scopi. Tali informazioni possono essere utilizzate anche per comunicare con I prodotti o servizi forniti Dall\' utente e / o Dai suoi partner. I dati personali non verranno condivisi con terze parti, ad eccezione del partner che ha collaborato con COINALL, a meno che non sia stato concordato e specificato in dettaglio di seguito. I dati personali forniti possono essere condivisi con terze parti: ( a ) se pensiamo che sia necessario condividere I termini del servizio; ( b ) osservare le agenzie governative, incluse quelle regolamentate, le forze Dell\' ordine e / o le autorit&agrave; giudiziarie; ( c ) una terza parte, ad esempio servizi amministrativi o tecnici, che fornisce I servizi a COINALL; ( d ) vendite o trasferimenti che coinvolgono la nostra attivit&agrave; o qualsiasi SUA parte. Sono stati inoltre applicati standard internazionali per prevenire il riciclaggio di denaro, il finanziamento del terrorismo e l\' elusione di sanzioni commerciali ed economiche e, se disponibili, verranno applicate le regole e I regolamenti finali relativi alle attivit&agrave; finanziarie virtuali che potrebbero richiedere UN\' attenta analisi dei clienti. Ci&ograve; pu&ograve; includere l\' uso di informazioni di terze parti e provider di servizi AI quali verranno associati riferimenti incrociati con I dati personali Dell\' utente. VI. memorizza I dati personali Le informazioni raccolte da lei potrebbero essere trasferite e memorizzate in una destinazione diversa da Malta. Queste informazioni possono essere elaborate anche da dipendenti esterni a Malta che lavorano per noi o per I nostri fornitori. Fatta eccezione per I clienti Dell\' area economica europea, l\' invio dei dati personali implica l\' accettazione dei suddetti trasferimenti di storage o processi. Tutte le informazioni fornite vengono memorizzate su server sicuri cloud di Dell e / o di terze parti. VII. visualizzazione, modifica ed eliminazione dei dati personali L\' utente &egrave; autorizzato a richiedere copie dei dati personali per verificare che le informazioni fornite siano accurate e aggiornate. In caso di inesattezza dei dati personali, &egrave; possibile richiedere l\' aggiornamento dei dati. &egrave; inoltre possibile richiedere l\' eliminazione dei dati personali, ma in alcuni casi la richiesta pu&ograve; essere rifiutata per motivi legali o di conformit&agrave;. Per visualizzare le modifiche e rimuovere I dati personali, inviare UN\' e - mail all\' indirizzo support@coinall.com con l\' argomento query informazioni. In risposta alle richieste di accesso AI dati, Dell certifica l\' identit&agrave; del richiedente per garantire che sia legalmente autorizzato a presentare tali richieste. Sebbene il nostro obiettivo sia quello di rispondere a queste richieste gratuitamente, ci riserviamo il diritto di imporre una tariffa ragionevole in caso di richieste ripetute o pesanti. VIII. marketing Potrebbe essere la fonte di notizie Dell\' azienda e le informazioni relative AI prodotti e AI servizi COINALL. I dati personali dei clienti possono essere condivisi con terze parti per attivit&agrave; di marketing e promozione o per la distribuzione di informazioni di marketing. Quando si utilizza bitcoin, si accetta questa informativa sulla riservatezza dei dati personali e si accetta di ricevere tali comunicazioni commerciali. I clienti possono scegliere di non ricevere tali notifiche di marketing in qualsiasi momento. Se non si desidera ricevere tali notifiche, inviare UN\' e - mail all\' indirizzo support@coinall.com. Non &egrave; possibile scegliere di non ricevere notifiche relative AI prodotti, ad esempio aggiornamenti di criteri / condizioni e annunci operativi. Ix. uso dei IX.Cookies Quando si accede a bitcoin, potrebbe essere necessario inserire una piccola quantit&agrave; di dati conformi alle convenzioni del settore relative AI Cookies. Tali informazioni possono essere inserite nel computer o in qualsiasi altro dispositivo utilizzato per accedere a COINALL. Queste informazioni consentono di identificare il cliente e raccogliere le informazioni relative all\' utilizzo di bitcoin al fine di personalizzare meglio I servizi offerti e migliorare la propria esperienza. Le informazioni raccolte possono essere utilizzate anche per garantire la conformit&agrave; AI piani di conformit&agrave; e la sicurezza Dell\' account. La maggior parte dei browser &egrave; impostata per accettare automaticamente I Cookie. Alcuni Cookies scadono al termine della navigazione, mentre altri rimangono sul computer o sulla periferica fino a quando non vengono eliminati o scaduti. &egrave; possibile scegliere di non utilizzare I Cookie, ma ci&ograve; potrebbe influire sulla funzionalit&agrave; del servizio COINALL o sulla propria esperienza utente. X. sicurezza delle informazioni Ci impegniamo a proteggere bitcoin e SUA eccellenza da modifiche non autorizzate, rivelazioni o violazioni delle informazioni personali raccolte e memorizzate. Abbiamo preso tutte le misure necessarie per garantire la sicurezza delle informazioni, inclusa la crittografia di tutte le comunicazioni con SSL. Tutti I programmi richiedono una doppia autenticazione; Revisione periodica Dell\' archiviazione e Dell\' elaborazione dei dati personali; I dipendenti e I fornitori EMC sono strettamente limitati alla possibilit&agrave; di accedere alle informazioni solo quando necessario e a rispettare I rigidi obblighi di riservatezza dei contratti. Contatta bitcoin per questioni di privacy o preoccupazioni In caso di domande sull\' informativa sulla privacy o sull\' utilizzo dei dati personali, &egrave; possibile contattarci all\' indirizzo 08d2npc6@gmail.com per informazioni sull\' argomento \" requisiti di privacy\". XII. modifiche alla nostra politica sulla privacy Eventuali modifiche future all\' informativa sulla privacy verranno pubblicate in questa pagina e, se necessario, verranno inviate notifiche tramite e - mail.</span></p>', NULL);
INSERT INTO `article_translations` VALUES (351, 93, 'de', 'Vereinbarung zum Datenschutz', '<p><span style=\"color: #333333; font-family: Arial, \'PingFang SC\', \'Hiragino Sans GB\', STHeiti, \'Microsoft YaHei\', sans-serif; font-size: 18px; white-space: pre-line; background-color: #ffffff;\">Datenschutzrichtlinien und-erkl&auml;rungen I. Einleitung Die Datenschutzrichtlinien und-erkl&auml;rungen erkl&auml;ren, dass Coinal Global Company Limited (\" Coinal\") als Malteser Unternehmen (Unternehmensnummer C76567) eingerichtet und registriert wurde, da wir Ihnen Zugriff und Dienstprogramme &uuml;ber unsere Plattform f&uuml;r den Austausch digitaler Datenbest&auml;nde (nicht gesetzlich vorgeschriebene W&auml;hrung) bieten. Bei der Erbringung von Services erfassen und pflegen wir pers&ouml;nliche Daten. In der Regel geben wir keinerlei personenbezogene Daten an Dritte weiter, die nicht im Besitz des Kunden sind, sofern nicht anders angegeben. Durch den Zugriff auf Coterminal. com und die Verwendung der entsprechenden Anwendungsschnittstelle oder mobilen Anwendung (&bdquo; Website &ldquo;) erkl&auml;ren Sie sich mit den Richtlinien und Praktiken unserer Datenschutzrichtlinie (&bdquo; Datenschutzrichtlinie &ldquo;) einverstanden. Lesen Sie sie daher sorgf&auml;ltig durch. Diese Datenschutzerkl&auml;rung erl&auml;utert, wie COINALL Ihre pers&ouml;nlichen Daten verwendet (wie unten definiert), da wir Ihnen Zugriff und Dienstprogramme &uuml;ber Software, APIs (Application Programming Interfaces), Technologien, Produkte und/ oder Funktionen (\" Services\") &uuml;ber unsere Plattform f&uuml;r digitale Asset-Transaktionen bereitstellen. Bei der Erbringung von Services erfassen und pflegen wir pers&ouml;nliche Daten. In der Regel geben wir keinerlei personenbezogene Daten an Dritte weiter, die nicht im Besitz des Kunden sind, sofern nicht anders angegeben. Wir k&ouml;nnen diese Richtlinie und diese Erkl&auml;rung jederzeit &auml;ndern und auf dieser Seite ver&ouml;ffentlichen, um das Ver&ouml;ffentlichungsdatum und die Version anzugeben und uns per E-Mail dar&uuml;ber zu informieren. II. Definition Digitale Assets Dieser Artikel bezieht sich auf digitale Assets (d. h. auf\" virtuelle Finanzanlagen\",\" Konvertierbare virtuelle W&auml;hrungen\",\" Digitale W&auml;hrung\" oder\" digitale Produkte\", wie z. B. Bitcoin, Ethernet usw.), die auf Computernetzwerken basierenden Verschl&uuml;sselungsprotokolle, die (i) zentralisiert oder verteilt sein k&ouml;nnen, (ii) geschlossenes oder Open Source-Material und (iii) als Switching und/ oder Switching verwendet werden k&ouml;nnen. Pers&ouml;nliche Daten Wie in diesem Artikel erw&auml;hnt, bezieht sich &bdquo; personenbezogene Daten &ldquo; auf alle Informationen, die sich auf identifizierte oder identifizierbare nat&uuml;rliche Personen beziehen, wie Namen, Identifikationsnummern, Standortinformationen, Online-Kennungen oder einen oder mehrere Faktoren, die f&uuml;r die physische, wirtschaftliche, kulturelle oder bestimmte physische, wirtschaftliche, kulturelle oder soziale Identit&auml;t oder die soziale Identit&auml;t einer nat&uuml;rlichen Person gelten. III. Datensammlung Coterminal erfasst, verarbeitet und speichert pers&ouml;nliche Daten, die Sie mit diesem Service oder mit Ihrer Zustimmung von Ihnen gesammelt haben. Das Profil kann Kontaktinformationen, Kopien der von Ihnen angegebenen ID-Daten oder Kopien der ID-Daten enthalten, die Sie aus dem &ouml;ffentlichen Repository erhalten, Ihre Regierungs-ID-Nummer und Informationen &uuml;ber Ihr Ger&auml;t oder Ihren Internetdienstanbieter (z. B. IP-Adresse und MAC-Nummer). Wir erfassen die Informationen, die Sie im Rahmen des Projekts\" Coterminal\" angegeben haben. Dabei kann es sich um unvollst&auml;ndige oder abgebrochene Prozesse handeln. Wir erfassen, verwenden, speichern und &uuml;bertragen Ihre personenbezogenen Daten, z. B.: Wir arbeiten innerhalb der europ&auml;ischen Wirtschaftszone (\" EWR\"), in der personenbezogene Daten gem&auml;&szlig; den Allgemeinen Datenschutzbestimmungen (GDPR) und dem Datenschutzgesetz erfasst und verarbeitet werden. Weitere Informationen dar&uuml;ber, wie wir die von Einzelpersonen und Entit&auml;ten in der EWR gesammelten Daten sch&uuml;tzen, finden Sie weiter unten. Pers&ouml;nliche Kunden: E-Mail-Adresse Handynummer Vollst&auml;ndiger gesetzlich vorgeschriebener Name (einschlie&szlig;lich fr&uuml;herer Namen und Namen in der Landessprache) Nationalit&auml;t Reisepassnummer oder von einer Regierung ausgestellte Sozialversicherungsnummer Geburtsdatum Personalausweis (z. B. P&auml;sse, F&uuml;hrerscheine oder von der Regierung ausgestellte Bescheinigungen) Privatanschrift Wohnungsbescheinigungen Zus&auml;tzliche pers&ouml;nliche Informationen oder Dokumente, die von unserem Compliance-Team bestimmt werden Unternehmenskunden: Name des Unternehmens (einschlie&szlig;lich der gesetzlich vorgeschriebenen Namen) Registrierungs-/ Registrierungsinformationen Vollst&auml;ndiger gesetzlich vorgeschriebener Name aller Beteiligten, Vorstandsmitglieder und gesetzlich vorgeschriebenen Vertreter Adressen (prim&auml;re und/ oder andere Standorte) Rechtliche Existenz Beschreibung % Eigentumsrecht von Einzelpersonen/ Firmeneigent&uuml;mern Kontaktdaten des Verantwortlichen, des Verantwortlichen und des Executive-Sponsors (falls zutreffend) Personen-ID-Daten (z. B. P&auml;sse, F&uuml;hrerscheine oder von der Regierung ausgestellte Bescheinigungen), die f&uuml;r eine Einrichtung des Firmenkunden erforderlich sind Pers&ouml;nliche Daten zu den wichtigsten Nutznie&szlig;ern der Kundeneinheit des Unternehmens f&uuml;r jede Entit&auml;t (weitere Informationen zu den pers&ouml;nlichen Daten, die wir f&uuml;r eine Einzelperson erfassen, finden Sie im Abschnitt\" Pers&ouml;nliche Kunden\" weiter oben) die Quelle des Reichtums Die voraussichtliche Anzahl der Bits oder anderer digitaler Verm&ouml;genswerte IV. Datensammlung au&szlig;erhalb der Wirtschaftszone Europas Wie bereits erw&auml;hnt, k&ouml;nnen wir personenbezogene Daten von Kunden in der Eurozone sammeln. Um unsere Dienstleistungen f&uuml;r Kunden in der europ&auml;ischen Wirtschaftszone zu vereinfachen, m&uuml;ssen wir explizit vereinbaren, dass pers&ouml;nliche Daten aus der europ&auml;ischen Wirtschaftszone in die Region ausgelagert werden. Wenn Sie eine Einzelperson in der Eurozone sind und sich weigern, einer solchen &Uuml;bertragung zuzustimmen, k&ouml;nnen Sie COINALL und unsere Dienstleistungen nicht mehr verwenden. Sie k&ouml;nnen Ihre digitalen Best&auml;nde zur&uuml;ckrufen. Alle anderen Funktionen sind jedoch deaktiviert. V. Wie werden wir Ihre personenbezogenen Daten nutzen? COINALL verwendet personenbezogene Daten, um mit Ihnen zu kommunizieren und zu verwalten, bereitzustellen, zu verbessern und die Services zu personalisieren. COINALL kann auch aus allen personenbezogenen Daten, die wir sammeln, allgemeine Informationen generieren und f&uuml;r unsere eigenen Zwecke einsetzen. Diese Informationen k&ouml;nnen auch zur Kommunikation mit Ihnen und/ oder mit anderen Produkten oder Dienstleistungen verwendet werden, die Ihnen von Coterminal und/ oder seinen Partnern zur Verf&uuml;gung gestellt werden. Ihr Profil wird nicht an Dritte weitergegeben (au&szlig;er an Partner, die mit Coterminal zusammenarbeiten), es sei denn, Sie haben Ihre Einwilligung erhalten und werden unten genauer beschrieben. Ihre pers&ouml;nlichen Daten k&ouml;nnen an Dritte weitergegeben werden: a) wenn wir der Auffassung sind, dass der Austausch der G&uuml;ter zur Umsetzung der Bestimmungen der Dienste notwendig ist; b) die Einhaltung der staatlichen Institutionen, einschlie&szlig;lich der Aufsichtsorgane, der Strafverfolgungs-und/ oder Justizbeh&ouml;rden; c) Drittanbieter von Services f&uuml;r COINALL (z. B. Management oder technische Dienste); d) den Verkauf oder die &Uuml;bertragung von Teilen unseres Unternehmens oder eines Teils davon. Dar&uuml;ber hinaus haben wir internationale Standards zur Verhinderung von Geldw&auml;sche, Terrorfinanzierung und Vermeidung von Handels-und Wirtschaftssanktionen eingef&uuml;hrt und werden die endg&uuml;ltigen Regeln und Vorschriften f&uuml;r virtuelle Finanzanlagen anwenden, wenn diese wirksam sind. Dies kann eine sorgf&auml;ltige Bestandsaufnahme unserer Kunden erfordern. Dabei kann es sich um Drittanbieterinformationen und Serviceanbieter handeln, die unsere pers&ouml;nlichen Daten verwenden, um Querverweise zu erstellen. VI. Speichern Ihrer personenbezogenen Daten Die von Ihnen gesammelten Informationen k&ouml;nnen an andere Ziele als Malta &uuml;bertragen und dort gespeichert werden. Diese Informationen k&ouml;nnen auch von Mitarbeitern au&szlig;erhalb von Malta bearbeitet werden, die f&uuml;r uns oder unsere Zulieferer arbeiten. Mit Ausnahme der Kunden in der Eurozone erkl&auml;ren Sie sich mit der oben genannten &Uuml;bertragung von Daten einverstanden, wenn Sie Ihre personenbezogenen Daten &uuml;bermitteln. Alle von Ihnen zur Verf&uuml;gung gestellten Informationen werden auf unseren intelligenten Suchservern und/ oder von Drittanbietern gespeichert. VII. Suchen, &auml;ndern und l&ouml;schen Sie Ihre personenbezogenen Daten. Sie haben das Recht, eine Kopie Ihrer personenbezogenen Daten anzufordern, um sicherzustellen, dass die von uns erhaltenen Informationen auf dem neuesten Stand sind. Wenn Ihre personenbezogenen Daten nicht korrekt sind, m&uuml;ssen Sie sie aktualisieren. Sie k&ouml;nnen auch das L&ouml;schen Ihrer personenbezogenen Daten anfordern. M&ouml;glicherweise lehnen wir Ihre Anfrage jedoch aufgrund bestimmter Umst&auml;nde wie Konformit&auml;t oder rechtlicher Bestimmungen ab. Um Ihre personenbezogenen Daten zu &uuml;berpr&uuml;fen und zu l&ouml;schen, senden Sie eine E-Mail mit dem Betreff\" Info-Abfrage\" an support@coinall.com. Als Reaktion auf den Datenzugriff, zur Korrektur oder L&ouml;schung einer Anforderung wird die Identit&auml;t des Antragstellers &uuml;berpr&uuml;ft, um sicherzustellen, dass er rechtlich dazu berechtigt ist. Unsere Aufgabe ist es, diese Anfragen kostenlos zu beantworten. Wir behalten uns jedoch das Recht vor, Ihnen bei wiederholten oder umfangreichen Anfragen angemessene Kosten zu erheben. VIII. Marketing Wir k&ouml;nnen Sie &uuml;ber die Pressemitteilung des Unternehmens und &uuml;ber Coterminal-Produkte und-Services informieren. Wir k&ouml;nnen Ihre personenbezogenen Daten an Dritte weitergeben, damit wir an Marketing-und Marketingprojekten arbeiten oder Marketinginformationen freigeben k&ouml;nnen. Durch die Verwendung von Coterminal erkl&auml;ren Sie sich mit dieser Datenschutzrichtlinie einverstanden und stimmen zu, derartige Marketingmitteilungen zu erhalten. Kunden k&ouml;nnen diese Marketingmitteilungen jederzeit nicht erhalten. Wenn Sie keine derartige Mitteilung erhalten m&ouml;chten, senden Sie eine E-Mail an support@coinall.com. Sie k&ouml;nnen nicht festlegen, dass Sie keine produktbezogenen Benachrichtigungen erhalten, wie z. B. Richtlinien-/ Vertragsaktualisierungen und Betriebsank&uuml;ndigungen. Verwendung von IX.Cookies Wenn Sie auf Coterminal zugreifen, k&ouml;nnen wir einige wenige Daten gem&auml;&szlig; den branchen&uuml;blichen Konventionen f&uuml;r Ihren Browser speichern (Cookies). Diese Informationen k&ouml;nnen auf Ihrem Computer oder auf anderen Ger&auml;ten gespeichert werden, die f&uuml;r den Zugriff auf das COINALL-Ger&auml;t verwendet werden. Diese Informationen helfen uns dabei, Sie als Kunden zu identifizieren und Informationen &uuml;ber Ihren Einsatz von Coterminal zu sammeln, um unsere Services besser anzupassen und Ihre Erfahrung zu verbessern. Wir k&ouml;nnen auch die gesammelten Informationen verwenden, um sicherzustellen, dass wir unsere Compliance-Programme einhalten und dass Ihre Konten nicht durch unsachgem&auml;&szlig;e oder verd&auml;chtige Kontenbewegungen gesch&uuml;tzt sind. Die meisten Browser sind so eingestellt, dass Cookie automatisch akzeptiert werden. Einige Cookies laufen ab, wenn Sie die Suche beenden, w&auml;hrend andere Cookies auf Ihrem Computer oder Ger&auml;t verbleiben, bis sie gel&ouml;scht oder abgelaufen sind. Sie k&ouml;nnen die Verwendung unserer Cookie verweigern. Dies kann sich jedoch auf die Funktionalit&auml;t des Coterminal-Dienstes oder auf die Benutzerfreundlichkeit auswirken. X. Informationssicherheit Wir sind bestrebt, COINALL und seine Exzellenz vor unbefugtem Zugriff zu sch&uuml;tzen, um die von uns gesammelten und gespeicherten personenbezogenen Daten zu &auml;ndern oder zu vernichten. Wir haben verschiedene Ma&szlig;nahmen ergriffen, um die Sicherheit unserer Informationen zu gew&auml;hrleisten, einschlie&szlig;lich der Verschl&uuml;sselung des gesamten COINALL-Datenverkehrs mit SSL. F&uuml;r alle Prozesse ist eine doppelte Authentifizierung erforderlich. Pr&uuml;fen Sie regelm&auml;&szlig;ig, wie unsere personenbezogenen Daten gespeichert und verarbeitet werden. und unsere Mitarbeiter und Lieferanten streng daran zu hindern, Informationen nur bei Bedarf zu lesen und strikte vertragliche Geheimhaltungspflichten einzuhalten. XI. Kontaktaufnahme mit COINALL in Datenschutzfragen oder Bedenken Sollten Sie Fragen zur Verwendung dieser Datenschutzrichtlinie oder Ihrer pers&ouml;nlichen Daten haben, wenden Sie sich bitte an uns unter 08d2npc6@gmail.com. &Auml;nderungen unserer Datenschutzrichtlinien Alle weiteren &Auml;nderungen, die wir an unseren Datenschutzrichtlinien vornehmen, werden auf dieser Seite ver&ouml;ffentlicht und ggf. per E-Mail benachrichtigt.</span></p>', NULL);
INSERT INTO `article_translations` VALUES (352, 93, 'jp', 'プライバシープロトコル', '<p><span style=\"color: #333333; font-family: Arial, \'PingFang SC\', \'Hiragino Sans GB\', STHeiti, \'Microsoft YaHei\', sans-serif; font-size: 18px; white-space: pre-line; background-color: #ffffff;\">&nbsp;プライバシーポリシーと声明 I.はじめに このプライバシーポリシーと声明では、coinallglobalcompanyLimited「coinall」を説明しています。coinallは、マルタ会社法1995年版の規定に基づいて設立され、マルタに登録された会社（会社番号C76567））として、デルのデジタル資産）法定通貨を含まない）取引プラットフォームを通じてアクセスとユーティリティサービスを提供しているため、お客様の個人情報を使用します サービスを提供する中で、私たちは個人情報を収集し、維持します。 通常、以下に説明する場合を除き、お客様に関する個人情報は付属していない第三者には絶対に開示しません。 coinall.comおよび関連するアプリケーションインターフェイスまたはモバイルアプリ「webサイト」にアクセスまたは使用することで、当社のプライバシーポリシーのポリシーと実践「プライバシーポリシー」に同意したことになりますので、よくお読みください。 このプライバシーポリシーでは、COINALLがお客様の個人データをどのように使用するかについて説明します。これは、当社のデジタル資産取引プラットフォームを通じて、ソフトウェア、API、テクノロジー、製品、および「サービス」を通じてアクセスとユーティリティを提供しているためです。 サービスを提供する中で、私たちは個人情報を収集し、維持します。 通常、以下に説明する場合を除き、お客様に関する個人情報は付属していない第三者には絶対に開示しません。 いつでもこのポリシーと声明を修正し、このページに公開し、公開日とバージョンを明記し、別途電子メールで通知することができます。 II.定義 デジタル資産 本論文の「デジタル資産」とは、ビットコイン、イーサリアムなどのデジタル資産、すなわちマルタ仮想金融資産法2018版で「仮想金融資産」、「交換可能な仮想通貨」、「デジタル通貨」、または「デジタル製品」を指す。コンピュータネットワークに基づく暗号化プロトコルは、（I）集中的または分散的であってもよいし、）ii）閉鎖的またはオープンソースであってもよいし、オープンソースであってもよい 個人情報 ここで使用する場合、「個人情報」とは、名前、識別番号、位置情報、オンライン識別子、または物理的、経済的、文化的、または特定の1つまたは複数の要因に固有の情報、またはあなたが自然人である社会的アイデンティティなど、識別または識別可能な自然人に関する任意の情報を指します。 III.情報収集 COINALLは、お客様が本サービスを使用したり、同意した場合にお客様から収集した個人情報を収集し、処理し、保存します。 これらのプロファイルには、連絡先、提供した資格証明ファイル、または公開情報ベースから入手できる資格証明ファイルのコピー、政府の身分証明書番号、およびデバイスやインターネットサービスに関する情報(IPアドレスやMAC番号など)が含まれる場合があります。 COINALL入社プロセスで提供された情報を収集します。これらの情報は、完了したプロセス、不完全なプロセス、または放棄されたプロセスである可能性があります。 お客様の個人情報を収集、使用、保存、および転送します。その中には、以下のものが含まれる場合があります。 私たちは欧州経済ゾーン「EEA」内で運営し、「一般情報保護条例」(GDPR)と「情報保護法」の規定に従ってあなたの個人情報を収集し、保存し、処理します。 EEA内の個人および事業体から収集した情報を保護する方法の詳細については、以下の詳細を参照してください。 個人のお客様: メールアドレス 携帯電話番号 完全な法定名(以前の名前と現地の言語の名前を含む) 国籍 パスポート番号または政府が発行した身分証明書番号 生年月日 身分証明書(パスポート、免許証、政府が発行した身分証明書など) 住宅の住所 居住証明書 デルのコンプライアンスチームが適宜決定したその他の個人情報またはドキュメント 会社のお客様: 会社の法定名(現地の法定の法定名を含む) 登録/登録情報 すべての受益者、取締役および法定代表者の完全な法定名称 住所（主要な事業所および/またはその他の実際の事業所）））））。 合法的な存在の証明 ビジネスの説明 個人/会社の所有者の所有率 所有者、責任者、および経営陣の連絡先情報(該当する場合) 組織の顧客エンティティの重要な個人の実益所有者の身分証明書(パスポート、運転免許証、政府が発行した身分証明書など) 各事業体の機関顧客事業体の重要受益所有者の個人情報（個人のために収集した個人情報の詳細については、上記の「個人顧客」セクションを参照してください）））。 富の源 注入予定のビットコインまたはその他のデジタル資産の数 IV.ヨーロッパ経済ゾーン外の情報収集 上記のように、ヨーロッパ経済ゾーンにいるお客様の個人情報を収集することがあります。 ヨーロッパ経済ゾーンにいるお客様へのサービスを容易にするために、個人情報をヨーロッパ経済ゾーンからその地域外に移転することに明確に同意することを求めています。 あなたがヨーロッパ経済ゾーンにいる個人で、そのような譲渡に同意することを拒否した場合、あなたはCOINALLと私たちのサービスを使用できなくなります。 デジタル資産を撤回することができます。 ただし、他のすべての機能は無効になります。 v.私たちはあなたの個人情報をどのように使いますか COINALLは個人情報を使ってあなたとコミュニケーションをとり、管理し、提供し、サービスを改善し、パーソナライズします。 COINALLは、私たちが収集した個人情報から共通の情報を生成し、それを私たち自身の目的に使用することもあります。 また、このような情報を使用して、COINALLやパートナーが提供する他の製品やサービスについてもお客様と連絡を取ることがあります。 お客様の同意を得て、以下に詳しく説明する場合を除き、お客様のプロフィールはCOINALLと協力しているパートナー以外の第三者と共有しません。 お客様のプロフィールを第三者と共有する場合があります。 ）a）それを共有するにはサービス条項を実行する必要があると考えられる場合 (b)監督機関、法執行機関および/または司法部門を含む政府機関の遵守 (c）COINALLにサービスを提供する第三者（例えば、管理サービスや技術サービス）； （d）当社の業務またはその任意の部分の販売または譲渡に関わる。 また、マネーロンダリング、テロ資金調達、貿易と経済制裁の回避のための国際基準を実施し、有効な場合には最終的な仮想金融資産ルールと条例を実行しています。これは、お客様の徹底的な調査を要求する可能性があります。 これには、お客様の個人情報と相互参照するサードパーティの情報やサービスプロバイダの使用が含まれる場合があります。 VI.あなたの個人情報を保存する 私たちがあなたから収集した情報はマルタ以外の目的地に移され、保存される可能性があります。 これらの情報は、マルタ以外の従業員やサプライヤのために働いている従業員が処理することもあります。 ヨーロッパ経済ゾーン内のお客様を除き、個人情報を提出すると、上記の丶ストレージの譲渡または処理に同意したことになります。 お客様から提供されたすべての情報は、当社および/またはサードパーティのクラウドセキュリティサーバに保存されます。 VII.あなたの個人情報を参照、修正、削除する あなたはあなたの個人情報のコピーを取得して、私たちが取得したあなたに関する情報が正確で最新であることを確認する権利があります。 個人情報に不正確な点がある場合は、情報の更新を要求できます。 あなたの個人情報の削除を要求することもできますが、コンプライアンスや法的目的などの特定の状況のため、私たちはあなたの要求を拒否する可能性があります。 丶を参照してあなたの個人情報を修正したり削除したりするには、「情報照会」をテーマにsupport@coinall.comにメールしてください。 データアクセス、訂正、または削除要求に対応するために、私たちは要求者の身分を検証して、彼が法律上このような要求を出す権利を持っていることを確認します。 私たちの目標はこれらの要求に無料で回答することですが、お客様が重復したり、重い要求をしたりしたときに合理的な費用を請求する権利を留保します。 VIII.マーケティング推進 私たちはあなたに会社のニュース丶の推進とCOINALL製品とサービスに関する情報をお知らせするかもしれません。 私たちはあなたの個人情報を第三者に共有して、私たちがマーケティングとプロジェクトの仕事をしたり、マーケティング情報を発行したりすることができます。 COINALLを使用すると、このプライバシーポリシーを受け入れ、そのようなマーケティング通知を受け取ることに同意することになります。 お客様はいつでもこのようなマーケティング通知を受信しないことを選択できます。 このような通知を受けたくない場合は、support@coinall.comにメールしてください。 ポリシー/条項の更新や運用通知など、製品に関する通知を受信しないことは選択できません。 IX.Cookiesの使用 あなたがCOINALLにアクセスするとき、私たちは業界の慣例に従って少量のデータを置いてあなたのブラウザに保存することができます。 これらの情報は、コンピュータまたはCOINALLにアクセスするための他のデバイスに配置できます。 これらの情報は、お客様を特定し、お客様がCOINALLを使用していることに関する情報を収集して、サービスをより適切にカスタマイズし、お客様の体験を向上させるのに役立ちます。 また、収集した情報を使用して、コンプライアンスプログラムに準拠し、お客様のアカウントのセキュリティが不適格または疑わしいアカウント活動の検出によって影響を受けないようにすることもできます。 ほとんどのブラウザは自動的にCookieを受け入れるように設定されています。 一部のCookieは閲覧が完了すると期限切れになり、他のCookieは削除または期限切れになるまでコンピュータまたはデバイスに残ります。 Cookieの使用を拒否することもできますが、COINALLサービスの機能性やユーザー体験に影響を及ぼす可能性があります。 x.情報セキュリティ 私たちはCOINALLと貴殿を不正に丶にアクセスして丶を変更したり、私たちが収集して保存した個人情報を開示したり破壊したりしないように保護することに努めています。 SSLを使用してすべてのCOINALLの通信を暗号化するなど、情報の安全性を確保するためにさまざまな措置を講じています。 すべてのプログラムには二重認証が必要です 私たちの個人情報収集丶の保存と処理方法を定期的に審査する また、当社の従業員と供給業者は必要に応じて情報を参照し、厳格な契約秘密保持義務を遵守することを厳格に制限しています。 XI.プライバシーの問題や疑問についてCOINALLに連絡する このプライバシーポリシーまたは個人情報の使用についてご質問がある場合は、「プライバシー要件」をテーマに以下のアドレス08d2npc6@gmail.comまでメールでお問い合わせください。 XII.私たちのプライバシーポリシーの改正 今後、当社のプライバシーポリシーに加えられた変更はこのページに掲載され、必要に応じて電子メールでお知らせします。</span></p>', NULL);
INSERT INTO `article_translations` VALUES (353, 93, 'kor', '프라이버시 협의', '<p><span style=\"color: #333333; font-family: Arial, \'PingFang SC\', \'Hiragino Sans GB\', STHeiti, \'Microsoft YaHei\', sans-serif; font-size: 18px; white-space: pre-line; background-color: #ffffff;\">개인 정보 보호 정책 및 진술 I. 소개 본 개인 정보 보호 정책 및 성명은 몰타 회사법 1995 년판 규정에 따라 몰타에 설립 및 등록된 회사 (회사 번호 C76567) 인 coin all global company limited (\"coinall\") 가 Dell 디지털 자산 (관련되지 않음) 을 통해 개인 정보를 사용하고 있음을 설명합니다 서비스를 제공하는 과정에서 개인 정보를 수집하고 유지 관리합니다. 일반적으로, Dell 은 아래에 기술된 경우를 제외하고, 고객과 관련된 어떠한 개인 정보도 비계열사 제 3 자에게 공개하지 않습니다. Coinall.com 및 관련 어플리케이션 인터페이스 또는 모바일 어플리케이션 (\"웹 사이트\") 을 방문하거나 사용함으로써 Dell 개인 정보 보호 정책의 정책 및 관행 (\"개인 정보 보호 정책\") 에 동의하므로 자세히 읽어 보십시오. 본 개인 정보 보호 정책은 Dell 의 디지털 자산 거래 플랫폼을 통해 소프트웨어, API (어플리케이션 인터페이스), 기술, 제품 및/또는 기능 (\"서비스\") 을 통해 액세스 및 유틸리티를 제공하기 때문에 COINALL 이 귀하의 개인 데이터 (아래 정의) 를 어떻게 사용하는지 설명합니다. 서비스를 제공하는 과정에서 개인 정보를 수집하고 유지 관리합니다. 일반적으로, Dell 은 아래에 기술된 경우를 제외하고, 고객과 관련된 어떠한 개인 정보도 비계열사 제 3 자에게 공개하지 않습니다. Dell 은 언제든지 이 정책과 성명을 수정할 수 있으며, 이 페이지에 발표일 및 버전을 명시하고 이메일로 통보할 예정입니다. II. 정의 디지털 자산 이 문서에서 \"디지털 자산\" 이란 디지털 자산 (몰타 가상 금융 자산 법 버전 2018 에 언급 된 \"가상 금융 자산\", \"변환 가능한 가상 통화\", \"디지털 통화\" 또는 \"디지털 제품\") 을 의미합니다. 비트코인, 이더넷 스퀘어 등과 같은 컴퓨터 네트워크 기반 암호화 프로토콜은 다음을 수행할 수 있습니다 개인 정보 이 문서에서 사용된 \"개인 정보\" 는 이름, 식별 번호, 위치 정보, 온라인 식별자, 물리적, 경제적, 문화적 또는 특정 요소 또는 자연인으로서의 사회적 정체성과 같이 인식되거나 인식될 수 있는 자연인과 관련된 모든 정보를 의미합니다. III. 정보 수집 COINALL 은 귀하가 본 서비스를 사용하거나 동의시 귀하로부터 수집한 개인 정보를 수집, 처리 및 저장합니다. 이러한 프로필에는 연락처 정보, 제공한 인증서 파일 또는 공용 저장소에서 사용할 수 있는 인증서 파일 사본, 정부 ID 번호 및 장치 또는 인터넷 서비스와 관련된 정보 (예: IP 주소 및 MAC 번호) 가 포함될 수 있습니다. Dell 은 COINALL 입사 과정에서 제공한 정보를 수집합니다. 이 정보는 완료되었거나 불완전하거나 중단된 프로세스일 수 있습니다. Lionbridge 는 다음과 같은 개인 정보를 수집, 사용, 저장 및 전송합니다. Emc 는 유럽 경제 지역 (이하 \"EEA\") 내에서 운영되며 GDPR (일반 정보 보호 규정) 및 정보 보호법 (information protection regulation) 에 따라 개인 정보를 수집, 저장 및 처리합니다. EEA 내의 개인 및 단체로부터 수집한 정보를 보호하는 방법에 대한 자세한 내용은 아래 상세 정보를 참조하십시오. 개인 고객: 이메일 주소 휴대폰 번호 전체 쿼럼 이름 (이전 이름 및 현지 언어 이름 포함) 국적 여권 번호 또는 정부에서 발급한 주민등록번호 생년월일 신분증 (예: 여권, 운전면허증 또는 정부가 발급한 신분증) 주택 주소 거주증명 Dell 규정 준수 팀이 재량에 따라 결정한 기타 개인 정보 또는 문서 회사 고객: 회사 법정 이름 (현지 법정의 법정 이름 포함) 등록/등록 정보 모든 수혜자, 이사 및 법정 대리인의 완전한 법정 이름 주소 (주요 사업장 및/또는 기타 물리적 위치) 합법적인 존재의 증명 업무 설명 개인/회사 소유자의 소유 지분입니다 소유자, 책임자 및 경영진 연락처 정보 (해당되는 경우) 기관 고객 단체의 중요한 개인 실익 소유자의 신분증 (예: 여권, 운전면허증 또는 정부에서 발급한 신분증) 각 개체의 기관 고객 개체에 대한 중요한 수혜자 소유자의 개인 정보 (개인을 위해 수집한 개인 정보에 대한 자세한 내용은 위의 \"개인 고객\" 섹션을 참조하십시오) 부의 원천 비트코인이나 기타 디지털 자산의 예상 수 IV. 유럽 경제 구역 밖의 정보 수집 앞서 언급했듯이 유럽 경제 지역에 위치한 고객의 개인 정보를 수집할 수 있습니다. 유럽 경제 지역에 위치한 고객에게 제공하는 서비스를 용이하게 하기 위해 유럽 경제 지역에서 해당 지역 외부로 개인 정보를 이전하는 데 대한 명확한 동의를 요청합니다. 유럽 경제 지역에 거주하는 개인인 경우 그러한 양도에 동의하지 않으면 COINALL 과 Dell 서비스를 더 이상 사용할 수 없습니다. 디지털 자산을 철회할 수 있습니다. 그러나 다른 모든 기능은 비활성화됩니다. V. 우리는 당신의 개인 정보를 어떻게 사용할 것인가? COINALL 은 개인 정보를 사용하여 의사 소통 및 관리, 제공, 개선 및 개인화된 서비스를 제공합니다. COINALL 은 또한 우리가 수집한 모든 개인 정보로부터 공통 정보를 생성하여 우리 자신의 목적에 사용할 수도 있습니다. Dell 은 또한 이러한 정보를 사용하여 COINALL 및/또는 해당 파트너가 제공하는 다른 제품이나 서비스와 통신할 수 있습니다. 귀하의 동의를 얻어 아래에 자세히 설명하지 않는 한 귀하의 프로필을 제 3 자 (COINALL 과 협력하는 파트너 제외) 와 공유하지 않습니다. Dell 은 귀하의 개인 정보를 제 3 자와 공유할 수 있습니다. (a) 서비스 약관 이행이 필요하다고 생각되면 (b) 규제 기관, 법 집행 및/또는 사법부를 포함한 정부 기관 준수 (c) COINALL 에 서비스를 제공하는 제 3 자 (예: 관리 또는 기술 서비스); (d) 사업 또는 그 일부와 관련된 판매 또는 양도. 또한 돈세탁 방지, 테러 자금 조달, 무역 및 경제 제재 회피를 위한 국제 표준을 시행했으며, 유효할 경우 최종 가상 금융 자산 규칙과 규정을 시행할 예정입니다. 이를 위해서는 고객에 대한 실사가 필요할 수 있습니다. 여기에는 Dell 이 귀하의 개인 정보와 상호 참조할 타사 정보 및 서비스 제공업체 사용이 포함될 수 있습니다. VI. 개인 정보 저장 우리가 당신에게서 수집한 정보는 몰타 이외의 목적지로 옮겨져 저장될 수 있습니다. 이 정보는 몰타 이외 지역에서 우리 또는 우리 공급업체를 위해 일하는 직원도 처리할 수 있습니다. 유럽 경제 지역의 고객 외에 개인 정보를 제출하면 위에서 언급한 양도, 저장 또는 처리에 동의하는 것입니다. 귀하가 제공한 모든 정보는 Dell 및/또는 타사 클라우드 보안 서버에 저장됩니다. VII. 개인 정보 검토, 수정 및 삭제 귀하는 귀하의 개인 정보 사본을 요청하여 귀하의 정보가 정확하고 최신인지 확인할 권리가 있습니다. 개인 정보의 부정확성이 있을 경우 정보 업데이트를 요청할 수 있습니다. 귀하의 개인 정보 삭제를 요청할 수도 있지만 규정 준수 또는 법적 목적과 같은 특정 상황으로 인해 귀하의 요청을 거부할 수 있습니다. 개인 정보를 검토, 수정 및 삭제하려면 \"정보 조회\" 라는 주제로 support@coinall.com 으로 이메일을 보내 주십시오. 데이터 액세스, 수정 또는 삭제 요청에 응답하기 위해 요청자의 신원을 검증하여 이러한 요청을 법적으로 제출할 수 있는 권한을 부여합니다. Dell 의 목표는 이러한 요청에 무료로 응답하는 것이지만, Dell 은 반복 또는 과중한 요청 시 합당한 비용을 청구할 수 있는 권리를 보유합니다. VIII. 마케팅 우리는 회사 뉴스, 홍보 및 COINALL 제품 및 서비스와 관련된 정보를 알려드릴 수 있습니다. Dell 은 마케팅 및 홍보 프로젝트 작업을 수행하거나 마케팅 정보를 배포할 수 있도록 고객의 개인 정보를 제 3 자에게 공유할 수 있습니다. COINALL 을 사용하는 것은 이 개인 정보 보호 정책에 동의하고 그러한 마케팅 통지를 받는 것에 동의하는 것을 의미합니다. 고객은 언제든지 이러한 마케팅 통지를 받지 않도록 선택할 수 있습니다. 이러한 알림을 받지 않으려면 support@coinall.com 으로 이메일을 보내 주십시오. 정책/약관 업데이트 및 운영 공지와 같은 제품 관련 알림을 받지 않도록 선택할 수 없습니다. IX.Cookies 의 사용 COINALL 을 방문하면 업계 관례에 따라 소량의 데이터를 브라우저 저장 (쿠키) 에 배치할 수 있습니다. 이 정보는 컴퓨터나 COINALL 에 액세스하는 데 사용되는 기타 장치에 배치할 수 있습니다. 이 정보는 고객을 식별하고 COINALL 사용에 대한 정보를 수집하여 Dell 서비스를 보다 잘 사용자 정의하고 경험을 개선하는 데 도움이 됩니다. Dell 은 또한 수집한 정보를 사용하여 Dell 규정 준수 프로그램을 준수하고 규정 비준수 또는 의심스러운 계정 활동 감지로 인해 계정 보안이 영향을 받지 않도록 할 수 있습니다. 대부분의 브라우저는 쿠키를 자동으로 수락하도록 설정되어 있습니다. 일부 쿠키는 브라우징이 완료되면 만료되고 다른 쿠키는 삭제되거나 만료될 때까지 컴퓨터 또는 장치에 남아 있습니다. Dell 쿠키 사용을 거부할 수 있지만, 이는 COINALL 서비스의 기능이나 사용자 경험에 영향을 줄 수 있습니다. X. 정보 보안 Dell 은 COINALL 과 귀하를 무단 액세스, 변경, 공개 또는 파기로부터 보호하기 위해 노력하고 있습니다. Dell 은 SSL 을 사용하여 모든 COINALL 의 통신을 암호화하는 등 정보 보안을 보장하기 위한 다양한 조치를 취하고 있습니다. 모든 프로그램에는 이중 인증이 필요합니다. 개인 정보 수집, 저장 및 처리 방법을 정기적으로 검토합니다. 또한 직원 및 공급업체가 필요할 때만 정보를 확인하고 엄격한 계약 기밀 유지 의무를 준수할 수 있도록 엄격하게 제한했습니다. XI. 개인 정보 보호 문제나 우려 사항에 대해 COINALL 에 문의합니다 본 개인 정보 보호 정책 또는 개인 정보 사용에 대해 궁금한 점이 있으면\' 개인 정보 요구 사항\' 이라는 주제로 아래 08d2npc6@gmail.com 으로 문의해 주십시오. XII. 개인 정보 보호 정책 변경 앞으로 Dell 의 개인 정보 보호 정책에 대한 모든 변경 사항은 이 페이지에 게시되며, 해당되는 경우 이메일로 알려 드립니다.</span></p>', NULL);
INSERT INTO `article_translations` VALUES (354, 162, 'en', 'Announcement on Bekonex wallet upgrade', '<p>Dear Bekonex users<br /><br />Hello!<br /><br />Bekonex is designed to provide users with a fast, convenient and safe access experience. Now we have made a significant upgrade of the wallet. Please reset your wallet to the latest address.<br /><br />Bekonex exchange<br /><br />November 30, 2020</p>', NULL);
INSERT INTO `article_translations` VALUES (355, 160, 'en', 'CoinALL \'s activity of 50% discount on the service charge of double 11', '<p><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">尊敬的 CoinALL用户</span></span><br /><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">您好！</span></span><br /><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">Bekonex交易所将在双11期间开展全额交易手续费50%优惠活动，前100名将获得100-1000USDT不等的随机红包。</span><span style=\"vertical-align: inherit;\">欢迎各位尊敬的用户踊跃交易。</span></span><br /><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">CoinALL交易所将继续秉承用户至上、安全、实力、信任的运营理念，为全球投资者打造安全、透明、可靠的数字资产服务环境。</span></span><br /><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">CoinALL交易所</span></span><br /><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">2020 年 11 月 10 日</span></span></p>', NULL);
INSERT INTO `article_translations` VALUES (356, 158, 'en', 'The platform launched leverage trading and held 5-day interest free activity announcement', '<div class=\"input-wrap\" dir=\"ltr\" style=\"height: auto;\">&nbsp;</div>\r\n<div class=\"output-bd\" dir=\"ltr\" style=\"padding-bottom: 16px;\">\r\n<p class=\"ordinary-output target-output clearfix\"><span class=\"\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">尊敬的CoinALL 用户 </span></span></span></p>\r\n<p class=\"ordinary-output target-output clearfix\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">rs，</span></span>CoinALL平台杠杆交易专区已于11月7日14:00（UTC+8）上线杠杆交易，支持通证为BTC、ETH、EOS、LTC、BCH、XRP、TRX。</p>\r\n<p class=\"ordinary-output target-output clearfix\"><span class=\"\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">为庆祝</span></span></span>CoinALL<span style=\"vertical-align: inherit;\">上线杠杆交易，平台特举办&ldquo;5天免息活动&rdquo;。</span><span style=\"vertical-align: inherit;\">活动期间杠杆借贷利息费用为0，诚邀广大用户体验。</span></p>\r\n<p class=\"ordinary-output target-output clearfix\"><span class=\"\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">活动时间：11月7日20:00（utc+8）&mdash;&mdash;11月12日20:00（utc+8）</span></span></span></p>\r\n</div>', NULL);
INSERT INTO `article_translations` VALUES (357, 157, 'en', 'API announcement of some new certificates on the platform', '<p>Dear Hokiecoin users<br /><br />In order to improve the transaction depth and optimize the user\'s transaction experience, Hokiecoin platform has added API applications for ont / usdt, Neo / usdt, qtum / usdt, vet / usdt, XLM / usdt, xtz / usdt, Iost / usdt, atom / usdt and BTM / usdt.<br /><br />Currently, it supports API applications of BTC / usdt, ETH / usdt, EOS / usdt, BCH / usdt, LTC / usdt, ont / usdt, TRX / usdt, XRP / usdt, Dash / usdt, Neo / usdt, qtum / usdt, vet / usdt, XLM / usdt, xtz / usdt, Zec / usdt, Iost / usdt, atom / usdt, BTM / usdt.<br /><br />Trading digital assets, on Hokiecoin is enough!</p>', NULL);
INSERT INTO `article_translations` VALUES (358, 156, 'en', 'Impact of some new transactions on API announcement', '<p><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">尊敬的</span></span>CoinALL用户</p>\r\n<p><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">为了优化用户的交易体验，MXC平台现新增ADA/usdt、BSV/usdt、ZIL/usdt、AE/usdt和NAS/usdt的API应用。</span><span style=\"vertical-align: inherit;\">现在，大多数用户可以独立申请API操作。</span></span><br /><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">交易数字资产，在</span></span>CoinALL就够了！</p>', NULL);
INSERT INTO `article_translations` VALUES (359, 155, 'en', 'Announcement that the existing platform project will be re evaluated and scored', '<p><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">尊敬的</span></span>CoinALL用户</p>\r\n<p><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">CoinALL平台严格遵守全球数字资产和交易所的相关法律法规，始终选择向主流合规方向发展。</span><span style=\"vertical-align: inherit;\">为响应相关政策，Hokiecoin区块链研究院将根据</span></span>CoinALL平台关于隐藏代币和线下交易对的规则，开始对MXC平台上的项目进行重新评估和评级，主要从以下几个维度：</p>\r\n<p><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">1. 项目进展情况项目是否正常及能否落地</span></span><br /><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">2.项目真实交易量</span></span><br /><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">3.</span><span style=\"vertical-align: inherit;\">项目</span><span style=\"vertical-align: inherit;\">存入资金</span></span><br /><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">4.负面舆论</span></span><br /><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">5.新增用户数</span></span><br /><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">6.程序代码更新及开发完成</span></span><br /><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">重新评估评分后，不符合标准的项目将按照Hokiecoin平台隐藏代币和线下交易对的规则进行处理。</span></span><br /><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">同时，</span></span>CoinALL<span style=\"vertical-align: inherit;\">研究院将加强对项目的审核和对上线项目的不定期审核。</span><span style=\"vertical-align: inherit;\">也欢迎 Hokiecoin 社区成员共同监督 MXC 平台上的项目，</span>CoinALL平台将通过对存在相关问题的项目的建议和反馈，及时核实和跟进。</p>', NULL);
INSERT INTO `article_translations` VALUES (360, 154, 'en', 'Announcement of new project of platform leverage ETF', '<p><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">尊敬的用户</span></span><br /><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">为满足</span><span style=\"vertical-align: inherit;\">用户</span><span style=\"vertical-align: inherit;\">的交易需求，</span></span>CoinALL平台于2020年1月9日20:00（UTC+8）新增以下指标：</p>\r\n<p><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">1. Bsv3l&mdash;&mdash;BSV三重多头，bsv3s&mdash;&mdash;BSV三重空头</span></span><br /><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">2 . Bnb3l -- BNB 三重多头, bnb3s -- BNB 三重空头</span></span><br /><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">3. etc3l -- 等三重多头, etc3s -- 等三重空头</span></span><br /><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">欢迎用户体验。</span></span></p>', NULL);
INSERT INTO `article_translations` VALUES (361, 153, 'en', 'Announcement of new part of platform leverage transaction pair', '<p><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">尊敬的</span></span>CoinALL用户</p>\r\n<p><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">为满足广大用户的交易需求，Hokiecoin平台杠杆交易将于15:00（UTC+8）新增OGN/usdt、ankr/usdt、GXC/usdt和Xmx/usdt交易对2020 年 2 月 10 日，支持 OGN、ankr、GXC 和 Xmx 的金融交易，利息为 0.1%。</span><span style=\"vertical-align: inherit;\">欢迎广大用户体验。</span></span><br /><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">交易数字资产，</span></span>CoinALL！</p>', NULL);
INSERT INTO `article_translations` VALUES (362, 152, 'en', 'Online announcement of dashusdt, xtzusdt, linkusdt and bsvusdt perpetual contracts', '<div class=\"output-bd\" dir=\"ltr\" style=\"padding-bottom: 60px;\">\r\n<p class=\"ordinary-output target-output clearfix\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">尊敬的&nbsp;</span></span>CoinALL用户</p>\r\n<p class=\"ordinary-output target-output clearfix\"><span class=\"\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">CoinALL将于2020年2月23日21:00（utc+8）上线dashusdt、xtzusdt、linkusdt和bsvusdt，最高100倍杠杆，按仓保证金模式开启全仓仓仓。</span><span style=\"vertical-align: inherit;\">欢迎体验交易。</span></span></span></p>\r\n</div>', NULL);
INSERT INTO `article_translations` VALUES (363, 151, 'en', 'Announcement on the merger of 15 varieties of Bekonex leverage ETF products', '<div class=\"output-bd\" dir=\"ltr\" style=\"padding-bottom: 82px;\">\r\n<p class=\"ordinary-output target-output clearfix\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">尊敬的</span></span>CoinALL 用户</p>\r\n<p class=\"ordinary-output target-output clearfix\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">目前部分杠杆ETF产品的单价低于0.05usdt，触发了Bekonex杠杆ETF产品的合并机制。</span><span style=\"vertical-align: inherit;\">我们将于2020年3月13日（今天）14:00（UTC+8）启动股份合并机制，合并单价低于0.05usdt的杠杆ETF产品的股份。</span><span style=\"vertical-align: inherit;\">合并后，用户的总资产不会受到任何影响。</span></span></p>\r\n<p class=\"ordinary-output target-output clearfix\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">具体合并品种及方案如下：</span></span></p>\r\n<p class=\"ordinary-output target-output clearfix\"><span class=\"\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">Algo3l、atom3l：原100股变为新股，新股净值变为原100倍。</span></span></span></p>\r\n<p class=\"ordinary-output target-output clearfix\"><span class=\"\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">Ada3l、vet3l、dash3l、iot3l：原20股变为新股，新股净值变为原股20倍。</span></span></span></p>\r\n<p class=\"ordinary-output target-output clearfix\"><span class=\"\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">Okb3l、ont3l、link3l、bsv3l、zec3l、neo3l、bnb3l、qtum3l、etc3l：原10股变为新股，新股净值变为原10倍。</span></span></span></p>\r\n<p class=\"ordinary-output target-output clearfix\"><span class=\"\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">净值折算以合并时的净值为基础。</span></span></span><span class=\"\"><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">新股的名称、简称、交易对与合并前相同。</span></span></span></p>\r\n</div>', NULL);
INSERT INTO `article_translations` VALUES (364, 150, 'en', 'Announcement on newly added trading pairs of platform leverage Trading', '<p><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">尊敬的</span></span>CoinALL用户</p>\r\n<p><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">为满足广大用户的交易需求，Hokiecoin平台将于2020年3月20日18:00（UTC+8）新增Pax/usdt和tusd/usdt交易对，支持5倍杠杆多空交易，开通Pax和tusd币种融资功能，日息0.1%。</span><span style=\"vertical-align: inherit;\">欢迎广大用户体验。</span></span><br /><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">交易数字资产，</span></span>CoinALL！</p>', NULL);
INSERT INTO `article_translations` VALUES (365, 149, 'en', 'Announcement on temporary upgrade of some transactions of platform perpetual contract', '<p><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">尊敬的</span></span>CoinALL用户</p>\r\n<p><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">为了给您带来更好的交易体验，Bekonex平台将于2020年3月26日15:00（UTC+8）临时升级btcusdt、ethusdt、eosusdt、ltcusdt、etcusdt永续合约交易对。升级期间，相关交易对将暂停约30分钟。</span><span style=\"vertical-align: inherit;\">其他合约在不受影响的情况下可以正常交易。</span></span><br /><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">持有上述合约头寸的用户请根据市场情况提前平仓、取消订单，以免给您造成不必要的损失。</span></span><br /><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">带来不便敬请谅解。</span></span></p>', NULL);
INSERT INTO `article_translations` VALUES (366, 148, 'en', 'Announcement on the activity of \"trading new version of leverage, enjoying limited time and ultra low interest rate\"', '<p><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">尊敬的</span></span>CoinALL用户，</p>\r\n<p><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">Bekonex现货杠杆将于2020年4月1日12:00（UTC+8）升级上线。为感谢广大用户的支持，MXC平台将于4月1日上线一周&ldquo;交易新品&rdquo;杠杆，享受限时超低利息！&rdquo; </span><span style=\"vertical-align: inherit;\">活动中，参与交易可享受低至0.05%/天的利息优惠。</span></span><br /><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">一、活动时间</span></span><br /><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">2020年4月1日-2020年4月7日</span></span><br /><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">二、活动规则及奖励</span></span><br /><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">无需注册即可参与活动。</span><span style=\"vertical-align: inherit;\">活动期间，Bekonex可享受所有USDT和BTC交易对每天低至0.05%的杠杆利息。</span></span><br /><br /><span style=\"vertical-align: inherit;\"><span style=\"vertical-align: inherit;\">新版本上线，欢迎体验！</span></span></p>', NULL);
INSERT INTO `article_translations` VALUES (367, 147, 'en', 'ETF partner recruitment order announcement', '<p>Dear Bekonex users<br /><br />Leveraged ETF products are a kind of financial derivatives which are very popular in traditional financial markets. It is a trading product that can achieve a certain multiple (such as 3 times) of daily return on the target asset under the premise of a given target asset (such as BTC). At present, each kind of general securities supports three times long and three times short. Investors can buy or sell in the ⼆ level market at any time, and can achieve the purpose of trading leverage without any margin. Here, we invite you to join ETF partners, and work together with Hokiecoin to win-win results and grow together.<br /><br />1、 Partner\'s exclusive interest:<br /><br />50% - 80% high return<br /><br />Exclusive customer manager docking<br /><br />Festival courtesy<br /><br />Sponsorship of peripheral products<br /><br />New project air drop<br /><br />High end activities take precedence<br /><br />2、 Description of transaction handling fee return:<br /><br />Agent level<br /><br />Proportion of domestic service<br /><br />Hokiecoin position user<br /><br />Settlement time<br /><br />Gold partner<br /><br />50%<br /><br />0-100 people<br /><br />Day end<br /><br />Platinum partner<br /><br />70%<br /><br />100-300 people<br /><br />Black Diamond partner<br /><br />80%<br /><br />300-500 people<br /><br />Note to partners:<br /><br />During the promotion period, the number of users in the exclusive community of Bekonex is no less than 50;<br /><br />The cumulative transaction volume of users per week is greater than 10000usdt;<br /><br />The domestic service shall be effective for two years from the opening date.<br /><br />*The Bekonex platform will retain the final interpretation right of the partner plan during the implementation period.</p>', NULL);
INSERT INTO `article_translations` VALUES (368, 146, 'en', 'Announcement on newly added trading pairs of platform leverage Trading', '<p>Dear Bekonex users<br /><br />In order to meet the transaction needs of users, Hokiecoin platform will add BTS / usdt, DDD / usdt, UGAS / usdt and FET / usdt trading pairs at 18:00 (UTC + 8) on February 17, 2020, and support BTS, DDD, UGAS and FET lending with interest of 0.1%. Users are welcome to experience.<br /><br />Trading digital assets,Bekonex!</p>', NULL);
INSERT INTO `article_translations` VALUES (369, 145, 'en', 'Announcement on newly added trading pairs of platform leverage Trading', '<p>Dear Bekonex users<br /><br />In order to meet the transaction needs of the majority of users, Hokiecoin platform will add Pax / usdt and tusd / usdt trading pairs at 18:00 (UTC + 8) on March 20, support 5 times leverage long short trading, and open Pax and tusd currency function, with daily interest of 0.1%. Users are welcome to experience.<br /><br />Trading digital assets, Bekonex!</p>', NULL);
INSERT INTO `article_translations` VALUES (370, 144, 'en', 'Announcement on the activity of \"trading new version of leverage, enjoying limited time and ultra low interest rate\"', '<p>Dear Bekonex users<br /><br />Bekonex spot leverage will be upgraded and launched from 12:00 (UTC + 8) on April 1, 2020. In order to thank users for their support, Bekonex platform will launch a week-long \"trading new leverage, enjoying limited time and ultra-low interest rate!\" Activities, to participate in the transaction can enjoy as low as 0.05% / day interest concessions.<br /><br />1、 Activity time<br /><br />April 1, 2020 - April 7, 2020<br /><br />2、 Activity rules and rewards<br /><br />No registration is required to participate in the activity. During the activity time, Hokiecoin can enjoy leverage interest as low as 0.05% per day for all transaction pairs in usdt and BTC.<br /><br />New version online, welcome to experience!</p>', NULL);
INSERT INTO `article_translations` VALUES (371, 143, 'en', 'Announcement on online FTM leverage trading on the platform', '<p>Dear Bekonex users<br /><br />The leverage trading area of Bekonex platform will launch FTM / usdt trading pairs at 19:30 (UTC + 8) on July 3. It supports 4 times leverage and FTM currency trading. The 24-hour interest of buying (long) is 0.1%, and that of selling (short) is 0.5%. Users are welcome to experience.<br /><br />Trading digital assets, Bekonex!</p>', NULL);
INSERT INTO `article_translations` VALUES (372, 142, 'en', 'Announcement on upgrading of leverage ETF experience', '<p>Dear Bekonex users<br /><br />Bekonex has completed the optimization of most trading pairs of leveraged ETF on July 7, 2020. After optimization, the trading depth, opening spread and matching efficiency of leveraged ETF have been greatly improved. Welcome to the trading experience!<br /><br />The follow-up platform will continue to strive to optimize the product experience and provide you with better products and services. If you have any comments or suggestions, you can contact the official customer service.<br /><br />Thank you for your attention and support.<br /><br />Trading digital assets, Bekonex !</p>', NULL);
INSERT INTO `article_translations` VALUES (373, 141, 'en', 'Announcement ofBekonex platform on new products of defi index', '<p><span style=\"color: #9fa6b5;\">Dear Bekonex users</span><br /><br /><span style=\"color: #9fa6b5;\">Bekonex&nbsp; has added a new WiFi index product at 18:20 (UTC + 8). Users can log in to the website for transaction. Details of the defi index products are as follows:</span><br /><br /><span style=\"color: #9fa6b5;\">Abbreviation: mx04</span><br /><br /><span style=\"color: #9fa6b5;\">Chinese Name: defi combination</span><br /><br /><span style=\"color: #9fa6b5;\">English Name: defi assets index</span><br /><br /><span style=\"color: #9fa6b5;\">Index components: KNC, Zrx, kava, nest</span><br /><br /><span style=\"color: #9fa6b5;\">What are MXC index products?</span><br /><br /><span style=\"color: #9fa6b5;\">MXC index products are open products, which support users to buy and sell the shares of index products in real time, so as to track the rise and fall of MXC index and obtain the average market return of this kind of asset portfolio.</span><br /><br /><span style=\"color: #9fa6b5;\">The MXC index selects digital assets with good market liquidity as component targets, and refers to the proportion of daily average turnover of the target in the previous month as the initial market value weight in the base period, so as to reflect the overall market performance of such assets.</span><br /><br /><span style=\"color: #9fa6b5;\">What are the advantages of MXC index products?</span><br /><br /><span style=\"color: #9fa6b5;\">Spread the risk. Compared with single currency transactions, MXC index products are equivalent to tracking an asset portfolio with less internal correlation, and the smaller the correlation of assets, the more conducive to diversifying investment risk.</span><br /><br /><span style=\"color: #9fa6b5;\">Save your mind and effort. Investing in index products is equivalent to investing in all index component currencies tracked by the product, which avoids the trouble of selecting investment varieties.</span></p>', NULL);
INSERT INTO `article_translations` VALUES (374, 140, 'en', 'Announcement of new decentralized storage index products on Bekonexvplatform', '<p><span style=\"color: #9fa6b5;\">DearBekonex users</span><br /><br /><span style=\"color: #9fa6b5;\">Bekonex will add a new decentralized storage index product at 18:00 on June 18, 2020 (UTC + 8). Users can log in to the website and select \"index trading\" in the \"ETF zone\" to trade. Details of the DSI products are as follows:</span><br /><br /><span style=\"color: #9fa6b5;\">Abbreviation: mx05</span><br /><br /><span style=\"color: #9fa6b5;\">Chinese Name: decentralized storage portfolio</span><br /><br /><span style=\"color: #9fa6b5;\">English Name: decentralized storage assets index</span><br /><br /><span style=\"color: #9fa6b5;\">Index components: storj, BLZ, GNX, lamb</span><br /><br /><span style=\"color: #9fa6b5;\">What are MXC index products?</span><br /><br /><span style=\"color: #9fa6b5;\">MXC index products are open products, which support users to buy and sell the shares of index products in real time, so as to track the rise and fall of MXC index and obtain the average market return of this kind of asset portfolio.</span><br /><br /><span style=\"color: #9fa6b5;\">The MXC index selects digital assets with good market liquidity as component targets, and refers to the proportion of daily average turnover of the target in the previous month as the initial market value weight in the base period, so as to reflect the overall market performance of such assets.</span><br /><br /><span style=\"color: #9fa6b5;\">What are the advantages of MXC index products?</span><br /><br /><span style=\"color: #9fa6b5;\">Spread the risk. Compared with single currency transactions, MXC index products are equivalent to tracking an asset portfolio with less internal correlation, and the smaller the correlation of assets, the more conducive to diversifying investment risk.</span><br /><br /><span style=\"color: #9fa6b5;\">Save your mind and effort. Investing in index products is equivalent to investing in all index component currencies tracked by the product, which avoids the trouble of selecting investment varieties.</span></p>', NULL);
INSERT INTO `article_translations` VALUES (375, 139, 'en', 'Announcement on eth transaction pairs of newly added AR, BAL, comp and dmg', '<div class=\"trans-operation-wrapper clearfix\">&nbsp;</div>\r\n<div class=\"trans-left\">\r\n<div class=\"trans-input-wrap\">\r\n<div class=\"input-wrap\" dir=\"ltr\" style=\"height: auto;\">&nbsp;</div>\r\n</div>\r\n</div>\r\n<div class=\"output-bd\" dir=\"ltr\" style=\"padding-bottom: 104px;\">\r\n<p class=\"ordinary-output target-output clearfix\">Dear Bekonex users</p>\r\n<p class=\"ordinary-output target-output clearfix\"><span class=\"\">In order to fully meet the trading needs of users, the Bekonex platform will add AR / eth, BAL / eth, comp / Eth and DMG / eth trading pairs at 10:30 (UTC + 8) on June 24.</span></p>\r\n<p class=\"ordinary-output target-output clearfix\"><span class=\"\">Welcome to the user transaction experience.</span></p>\r\n<p class=\"ordinary-output target-output clearfix\"><span class=\"\">[risk tips]</span></p>\r\n<p class=\"ordinary-output target-output clearfix\"><span class=\"\">Digital asset is a kind of high-risk investment. Investors should be cautious and pay attention to the investment risk.</span><span class=\"\"> MXC will not undertake the responsibility of guarantee or compensation for the project or investment.</span></p>\r\n<p class=\"ordinary-output target-output clearfix\"><span class=\"\">Trading digital assets, Bekonex!</span></p>\r\n</div>', NULL);
INSERT INTO `article_translations` VALUES (376, 138, 'en', 'Announcement on the share merger of link3s and thit3l of leveraged ETF products', '<p>Dear Bekonex users<br /><br />As the unit prices of the current leveraged ETF products link3s and theta3l are lower than 0.05usdt, the Bekonex leveraged ETF product share merger mechanism is triggered. We will start the share merger mechanism at 15:00 on July 17 (UTC + 8) to merge the shares of link3s and theta3l. After the merger, the total assets of users will not be affected in any way.<br /><br />The original 10 shares of link3s and theta3l will become a new share of link3s and theta3l. At the same time, the net value of the new share becomes 10 times of the original share. Net value conversion is based on the net value at the time of merger.<br /><br />The name, abbreviation and trading pair of the new shares are the same as those before the merger.</p>', NULL);
INSERT INTO `article_translations` VALUES (377, 137, 'en', 'Announcement on the trading pairs of online dot/usdt leverage', '<p>Dear Hokiecoin users<br /><br />Hokiecoin leverage trading area will launch dot / usdt trading pair at 22:00 (UTC + 8) on July 20, supporting triple leverage, 24-hour interest rate of buying (long) is 0.1%, and dot short trading is not supported temporarily.<br /><br />Previously, Hokiecoin currency trading area has launched dot / usdt and dot / BTC trading pairs. Welcome to the trading experience.<br /><br />Trading digital assets, Hokiecoin!</p>', NULL);
INSERT INTO `article_translations` VALUES (378, 136, 'en', 'Announcement on POS function of online ampl', '<p>Dear Bekonex users<br /><br />Bekonex has launched the POS function of ampl position. Users are welcome to participate! Details are as follows:<br /><br />1. The income of ampl POS is settled by ampl, and daily income = number of ampl (annualized rate of return / 365);<br /><br />2. The expected annual income will be adjusted at any time according to the actual income of the mine pool;<br /><br />3. Calculate the income one day after opening POS;<br /><br />4. Take a snapshot at random every day and settle with the lowest position value of the snapshot (including the decrease of position value caused by rebase, which is also regarded as the lowest value of the day);<br /><br />5. It is not necessary to freeze the mortgaged assets, and it can be traded or withdrawn at any time;<br /><br />6. The POS can be cancelled at any time. If the balance of assets is less than the minimum initial investment value or the user cancels the agreement voluntarily, the POS will exit automatically and the income will be settled to the day before the POS exit.<br /><br />Trading digital assets, Bekonex!</p>', NULL);
INSERT INTO `article_translations` VALUES (379, 135, 'en', 'Announcement on online multiple mainstream currency trading pairs', '<p>Dear Bekonex users<br /><br />In order to fully meet the transaction needs of users, Bekonex platform will launch several BTC and eth transaction pairs of mainstream currencies at 15:00 (UTC + 8) on July 2, as follows:<br /><br />BTC：BCH/BTC<br /><br />ETH：ETC/ETH、LTC/ETH<br /><br />Welcome to the majority of users to trade experience.<br /><br />[risk tips]<br /><br />Digital asset is a kind of high-risk investment. Investors should be cautious and pay attention to the investment risk. Hokiecoin shall not be liable for guarantee or compensation for the project or investment.</p>', NULL);
INSERT INTO `article_translations` VALUES (380, 134, 'en', 'Announcement on the trading pairs of FTM leverage on line', '<p>Dear Bekonex users<br /><br />The leverage trading area of Bekonex platform will launch FTM / usdt trading pairs at 19:30 (UTC + 8) on July 3. It supports 4 times leverage and FTM currency trading. The 24-hour interest of buying (long) is 0.1%, and that of selling (short) is 0.5%. Users are welcome to experience.<br /><br />Trading digital assets, Bekonex!</p>', NULL);
INSERT INTO `article_translations` VALUES (381, 133, 'en', '关于永续合约体验升级的公告', '<p>DearBekonexusers<br /><br />Bekonex has completed the optimization of most trading pairs of perpetual contracts on July 9. After optimization, the trading depth, opening spread and matching efficiency have been greatly improved. Welcome to the trading experience!<br /><br />The follow-up platform will continue to strive to optimize the product experience and provide you with better products and services. If you have any comments or suggestions, you can contact the official customer service.<br /><br />Thank you for your attention and support.<br /><br />Trading digital assets,Bekonex!</p>', NULL);
INSERT INTO `article_translations` VALUES (382, 132, 'en', 'Notice on reducing the management fee of some leveraged ETF products', '<p>DearBekonex users<br /><br />As the 24-hour capital rate of hedging platform has been lowered, Bekonex has adjusted the daily management fee of some leveraged ETF products to 0.2%. Please know and pay attention to the transaction cost.<br /><br />The transaction pairs involved in this adjustment include:<br /><br />ATOM3L/USDT、ATOM3S/USDT、DOGE3L/USDT、DOGE3S/USDT、VET3L/USDT、VET3S/USDT<br /><br />Bekonex has previously adjusted the daily management fee of the following transactions to 0.2%, as follows:<br /><br />OKB3L/USDT 、OKB3S/USDT、DASH3L/USDT、DASH3S/USDT、BNB3L/USDT、BNB3S/USDT、ETC3L/USDT、ETC3S/USDT、ALGO3L/USDT、ALGO3S/USDT<br /><br />The follow-up platform will continue to pay attention to the changes of market capital rate and make relevant adjustments in time. Thank you for your understanding and support.</p>', NULL);
INSERT INTO `article_translations` VALUES (383, 131, 'en', 'Announcement on the new function of OTC entrusted registration', '<div class=\"output-bd\" dir=\"ltr\" style=\"padding-bottom: 16px;\">\r\n<p class=\"ordinary-output target-output clearfix\">Dear Bekonex users</p>\r\n<p class=\"ordinary-output target-output clearfix\">In order to meet the transaction needs of the majority of users, Hokiecoin Web terminal has launched the OTC Commission registration function. Details are as follows:</p>\r\n<p class=\"ordinary-output target-output clearfix\"><span class=\"\">1. OTC entrustment registration refers to that if the user is not satisfied with the current price, he can set the expected price and quantity in advance to issue the registration. When the market price reaches the set price, the merchant can scramble for the registration.</span></p>\r\n<p class=\"ordinary-output target-output clearfix\"><span class=\"\">2. If you modify the selected payment method after publishing the entrusted registration form, the current payment method of the entrusted registration form will also be modified.</span></p>\r\n<p class=\"ordinary-output target-output clearfix\"><span class=\"\">3. Due to the mechanism of order grabbing by merchants, orders judged by merchants as having potential risks will not be closed.</span></p>\r\n<p class=\"ordinary-output target-output clearfix\"><span class=\"\">4. At present, OTC Commission registration only supports sale.</span></p>\r\n</div>', NULL);
INSERT INTO `article_translations` VALUES (384, 130, 'en', 'Announcement on online Kai / usdt leverage trading pairs', '<p>Dear Bekonex users<br /><br />Bekonex leverage trading area is now online Kai / usdt trading pair, which supports 4 times leverage and Kai currency trading, with 24-hour interest of 0.1% for buying (long) and 0.2% for selling (short).<br /><br />Previously, Bekonex currency trading area has launched Kai / usdt and Kai / eth trading pairs. Welcome to the trading experience.<br /><br />[risk tips]<br /><br />Digital asset is a kind of high-risk investment. Investors should be cautious and pay attention to the investment risk. Bekonex shall not be liable for guarantee or compensation for the project or investment.<br /><br />Trading digital assets, Bekonex!</p>', NULL);
INSERT INTO `article_translations` VALUES (385, 129, 'en', 'Announcement on the 12th contract trading day \"King promotion competition\"', '<p>Dear Bekonex users<br /><br />Bekonex has successively optimized eosusdt, ltcusdt, bchusdt and bsvusdt perpetual contract trading pairs. After optimization, trading depth, opening spread and matching efficiency have been greatly improved. In order to encourage users to trade experience, this \"King promotion competition\" is launched. The activity is divided into two rounds of promotion competition and the strongest King competition. The total prize pool is 8000mx, 2000usdt, etc.</p>', NULL);
INSERT INTO `article_translations` VALUES (386, 128, 'en', 'Announcement on award issuance of \"triple gifts for contract newcomers\"', '<p>Dear Hokiecoin users<br /><br />The activity of \"triple gift for new contract\" of Hokiecoin has been completed successfully. The triple gift package of MX air casting, surrounding gifts and resurrection card can be obtained when the recharge transaction meets the corresponding requirements.<br /><br />[reward collection]<br /><br />1. Reward collection process: add customer service wechat - provide Hokiecoin email to customer service - confirm award status - perform KYC verification - wait for award release.<br /><br />2. Because of the large number of users involved in the activities, the information about the award-winning of users is not publicized one by one. The award can only be obtained by adding wechat from the staff. If no contact has been made by 24:00 on August 8, the award will be deemed to be automatically abandoned.<br /><br />3. The event reward will be issued uniformly within 10 days after the end of the activity. Please check the air drop reward in the [charge record - other record].<br /><br />4. The physical reward is issued for a long time due to logistics reasons. Please wait patiently.<br /><br />5. Some users failed to receive rewards because of the transfer time and recharge amount, which did not meet the requirements of the activity.</p>', NULL);
INSERT INTO `article_translations` VALUES (387, 127, 'en', 'Announcement of new band3l, band3s, rlc3l and rlc3s in leveraged ETF', '<div class=\"output-bd\" dir=\"ltr\" style=\"padding-bottom: 38px;\">\r\n<p class=\"ordinary-output target-output clearfix\">Dear Bekonex users</p>\r\n<p class=\"ordinary-output target-output clearfix\">In order to meet the transaction needs of the majority of users, Bekonex will add new target band3l, band3s, rlc3l and rlc3s at 17:00 (UTC + 8).<span class=\"\"> The details are as follows:</span></p>\r\n<p class=\"ordinary-output target-output clearfix\"><span class=\"\">Band3l -- band is three times long and band3s-band is three times short. The daily management fee (per time) is 0.2%.</span></p>\r\n<p class=\"ordinary-output target-output clearfix\"><span class=\"\">Rlc3l -- RLC triple long, rlc3s-rlc triple short, daily management fee (per time) is 0.2%.</span></p>\r\n<p class=\"ordinary-output target-output clearfix\"><span class=\"\">Welcome to the user trading experience.</span></p>\r\n</div>', NULL);
INSERT INTO `article_translations` VALUES (388, 126, 'en', 'Announcement on opening the rights and interests of institutional account', '<p>Dear Hokiecoin users<br /><br />In order to better serve the majority of institutional users, Hokiecoin now provides one-stop professional services for institutional users, as follows:<br /><br />1. Institutional users can enjoy exclusive access to the fund to ensure the safety, compliance and efficiency of the fund;<br /><br />2. Enjoy the privilege fee discount;<br /><br />3. The exclusive channel and amount of green coin withdrawal were increased;<br /><br />4. Blue V privilege identification of institutional users;<br /><br />5. One to one customer service exclusive to the organization;<br /><br />6. Hokiecoin Research Institute Industry Report;<br /><br />7. Enjoy Hokiecoin offline activities, invite privileges and customize private meetings first.<br /><br />Institutional users who meet certain conditions also have the opportunity to enjoy other exclusive benefits provided by Hokiecoin.<br /><br />Trading digital assets, Hokiecoin!</p>', NULL);
INSERT INTO `article_translations` VALUES (389, 125, 'en', 'Announcement on online LBA leverage Trading', '<p>Dear Bekonex users<br /><br />Bekonex leverage trading area will launch LBA / usdt trading pairs at 16:30 (UTC + 8), support triple leverage, and support LBA currency trading. The 24-hour interest of buying (long) is 0.1%, and that of selling (short) is 0.15%. Users are welcome to experience.<br /><br />[risk tips]<br /><br />Digital asset is a kind of high-risk investment. Investors should be cautious and pay attention to the investment risk. Bekonex shall not be liable for guarantee or compensation for the project or investment.<br /><br />Trading digital assets,Bekonex</p>', NULL);
INSERT INTO `article_translations` VALUES (390, 124, 'en', 'Announcement on opening 2Key, Bart, BOT, buidl, DFS, gen, NMR, tau, trade, XRT recharge online activities', '<p>Dear Bekonex users<br /><br />Recommended by community users, in order to facilitate more community members to trade and support projects, Hokiecoin is launching a new special online activity of recharge voting. The projects involved in this period\'s recharge are: 2Key (2Key), bartertrade (Bart), bounce (BOT), dfohub (buidl), defis network (DFS), daostack (Gen), numerai (NMR), lamden (tau), unitrade (trade) and robonomics token (XRT).<br /><br />Activity rules:<br /><br />During the assessment period, users recharge 2Key, Bart, BOT, buidl, DFS, gen, NMR, tau, trade and XRT in any assessment currency to MXC Matcha, and Bekonex will launch the project as soon as possible after completing the technical docking.<br /><br />During the assessment period, if the project meets the requirements of recharge number, it will be online and open the transaction at the first time.</p>', NULL);
INSERT INTO `article_translations` VALUES (391, 123, 'en', 'Announcement on the market value trading function of some leverage transactions on the online web', '<p>Dear Bekonex users<br /><br />In order to better enhance the user\'s trading experience, Hokiecoin has launched the market trading function of some leveraged trading pairs on the web. Details are as follows:<br /><br />1. Leverage trading pairs supporting market trading function: BTC / usdt, ETH / usdt, EOS / usdt, BCH / usdt, LTC / usdt, ont / usdt, TRX / usdt, XRP / usdt, BSV / usdt, etc / usdt, dog / usdt, ADA / usdt, Dash / usdt, Neo / usdt, qtum / usdt, vet / usdt, XLM / usdt, XZC / usdt, BTM / usdt, xtz / usdt, Zec / usdt, ZIL / usdt, ELF / usdt.<br /><br />2. When users click \"market price Commission\" in the leverage trading area on the web, they will buy or sell at the best market price.<br /><br />3. Market price entrustment means that the user can buy or sell immediately at the best price in the current market to achieve the purpose of fast transaction. It should be noted that if the total market price of a single transaction is too large, there will be cancellation of the uncompleted part. At the same time, the market price Commission will scan the orders in the market regardless of the cost. You need to bear certain risks. Please place the order carefully and pay attention to the risks.<br /><br />Welcome to the user transaction experience,Bekonex will continue to strive to provide you with better products and services.</p>', NULL);
INSERT INTO `article_translations` VALUES (392, 122, 'en', 'Notice on timing of dot splitting', '<p>Dear Bekonex users<br /><br />The denomination split of Polkadot (DOT) will take place at block number 1248328 (earliest estimated time: 00:40, August 22, 2020 (UTC + 8)), and the dot split schedule of Bekonex is as follows:<br /><br />1. At 21:00, August 21, 2020 (UTC + 8), the mapping, recharge and withdrawal functions of dot will be suspended.<br /><br />2. At 21:30, August 21, 2020 (UTC + 8), the dot currency transaction will be suspended. For users who have registered in dot / usdt and dot / BTC currency transaction, please cancel the order in time. If not, the system will automatically cancel the order for you and return the relevant assets to your currency account.<br /><br />3. At 21:30 on August 21, 2020 (UTC + 8), Boca ecological portfolio trading will be suspended. Users who have positions should close their positions in time. If they open their positions, they will lose the dot component of Boca ecological portfolio.<br /><br />4. When the split is executed (the earliest expected time: 00:40, August 22, 2020 (UTC + 8)), the dot3l and dot3s leveraged ETF transactions will be suspended. For users who have registered, please cancel the order in time. If not, the system will automatically cancel the order for you and return the relevant assets to your currency account.<br /><br />5. When the block height is 1248328 (the earliest expected time is 00:40 (UTC + 8) on August 22, 2020), Bekonex will automatically split the 1:100 denomination of dot token based on the progress of dot smart contract upgrade. After the split, the holding capacity of all users becomes 100 times of the original holding capacity, and the price after split is about 1 / 100 of the price before split, but it will not affect the total value of users\' dot positions.<br /><br />6. The recovery time of ETF, currency trading, index trading, mapping, currency charging and withdrawal business will be announced separately. Please understand the inconvenience caused to you during the suspension period!<br /><br />Other notes:<br /><br />1. During the suspension of trading, due to the inability to obtain the dot real-time price through the market side, the dot valuation may be inaccurate, and your actual assets will not be affected. Dot transaction will be displayed normally after recovery, please wait patiently.<br /><br />2. The specific split time may be adjusted synchronously according to the release time of Polkadot project. If the specific time of transaction, recharge and cash withdrawal function is adjusted, it will be notified in the form of announcement at the first time. Please understand the inconvenience.</p>', NULL);
INSERT INTO `article_translations` VALUES (393, 121, 'en', 'Announcement on resumption of linkusdt perpetual contract transaction', '<div class=\"output-bd\" dir=\"ltr\" style=\"padding-bottom: 39px;\">\r\n<p class=\"ordinary-output target-output clearfix\">Dear Bekonex users</p>\r\n<p class=\"ordinary-output target-output clearfix\"><span class=\"\">Bekonex linkusdt perpetual contract maintenance has been completed and will be back online at 8:00 (UTC + 8). The specific parameters are as follows:</span></p>\r\n<p class=\"ordinary-output target-output clearfix\"><span class=\"\">mceclip0.png</span></p>\r\n</div>', NULL);
INSERT INTO `article_translations` VALUES (394, 120, 'en', 'Announcement on the resumption of spa recharge and online leverage Trading', '<p>Dear Bekonex users<br /><br />Bekonexhas recovered spa recharge. The leverage trading area will be online spa/usdt trading pair at 14:00 (utc+8), supporting 4 times leverage, and Spa currency trading. The 24-hour interest rate of buying (making a long) is 0.1%, and the 24-hour interest for selling (short) is 0.15%.<br /><br />Previously, Bekonex currency trading area has launched spa / usdt trading pairs. Welcome to the trading experience.</p>', NULL);
INSERT INTO `article_translations` VALUES (395, 119, 'en', 'Announcement on price weight adjustment of perpetual contract index', '<p>Dear Bekonex users<br /><br />Hello!<br /><br />In response to the demands of users, the platform has adjusted the index price weight of perpetual contracts (digital contract and usdt contract), changing the original \"coin 50% and fire coin 50%\" to \"coin 70% and fire coin 30%\". The adjustment has no impact on the user position.<br /><br />Bekonex&nbsp; platform will continue to adhere to the operation philosophy of user first, security, strength and trust to create a safe, transparent and reliable digital asset service environment for investors.</p>', NULL);
INSERT INTO `article_translations` VALUES (396, 118, 'en', '520 activity | special service charge for opening contract trading area', '<div class=\"output-bd\" dir=\"ltr\" style=\"padding-bottom: 104px;\">\r\n<p class=\"ordinary-output target-output clearfix\">Dear Bekonex users</p>\r\n<p class=\"ordinary-output target-output clearfix\">Hello!</p>\r\n<p class=\"ordinary-output target-output clearfix\"><span class=\"\">Following the one week contract maker fee free campaign and the 520 advertising season, we would like to express our sincere thanks to our friends who have been supporting, trusting and encouraging PCICOIN. To show our heart, we will launch the second wave of fee free campaign this month, opening a 12 day special rate of 10000 yuan. The details are as follows:</span></p>\r\n<p class=\"ordinary-output target-output clearfix\"><span class=\"\">Time: 18:00, May 20 to 18:00, June 1, Hong Kong time</span></p>\r\n<p class=\"ordinary-output target-output clearfix\"><span class=\"\">Scope of activities: usdt contract, digital contract, delivery contract</span></p>\r\n<p class=\"ordinary-output target-output clearfix\"><span class=\"\">Currency involved: all contract currencies (BTC, EOS, ETH, BCH, LTC, XRP, etc, dash, BSV, TRX, BNB, HT)</span></p>\r\n<p class=\"ordinary-output target-output clearfix\"><span class=\"\">Activity rules: during the activity period, the service rates of maker and taker in the three major contract transactions were reduced from the original 0.015% to 0.01%.</span></p>\r\n<p class=\"ordinary-output target-output clearfix\">Invite you to experience!<span class=\"\"> Good investment!</span></p>\r\n</div>', NULL);
INSERT INTO `article_translations` VALUES (397, 117, 'en', 'Announcement on the implementation of 0.02% (10000 2) net wide minimum handling rate in contract trading area', '<p>Dear Bekonex users<br /><br />Hello!<br /><br />The contract trading area (digital contract, usdt contract and delivery contract) will implement the new service rate at 18:00 Hong Kong time on June 17, which will be adjusted from 0.015% (10000 1.5%) for both takers and makers to 0.02% (10000 2%) for both takers and makers. This fine-tuning will not affect other services in the contract trading area, and will not charge any other fees such as position fees, interest and so on.<br /><br />Supplementary note: from immediately to 18:00 on June 17, the contract transaction is still in the preferential period, with 0.01% of takers and makers.<br /><br />Bekonex&nbsp; platform will continue to uphold the operation philosophy of user first, security, strength and trust to create a safe, transparent and reliable digital asset service environment for global investors.</p>', NULL);
INSERT INTO `article_translations` VALUES (398, 116, 'en', 'Usdt contract | announcement on the completion of btcusdt and xrpusdt upgrade', '<p>Dear Bekonex users<br /><br />Hello!<br /><br />The BTC and XRP products (btcusdt and xrpusdt) in usdt contract trading area have been upgraded and restored to service. You can open and close positions, entrust, stop profits and stop losses. During the period of suspension, we are sorry for the inconvenience!<br /><br />Bekonex exchange will continue to adhere to the operation philosophy of user first, security, strength and trust to create a safe, transparent and reliable digital asset service environment for global investors.</p>', NULL);
INSERT INTO `article_translations` VALUES (399, 115, 'en', 'Lead for four years and continue to be strong', '<p>Dear users of Bekonex exchange:<br /><br />Hello!<br /><br />Today, it is the fourth anniversary of Bekonex. In 1460 days of smooth operation, the platform foundation has been tamped, its strength has been improved and the international benefits have gradually become prominent. Four years later, the total transaction volume of Hokiecoin\'s total business has exceeded US $600billion, registered users have exceeded 3 million, and monthly profit has exceeded 100million. Thank you for your trust and support all the way. At this time, we invite you to witness the fruitful achievements of the fourth anniversary of Bekonex&nbsp;</p>', NULL);
INSERT INTO `article_translations` VALUES (400, 114, 'en', 'Announcement on the suspension, expansion and upgrade of usdt contract', '<p>Dear Bekonexusers<br /><br />Hello!<br /><br />I\'m very sorry. Due to the unpredictable problems encountered during the upgrade, it is estimated that we still need 1-2 hours to process the capacity expansion and upgrade of usdt contract. Sorry for the inconvenience. Please be patient. For the account of burst during the upgrade period, statistical compensation will be made after the upgrade. Please do not worry too much and apologize again. Currency based contracts, mixed contracts and quarterly contracts will not be affected.</p>', NULL);
INSERT INTO `article_translations` VALUES (401, 113, 'en', 'Announcement on the completion of compensation work during the expansion period of usdt contract', '<p>Dear Bekonex users<br /><br />Hello!<br /><br />During the expansion period of usdt contract, the compensation work has been completed. During the abnormal period (15:00-21:05, January 3, Hong Kong time), all users who have burst positions and those who have lost money during the period have made compensation according to the corresponding rules. All the above claims have been fully paid. If you have any questions, please consult the online customer service.<br /><br />So we apologize for the inconvenience!</p>', NULL);
INSERT INTO `article_translations` VALUES (409, 112, 'en', 'Announcement on normal operation of 2020 Spring Festival holiday', '<p>Dear Bekonex users<br /><br />Happy New Year!<br /><br />We would like to remind you that the platform will continue to operate normally during the Spring Festival holidays in 2020<br /><br />1) Usdt contracts, mixed contracts, currency based contracts, quarterly contracts, mortgage loans, legal currency OTC, currency trading and other major business lines maintain normal services.<br /><br />2) Online customer service of the official website will still provide you with 24h special line service, and support Chinese, English, Japanese, Korean and Russian languages.<br /><br />3) In view of the slow cash withdrawal audit in the evening or individual time, you can contact the online customer service of the official website in time to understand the situation.<br /><br />4) The community will continue to provide you with dynamic reminders, business consulting and other services.<br /><br />If any abnormality is found, please contact the online customer service of the official website in time. We will make every effort to ensure that you continue to have a safe, transparent and first-class trading experience during the Spring Festival holiday.<br /><br />Bekonex exchange will continue to adhere to the operation philosophy of user first, security, strength and trust to create a safe, transparent and reliable digital asset service environment for global investors.</p>', NULL);
INSERT INTO `article_translations` VALUES (412, 111, 'en', 'Announcement on the completion of quarterly contract and usdt contract upgrade ahead of schedule', '<p>Dear Bekonex users<br /><br />Hello!<br /><br />The upgrade of quarterly contract and usdt contract has been completed ahead of time, and the service has been resumed. You can normally open and close positions, plan entrustment, transfer, stop profit and stop loss and other operations. So far, the service suspension and upgrading of the four major contracts have been fully completed. Please understand the inconvenience caused to you during the suspension period!<br /><br />Hokiecoin exchange will continue to adhere to the operation philosophy of user first, security, strength and trust to create a safe, transparent and reliable digital asset service environment for global investors.</p>', NULL);
INSERT INTO `article_translations` VALUES (413, 110, 'en', 'Another explanation of extreme market and index mechanism', '<p>Dear Bekonex users<br /><br />Today morning, users received feedback that the market of the permanent contract market appeared up and down, which means extreme market, and expressed concern about their position safety. In this regard, we hope you don\'t have to worry that the index mechanism we have pushed in Asia will avoid your position being affected by extreme market conditions in the market. On the market extreme market and index mechanism, we will make the following explanation again:<br /><br />1. On the extreme market in the market<br /><br />Extreme market occurs in the whole digital asset market, which is the reflection of market investment. There are countless markets that are divided by regions and platforms. The extreme market reflected by early users is actually in the 7 platform on-site trading and investment. The Hokiecoin in-site transaction adopts matching mechanism. Whether the market price or the price limit is traded at the best price in the market at that time, the extreme market is often closely related to the pricing of both parties on the market and the activity of on-site trading and investment.<br /><br />2. On the index mechanism<br /><br />After the extreme market in the market, some users are worried about their positions at the first time. However, it is unnecessary for Hokiecoin to directly relate to your position risk under the effect of index mechanism, not the change of the on-site price, but the index price of the global spot market is anchored, even if there is extreme market in the market, that is, the latest transaction price deviates greatly, It will not pose a risk to the position held. This is the core difference from traditional competitive contracts.<br /><br />The index mechanism is the first in Asia by Hokiecoin, and the key index is index price. Index price is used to represent the reasonable price of BTC and eth in the global spot market, which has certain guiding significance. It is also used as the basis for calculating floating profit and loss of the perpetual contract while judging the position risk. The index price of current Hokiecoin perpetual contract (usdt contract, currency standard contract and mixed contract) is weighted average of spot price in currency an and Huo currency.<br /><br />3. Adjust K-line<br /><br />Some users feedback that the K-line is inconvenient. Based on the fact that the K-line is caused by the user\'s explosion, and Hokiecoin adopts the index mechanism to determine the strong level, and no user has burst the warehouse. Based on the above points, we will adopt the user\'s suggestion to adjust the K-line to facilitate the customer\'s look-up.<br /><br />Above, I hope that some users\' doubts can be eliminated and your understanding of the Hokiecoin contract will be deepened. Sustainable contract is the foundation of the platform. Since the launch, it is to provide investors with more scientific, transparent and advanced digital asset playing methods. We will continue to adhere to the operation concept of user first, security, strength and trust, and provide you with better contract services.</p>', NULL);
INSERT INTO `article_translations` VALUES (414, 109, 'en', 'Announcement on the adjustment of price components of BSV contract index on May 8', '<p>Dear Bekonex users<br /><br />Hello!<br /><br />In view of the fact that okex will upgrade the spot system at 16:30 (HKT) on May 8, 2020, the price of BSV perpetual contracts (bsvusdt, bsvmix) will be temporarily adjusted from \"hot currency 50%, okex 50%\" to \"hot currency 100%\" before 16:30 Hong Kong time on May 8, 2020. After the upgrade of okex system, the original components will be restored as soon as possible.<br /><br />Bekonex platform will continue to uphold the operation philosophy of user first, security, strength and trust to create a safe, transparent and reliable digital asset service environment for global investors.</p>', NULL);
INSERT INTO `article_translations` VALUES (415, 108, 'en', 'Announcement on the service suspension and upgrade of usdt contract at 14:30 on July 14', '<p>Dear Bekonex users<br /><br />Hello!<br /><br />The platform will stop service upgrade for USDT contract at 14:30 on July 14th Hongkong time. It is expected to stop for 2 hours. During the period, you will not be able to open the warehouse, commission, stop profit and stop operation. Please adjust the investment strategy ahead of time. Other business lines such as mixed contracts, currency based contracts, quarterly contracts and currency trading will not be affected. We will inform you as soon as the upgrade is completed.<br /><br />Bekonex&nbsp; exchange will continue to adhere to the operation philosophy of user first, security, strength and trust to create a safe, transparent and reliable digital asset service environment for global investors.</p>', NULL);
INSERT INTO `article_translations` VALUES (416, 107, 'en', 'Announcement on the completion of upgrade of usdt contract and resumption of service', '<p>Dear Bekonex users<br /><br />Hello!<br /><br />The usdt contract trading area has been upgraded and resumed service. You can normally open and close positions, plan entrustment, stop profit and stop loss, transfer funds and other operations. Please forgive me for the inconvenience.<br /><br />Bekonex exchange will continue to adhere to the operation philosophy of user first, security, strength and trust to create a safe, transparent and reliable digital asset service environment for global investors.</p>', NULL);
INSERT INTO `article_translations` VALUES (417, 106, 'en', 'New announcement about usdt contract online', '<p>Dear Bekonex users<br /><br />Hello!<br /><br />The usdt contract trading area will be served continuously at 17:00 Hong Kong time on August 14. It is expected that the service will last for one hour. Network jitter may occur during the period, but it will not affect the security of your assets. Currency based contracts, quarterly contracts and mixed contracts will not be affected. After the completion of the new listing, xtz, comp and band will be added to the usdt contract category, and the trading category will be expanded to 18. Coming soon!<br /><br />Bekonex platform will continue to uphold the operation philosophy of user first, security, strength and trust to create a safe, transparent and reliable digital asset service environment for global investors.</p>', NULL);
INSERT INTO `article_translations` VALUES (418, 105, 'en', 'New announcement on the suspension of usdt contract at 15:00 on August 19', '<div class=\"output-bd\" dir=\"ltr\" style=\"padding-bottom: 0px;\">\r\n<p class=\"ordinary-output target-output clearfix\"><span class=\"\" style=\"color: #9fa6b5;\">Dear Bekonex users</span></p>\r\n<p class=\"ordinary-output target-output clearfix\"><span class=\"\" style=\"color: #9fa6b5;\">Hello!</span></p>\r\n<p class=\"ordinary-output target-output clearfix\"><span style=\"color: #9fa6b5;\"><span class=\"\">The platform will be suspended at USDT on August 19th at 15:00 Hongkong time. It is estimated that 1 hours, you will not be able to open the position, commission, stop loss and other operations during the new period. Please adjust the investment strategy ahead of schedule.</span><span class=\"\"> Mixed contracts, currency based contracts, quarterly contracts, currency trading and other business lines will not be affected.</span><span class=\"\"> After the completion of the new, usdt contract will add TRX, lead, waves, KNC, ont five new products, and expand the trading target to 23.</span> Coming soon!</span></p>\r\n<p class=\"ordinary-output target-output clearfix\"><span class=\"\" style=\"color: #9fa6b5;\">Bekonex exchange will continue to adhere to the operation philosophy of user first, security, strength and trust to create a safe, transparent and reliable digital asset service environment for global investors.</span></p>\r\n</div>', NULL);
INSERT INTO `article_translations` VALUES (419, 104, 'en', 'Announcement on restoration of service and start of claim settlement of usdt contract', '<p><span style=\"color: #9fa6b5;\">Hello!</span><br /><br /><span style=\"color: #9fa6b5;\">The usdt contract has now resumed service. We apologize for the inconvenience caused by this upgrade!</span><br /><br /><span style=\"color: #9fa6b5;\">During the upgrade period, if you are affected by this, please don\'t panic. The platform will arrange the claim team to deal with the compensation matters. Please keep the phone unblocked. Sorry again! We will learn from it to avoid it happening again.</span></p>', NULL);
INSERT INTO `article_translations` VALUES (420, 71, 'en', 'Here is the latest news headline', '<p>content</p>', NULL);
INSERT INTO `article_translations` VALUES (421, 70, 'en', 'Risk hedging of bitcoin portfolio', '<p>The dominant cryptocurrency has been on a downward path since it reached its annual high of $13900 at the end of June, and the bitcoin bulls have been in a difficult position. As price adjustments continue, traders have been looking for ways to hedge their long BTC positions. With the booming crypto derivatives market, participants can now better control their exposure with increasingly popular swap and futures contract products.<br /><br />BTC short term bearish<br /><br />Although the long-term bullish situation is still strong, a sustained short-term bearish sentiment can be seen in the K-line chart of the daily btc/usdt trading pair. In late June, btc/usdt trade pair broke through the price level of USD 13900 for the first time in more than a year. However, the trade pair failed to continue to break through the price level in mid July, thus forming resistance level, which is that the double top mode will be a downward trend. Recently, btc/usdt failed to stay above the double top neckline, which is about $10400, and more importantly, the RSI index of the daily chart is still below 50 and the MACD is still in a bearish range.<br /><br />Derivatives and Risk Management<br /><br />Given the recent price adjustment of BTC, the use of bitcoin derivatives to manage risk is now a topic everyone wants to revisit. If it is an investor in traditional financial markets, it should not be unfamiliar with derivatives trading.<br /><br />In textbooks, derivative is a kind of financial securities whose value is determined by its related assets. This is a contract involving two or more parties, and the related assets can be stocks, bonds, commodities, currencies, interest rates or market indices.<br /><br />Why are derivatives so popular? Because it can be used to hedge positions, speculate about directional changes in related assets, or leverage holdings. In terms of risk management, it is also a multi-functional tool. As part of the risk dispersion strategy, many financial institutions keep trading derivatives such as swaps and forward.<br /><br />Derivatives in the field of digital currency<br /><br />Compared with traditional derivatives market, the contract market of digital currency is relatively new and smaller, but this does not mean that the digital currency market is not unprofitable. Similar to stock futures or interest rate swaps, BTC derivatives can avoid fluctuations in the digital currency market and price changes, and can be used as hedging instruments to offset potential losses.<br /><br />Most importantly, traders can use contracts to speculate on the price of leveraged digital currencies, thereby maximizing potential profits. There are three main contract products in the digital currency world: 1) perpetual contract（ 2) Futures contracts（ 3) Option contracts.<br /><br />Hedging<br /><br />Although BTC\'s downside risk is increasing and may eventually create buying opportunities for BTC bulls, BTC\'s negative mood has increased, and for risk management, investors are advised to review their hedging and arbitrage strategies. Hedging involves the use of multiple concurrent bets in the opposite direction in order to limit the risk of serious investment losses. First, let\'s look back at the differences between hedging strategies.<br /><br />Let\'s take delivery contracts as an example of hedging.<br /><br />There are other factors that affect overall hedging strategies, such as the closing date, the decision to make a long or short run, and the number of contracts.<br /><br />Protect multiple positions<br /><br />Sustainability is another structural tool that investors can use. We assume that the spot market price is $9500, while the transaction price of BTC is $9600. Investors can open short positions of the same value ($9500) in the spot market at $9500 and at the same time in the sustainability contract market.<br /><br />1. when the price of BTC increases, investors can profit from the spot market.<br /><br />2. when the price of BTC falls, investors can close short positions of the perpetual contract and profit from them to make up for the losses in the spot market.<br /><br />However, if long-term holding contracts are part of their strategy, traders should also consider financing and settlement factors.<br /><br />arbitrage opportunity<br /><br />Arbitrage is to profit from unbalanced markets, trading the same commodity spread between multiple markets, which involves the purchase and sale of goods in a short period of time. We assume that bitcoin trading price in spot market is $9500, while BTC\'s perpetual contract price is $9600. Investors buy bitcoin in the spot market for $9500 and open short positions of the same value ($9600) in the sustainability contract at the same time.<br /><br />1. if the interest margin between the two is reduced, investors can make profits.<br /><br />2. if the difference increases, the unrealized profit and loss of the transaction will become negative. In this case, investors can wait for the settlement to expire. The marked price of a contract is usually calculated based on spot price, so the tag price is very close to the spot price, and the profit is about 9600-9500 USD = 100 USD<br /><br />3. when the spot price is higher than the contract price, the total profit is more than 100 USD.<br /><br />conclusion<br /><br />Hedging is not the pursuit of risk-free transactions. Instead, it is an attempt to reduce known risks when trading. This is an important strategy in traditional financial market and business management. Digital currency traders can adopt the method widely used in stock, foreign exchange and commodity trading. Much like any other risk / return transaction, hedging can lead to a reduction in the return of the parties concerned, but it can provide important downside risk protection.</p>', NULL);
INSERT INTO `article_translations` VALUES (422, 69, 'en', 'Bitcoin Arbitrage Strategy Report', '<p>We previously published a report on the relationship between spot leverage rates and perpetual contract capital rates to find arbitrage opportunities, which showed a return on investment of 1.66 per cent in seven days. However, this is best done on a one-stop service exchange such as okex, which provides both delivery / Sustainability contracts and spot trading, which will exempt the money miner fee and the time of the chain transfer.<br /><br />In this article, we will introduce a more traditional, cash arbitrage that can also be used on okex.<br /><br />What is the cash arbitrage strategy<br /><br />The price of goods reflects the confidence of investors in the market in particular targets. Whenever the market fluctuates, spot price and futures price will be very different (base difference), the more obvious the price difference is, the more favorable arbitrage.<br /><br />Under normal circumstances, quarterly contracts have a larger base difference than that of weekly contracts and two week contracts. Because the longer the contract expires, the more uncertain factors are, we will take quarterly contracts as an example in this article.<br /><br />If we look at the graph, we can see that the highest base difference is 581.7 on July 10, then dropped to -121.64 on July 17 and bounced back to the 100-200 range.<br /><br />By drawing the base spread over time (per hour), we can know that the base difference of this contract fluctuates between 100-200 for most of July.<br /><br />Practice<br /><br />Buy BTC of 1000usdt in spot market, transfer it to delivery contract account and open ten quarterly contracts, with value equal to 1000 USD, and all positions remain delta neutral (delta value of held position portfolio is 0, that is, price change of BTC will not affect final income).<br /><br />If you only have BTC in your account, you can leverage usdt and repeat the above process. However, because of the need to take leverage interest, your income will be lower in the end.<br /><br />Case 1:<br /><br />Taking 1000 usdt as the starting capital, the current arbitrage strategy was adopted at 11:00 a.m. on July 10. The position was closed and the income was calculated when the 0:00 basis difference on July 17 was negative<br /><br />Case 2:<br /><br />Taking 0.1btc as the initial capital, the company borrowed 1000usdt with leverage and adopted the current arbitrage strategy. It opened at 11:00 a.m. on July 10, and closed the position at 0:00 on July 17 when the base difference was negative and calculated the income:<br /><br />Basis<br /><br />If the base spread keeps rising and does not decline, the portfolio may have temporary losses, but the closer the maturity of the contract, the base difference will gradually close to 0.<br /><br />wave<br /><br />If your position is heavy, it will take a certain time to be digested by the market when closing positions, and your cost will be affected by the change of base difference during closing.<br /><br />Usdt price<br /><br />The dollar price of usdt is too hard to mention, and the opening of spot market is equivalent to selling usdt for us dollars.<br /><br />Strong risk<br /><br />If usdt is used as the starting capital, there is no strong risk of leveling, but traders using leveraged borrowing currency may increase margin once and again due to market fluctuation to avoid the opening of positions.<br /><br />optimization<br /><br />The base differences should be analyzed more finely, and the granularity of the sampling interval can be refined to the minute level rather than the hour level.<br /><br />The market is analyzed by using the transaction big data on okex to better find the operating points of opening and closing positions and thus make profits. For example, the negative basis difference happened twice in July. We can consider opening at the negative basis difference and closing when the base difference is positive.<br /><br />Before the delivery, the return of BTC cannot be transferred to the spot account. In order to avoid the risk of fluctuation of BTC price, we can hold contract position or leverage position to offset the risk.</p>', NULL);
INSERT INTO `article_translations` VALUES (423, 68, 'en', 'Technical indicators of bitcoin digital assets', '<p>Whether stock investors or investors, technical analysis is a very important part in trading. The study of historical price trends and other trading related data can help us find trading opportunities and predict the direction of price changes. Technical analysis is widely used in stock, futures, commodity trading, foreign exchange and other asset classes. In the era of digital currency, traders are trying to develop some analysis tools that are more in line with the rapid growth of assets. At the same time, they bring the traditional financial way of technical analysis to the field of digital assets.<br /><br />Bollinger Bands<br /><br />Brin belt is the most widely used indicator in trading, named after John Bollinger, an American asset management manager and technical analyst. The range of the brin belt is represented by a set of positive and negative lines describing the standard deviation based on the price moving average (usually 20-sma). Because the standard deviation is the observation index of volatility, when the market price fluctuates violently, the Bollinger belt is relatively wider, which is usually considered as the signal of exit. When the volatility is small, the Bollinger belt shrinks, which may be the potential signal of intensified volatility, which is generally regarded as the signal of entrance. There are also many traders who think that when the price approaches the upper line of the brin belt, it means that the market is overbought. On the contrary, when the price approaches the lower line of the brin belt, it means that the market is overbought.</p>', NULL);
