INSERT INTO `article_translations` VALUES (503, 176, 'en', 'U.S. SEC Opens Public Comment Period on Canary’s Staked INJ ETF', '<p>The U.S. Securities and Exchange Commission (SEC) is seeking public comment on whether to approve Canary&rsquo;s proposed Staked Injective (INJ) Exchange-Traded Fund (ETF). The SEC has set a 21-day deadline for submitting comments and will decide on the next steps within 90 days.</p>', NULL);
