INSERT INTO `coins` VALUES (1, 'USDT', 'USDT', 2, 4, 'Tether', '1', '100', '1000000', '.请仔细检查并输入正确的钱包地址。 .发送不对应的加密货币到钱包地址会造成永久损失。 .提币手续费将从提币数量中扣除', '.此地址是您最新的充值地址，当系统收到充值时，将进行自动入账。转账需要由整个区块链网络进行确认，达到10个网络确认时，您的USDT将被自动存入到账户中 .请只发送USDT到此地址 发送其他其他加密数字货币到此地址会造成永久性的损失.', '请您详细确认划转账户CoinALL支持多账户划转，合约=币币 ，币币=合约，币币=期权，合约=期权', 'USDT是Tether公司推出的基于稳定价值货币美元（USD）的代币Tether USD（下称USDT），1USDT=1美元，用户可以随时使用USDT与USD进行1:1兑换。Tether公司严格遵守1:1准备金保证，即每发行1个 USDT代币，其银行账户都会有1美元的资金保障。用户可以在Tether平台进行资金查询，以保障透明度。用户可以通过SWIFT电汇美元至Tether公司提供的银行帐户，或通过交易所换取USDT；赎回美元时，反向操作即可。用户也可在交易平台用比特币换取USDT。', 'coin_icon/USDT.png', 1, 'cecf9783qweq1', 'a33d0c05b7d811ff6e3reg4ghy9ed9', 'https://tether.to/', 'https://tether.to/wp-content/uploads/2016/06/TetherWhitePaper.pdf', 'https://www.omniexplorer.info/', '2023-04-05 23:00:00', 10281372504, 10281372504, '$1', 1, 1, 1, 1, '2020-08-12 13:15:35', '2024-02-20 16:16:51', NULL, 'TSs7PW7U2jANH3eNvJTvAhXMbQtjqpNaoY', 1);
INSERT INTO `coins` VALUES (2, 'BTC', 'BTC', 6, 2, 'Bitcoin', '0.0005', '0.0001', '100', NULL, NULL, NULL, '比特币（Bitcoin，简称BTC）是目前使用最为广泛的一种数字货币，它诞生于2009年1月3日，是一种点对点（P2P）传输的数字加密货币，总量2100万枚。比特币网络每10分钟释放出一定数量币，预计在2140年达到极限。比特币被投资者称为“数字黄金”。比特币依据特定算法，通过大量的计算产生，不依靠特定货币机构发行，其使用整个P2P网络中众多节点构成的分布式数据库来确认并记录所有的交易行为，并使用密码学设计确保货币流通各个环节安全性，可确保无法通过大量制造比特币来人为操控币值。基于密码学的设计可以使比特币只能被真实拥有者转移、支付及兑现。同样确保了货币所有权与流通交易的匿名性。', 'coin_icon/BTC.png', 1, '2c64010c11713ea', '7ead483a9f61c2d5fa3662c7c50776', 'https://bitcoin.org/en/', 'https://bitcoin.org/bitcoin.pdf', 'https://www.blockchain.com/explorer', '2024-03-05 00:00:00', 21000000, 18374575, '--', 1, 1, 1, 1, '2020-08-12 13:15:38', '2024-06-04 23:13:54', NULL, '35sZSWu4yDxvuC3XuU7wfY2DTSYbdYm5mA', 1);
INSERT INTO `coins` VALUES (3, 'ETH', 'ETH', 5, 2, 'Ethereum', '0.01', '0.1', '1000', NULL, NULL, NULL, '以太坊（Ethereum）是下一代密码学账本，可以支持众多的高级功能，包括用户发行货币，智能协议，去中心化的交易和设立去中心化自治组织(DAOs)或去中心化自治公司（DACs）。以太坊并不是把每一单个类型的功能作为特性来特别支持，相反，以太坊包括一个内置的图灵完备的脚本语言，允许通过被称为“合同”的机制来为自己想实现的特性写代码。一个合同就像一个自动的代理，每当接收到一笔交易，合同就会运行特定的一段代码，这段代码能修改合同内部的数据存储或者发送交易。', 'coin_icon/ETH.png', 1, '168be8ac41f944c', 'ca83d7ffcaf8f1c8dac1b14772fad5', 'https://ethereum.org/en/', 'https://github.com/ethereum/wiki/wiki', 'https://etherscan.io/', '2021-09-04 23:00:00', 110249440, 110249440, '$0.31', 1, 1, 1, 1, '2020-08-12 13:15:41', '2024-02-20 16:18:20', NULL, '0x4F93722B9a03cd6E55d943e1ca9B445AD1cED9A7', 1);
