INSERT INTO `user_subscribe` VALUES (4, 'eos', '0.02', 'USDT/ETH/BTC', '2023-01-19 00:00:00', '2023-01-20 00:00:00', '2023-02-19 00:00:00', '2023-03-19 00:00:00', 1, 'GriffinArt （项目总发行量100亿）由土耳其的一个团队于 25/07/2021 推出。Griffin Art 将拥有一个 NFT 市场和一个由超通货紧缩代币提供支持的手机游戏（围绕神话生物）\r\nGriffin Art 市场进入策略包括启动 NFT 市场，允许生成 NFT 和 Griffin Art 社区的治理代币 ($GART)。Griffin Art 将成为一个包罗万象的 NFT 市场，利用币安智能链的潜力实现可访问性、NFT 共享、创建和所有权。\r\nGriffin Art 还将创建与 $GART 代币和 NFT 市场集成的流行类型的手机游戏；允许玩家在游戏内玩、交易、使用 NFT 物品并赚取代币。只有 $GART 持有者才能访问游戏。他们将能够通过竞技游戏赚取 $GART。《Griffin Land》将是Griffin Art平台上的第一款游戏，它将是一款战略性的3D，1v1格斗游戏。', 'GriffinArt (the total circulation of the project is 10 billion yuan) was launched by a team in Turkey on 25th July/21st. Griffin Art will have an NFT market and a mobile game supported by super-deflation tokens (around mythological creatures)\r\nGriffin Art will also create popular mobile games integrated with $GART tokens and NFT market; Allow players to play, trade, use NFT items and earn tokens in the game. Only $GART holders can access the game. They will be able to earn $GART through competitive games. Griffin Land will be the first game on Griffin Art platform, and it will be a strategic 3D, 1v1 fighting game.', 10000000, 100);
